INSERT INTO `mdl_course` (`id`, `category`, `sortorder`, `fullname`, `shortname`, `idnumber`, `summary`, `summaryformat`, `format`, `showgrades`, `newsitems`, `startdate`, `enddate`, `relativedatesmode`, `marker`, `maxbytes`, `legacyfiles`, `showreports`, `visible`, `visibleold`, `downloadcontent`, `groupmode`, `groupmodeforce`, `defaultgroupingid`, `lang`, `calendartype`, `theme`, `timecreated`, `timemodified`, `requested`, `enablecompletion`, `completionnotify`, `cacherev`, `originalcourseid`, `showactivitydates`, `showcompletionconditions`, `pdfexportfont`, `enableaitools`) VALUES
(1, 0, 1, 'â€śSilent Moodle: Media Pembelajaran Visual-Audio dengan Pengawasan Fokus dan Kejujuran Belajarâ€ť', '\"SM-VisualAudio\"', '', '', 0, 'site', 1, 3, 0, 0, 0, 0, 0, 0, 0, 1, 1, NULL, 0, 0, 0, '', '', '', 1772783117, 1778564274, 0, 0, 0, 1778574896, NULL, 1, NULL, NULL, NULL),
(2, 1, 10002, 'Administrasi Sistem Jaringan', 'ASJ', 'ASJ-01', '<p data-start=\"38\" data-end=\"452\" style=\"text-align: left;\">Mata pelajaran <strong data-start=\"53\" data-end=\"94\"><span class=\"whitespace-normal\">Administrasi Sistem Jaringan</span></strong> bertujuan untuk memberikan pemahaman kepada peserta didik mengenai konsep, prinsip, serta praktik dalam pengelolaan dan administrasi sistem jaringan komputer. Pembelajaran ini mencakup materi tentang instalasi sistem operasi jaringan, konfigurasi layanan jaringan, manajemen pengguna, pengaturan hak akses, serta pemeliharaan dan pengamanan sistem jaringan.</p>\r\n<p data-start=\"454\" data-end=\"853\" data-is-last-node=\"\" data-is-only-node=\"\" style=\"text-align: left;\">Melalui kegiatan pembelajaran yang mengintegrasikan teori dan praktik, peserta didik diharapkan mampu mengelola layanan jaringan secara efektif dan efisien sesuai dengan kebutuhan organisasi atau lingkungan kerja. Selain itu, mata pelajaran ini juga bertujuan untuk mengembangkan kemampuan berpikir logis, ketelitian, serta keterampilan teknis yang relevan dengan bidang teknologi jaringan komputer.</p>', 1, 'weeks', 1, 0, 1785430800, 1787850000, 0, 0, 262144000, 0, 1, 1, 1, NULL, 2, 0, 0, '', '', '', 1773559508, 1773559508, 0, 1, 0, 1778574896, NULL, 1, 1, NULL, NULL),
(3, 1, 10001, 'Basis Data', 'Basdat', 'BSD-01', '<p>Mata pelajaranÂ <strong>Basis Data</strong> mempelajari konsep dasar pengelolaan data menggunakan sistem basis data. Dalam pembelajaran ini, peserta didik akan memahami bagaimana data disimpan, diorganisasi, dan dikelola secara terstruktur agar mudah diakses dan digunakan dalam suatu sistem informasi.</p>\r\n<p>Materi yang dipelajari meliputi konsep dasar basis data, perancangan database, pembuatan tabel, pengelolaan relasi antar tabel, serta penggunaan bahasa query seperti SQL untuk melakukan pengolahan data. Melalui pembelajaran teori dan praktik, peserta didik diharapkan mampu merancang dan mengelola basis data sederhana yang dapat digunakan dalam pengembangan aplikasi atau sistem informasi.</p>', 1, 'topics', 1, 5, 1782838800, 1798736340, 0, 0, 0, 0, 0, 1, 1, NULL, 0, 0, 0, '', '', '', 1773595594, 1777972777, 0, 1, 0, 1778584187, NULL, 1, 1, NULL, NULL);
