INSERT INTO `mdl_event` (`id`, `name`, `description`, `format`, `categoryid`, `courseid`, `groupid`, `userid`, `repeatid`, `component`, `modulename`, `instance`, `type`, `eventtype`, `timestart`, `timeduration`, `timesort`, `visible`, `uuid`, `sequence`, `timemodified`, `subscriptionid`, `priority`, `location`) VALUES
(1, 'Tugas Mandiri: Analisis Fakta dan Opini SQL. is due', '<p><span><span class=\"citation-943\">\"Silakan unduh LKS yang telah disediakan. Analisislah sebuah kasus manipulasi data berdasarkan video yang telah ditonton, lalu identifikasi mana yang merupakan </span><strong><span class=\"citation-943\">fakta</span></strong><span class=\"citation-943\"> dan mana yang </span><strong><span class=\"citation-943\">opini</span></strong><span class=\"citation-943\"> terkait penggunaan perintah SQL</span></span><span class=\"citation-943 citation-end-943\"><sup class=\"superscript\"></sup><sup class=\"superscript\"></sup><sup class=\"superscript\"></sup><sup class=\"superscript\"></sup></span><span>. Kumpulkan jawaban dalam format PDF.\"</span></p>', 1, 0, 3, 0, 2, 0, NULL, 'assign', 1, 1, 'due', 1773853140, 0, 1773853140, 1, '', 1, 1773598933, NULL, NULL, NULL),
(2, 'Tugas Mandiri: Analisis Fakta dan Opini SQL. is due to be graded', '<p><span><span class=\"citation-943\">\"Silakan unduh LKS yang telah disediakan. Analisislah sebuah kasus manipulasi data berdasarkan video yang telah ditonton, lalu identifikasi mana yang merupakan </span><strong><span class=\"citation-943\">fakta</span></strong><span class=\"citation-943\"> dan mana yang </span><strong><span class=\"citation-943\">opini</span></strong><span class=\"citation-943\"> terkait penggunaan perintah SQL</span></span><span class=\"citation-943 citation-end-943\"><sup class=\"superscript\"></sup><sup class=\"superscript\"></sup><sup class=\"superscript\"></sup><sup class=\"superscript\"></sup></span><span>. Kumpulkan jawaban dalam format PDF.\"</span></p>', 1, 0, 3, 0, 2, 0, NULL, 'assign', 1, 1, 'gradingdue', 1774803600, 0, 1774803600, 1, '', 1, 1773598934, NULL, NULL, NULL),
(3, 'Evaluasi akhir tentang Query SQL opens', '', 1, 0, 3, 0, 2, 0, NULL, 'quiz', 2, 0, 'open', 1773637200, 0, 1773637200, 0, '', 1, 1773612319, NULL, NULL, NULL),
(4, 'Evaluasi akhir tentang Query SQL closes', '', 1, 0, 3, 0, 2, 0, NULL, 'quiz', 2, 1, 'close', 1773639000, 0, 1773639000, 0, '', 1, 1773612319, NULL, NULL, NULL),
(5, 'Membuat Tabel Database Sekolah is due', '<p><strong>Deskripsi Tugas:</strong> Setelah mempelajari materi tentang <i>Data Definition Language</i> (DDL), tugas Anda adalah mengimplementasikan rancangan database sekolah sederhana ke dalam SQL. Tugas ini bertujuan untuk menguji pemahaman Anda dalam pembuatan tabel, penentuan tipe data, dan penggunaan <i>Primary Key</i>.</p>\r\n<p><strong>Instruksi Pengerjaan:</strong></p>\r\n<ol start=\"1\">\r\n<li>\r\n<p><strong>Buatlah Database</strong> dengan nama <code>db_sekolah_nama_anda</code>.</p>\r\n</li>\r\n<li>\r\n<p><strong>Buatlah 3 Tabel utama</strong> dengan ketentuan sebagai berikut:</p>\r\n<ul>\r\n<li>\r\n<p><strong>Tabel Siswa:</strong> (NIS sebagai <i>Primary Key</i>, Nama, Alamat, Tanggal Lahir).</p>\r\n</li>\r\n<li>\r\n<p><strong>Tabel Guru:</strong> (NIP sebagai <i>Primary Key</i>, Nama Guru, Mata Pelajaran).</p>\r\n</li>\r\n<li>\r\n<p><strong>Tabel Kelas:</strong> (ID Kelas sebagai <i>Primary Key</i>, Nama Kelas, Tingkat).</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li>\r\n<p><strong>Gunakan Perintah SQL</strong> (<code>CREATE TABLE</code>) untuk membuat ketiga tabel tersebut.</p>\r\n</li>\r\n<li>\r\n<p><strong>Screenshot</strong> hasil eksekusi perintah SQL Anda (baik di Terminal maupun di phpMyAdmin).</p>\r\n</li>\r\n</ol>', 1, 0, 3, 0, 2, 0, NULL, 'assign', 2, 1, 'due', 1774544340, 0, 1774544340, 0, '', 1, 1773612728, NULL, NULL, NULL),
(6, 'Membuat Tabel Database Sekolah is due to be graded', '<p><strong>Deskripsi Tugas:</strong> Setelah mempelajari materi tentang <i>Data Definition Language</i> (DDL), tugas Anda adalah mengimplementasikan rancangan database sekolah sederhana ke dalam SQL. Tugas ini bertujuan untuk menguji pemahaman Anda dalam pembuatan tabel, penentuan tipe data, dan penggunaan <i>Primary Key</i>.</p>\r\n<p><strong>Instruksi Pengerjaan:</strong></p>\r\n<ol start=\"1\">\r\n<li>\r\n<p><strong>Buatlah Database</strong> dengan nama <code>db_sekolah_nama_anda</code>.</p>\r\n</li>\r\n<li>\r\n<p><strong>Buatlah 3 Tabel utama</strong> dengan ketentuan sebagai berikut:</p>\r\n<ul>\r\n<li>\r\n<p><strong>Tabel Siswa:</strong> (NIS sebagai <i>Primary Key</i>, Nama, Alamat, Tanggal Lahir).</p>\r\n</li>\r\n<li>\r\n<p><strong>Tabel Guru:</strong> (NIP sebagai <i>Primary Key</i>, Nama Guru, Mata Pelajaran).</p>\r\n</li>\r\n<li>\r\n<p><strong>Tabel Kelas:</strong> (ID Kelas sebagai <i>Primary Key</i>, Nama Kelas, Tingkat).</p>\r\n</li>\r\n</ul>\r\n</li>\r\n<li>\r\n<p><strong>Gunakan Perintah SQL</strong> (<code>CREATE TABLE</code>) untuk membuat ketiga tabel tersebut.</p>\r\n</li>\r\n<li>\r\n<p><strong>Screenshot</strong> hasil eksekusi perintah SQL Anda (baik di Terminal maupun di phpMyAdmin).</p>\r\n</li>\r\n</ol>', 1, 0, 3, 0, 2, 0, NULL, 'assign', 2, 1, 'gradingdue', 1774803600, 0, 1774803600, 0, '', 1, 1773612728, NULL, NULL, NULL),
(9, 'Quiz: Pemahaman Database is due', '<p>đź“ť Jawab pertanyaan berikut berdasarkan video dan audio sebelumnya:</p>\r\n<p>1. Apa yang dimaksud dengan database?<br />2. Sebutkan 1 contoh database dalam kehidupan sehari-hari</p>\r\n<p>Tuliskan dengan bahasa sendiri.</p>', 1, 0, 3, 0, 0, 0, NULL, 'assign', 3, 1, 'due', 1778518800, 0, 1778518800, 1, '', 1, 1777988444, NULL, NULL, NULL),
(10, 'Quiz: Pemahaman Database is due to be graded', '<p>đź“ť Jawab pertanyaan berikut berdasarkan video dan audio sebelumnya:</p>\r\n<p>1. Apa yang dimaksud dengan database?<br />2. Sebutkan 1 contoh database dalam kehidupan sehari-hari</p>\r\n<p>Tuliskan dengan bahasa sendiri.</p>', 1, 0, 3, 0, 0, 0, NULL, 'assign', 3, 1, 'gradingdue', 1779123600, 0, 1779123600, 1, '', 1, 1777988444, NULL, NULL, NULL),
(11, 'Quiz: Pemahaman Database should be completed', '<div class=\"no-overflow\"><p>đź“ť Jawab pertanyaan berikut berdasarkan video dan audio sebelumnya:</p>\r\n<p>1. Apa yang dimaksud dengan database?<br>2. Sebutkan 1 contoh database dalam kehidupan sehari-hari</p>\r\n<p>Tuliskan dengan bahasa sendiri.</p></div>', 1, 0, 3, 0, 2, 0, NULL, 'assign', 3, 1, 'expectcompletionon', 1780651200, 0, 1780651200, 1, '', 1, 1777988444, NULL, NULL, NULL),
(12, 'Audio Penjelasan: Database should be completed', '<div class=\"no-overflow\"><p>â–¶ď¸ŹDengarkan audio berikut dengan fokus.</p></div>', 1, 0, 3, 0, 2, 0, NULL, 'page', 2, 1, 'expectcompletionon', 1780651440, 0, 1780651440, 1, '', 1, 1777988221, NULL, NULL, NULL),
(13, 'Apa itu Database? should be completed', '<div class=\"no-overflow\"><p>đźŽ¬ Perhatikan video berikut dengan fokus<br>Gunakan headset untuk hasil maksimal</p></div>', 1, 0, 3, 0, 2, 0, NULL, 'page', 1, 1, 'expectcompletionon', 1780651500, 0, 1780651500, 1, '', 1, 1777973163, NULL, NULL, NULL);
