(6, 'H5P.JoubelUI', 'Joubel UI', 1, 3, 19, 0, 0, '', 'js/joubel-help-dialog.js, js/joubel-message-dialog.js, js/joubel-progress-circle.js, js/joubel-simple-rounded-button.js, js/joubel-speech-bubble.js, js/joubel-throbber.js, js/joubel-tip.js, js/joubel-slider.js, js/joubel-score-bar.js, js/joubel-progressbar.js, js/joubel-ui.js', 'css/joubel-help-dialog.css, css/joubel-message-dialog.css, css/joubel-progress-circle.css, css/joubel-simple-rounded-button.css, css/joubel-speech-bubble.css, css/joubel-tip.css, css/joubel-slider.css, css/joubel-score-bar.css, css/joubel-progressbar.css, css/joubel-ui.css, css/joubel-icon.css', '', '', NULL, 1, 3, NULL, NULL, NULL, 1),
(7, 'H5P.Transition', 'Transition', 1, 0, 4, 0, 0, '', 'transition.js', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, 1),
(8, 'H5PEditor.ShowWhen', 'Toggle visibility of a field based on rules', 1, 0, 9, 0, 0, '', 'h5p-show-when.js', 'h5p-show-when.css', '', '', NULL, NULL, NULL, NULL, NULL, NULL, 1),
(9, 'H5P.Chart', 'Chart', 1, 2, 22, 1, 0, 'iframe', 'chart.js, d3.js, pie.js, bar.js', 'chart.css', '', '[\n  {\n    \"name\": \"graphMode\",\n    \"type\": \"select\",\n    \"label\": \"Type of chart\",\n    \"importance\": \"high\",\n    \"options\": [\n      {\n        \"value\": \"pieChart\",\n        \"label\": \"Pie Chart\"\n      },\n      {\n        \"value\": \"barChart\",\n        \"label\": \"Bar Chart\"\n      }\n    ],\n    \"default\": \"pieChart\"\n  },\n  {\n    \"name\": \"listOfTypes\",\n    \"type\": \"list\",\n    \"label\": \"Data elements\",\n    \"importance\": \"high\",\n    \"entity\": \"option\",\n    \"min\": 1,\n    \"defaultNum\": 2,\n    \"field\": {\n      \"name\": \"type\",\n      \"type\": \"group\",\n      \"label\": \"Data element\",\n      \"importance\": \"high\",\n      \"fields\": [\n        {\n          \"name\": \"text\",\n          \"type\": \"text\",\n          \"label\": \"Name\",\n          \"importance\": \"medium\"\n        },\n        {\n          \"name\": \"value\",\n          \"type\": \"number\",\n          \"label\": \"Value\",\n          \"importance\": \"low\",\n          \"default\": 1,\n          \"min\": 0.0001,\n          \"decimals\": 4\n        },\n        {\n          \"name\": \"color\",\n          \"type\": \"text\",\n          \"widget\": \"colorSelector\",\n          \"label\": \"Color\",\n          \"importance\": \"low\",\n          \"default\": \"#000\",\n          \"optional\": true,\n          \"spectrum\": {\n            \"showInput\": true,\n            \"preferredFormat\": \"hex\"\n          }\n        },\n        {\n          \"name\": \"fontColor\",\n          \"type\": \"text\",\n          \"widget\": \"colorSelector\",\n          \"label\": \"Font Color\",\n          \"importance\": \"low\",\n          \"default\": \"#fff\",\n          \"optional\": true,\n          \"spectrum\": {\n            \"showInput\": true,\n            \"preferredFormat\": \"hex\"\n          }\n        }\n      ]\n    }\n  },\n  {\n    \"name\": \"figureDefinition\",\n    \"type\": \"text\",\n    \"label\": \"Text read by readspeakers defining the figure as a chart.\",\n    \"importance\": \"low\",\n    \"default\": \"Chart\",\n    \"common\": true\n  }\n]\n', NULL, 1, 21, NULL, 'https://h5p.org/tutorial-chart', 'https://h5p.org/chart', 1),
(10, 'H5PEditor.ColorSelector', 'H5PEditor.ColorSelector', 1, 3, 1, 0, 0, '', 'scripts/spectrum.js, scripts/color-selector.js', 'styles/spectrum.css, styles/color-selector.css', '', '', NULL, 1, 24, NULL, NULL, NULL, 1),
(11, 'H5P.Collage', 'Collage', 0, 3, 25, 1, 0, '', 'collage.js, template.js, clip.js', 'collage.css', '', '[\n  {\n    \"name\": \"collage\",\n    \"label\": \"Preview\",\n    \"importance\": \"high\",\n    \"type\": \"group\",\n    \"widget\": \"collage\",\n    \"description\": \"You can move(pan) the images around by dragging them. You can also select an image and then use the + or - keys on your keyboard to zoom or simply hold down the Z key while moving your mouse wheel.\",\n    \"fields\": [\n      {\n        \"name\": \"template\",\n        \"label\": \"Layout\",\n        \"importance\": \"high\",\n        \"type\": \"select\",\n        \"options\": [\n          {\n            \"value\": \"1\",\n            \"label\": \"1\"\n          },\n          {\n            \"value\": \"1-1\",\n            \"label\": \"1-1\"\n          },\n          {\n            \"value\": \"2\",\n            \"label\": \"2\"\n          },\n          {\n            \"value\": \"2-1\",\n            \"label\": \"2-1\"\n          },\n          {\n            \"value\": \"1-2\",\n            \"label\": \"1-2\"\n          },\n          {\n            \"value\": \"2-2\",\n            \"label\": \"2-2\"\n          },\n          {\n            \"value\": \"3-1\",\n            \"label\": \"3-1\"\n          },\n          {\n            \"value\": \"1-3\",\n            \"label\": \"1-3\"\n          },\n          {\n            \"value\": \"2-3\",\n            \"label\": \"2-3\"\n          },\n          {\n            \"value\": \"3-2\",\n            \"label\": \"3-2\"\n          },\n          {\n            \"value\": \"3-3\",\n            \"label\": \"3-3\"\n          }\n        ],\n        \"default\": \"2-1\"\n      },\n      {\n        \"name\": \"options\",\n        \"label\": \"Display options\",\n        \"importance\": \"low\",\n        \"type\": \"group\",\n        \"fields\": [\n          {\n            \"name\": \"heightRatio\",\n            \"label\": \"Height\",\n            \"importance\": \"low\",\n            \"type\": \"number\",\n            \"decimals\": 2,\n            \"min\": 0.1,\n            \"max\": 2,\n            \"default\": 0.75\n          },\n          {\n            \"name\": \"spacing\",\n            \"label\": \"Spacing\",\n            \"importance\": \"low\",\n            \"type\": \"number\",\n            \"decimals\": 2,\n            \"min\": 0,\n            \"max\": 2,\n            \"default\": 0.5\n          },\n          {\n            \"name\": \"frame\",\n            \"label\": \"Frame\",\n            \"importance\": \"low\",\n            \"type\": \"boolean\",\n            \"default\": true\n          }\n        ]\n      },\n      {\n        \"name\": \"clips\",\n        \"label\": \"Clips\",\n        \"importance\": \"low\",\n        \"type\": \"list\",\n        \"min\": 1,\n        \"entity\": \"clip\",\n        \"field\": {\n          \"name\": \"clip\",\n          \"label\": \"Clip\",\n          \"importance\": \"low\",\n          \"type\": \"group\",\n          \"fields\": [\n            {\n              \"name\": \"image\",\n              \"type\": \"image\",\n              \"label\": \"Image\",\n              \"importance\": \"low\"\n            },\n            {\n              \"name\": \"offset\",\n              \"label\": \"Offset\",\n              \"importance\": \"low\",\n              \"type\": \"group\",\n              \"fields\": [\n                {\n                  \"name\": \"top\",\n                  \"label\": \"Top\",\n                  \"importance\": \"low\",\n                  \"type\": \"number\",\n                  \"default\": 0\n                },\n                {\n                  \"name\": \"left\",\n                  \"label\": \"Left\",\n                  \"importance\": \"low\",\n                  \"type\": \"number\",\n                  \"default\": 0\n                }\n              ]\n            },\n            {\n              \"name\": \"alt\",\n              \"type\": \"text\",\n              \"label\": \"Alternative text\",\n              \"importance\": \"high\",\n              \"description\": \"Required. If the browser can\'t load the image this text will be displayed instead. Also used by readspeakers.\"\n            },\n            {\n              \"name\": \"title\",\n              \"type\": \"text\",\n              \"label\": \"Hover text\",\n              \"importance\": \"low\",\n              \"description\": \"Optional. This text is displayed when the user hovers his pointing device over the image.\",\n              \"optional\": true\n            },\n            {\n              \"name\": \"scale\",\n              \"label\": \"Scale\",\n              \"importance\": \"low\",\n              \"type\": \"number\",\n              \"decimals\": 2,\n              \"min\": 0.01,\n              \"default\": 1\n            }\n          ]\n        }\n      }\n    ]\n  }\n]\n', NULL, 1, 7, NULL, 'https://h5p.org/tutorial-collage', 'https://h5p.org/collage', 1),
(12, 'H5PEditor.Collage', 'Collage Editor', 0, 3, 22, 0, 0, '', 'collage-editor.js, layout-selector.js, clip-editor.js', 'collage-editor.css', '', '', NULL, 1, 24, NULL, NULL, NULL, 1),
(13, 'H5P.Audio', 'Audio', 1, 5, 12, 1, 0, 'iframe', 'scripts/audio.js', 'styles/audio.css', '', '[\n  {\n    \"name\": \"files\",\n    \"type\": \"audio\",\n    \"importance\": \"high\",\n    \"label\": \"Source files\",\n    \"disableCopyright\": true\n  },\n  {\n    \"name\": \"playerMode\",\n    \"type\": \"select\",\n    \"importance\": \"low\",\n    \"label\": \"Player mode\",\n    \"description\": \"Select the layout of the player.\",\n    \"options\": [\n      {\n        \"value\": \"minimalistic\",\n        \"label\": \"Minimalistic\"\n      },\n      {\n        \"value\": \"full\",\n        \"label\": \"Full\"\n      },\n      {\n        \"value\": \"transparent\",\n        \"label\": \"Transparent\"\n      }\n    ],\n    \"default\": \"minimalistic\"\n  },\n  {\n    \"name\": \"fitToWrapper\",\n    \"type\": \"boolean\",\n    \"importance\": \"low\",\n    \"label\": \"Fit to wrapper\",\n    \"default\": false,\n    \"descriptions\": \"Adjust audioplayer size to use available space\",\n    \"widget\": \"showWhen\",\n    \"showWhen\": {\n      \"rules\": [\n        {\n          \"field\": \"playerMode\",\n          \"equals\": \"minimalistic\"\n        },\n        {\n          \"field\": \"playerMode\",\n          \"equals\": \"full\"\n        }\n      ]\n    }\n  },\n  {\n    \"name\": \"controls\",\n    \"type\": \"boolean\",\n    \"importance\": \"low\",\n    \"label\": \"Enable controls\",\n    \"default\": true,\n    \"description\": \"Controls allow the user to for instance pause the audio\",\n    \"widget\": \"showWhen\",\n    \"showWhen\": {\n      \"rules\": [\n        {\n          \"field\": \"playerMode\",\n          \"equals\": \"full\"\n        }\n      ]\n    }\n  },\n  {\n    \"name\": \"autoplay\",\n    \"type\": \"boolean\",\n    \"importance\": \"low\",\n    \"label\": \"Enable autoplay\",\n    \"description\": \"With autoplay the audio starts to play immediately. Do note that this is not supported by all browsers\"\n  },\n  {\n    \"name\": \"playAudio\",\n    \"type\": \"text\",\n    \"importance\": \"low\",\n    \"label\": \"Play audio (Readspeaker)\",\n    \"common\": true,\n    \"default\": \"Play audio\"\n  },\n  {\n    \"name\": \"pauseAudio\",\n    \"type\": \"text\",\n    \"importance\": \"low\",\n    \"label\": \"Pause audio (Readspeaker)\",\n    \"common\": true,\n    \"default\": \"Pause audio\"\n  },\n  {\n    \"name\": \"contentName\",\n    \"type\": \"text\",\n    \"importance\": \"low\",\n    \"label\": \"Audio content name\",\n    \"common\": true,\n    \"default\": \"Audio\"\n  },\n  {\n    \"name\": \"audioNotSupported\",\n    \"type\": \"text\",\n    \"label\": \"Audio not supported message\",\n    \"importance\": \"low\",\n    \"common\": true,\n    \"default\": \"Your browser does not support this audio\"\n  }\n]\n', NULL, 1, 19, NULL, NULL, NULL, 1),
(14, 'H5P.AudioRecorder', 'Audio Recorder', 1, 0, 33, 1, 0, 'iframe', 'dist/h5p-audio-recorder.js', 'fonts/h5p-audio-recorder-font-open-sans.css', '', '[\n  {\n    \"label\": \"Task Description\",\n    \"importance\": \"high\",\n    \"name\": \"title\",\n    \"type\": \"text\",\n    \"widget\": \"textarea\",\n    \"description\": \"Optional text to display above the audio recorder\",\n    \"optional\": true\n  },\n  {\n    \"label\": \"Localization\",\n    \"name\": \"l10n\",\n    \"type\": \"group\",\n    \"common\": true,\n    \"fields\": [\n      {\n        \"name\": \"recordAnswer\",\n        \"label\": \"Record button text\",\n        \"type\": \"text\",\n        \"default\": \"Record\"\n      },\n      {\n        \"name\": \"pause\",\n        \"label\": \"Pause button text\",\n        \"type\": \"text\",\n        \"default\": \"Pause\"\n      },\n      {\n        \"name\": \"continue\",\n        \"label\": \"Continue button text\",\n        \"type\": \"text\",\n        \"default\": \"Continue\"\n      },\n      {\n        \"name\": \"download\",\n        \"label\": \"Download button text\",\n        \"type\": \"text\",\n        \"default\": \"Download\"\n      },\n      {\n        \"name\": \"done\",\n        \"label\": \"Done button text\",\n        \"type\": \"text\",\n        \"default\": \"Done\"\n      },\n      {\n        \"name\": \"retry\",\n        \"label\": \"Retry button text\",\n        \"type\": \"text\",\n        \"default\": \"Retry\"\n      },\n      {\n        \"name\": \"microphoneNotSupported\",\n        \"label\": \"Microphone not supported error message\",\n        \"type\": \"text\",\n        \"default\": \"Microphone not supported. Make sure you are using a browser that allows microphone recording.\"\n      },\n      {\n        \"name\": \"microphoneInaccessible\",\n        \"label\": \"Microphone inaccessible error message\",\n        \"type\": \"text\",\n        \"default\": \"Microphone is not accessible. Make sure that the browser microphone is enabled.\"\n      },\n      {\n        \"name\": \"insecureNotAllowed\",\n        \"type\": \"text\",\n        \"label\": \"Message displayed when insecure access is not allowed\",\n        \"description\": \"Some browsers do not allow using the microphone when the page is served using HTTP. This message will be displayed if that is the case\",\n        \"default\": \"Access to microphone is not allowed in your browser since this page is not served using HTTPS. Please contact the author, and ask him to make this available using HTTPS\"\n      },\n      {\n        \"name\": \"statusReadyToRecord\",\n        \"label\": \"Ready to record status message\",\n        \"type\": \"text\",\n        \"default\": \"Press a button below to record your answer.\"\n      },\n      {\n        \"name\": \"statusRecording\",\n        \"label\": \"Recording status message\",\n        \"type\": \"text\",\n        \"default\": \"Recording...\"\n      },\n      {\n        \"name\": \"statusPaused\",\n        \"label\": \"Paused status message\",\n        \"type\": \"text\",\n        \"default\": \"Recording paused. Press a button to continue recording.\"\n      },\n      {\n        \"name\": \"statusFinishedRecording\",\n        \"label\": \"Finished recording status message\",\n        \"type\": \"text\",\n        \"default\": \"You have successfully recorded your answer! Listen to the recording below.\"\n      },\n      {\n        \"name\": \"downloadRecording\",\n        \"label\": \"Download recording message\",\n        \"type\": \"text\",\n        \"default\": \"Download this recording or retry.\"\n      },\n      {\n        \"name\": \"retryDialogHeaderText\",\n        \"label\": \"Retry dialog header text\",\n        \"type\": \"text\",\n        \"default\": \"Retry recording?\"\n      },\n      {\n        \"name\": \"retryDialogBodyText\",\n        \"label\": \"Retry dialog body text\",\n        \"type\": \"text\",\n        \"default\": \"By pressing \\\"Retry\\\" you will lose your current recording.\"\n      },\n      {\n        \"name\": \"retryDialogConfirmText\",\n        \"label\": \"Retry dialog confirm text\",\n        \"type\": \"text\",\n        \"default\": \"Retry\"\n      },\n      {\n        \"name\": \"retryDialogCancelText\",\n        \"label\": \"Retry dialog cancel text\",\n        \"type\": \"text\",\n        \"default\": \"Cancel\"\n      },\n      {\n        \"name\": \"statusCantCreateTheAudioFile\",\n        \"label\": \"Can\'t create audio file status message\",\n        \"type\": \"text\",\n        \"default\": \"Can\'t create the audio file.\"\n      }\n    ]\n  }\n]\n', NULL, NULL, NULL, NULL, NULL, NULL, 1),
(15, 'H5P.Blanks', 'Fill in the Blanks', 1, 14, 13, 1, 0, 'iframe', 'js/blanks.js, js/cloze.js', 'css/blanks.css', '', '[\n  {\n    \"name\": \"media\",\n    \"type\": \"group\",\n    \"label\": \"Media\",\n    \"importance\": \"medium\",\n    \"fields\": [\n      {\n        \"name\": \"type\",\n        \"type\": \"library\",\n        \"label\": \"Type\",\n        \"options\": [\n          \"H5P.Image 1.1\",\n          \"H5P.Video 1.6\",\n          \"H5P.Audio 1.5\"\n        ],\n        \"optional\": true,\n        \"description\": \"Optional media to display above the question.\"\n      },\n      {\n        \"name\": \"disableImageZooming\",\n        \"type\": \"boolean\",\n        \"label\": \"Disable image zooming\",\n        \"importance\": \"low\",\n        \"default\": false,\n        \"optional\": true,\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"type\",\n              \"equals\": \"H5P.Image 1.1\"\n            }\n          ]\n        }\n      }\n    ]\n  },\n  {\n    \"label\": \"Task description\",\n    \"importance\": \"high\",\n    \"name\": \"text\",\n    \"type\": \"text\",\n    \"widget\": \"html\",\n    \"default\": \"Fill in the missing words\",\n    \"description\": \"A guide telling the user how to answer this task.\",\n    \"enterMode\": \"p\",\n    \"tags\": [\n      \"strong\",\n      \"em\",\n      \"u\",\n      \"a\",\n      \"ul\",\n      \"ol\",\n      \"h2\",\n      \"h3\",\n      \"hr\",\n      \"pre\",\n      \"code\"\n    ]\n  },\n  {\n    \"name\": \"questions\",\n    \"type\": \"list\",\n    \"label\": \"Text blocks\",\n    \"importance\": \"high\",\n    \"entity\": \"text block\",\n    \"min\": 1,\n    \"max\": 31,\n    \"field\": {\n      \"name\": \"question\",\n      \"type\": \"text\",\n      \"widget\": \"html\",\n      \"label\": \"Line of text\",\n      \"importance\": \"high\",\n      \"placeholder\": \"Oslo is the capital of *Norway*.\",\n      \"description\": \"\",\n      \"important\": {\n        \"description\": \"<ul><li>Blanks are added with an asterisk (*) in front and behind the correct word/phrase.</li><li>Alternative answers are separated with a forward slash (/).</li><li>You may add a textual tip, using a colon (:) in front of the tip.</li></ul>\",\n        \"example\": \"H5P content may be edited using a *browser/web-browser:Something you use every day*.\"\n      },\n      \"enterMode\": \"p\",\n      \"tags\": [\n        \"strong\",\n        \"em\",\n        \"del\",\n        \"u\",\n        \"code\"\n      ]\n    }\n  },\n  {\n    \"name\": \"overallFeedback\",\n    \"type\": \"group\",\n    \"label\": \"Overall Feedback\",\n    \"importance\": \"low\",\n    \"expanded\": true,\n    \"fields\": [\n      {\n        \"name\": \"overallFeedback\",\n        \"type\": \"list\",\n        \"widgets\": [\n          {\n            \"name\": \"RangeList\",\n            \"label\": \"Default\"\n          }\n        ],\n        \"importance\": \"high\",\n        \"label\": \"Define custom feedback for any score range\",\n        \"description\": \"Click the \\\"Add range\\\" button to add as many ranges as you need. Example: 0-20% Bad score, 21-91% Average Score, 91-100% Great Score!\",\n        \"entity\": \"range\",\n        \"min\": 1,\n        \"defaultNum\": 1,\n        \"optional\": true,\n        \"field\": {\n          \"name\": \"overallFeedback\",\n          \"type\": \"group\",\n          \"importance\": \"low\",\n          \"fields\": [\n            {\n              \"name\": \"from\",\n              \"type\": \"number\",\n              \"label\": \"Score Range\",\n              \"min\": 0,\n              \"max\": 100,\n              \"default\": 0,\n              \"unit\": \"%\"\n            },\n            {\n              \"name\": \"to\",\n              \"type\": \"number\",\n              \"min\": 0,\n              \"max\": 100,\n              \"default\": 100,\n              \"unit\": \"%\"\n            },\n            {\n              \"name\": \"feedback\",\n              \"type\": \"text\",\n              \"label\": \"Feedback for defined score range\",\n              \"importance\": \"low\",\n              \"placeholder\": \"Fill in the feedback\",\n              \"optional\": true\n            }\n          ]\n        }\n      }\n    ]\n  },\n  {\n    \"label\": \"Text for \\\"Show solutions\\\" button\",\n    \"name\": \"showSolutions\",\n    \"type\": \"text\",\n    \"default\": \"Show solution\",\n    \"common\": true\n  },\n  {\n    \"label\": \"Text for \\\"Retry\\\" button\",\n    \"importance\": \"low\",\n    \"name\": \"tryAgain\",\n    \"type\": \"text\",\n    \"default\": \"Retry\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"label\": \"Text for \\\"Check\\\" button\",\n    \"importance\": \"low\",\n    \"name\": \"checkAnswer\",\n    \"type\": \"text\",\n    \"default\": \"Check\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"label\": \"Text for \\\"Submit\\\" button\",\n    \"importance\": \"low\",\n    \"name\": \"submitAnswer\",\n    \"type\": \"text\",\n    \"default\": \"Submit\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"label\": \"Text for \\\"Not filled out\\\" message\",\n    \"importance\": \"low\",\n    \"name\": \"notFilledOut\",\n    \"type\": \"text\",\n    \"default\": \"Please fill in all blanks to view solution\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"label\": \"Text for \\\"\':ans\' is correct\\\" message\",\n    \"importance\": \"low\",\n    \"name\": \"answerIsCorrect\",\n    \"type\": \"text\",\n    \"default\": \"\':ans\' is correct\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"label\": \"Text for \\\"\':ans\' is wrong\\\" message\",\n    \"importance\": \"low\",\n    \"name\": \"answerIsWrong\",\n    \"type\": \"text\",\n    \"default\": \"\':ans\' is wrong\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"label\": \"Text for \\\"Answered correctly\\\" message\",\n    \"importance\": \"low\",\n    \"name\": \"answeredCorrectly\",\n    \"type\": \"text\",\n    \"default\": \"Answered correctly\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"label\": \"Text for \\\"Answered incorrectly\\\" message\",\n    \"importance\": \"low\",\n    \"name\": \"answeredIncorrectly\",\n    \"type\": \"text\",\n    \"default\": \"Answered incorrectly\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"label\": \"Assistive technology label for solution\",\n    \"importance\": \"low\",\n    \"name\": \"solutionLabel\",\n    \"type\": \"text\",\n    \"default\": \"Correct answer:\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"label\": \"Assistive technology label for input field\",\n    \"importance\": \"low\",\n    \"name\": \"inputLabel\",\n    \"type\": \"text\",\n    \"description\": \"Use @num and @total to replace current cloze number and total cloze number\",\n    \"default\": \"Blank input @num of @total\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"label\": \"Assistive technology label for saying an input has a tip tied to it\",\n    \"importance\": \"low\",\n    \"name\": \"inputHasTipLabel\",\n    \"type\": \"text\",\n    \"default\": \"Tip available\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"label\": \"Tip icon label\",\n    \"importance\": \"low\",\n    \"name\": \"tipLabel\",\n    \"type\": \"text\",\n    \"default\": \"Tip\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"name\": \"behaviour\",\n    \"type\": \"group\",\n    \"label\": \"Behavioural settings.\",\n    \"importance\": \"low\",\n    \"description\": \"These options will let you control how the task behaves.\",\n    \"optional\": true,\n    \"fields\": [\n      {\n        \"label\": \"Enable \\\"Retry\\\"\",\n        \"importance\": \"low\",\n        \"name\": \"enableRetry\",\n        \"type\": \"boolean\",\n        \"default\": true,\n        \"optional\": true\n      },\n      {\n        \"label\": \"Enable \\\"Show solution\\\" button\",\n        \"importance\": \"low\",\n        \"name\": \"enableSolutionsButton\",\n        \"type\": \"boolean\",\n        \"default\": true,\n        \"optional\": true\n      },\n      {\n        \"name\": \"enableCheckButton\",\n        \"type\": \"boolean\",\n        \"label\": \"Enable \\\"Check\\\" button\",\n        \"widget\": \"none\",\n        \"importance\": \"low\",\n        \"default\": true,\n        \"optional\": true\n      },\n      {\n        \"label\": \"Automatically check answers after input\",\n        \"importance\": \"low\",\n        \"name\": \"autoCheck\",\n        \"type\": \"boolean\",\n        \"default\": false,\n        \"optional\": true\n      },\n      {\n        \"name\": \"caseSensitive\",\n        \"importance\": \"low\",\n        \"type\": \"boolean\",\n        \"default\": true,\n        \"label\": \"Case sensitive\",\n        \"description\": \"Makes sure the user input has to be exactly the same as the answer.\"\n      },\n      {\n        \"label\": \"Require all fields to be answered before the solution can be viewed\",\n        \"importance\": \"low\",\n        \"name\": \"showSolutionsRequiresInput\",\n        \"type\": \"boolean\",\n        \"default\": true,\n        \"optional\": true\n      },\n      {\n        \"label\": \"Put input fields on separate lines\",\n        \"importance\": \"low\",\n        \"name\": \"separateLines\",\n        \"type\": \"boolean\",\n        \"default\": false,\n        \"optional\": true\n      },\n      {\n        \"label\": \"Show confirmation dialog on \\\"Check\\\"\",\n        \"importance\": \"low\",\n        \"name\": \"confirmCheckDialog\",\n        \"type\": \"boolean\",\n        \"description\": \"This options is not compatible with the \\\"Automatically check answers after input\\\" option\",\n        \"default\": false\n      },\n      {\n        \"label\": \"Show confirmation dialog on \\\"Retry\\\"\",\n        \"importance\": \"low\",\n        \"name\": \"confirmRetryDialog\",\n        \"type\": \"boolean\",\n        \"default\": false\n      },\n      {\n        \"name\": \"acceptSpellingErrors\",\n        \"type\": \"boolean\",\n        \"label\": \"Accept minor spelling errors\",\n        \"importance\": \"low\",\n        \"description\": \"If activated, an answer will also count as correct with minor spelling errors (3-9 characters: 1 spelling error, more than 9 characters: 2 spelling errors)\",\n        \"default\": false,\n        \"optional\": true\n      }\n    ]\n  },\n  {\n    \"label\": \"Check confirmation dialog\",\n    \"importance\": \"low\",\n    \"name\": \"confirmCheck\",\n    \"type\": \"group\",\n    \"common\": true,\n    \"fields\": [\n      {\n        \"label\": \"Header text\",\n        \"importance\": \"low\",\n        \"name\": \"header\",\n        \"type\": \"text\",\n        \"default\": \"Finish ?\"\n      },\n      {\n        \"label\": \"Body text\",\n        \"importance\": \"low\",\n        \"name\": \"body\",\n        \"type\": \"text\",\n        \"default\": \"Are you sure you wish to finish ?\",\n        \"widget\": \"html\",\n        \"enterMode\": \"p\",\n        \"tags\": [\n          \"strong\",\n          \"em\",\n          \"del\",\n          \"u\",\n          \"code\"\n        ]\n      },\n      {\n        \"label\": \"Cancel button label\",\n        \"importance\": \"low\",\n        \"name\": \"cancelLabel\",\n        \"type\": \"text\",\n        \"default\": \"Cancel\"\n      },\n      {\n        \"label\": \"Confirm button label\",\n        \"importance\": \"low\",\n        \"name\": \"confirmLabel\",\n        \"type\": \"text\",\n        \"default\": \"Finish\"\n      }\n    ]\n  },\n  {\n    \"label\": \"Retry confirmation dialog\",\n    \"importance\": \"low\",\n    \"name\": \"confirmRetry\",\n    \"type\": \"group\",\n    \"common\": true,\n    \"fields\": [\n      {\n        \"label\": \"Header text\",\n        \"importance\": \"low\",\n        \"name\": \"header\",\n        \"type\": \"text\",\n        \"default\": \"Retry ?\"\n      },\n      {\n        \"label\": \"Body text\",\n        \"importance\": \"low\",\n        \"name\": \"body\",\n        \"type\": \"text\",\n        \"default\": \"Are you sure you wish to retry ?\",\n        \"widget\": \"html\",\n        \"enterMode\": \"p\",\n        \"tags\": [\n          \"strong\",\n          \"em\",\n          \"del\",\n          \"u\",\n          \"code\"\n        ]\n      },\n      {\n        \"label\": \"Cancel button label\",\n        \"importance\": \"low\",\n        \"name\": \"cancelLabel\",\n        \"type\": \"text\",\n        \"default\": \"Cancel\"\n      },\n      {\n        \"label\": \"Confirm button label\",\n        \"importance\": \"low\",\n        \"name\": \"confirmLabel\",\n        \"type\": \"text\",\n        \"default\": \"Confirm\"\n      }\n    ]\n  },\n  {\n    \"name\": \"scoreBarLabel\",\n    \"type\": \"text\",\n    \"label\": \"Textual representation of the score bar for those using a readspeaker\",\n    \"default\": \"You got :num out of :total points\",\n    \"importance\": \"low\",\n    \"common\": true\n  },\n  {\n    \"name\": \"a11yCheck\",\n    \"type\": \"text\",\n    \"label\": \"Assistive technology description for \\\"Check\\\" button\",\n    \"default\": \"Check the answers. The responses will be marked as correct, incorrect, or unanswered.\",\n    \"importance\": \"low\",\n    \"common\": true\n  },\n  {\n    \"name\": \"a11yShowSolution\",\n    \"type\": \"text\",\n    \"label\": \"Assistive technology description for \\\"Show Solution\\\" button\",\n    \"default\": \"Show the solution. The task will be marked with its correct solution.\",\n    \"importance\": \"low\",\n    \"common\": true\n  },\n  {\n    \"name\": \"a11yRetry\",\n    \"type\": \"text\",\n    \"label\": \"Assistive technology description for \\\"Retry\\\" button\",\n    \"default\": \"Retry the task. Reset all responses and start the task over again.\",\n    \"importance\": \"low\",\n    \"common\": true\n  },\n  {\n    \"name\": \"a11yCheckingModeHeader\",\n    \"type\": \"text\",\n    \"label\": \"Assistive technology description for starting task\",\n    \"default\": \"Checking mode\",\n    \"importance\": \"low\",\n    \"common\": true\n  }\n]', NULL, 1, 19, NULL, NULL, NULL, 1),
