(17, 'H5P.Column', 'Page', 1, 18, 8, 1, 0, 'iframe', 'scripts/h5p-column.js', 'styles/h5p-column.css', '', '[\n  {\n    \"name\": \"content\",\n    \"label\": \"List of Column Content\",\n    \"importance\": \"high\",\n    \"type\": \"list\",\n    \"min\": 1,\n    \"entity\": \"content\",\n    \"field\": {\n      \"name\": \"content\",\n      \"type\": \"group\",\n      \"fields\": [\n        {\n          \"name\": \"content\",\n          \"type\": \"library\",\n          \"importance\": \"high\",\n          \"label\": \"Content\",\n          \"options\": [\n            \"H5P.Accordion 1.0\",\n            \"H5P.Agamotto 1.6\",\n            \"H5P.Audio 1.5\",\n            \"H5P.AudioRecorder 1.0\",\n            \"H5P.Blanks 1.14\",\n            \"H5P.Chart 1.2\",\n            \"H5P.Collage 0.3\",\n            \"H5P.CoursePresentation 1.26\",\n            \"H5P.Dialogcards 1.9\",\n            \"H5P.DocumentationTool 1.8\",\n            \"H5P.DragQuestion 1.14\",\n            \"H5P.DragText 1.10\",\n            \"H5P.Essay 1.5\",\n            \"H5P.GuessTheAnswer 1.5\",\n            \"H5P.Table 1.2\",\n            \"H5P.AdvancedText 1.1\",\n            \"H5P.IFrameEmbed 1.0\",\n            \"H5P.Image 1.1\",\n            \"H5P.ImageHotspots 1.10\",\n            \"H5P.ImageHotspotQuestion 1.8\",\n            \"H5P.ImageSlider 1.1\",\n            \"H5P.InteractiveVideo 1.27\",\n            \"H5P.Link 1.3\",\n            \"H5P.MarkTheWords 1.11\",\n            \"H5P.MemoryGame 1.3\",\n            \"H5P.MultiChoice 1.16\",\n            \"H5P.Questionnaire 1.3\",\n            \"H5P.QuestionSet 1.20\",\n            \"H5P.Row 1.0\",\n            \"H5P.SingleChoiceSet 1.11\",\n            \"H5P.Summary 1.10\",\n            \"H5P.Timeline 1.1\",\n            \"H5P.TrueFalse 1.8\",\n            \"H5P.Video 1.6\",\n            \"H5P.MultiMediaChoice 0.3\"\n          ]\n        },\n        {\n          \"name\": \"useSeparator\",\n          \"type\": \"select\",\n          \"importance\": \"low\",\n          \"label\": \"Separate content with a horizontal ruler\",\n          \"default\": \"auto\",\n          \"options\": [\n            {\n              \"value\": \"auto\",\n              \"label\": \"Automatic (default)\"\n            },\n            {\n              \"value\": \"disabled\",\n              \"label\": \"Never use ruler above\"\n            },\n            {\n              \"value\": \"enabled\",\n              \"label\": \"Always use ruler above\"\n            }\n          ]\n        }\n      ]\n    }\n  }\n]\n', NULL, 1, 27, NULL, 'https://h5p.org/tutorial-column', 'https://h5p.org/column', 1),
