INSERT INTO `mdl_h5p_libraries` (`id`, `machinename`, `title`, `majorversion`, `minorversion`, `patchversion`, `runnable`, `fullscreen`, `embedtypes`, `preloadedjs`, `preloadedcss`, `droplibrarycss`, `semantics`, `addto`, `coremajor`, `coreminor`, `metadatasettings`, `tutorial`, `example`, `enabled`) VALUES
(19, 'H5P.CoursePresentation', 'Course Presentation', 1, 26, 3, 1, 1, 'iframe', 'dist/h5p-course-presentation.js', 'dist/h5p-course-presentation.css', '', '[\n  {\n    \"name\": \"presentation\",\n    \"type\": \"group\",\n    \"importance\": \"high\",\n    \"widget\": \"coursepresentation\",\n    \"fields\": [\n      {\n        \"name\": \"slides\",\n        \"importance\": \"high\",\n        \"type\": \"list\",\n        \"field\": {\n          \"name\": \"slide\",\n          \"importance\": \"high\",\n          \"type\": \"group\",\n          \"fields\": [\n            {\n              \"name\": \"elements\",\n              \"importance\": \"high\",\n              \"type\": \"list\",\n              \"field\": {\n                \"name\": \"element\",\n                \"importance\": \"high\",\n                \"type\": \"group\",\n                \"fields\": [\n                  {\n                    \"name\": \"x\",\n                    \"importance\": \"low\",\n                    \"type\": \"number\",\n                    \"widget\": \"none\"\n                  },\n                  {\n                    \"name\": \"y\",\n                    \"importance\": \"low\",\n                    \"type\": \"number\",\n                    \"widget\": \"none\"\n                  },\n                  {\n                    \"name\": \"width\",\n                    \"importance\": \"low\",\n                    \"type\": \"number\",\n                    \"widget\": \"none\",\n                    \"optional\": true\n                  },\n                  {\n                    \"name\": \"height\",\n                    \"importance\": \"low\",\n                    \"type\": \"number\",\n                    \"widget\": \"none\",\n                    \"optional\": true\n                  },\n                  {\n                    \"name\": \"action\",\n                    \"type\": \"library\",\n                    \"importance\": \"high\",\n                    \"options\": [\n                      \"H5P.AdvancedText 1.1\",\n                      \"H5P.Link 1.3\",\n                      \"H5P.Image 1.1\",\n                      \"H5P.Shape 1.0\",\n                      \"H5P.Video 1.6\",\n                      \"H5P.Audio 1.5\",\n                      \"H5P.Blanks 1.14\",\n                      \"H5P.SingleChoiceSet 1.11\",\n                      \"H5P.MultiChoice 1.16\",\n                      \"H5P.TrueFalse 1.8\",\n                      \"H5P.DragQuestion 1.14\",\n                      \"H5P.Summary 1.10\",\n                      \"H5P.DragText 1.10\",\n                      \"H5P.MarkTheWords 1.11\",\n                      \"H5P.Dialogcards 1.9\",\n                      \"H5P.ContinuousText 1.2\",\n                      \"H5P.ExportableTextArea 1.3\",\n                      \"H5P.Table 1.2\",\n                      \"H5P.InteractiveVideo 1.27\",\n                      \"H5P.TwitterUserFeed 1.0\",\n                      \"H5P.AudioRecorder 1.0\",\n                      \"H5P.MultiMediaChoice 0.3\"\n                    ],\n                    \"optional\": true\n                  },\n                  {\n                    \"name\": \"solution\",\n                    \"type\": \"text\",\n                    \"widget\": \"html\",\n                    \"optional\": true,\n                    \"label\": \"Comments\",\n                    \"importance\": \"low\",\n                    \"description\": \"The comments are shown when the user displays the suggested answers for all slides.\",\n                    \"enterMode\": \"p\",\n                    \"tags\": [\n                      \"strong\",\n                      \"em\",\n                      \"del\",\n                      \"a\",\n                      \"ul\",\n                      \"ol\",\n                      \"h2\",\n                      \"h3\",\n                      \"hr\",\n                      \"pre\",\n                      \"code\"\n                    ]\n                  },\n                  {\n                    \"name\": \"alwaysDisplayComments\",\n                    \"type\": \"boolean\",\n                    \"label\": \"Always display comments\",\n                    \"importance\": \"low\",\n                    \"optional\": true\n                  },\n                  {\n                    \"name\": \"backgroundOpacity\",\n                    \"type\": \"number\",\n                    \"label\": \"Background Opacity\",\n                    \"importance\": \"low\",\n                    \"min\": 0,\n                    \"max\": 100,\n                    \"step\": 5,\n                    \"default\": 0,\n                    \"optional\": true\n                  },\n                  {\n                    \"name\": \"displayAsButton\",\n                    \"type\": \"boolean\",\n                    \"label\": \"Display as button\",\n                    \"importance\": \"medium\",\n                    \"default\": false,\n                    \"optional\": true\n                  },\n                  {\n                    \"name\": \"buttonSize\",\n                    \"type\": \"select\",\n                    \"label\": \"Button size\",\n                    \"importance\": \"low\",\n                    \"optional\": false,\n                    \"default\": \"big\",\n                    \"options\": [\n                      {\n                        \"value\": \"small\",\n                        \"label\": \"Small\"\n                      },\n                      {\n                        \"value\": \"big\",\n                        \"label\": \"Big\"\n                      }\n                    ]\n                  },\n                  {\n                    \"name\": \"title\",\n                    \"type\": \"text\",\n                    \"optional\": true,\n                    \"label\": \"Title\",\n                    \"importance\": \"medium\"\n                  },\n                  {\n                    \"name\": \"goToSlideType\",\n                    \"type\": \"select\",\n                    \"label\": \"Go to\",\n                    \"importance\": \"medium\",\n                    \"optional\": false,\n                    \"options\": [\n                      {\n                        \"value\": \"specified\",\n                        \"label\": \"Specific slide number\"\n                      },\n                      {\n                        \"value\": \"next\",\n                        \"label\": \"Next slide\"\n                      },\n                      {\n                        \"value\": \"previous\",\n                        \"label\": \"Previous slide\"\n                      }\n                    ],\n                    \"default\": \"specified\"\n                  },\n                  {\n                    \"name\": \"goToSlide\",\n                    \"type\": \"number\",\n                    \"label\": \"Specific slide number\",\n                    \"description\": \"Only applicable when \'Specific slide number\' is selected\",\n                    \"importance\": \"low\",\n                    \"min\": 1,\n                    \"optional\": true\n                  },\n                  {\n                    \"name\": \"invisible\",\n                    \"type\": \"boolean\",\n                    \"label\": \"Invisible\",\n                    \"importance\": \"low\",\n                    \"description\": \"Default cursor, no title and no tab index. Warning: Users with disabilities or keyboard only users will have trouble using this element.\",\n                    \"default\": false\n                  }\n                ]\n              }\n            },\n            {\n              \"name\": \"keywords\",\n              \"importance\": \"low\",\n              \"type\": \"list\",\n              \"optional\": true,\n              \"field\": {\n                \"name\": \"keyword\",\n                \"importance\": \"low\",\n       