(20, 'H5P.Dialogcards', 'Dialog Cards', 1, 9, 18, 1, 0, 'iframe', 'dist/h5p-dialogcards.js', 'dist/h5p-dialogcards.css', '', '[\n  {\n    \"name\": \"title\",\n    \"type\": \"text\",\n    \"widget\": \"html\",\n    \"label\": \"Heading\",\n    \"importance\": \"high\",\n    \"optional\": true,\n    \"tags\": [\n      \"p\",\n      \"br\",\n      \"strong\",\n      \"em\",\n      \"code\"\n    ]\n  },\n  {\n    \"name\": \"mode\",\n    \"type\": \"select\",\n    \"label\": \"Mode\",\n    \"description\": \"Mode of presenting the dialog cards\",\n    \"importance\": \"medium\",\n    \"options\": [\n      {\n        \"value\": \"normal\",\n        \"label\": \"Normal\"\n      },\n      {\n        \"value\": \"repetition\",\n        \"label\": \"Repetition\"\n      }\n    ],\n    \"default\": \"normal\"\n  },\n  {\n    \"name\": \"description\",\n    \"type\": \"text\",\n    \"widget\": \"html\",\n    \"label\": \"Task description\",\n    \"importance\": \"medium\",\n    \"optional\": true,\n    \"tags\": [\n      \"p\",\n      \"br\",\n      \"strong\",\n      \"em\",\n      \"code\"\n    ]\n  },\n  {\n    \"name\": \"dialogs\",\n    \"type\": \"list\",\n    \"importance\": \"high\",\n    \"widgets\": [\n      {\n        \"name\": \"VerticalTabs\",\n        \"label\": \"Default\"\n      }\n    ],\n    \"label\": \"Dialogs\",\n    \"entity\": \"dialog\",\n    \"min\": 1,\n    \"defaultNum\": 1,\n    \"field\": {\n      \"name\": \"question\",\n      \"type\": \"group\",\n      \"label\": \"Question\",\n      \"importance\": \"high\",\n      \"fields\": [\n        {\n          \"name\": \"text\",\n          \"type\": \"text\",\n          \"widget\": \"html\",\n          \"tags\": [\n            \"p\",\n            \"br\",\n            \"strong\",\n            \"em\",\n            \"code\"\n          ],\n          \"label\": \"Text\",\n          \"importance\": \"high\",\n          \"description\": \"Hint for the first part of the dialogue\",\n          \"default\": \"<p style=\\\"text-align: center;\\\"></p>\"\n        },\n        {\n          \"name\": \"answer\",\n          \"type\": \"text\",\n          \"widget\": \"html\",\n          \"tags\": [\n            \"p\",\n            \"br\",\n            \"strong\",\n            \"em\",\n            \"code\"\n          ],\n          \"label\": \"Answer\",\n          \"importance\": \"high\",\n          \"description\": \"Hint for the second part of the dialogue\",\n          \"default\": \"<p style=\\\"text-align: center;\\\"></p>\"\n        },\n        {\n          \"name\": \"image\",\n          \"type\": \"image\",\n          \"label\": \"Image\",\n          \"importance\": \"high\",\n          \"optional\": true,\n          \"description\": \"Optional image for the card. (The card may use just an image, just a text or both)\"\n        },\n        {\n          \"name\": \"imageAltText\",\n          \"type\": \"text\",\n          \"label\": \"Alternative text for the image\",\n          \"importance\": \"high\",\n          \"optional\": true\n        },\n        {\n          \"name\": \"audio\",\n          \"type\": \"audio\",\n          \"label\": \"Audio files\",\n          \"importance\": \"low\",\n          \"optional\": true\n        },\n        {\n          \"name\": \"tips\",\n          \"type\": \"group\",\n          \"label\": \"Tips\",\n          \"importance\": \"low\",\n          \"fields\": [\n            {\n              \"name\": \"front\",\n              \"type\": \"text\",\n              \"label\": \"Tip for text\",\n              \"importance\": \"low\",\n              \"optional\": true,\n              \"description\": \"Tip for the first part of the dialogue\"\n            },\n            {\n              \"name\": \"back\",\n              \"type\": \"text\",\n              \"label\": \"Tip for answer\",\n              \"importance\": \"low\",\n              \"optional\": true,\n              \"description\": \"Tip for the second part of the dialogue\"\n            }\n          ]\n        }\n      ]\n    }\n  },\n  {\n    \"name\": \"behaviour\",\n    \"type\": \"group\",\n    \"label\": \"Behavioural settings\",\n    \"importance\": \"low\",\n    \"description\": \"These options will let you control how the task behaves.\",\n    \"optional\": true,\n    \"fields\": [\n      {\n        \"name\": \"enableRetry\",\n        \"type\": \"boolean\",\n        \"label\": \"Enable \\\"Retry\\\" button\",\n        \"importance\": \"low\",\n        \"default\": true,\n        \"optional\": true\n      },\n      {\n        \"name\": \"disableBackwardsNavigation\",\n        \"type\": \"boolean\",\n        \"label\": \"Disable backwards navigation\",\n        \"importance\": \"low\",\n        \"description\": \"This option will only allow you to move forward with Dialog Cards\",\n        \"optional\": true,\n        \"default\": false,\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"../mode\",\n              \"equals\": \"normal\"\n            }\n          ]\n        }\n      },\n      {\n        \"name\": \"scaleTextNotCard\",\n        \"type\": \"boolean\",\n        \"label\": \"Scale the text to fit inside the card\",\n        \"importance\": \"low\",\n        \"description\": \"Unchecking this option will make the card adapt its size to the size of the text\",\n        \"default\": false\n      },\n      {\n        \"name\": \"randomCards\",\n        \"type\": \"boolean\",\n        \"label\": \"Randomize cards\",\n        \"importance\": \"low\",\n        \"description\": \"Enable to randomize the order of cards on display.\",\n        \"default\": false,\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"../mode\",\n              \"equals\": \"normal\"\n            }\n          ]\n        }\n      },\n      {\n        \"name\": \"maxProficiency\",\n        \"type\": \"number\",\n        \"label\": \"Maximum proficiency level\",\n        \"importance\": \"low\",\n        \"default\": 5,\n        \"min\": 3,\n        \"max\": 7,\n        \"optional\": true,\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"../mode\",\n              \"equals\": \"repetition\"\n            }\n          ]\n        }\n      },\n      {\n        \"name\": \"quickProgression\",\n        \"type\": \"boolean\",\n        \"label\": \"Allow quick progression\",\n        \"description\": \"If activated, learners can decide to indicate that they know a card without turning it\",\n        \"importance\": \"low\",\n        \"default\": false,\n        \"optional\": true,\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"../mode\",\n              \"equals\": \"repetition\"\n            }\n          ]\n        }\n      }\n    ]\n  },\n  {\n    \"label\": \"Text for the turn button\",\n    \"importance\": \"low\",\n    \"name\": \"answer\",\n    \"type\": \"text\",\n    \"default\": \"Turn\",\n    \"common\": true\n  },\n  {\n    \"label\": \"Text for the next button\",\n    \"importance\": \"low\",\n    \"type\": \"text\",\n    \"name\": \"next\",\n    \"default\": \"Next\",\n    \"common\": true\n  },\n  {\n    \"name\": \"prev\",\n    \"type\": \"text\",\n    \"label\": \"Text for the previous button\",\n    \"importance\": \"low\",\n    \"default\": \"Previous\",\n    \"common\": true\n  },\n  {\n    \"name\": \"retry\",\n    \"type\": \"text\",\n    \"label\": \"Text for the retry button\",\n    \"importance\": \"low\",\n    \"default\": \"Retry\",\n    \"common\": true\n  },\n  {\n    \"name\": \"correctAnswer\",\n    \"type\": \"text\",\n    \"label\": \"Text for the \\\"correct answer\\\" button\",\n    \"importance\": \"low\",\n    \"default\": \"I got it right!\",\n    \"common\": true\n  },\n  {\n    \"name\": \"incorrectAnswer\",\n    \"type\": \"text\",\n    \"label\": \"Text for the \\\"incorrect answer\\\" button\",\n    \"importance\": \"low\",\n    \"default\": \"I got it wrong\",\n    \"common\": true\n  },\n  {\n    \"name\": \"round\",\n    \"type\": \"text\",\n    \"label\": \"Text for \\\"Round\\\" message below cards and on the summary screen\",\n    \"description\": \"@round will be replaced by the number of the current round\",\n    \"importance\": \"low\",\n    \"default\": \"Round @round\",\n    \"common\": true\n  },\n  {\n    \"name\": \"cardsLeft\",\n    \"type\": \"text\",\n    \"label\": \"Text for \\\"Cards left\\\" message\",\n    \"description\": \"@number will be replaced by the number of cards left in this round\",\n    \"importance\": \"low\",\n    \"default\": \"Cards left: @number\",\n    \"common\": true\n  },\n  {\n    \"name\": \"nextRound\",\n    \"type\": \"text\",\n    \"label\": \"Text for the \\\"next round\\\" button\",\n    \"description\": \"@round will be replaced by the round number\",\n    \"importance\": \"low\",\n    \"default\": \"Proceed to round @round\",\n    \"common\": true\n  },\n  {\n    \"name\": \"startOver\",\n    \"type\": \"text\",\n    \"label\": \"Text for the \\\"Start over\\\" button\",\n    \"importance\": \"low\",\n    \"default\": \"Start over\",\n    \"common\": true\n  },\n  {\n    \"name\": \"showSummary\",\n    \"type\": \"text\",\n    \"label\": \"Text for the \\\"show summary\\\" button\",\n    \"importance\": \"low\",\n    \"default\": \"Next\",\n    \"common\": true\n  },\n  {\n    \"name\": \"summary\",\n    \"type\": \"text\",\n    \"label\": \"Title text for the summary page\",\n    \"importance\": \"low\",\n    \"default\": \"Summary\",\n    \"common\": true\n  },\n  {\n    \"name\": \"summaryCardsRight\",\n    \"type\": \"text\",\n    \"label\": \"Text for \\\"Cards you got right:\\\"\",\n    \"importance\": \"low\",\n    \"default\": \"Cards you got right:\",\n    \"common\": true\n  },\n  {\n    \"name\": \"summaryCardsWrong\",\n    \"type\": \"text\",\n    \"label\": \"Text for \\\"Cards you got wrong:\\\"\",\n    \"importance\": \"low\",\n    \"default\": \"Cards you got wrong:\",\n    \"common\": true\n  },\n  {\n    \"name\": \"summaryCardsNotShown\",\n    \"type\": \"text\",\n    \"label\": \"Text for \\\"Cards not shown:\\\"\",\n    \"importance\": \"low\",\n    \"default\": \"Cards in pool not shown:\",\n    \"common\": true\n  },\n  {\n    \"name\": \"summaryOverallScore\",\n    \"type\": \"text\",\n    \"label\": \"Text for \\\"Overall Score\\\"\",\n    \"importance\": \"low\",\n    \"default\": \"Overall Score\",\n    \"common\": true\n  },\n  {\n    \"name\": \"summaryCardsCompleted\",\n    \"type\": \"text\",\n    \"label\": \"Text for \\\"Cards completed\\\"\",\n    \"importance\": \"low\",\n    \"default\": \"Cards you have completed learning:\",\n    \"common\": true\n  },\n  {\n    \"name\": \"summaryCompletedRounds\",\n    \"type\": \"text\",\n    \"label\": \"Text for \\\"Completed rounds:\\\"\",\n    \"importance\": \"low\",\n    \"default\": \"Completed rounds:\",\n    \"common\": true\n  },\n  {\n    \"name\": \"summaryAllDone\",\n    \"type\": \"text\",\n    \"label\": \"Message when all cards have been learned proficiently\",\n    \"description\": \"@cards will be replaced by the number of all cards in the pool. @max will be replaced by the maximum proficiency level.\",\n    \"importance\": \"low\",\n    \"default\": \"Well done! You have mastered all @cards cards by getting them correct @max times!\",\n    \"common\": true\n  },\n  {\n    \"name\": \"progressText\",\n    \"type\": \"text\",\n    \"label\": \"Progress text\",\n    \"importance\": \"low\",\n    \"description\": \"Available variables are @card and @total.\",\n    \"default\": \"Card @card of @total\",\n    \"common\": true\n  },\n  {\n    \"name\": \"cardFrontLabel\",\n    \"type\": \"text\",\n    \"label\": \"Label for card text\",\n    \"importance\": \"low\",\n    \"description\": \"Used for accessibility by assistive technologies\",\n    \"default\": \"Card front\",\n    \"common\": true\n  },\n  {\n    \"name\": \"cardBackLabel\",\n    \"type\": \"text\",\n    \"label\": \"Label for card back\",\n    \"importance\": \"low\",\n    \"description\": \"Used for accessibility by assistive technologies\",\n    \"default\": \"Card back\",\n    \"common\": true\n  },\n  {\n    \"name\": \"tipButtonLabel\",\n    \"type\": \"text\",\n    \"label\": \"Label for the show tip button\",\n    \"importance\": \"low\",\n    \"default\": \"Show tip\",\n    \"common\": true\n  },\n  {\n    \"name\": \"audioNotSupported\",\n    \"type\": \"text\",\n    \"label\": \"Audio not supported message\",\n    \"importance\": \"low\",\n    \"common\": true,\n    \"default\": \"Your browser does not support this audio\"\n  },\n  {\n    \"name\": \"confirmStartingOver\",\n    \"type\": \"group\",\n    \"label\": \"Confirm starting over dialog\",\n    \"importance\": \"low\",\n    \"common\": true,\n    \"fields\": [\n      {\n        \"name\": \"header\",\n        \"type\": \"text\",\n        \"label\": \"Header text\",\n        \"importance\": \"low\",\n        \"default\": \"Start over?\"\n      },\n      {\n        \"name\": \"body\",\n        \"type\": \"text\",\n        \"label\": \"Body text\",\n        \"importance\": \"low\",\n        \"default\": \"All progress will be lost. Are you sure you want to start over?\",\n        \"widget\": \"html\",\n        \"enterMode\": \"p\",\n        \"tags\": [\n          \"strong\",\n          \"em\",\n          \"del\",\n          \"u\",\n          \"code\"\n        ]\n      },\n      {\n        \"name\": \"cancelLabel\",\n        \"type\": \"text\",\n        \"label\": \"Cancel button label\",\n        \"importance\": \"low\",\n        \"default\": \"Cancel\"\n      },\n      {\n        \"name\": \"confirmLabel\",\n        \"type\": \"text\",\n        \"label\": \"Confirm button label\",\n        \"importance\": \"low\",\n        \"default\": \"Start over\"\n      }\n    ]\n  }\n]\n', NULL, 1, 26, NULL, NULL, NULL, 1),
(21, 'H5P.DocumentationTool', 'Documentation Tool', 1, 8, 27, 1, 0, 'iframe', 'navigation-menu.js, documentation-tool.js', 'navigation-menu.css, documentation-tool.css', '', '[\n  {\n    \"name\": \"taskDescription\",\n    \"label\": \"Heading\",\n    \"importance\": \"high\",\n    \"type\": \"text\",\n    \"default\": \"Documentation tool\",\n    \"description\": \"Title for the documentation tool.\",\n    \"optional\": true\n  },\n  {\n    \"name\": \"pagesList\",\n    \"label\": \"Elements\",\n    \"importance\": \"high\",\n    \"type\": \"list\",\n    \"widgets\": [\n      {\n        \"name\": \"VerticalTabs\",\n        \"label\": \"Default\"\n      }\n    ],\n    \"min\": 1,\n    \"entity\": \"page\",\n    \"field\": {\n      \"name\": \"page\",\n      \"type\": \"library\",\n      \"label\": \"Page type\",\n      \"importance\": \"high\",\n      \"description\": \"Library for this slide.\",\n      \"options\": [\n        \"H5P.StandardPage 1.5\",\n        \"H5P.GoalsPage 1.5\",\n        \"H5P.GoalsAssessmentPage 1.4\",\n        \"H5P.DocumentExportPage 1.5\"\n      ]\n    }\n  },\n  {\n    \"label\": \"Localize documentation tool buttons\",\n    \"name\": \"i10n\",\n    \"type\": \"group\",\n    \"common\": true,\n    \"collapsed\": true,\n    \"importance\": \"low\",\n    \"fields\": [\n      {\n        \"label\": \"Previous button label\",\n        \"name\": \"previousLabel\",\n        \"type\": \"text\",\n        \"default\": \"Previous documentation step\",\n        \"importance\": \"low\"\n      },\n      {\n        \"label\": \"Next button label\",\n        \"name\": \"nextLabel\",\n        \"type\": \"text\",\n        \"default\": \"Next documentation step\",\n        \"importance\": \"low\"\n      },\n      {\n        \"label\": \"Close button label\",\n        \"name\": \"closeLabel\",\n        \"type\": \"text\",\n        \"default\": \"Close\",\n        \"importance\": \"low\"\n      }\n    ]\n  }\n]\n', NULL, 1, 19, NULL, NULL, NULL, 1);
INSERT INTO `mdl_h5p_libraries` (`id`, `machinename`, `title`, `majorversion`, `minorversion`, `patchversion`, `runnable`, `fullscreen`, `embedtypes`, `preloadedjs`, `preloadedcss`, `droplibrarycss`, `semantics`, `addto`, `coremajor`, `coreminor`, `metadatasettings`, `tutorial`, `example`, `enabled`) VALUES
(22, 'H5P.DocumentExportPage', 'Document Export Page', 1, 5, 19, 0, 0, '', 'dist/h5p-document-export-page.js', 'dist/h5p-document-export-page.css', '', '[\n  {\n    \"name\": \"description\",\n    \"label\": \"Description\",\n    \"importance\": \"medium\",\n    \"type\": \"text\",\n    \"widget\": \"html\",\n    \"description\": \"Description of the export page.\",\n    \"default\": \"On this page you can choose to export your text, goals and goals assessments.\",\n    \"enterMode\": \"p\",\n    \"tags\": [\n      \"strong\",\n      \"em\",\n      \"u\",\n      \"a\",\n      \"ul\",\n      \"ol\",\n      \"h2\",\n      \"h3\",\n      \"hr\",\n      \"pre\",\n      \"code\"\n    ],\n    \"optional\": true\n  },\n  {\n    \"name\": \"createDocumentLabel\",\n    \"label\": \"Create document button label\",\n    \"importance\": \"low\",\n    \"type\": \"text\",\n    \"description\": \"Text that will be displayed on the \\\"Create document\\\"-button.\",\n    \"default\": \"Create document\"\n  },\n  {\n    \"name\": \"submitTextLabel\",\n    \"label\": \"Submit text button\",\n    \"importance\": \"low\",\n    \"type\": \"text\",\n    \"description\": \"Text that will be displayed on the \\\"Submit\\\"-button.\",\n    \"default\": \"Submit\"\n  },\n  {\n    \"name\": \"submitSuccessTextLabel\",\n    \"type\": \"text\",\n    \"label\": \"Submit success label\",\n    \"optional\": false,\n    \"default\": \"Your report was submitted successfully!\"\n  },\n  {\n    \"name\": \"selectAllTextLabel\",\n    \"label\": \"Select all exportable text button label\",\n    \"importance\": \"low\",\n    \"type\": \"text\",\n    \"description\": \"Text that will be displayed on the \\\"Select all text\\\"-button.\",\n    \"default\": \"Select\"\n  },\n  {\n    \"name\": \"exportTextLabel\",\n    \"label\": \"Export text button label\",\n    \"importance\": \"low\",\n    \"type\": \"text\",\n    \"description\": \"Text that will be displayed on the \\\"Export text\\\"-button.\",\n    \"default\": \"Export\"\n  },\n  {\n    \"name\": \"helpTextLabel\",\n    \"label\": \"Label for help text\",\n    \"importance\": \"low\",\n    \"type\": \"text\",\n    \"description\": \"Label for showing additional helpful information to the user.\",\n    \"default\": \"More information\"\n  },\n  {\n    \"name\": \"helpText\",\n    \"label\": \"Fill in additional help information\",\n    \"importance\": \"low\",\n    \"type\": \"text\",\n    \"widget\": \"html\",\n    \"description\": \"Here you can fill in additional helpful information for the user.\",\n    \"enterMode\": \"p\",\n    \"optional\": true,\n    \"tags\": [\n      \"strong\",\n      \"em\",\n      \"u\",\n      \"a\",\n      \"ul\",\n      \"ol\",\n      \"h2\",\n      \"h3\",\n      \"hr\",\n      \"pre\",\n      \"code\"\n    ]\n  },\n  {\n    \"name\": \"requiresInputErrorMessage\",\n    \"label\": \"Required input missing text\",\n    \"importance\": \"low\",\n    \"type\": \"text\",\n    \"description\": \"An error message which will be displayed if one or more required input fields have not been filled. @pages will be replaced with the titles of affected pages.\",\n    \"default\": \"The following pages contain required fields that need to be filled in order to review or submit this document: @pages\"\n  }\n]\n', NULL, 1, 27, NULL, NULL, NULL, 1),
