(26, 'H5P.DragQuestion', 'Drag and Drop', 1, 14, 23, 1, 0, 'iframe', 'h5p-drag-question.js', 'css/dragquestion.css', '', '[\n  {\n    \"name\": \"scoreShow\",\n    \"type\": \"text\",\n    \"label\": \"Check answer button\",\n    \"importance\": \"low\",\n    \"default\": \"Check\",\n    \"common\": true\n  },\n  {\n    \"name\": \"submit\",\n    \"type\": \"text\",\n    \"label\": \"Submit answer button\",\n    \"importance\": \"low\",\n    \"default\": \"Submit\",\n    \"common\": true\n  },\n  {\n    \"name\": \"tryAgain\",\n    \"type\": \"text\",\n    \"label\": \"Retry button\",\n    \"importance\": \"low\",\n    \"default\": \"Retry\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"label\": \"Score explanation text\",\n    \"importance\": \"low\",\n    \"name\": \"scoreExplanation\",\n    \"type\": \"text\",\n    \"default\": \"Correct answers give +1 point. Incorrect answers give -1 point. The lowest possible score is 0.\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"name\": \"question\",\n    \"importance\": \"high\",\n    \"type\": \"group\",\n    \"widget\": \"wizard\",\n    \"fields\": [\n      {\n        \"name\": \"settings\",\n        \"type\": \"group\",\n        \"label\": \"Settings\",\n        \"importance\": \"high\",\n        \"fields\": [\n          {\n            \"name\": \"background\",\n            \"type\": \"image\",\n            \"label\": \"Background image\",\n            \"importance\": \"low\",\n            \"optional\": true,\n            \"description\": \"Optional. Select an image to use as background for your drag and drop task.\"\n          },\n          {\n            \"name\": \"size\",\n            \"type\": \"group\",\n            \"widget\": \"dimensions\",\n            \"label\": \"Task size\",\n            \"importance\": \"low\",\n            \"description\": \"Specify how large (in px) the play area should be.\",\n            \"default\": {\n              \"width\": 620,\n              \"height\": 310,\n              \"field\": \"background\"\n            },\n            \"fields\": [\n              {\n                \"name\": \"width\",\n                \"type\": \"number\"\n              },\n              {\n                \"name\": \"height\",\n                \"type\": \"number\"\n              }\n            ]\n          }\n        ]\n      },\n      {\n        \"name\": \"task\",\n        \"type\": \"group\",\n        \"widget\": \"dragQuestion\",\n        \"label\": \"Task\",\n        \"importance\": \"high\",\n        \"description\": \"Start by placing your drop zones.<br/>Next, place your droppable elements and check off the appropriate drop zones.<br/>Last, edit your drop zone again and check off the correct answers.\",\n        \"fields\": [\n          {\n            \"name\": \"elements\",\n            \"type\": \"list\",\n            \"label\": \"Elements\",\n            \"importance\": \"high\",\n            \"entity\": \"element\",\n            \"field\": {\n              \"type\": \"group\",\n              \"label\": \"Element\",\n              \"importance\": \"high\",\n              \"fields\": [\n                {\n                  \"name\": \"type\",\n                  \"type\": \"library\",\n                  \"description\": \"Choose the type of content you would like to add.\",\n                  \"importance\": \"medium\",\n                  \"options\": [\n                    \"H5P.AdvancedText 1.1\",\n                    \"H5P.Image 1.1\"\n                  ]\n                },\n                {\n                  \"name\": \"x\",\n                  \"type\": \"number\",\n                  \"widget\": \"none\"\n                },\n                {\n                  \"name\": \"y\",\n                  \"type\": \"number\",\n                  \"widget\": \"none\"\n                },\n                {\n                  \"name\": \"height\",\n                  \"type\": \"number\",\n                  \"widget\": \"none\"\n                },\n                {\n                  \"name\": \"width\",\n                  \"type\": \"number\",\n                  \"widget\": \"none\"\n                },\n                {\n                  \"name\": \"dropZones\",\n                  \"type\": \"select\",\n                  \"widget\": \"dynamicCheckboxes\",\n                  \"label\": \"Select drop zones\",\n                  \"importance\": \"high\",\n                  \"multiple\": true\n                },\n                {\n                  \"name\": \"backgroundOpacity\",\n                  \"type\": \"number\",\n                  \"label\": \"Background Opacity\",\n                  \"importance\": \"low\",\n                  \"min\": 0,\n                  \"max\": 100,\n                  \"step\": 5,\n                  \"default\": 100,\n                  \"description\": \"Reducing the opacity may result in an insufficient contrast and make the content not accessible.\",\n                  \"optional\": true\n                },\n                {\n                  \"name\": \"multiple\",\n                  \"type\": \"boolean\",\n                  \"label\": \"Infinite number of element instances\",\n                  \"importance\": \"low\",\n                  \"description\": \"Clones this element so that it can be dragged to multiple drop zones.\",\n                  \"default\": false\n                }\n              ]\n            }\n          },\n          {\n            \"name\": \"dropZones\",\n            \"type\": \"list\",\n            \"label\": \"Drop Zones\",\n            \"importance\": \"high\",\n            \"entity\": \"Drop Zone\",\n            \"field\": {\n              \"type\": \"group\",\n              \"label\": \"Drop Zone\",\n              \"importance\": \"high\",\n              \"fields\": [\n                {\n                  \"name\": \"label\",\n                  \"type\": \"text\",\n                  \"widget\": \"html\",\n                  \"label\": \"Label\",\n                  \"importance\": \"medium\",\n                  \"description\": \"The label is used by assistive technologies.\",\n                  \"enterMode\": \"div\",\n                  \"tags\": [\n                    \"strong\",\n                    \"em\",\n                    \"del\",\n                    \"code\"\n                  ]\n                },\n                {\n                  \"name\": \"showLabel\",\n                  \"type\": \"boolean\",\n                  \"label\": \"Show label\",\n                  \"importance\": \"low\"\n                },\n                {\n                  \"name\": \"x\",\n                  \"type\": \"number\",\n                  \"widget\": \"none\"\n                },\n                {\n                  \"name\": \"y\",\n                  \"type\": \"number\",\n                  \"widget\": \"none\"\n                },\n                {\n                  \"name\": \"height\",\n                  \"type\": \"number\",\n                  \"widget\": \"none\"\n                },\n                {\n                  \"name\": \"width\",\n                  \"type\": \"number\",\n                  \"widget\": \"none\"\n                },\n                {\n                  \"name\": \"correctElements\",\n                  \"type\": \"select\",\n                  \"widget\": \"dynamicCheckboxes\",\n                  \"label\": \"Select correct elements\",\n                  \"importance\": \"low\",\n                  \"multiple\": true\n                },\n                {\n                  \"name\": \"backgroundOpacity\",\n                  \"type\": \"number\",\n                  \"label\": \"Background Opacity\",\n                  \"importance\": \"low\",\n                  \"min\": 0,\n                  \"max\": 100,\n                  \"step\": 5,\n                  \"default\": 100,\n                  \"description\": \"Reducing the opacity may result in an insufficient contrast and make the content not accessible.\",\n                  \"optional\": true\n                },\n                {\n                  \"name\": \"tipsAndFeedback\",\n                  \"type\": \"group\",\n                  \"label\": \"Tips and feedback\",\n                  \"importance\": \"low\",\n                  \"optional\": true,\n                  \"fields\": [\n                    {\n                      \"name\": \"tip\",\n                      \"label\": \"Tip text\",\n                      \"importance\": \"low\",\n                      \"type\": \"text\",\n                      \"widget\": \"html\",\n                      \"tags\": [\n                        \"p\",\n                        \"br\",\n                        \"strong\",\n                        \"em\",\n                        \"code\"\n                      ],\n                      \"optional\": true\n                    },\n                    {\n                      \"name\": \"feedbackOnCorrect\",\n                      \"type\": \"text\",\n                      \"label\": \"Message displayed on correct match\",\n                      \"importance\": \"low\",\n                      \"description\": \"Message will appear below the task on \\\"check\\\" if correct droppable is matched.\",\n                      \"optional\": true\n                    },\n                    {\n                      \"name\": \"feedbackOnIncorrect\",\n                      \"type\": \"text\",\n                      \"label\": \"Message displayed on incorrect match\",\n                      \"importance\": \"low\",\n                      \"description\": \"Message will appear below the task on \\\"check\\\" if the match is incorrect.\",\n                      \"optional\": true\n                    }\n                  ]\n                },\n                {\n                  \"name\": \"single\",\n                  \"type\": \"boolean\",\n                  \"label\": \"This drop zone can only contain one element\",\n                  \"description\": \"Make sure there is only one correct answer for this dropzone\",\n                  \"importance\": \"low\",\n                  \"default\": false\n                },\n                {\n                  \"name\": \"autoAlign\",\n                  \"type\": \"boolean\",\n                  \"label\": \"Enable Auto-Align\",\n                  \"importance\": \"low\",\n                  \"description\": \"Will auto-align all draggables dropped in this zone.\"\n                }\n              ]\n            }\n          }\n        ]\n      }\n    ]\n  },\n  {\n    \"name\": \"overallFeedback\",\n    \"type\": \"group\",\n    \"label\": \"Overall Feedback\",\n    \"importance\": \"low\",\n    \"expanded\": true,\n    \"fields\": [\n      {\n        \"name\": \"overallFeedback\",\n        \"type\": \"list\",\n        \"widgets\": [\n          {\n            \"name\": \"RangeList\",\n            \"label\": \"Default\"\n          }\n        ],\n        \"importance\": \"high\",\n        \"label\": \"Define custom feedback for any score range\",\n        \"description\": \"Click the \\\"Add range\\\" button to add as many ranges as you need. Example: 0-20% Bad score, 21-91% Average Score, 91-100% Great Score!\",\n        \"entity\": \"range\",\n        \"min\": 1,\n        \"defaultNum\": 1,\n        \"optional\": true,\n        \"field\": {\n          \"name\": \"overallFeedback\",\n          \"type\": \"group\",\n          \"importance\": \"low\",\n          \"fields\": [\n            {\n              \"name\": \"from\",\n              \"type\": \"number\",\n              \"label\": \"Score Range\",\n              \"min\": 0,\n              \"max\": 100,\n              \"default\": 0,\n              \"unit\": \"%\"\n            },\n            {\n              \"name\": \"to\",\n              \"type\": \"number\",\n              \"min\": 0,\n              \"max\": 100,\n              \"default\": 100,\n              \"unit\": \"%\"\n            },\n            {\n              \"name\": \"feedback\",\n              \"type\": \"text\",\n              \"label\": \"Feedback for defined score range\",\n              \"importance\": \"low\",\n              \"placeholder\": \"Fill in the feedback\",\n              \"optional\": true\n            }\n          ]\n        }\n      }\n    ]\n  },\n  {\n    \"name\": \"behaviour\",\n    \"type\": \"group\",\n    \"label\": \"Behavioural settings\",\n    \"importance\": \"low\",\n    \"description\": \"These options will let you control how the task behaves.\",\n    \"optional\": true,\n    \"fields\": [\n      {\n        \"name\": \"enableRetry\",\n        \"type\": \"boolean\",\n        \"label\": \"Enable \\\"Retry\\\"\",\n        \"importance\": \"low\",\n        \"default\": true\n      },\n      {\n        \"name\": \"enableCheckButton\",\n        \"type\": \"boolean\",\n        \"label\": \"Enable \\\"Check\\\" button\",\n        \"widget\": \"none\",\n        \"importance\": \"low\",\n        \"default\": true,\n        \"optional\": true\n      },\n      {\n        \"name\": \"singlePoint\",\n        \"type\": \"boolean\",\n        \"label\": \"Give one point for the whole task\",\n        \"importance\": \"low\",\n        \"description\": \"Disable to give one point for each draggable that is placed correctly.\",\n        \"default\": false\n      },\n      {\n        \"label\": \"Apply penalties\",\n        \"name\": \"applyPenalties\",\n        \"type\": \"boolean\",\n        \"description\": \"Apply penalties for elements dropped in the wrong drop zones. This must be enabled when the same element(s) are able to be dropped into multiple drop zones, or if there is only one drop-zone. If this is not enabled, learners may match all items to all drop-zones and always receive a full score.\",\n        \"default\": true\n      },\n      {\n        \"name\": \"enableScoreExplanation\",\n        \"type\": \"boolean\",\n        \"label\": \"Enable score explanation\",\n        \"description\": \"Display a score explanation to user when checking their answers (if the \'Apply penalties\' option has been selected).\",\n        \"importance\": \"low\",\n        \"default\": true,\n        \"optional\": true,\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"singlePoint\",\n              \"equals\": false\n            }\n          ]\n        }\n      },\n      {\n        \"name\": \"backgroundOpacity\",\n        \"type\": \"text\",\n        \"label\": \"Background opacity for draggables\",\n        \"importance\": \"low\",\n        \"description\": \"If this field is set, it will override opacity set on all draggable elements. This should be a number between 0 and 100, where 0 means full transparency and 100 means no transparency\",\n        \"optional\": true\n      },\n      {\n        \"name\": \"dropZoneHighlighting\",\n        \"type\": \"select\",\n        \"label\": \"Drop Zone Highlighting\",\n        \"importance\": \"low\",\n        \"description\": \"Choose when to highlight drop zones.\",\n        \"default\": \"dragging\",\n        \"options\": [\n          {\n            \"value\": \"dragging\",\n            \"label\": \"When dragging\"\n          },\n          {\n            \"value\": \"always\",\n            \"label\": \"Always\"\n          },\n          {\n            \"value\": \"never\",\n            \"label\": \"Never\"\n          }\n        ]\n      },\n      {\n        \"name\": \"autoAlignSpacing\",\n        \"type\": \"number\",\n        \"label\": \"Spacing for Auto-Align (in px)\",\n        \"importance\": \"low\",\n        \"min\": 0,\n        \"default\": 2,\n        \"optional\": true\n      },\n      {\n        \"name\": \"enableFullScreen\",\n        \"label\": \"Enable FullScreen\",\n        \"importance\": \"low\",\n        \"type\": \"boolean\",\n        \"description\": \"Check this option to enable the full screen button.\",\n        \"default\": false\n      },\n      {\n        \"name\": \"showScorePoints\",\n        \"type\": \"boolean\",\n        \"label\": \"Show score points\",\n        \"description\": \"Show points earned for each answer. Not available when the \'Give one point for the whole task\' option is enabled.\",\n        \"importance\": \"low\",\n        \"default\": true\n      },\n      {\n        \"name\": \"showTitle\",\n        \"type\": \"boolean\",\n        \"label\": \"Show Title\",\n        \"importance\": \"low\",\n        \"description\": \"Uncheck this option if you do not want this title to be displayed. The title will only be displayed in summaries, statistics etc.\",\n        \"default\": true\n      }\n    ]\n  },\n  {\n    \"name\": \"localize\",\n    \"type\": \"group\",\n    \"label\": \"Localize\",\n    \"common\": true,\n    \"fields\": [\n      {\n        \"name\": \"fullscreen\",\n        \"type\": \"text\",\n        \"label\": \"Fullscreen label\",\n        \"default\": \"Fullscreen\"\n      },\n      {\n        \"name\": \"exitFullscreen\",\n        \"type\": \"text\",\n        \"label\": \"Exit fullscreen label\",\n        \"default\": \"Exit fullscreen\"\n      }\n    ]\n  },\n  {\n    \"name\": \"grabbablePrefix\",\n    \"type\": \"text\",\n    \"label\": \"Grabbable prefix\",\n    \"importance\": \"low\",\n    \"default\": \"Grabbable {num} of {total}.\",\n    \"common\": true\n  },\n  {\n    \"name\": \"grabbableSuffix\",\n    \"type\": \"text\",\n    \"label\": \"Grabbable suffix\",\n    \"importance\": \"low\",\n    \"default\": \"Placed in dropzone {num}.\",\n    \"common\": true\n  },\n  {\n    \"name\": \"dropzonePrefix\",\n    \"type\": \"text\",\n    \"label\": \"Dropzone prefix\",\n    \"importance\": \"low\",\n    \"default\": \"Dropzone {num} of {total}.\",\n    \"common\": true\n  },\n  {\n    \"name\": \"noDropzone\",\n    \"type\": \"text\",\n    \"label\": \"No dropzone selection label\",\n    \"importance\": \"low\",\n    \"default\": \"No dropzone.\",\n    \"common\": true\n  },\n  {\n    \"name\": \"tipLabel\",\n    \"type\": \"text\",\n    \"label\": \"Label for show tip button\",\n    \"importance\": \"low\",\n    \"default\": \"Show tip.\",\n    \"common\": true\n  },\n  {\n    \"name\": \"tipAvailable\",\n    \"type\": \"text\",\n    \"label\": \"Label for tip available\",\n    \"importance\": \"low\",\n    \"default\": \"Tip available\",\n    \"common\": true\n  },\n  {\n    \"name\": \"correctAnswer\",\n    \"type\": \"text\",\n    \"label\": \"Label for correct answer\",\n    \"importance\": \"low\",\n    \"default\": \"Correct answer\",\n    \"common\": true\n  },\n  {\n    \"name\": \"wrongAnswer\",\n    \"type\": \"text\",\n    \"label\": \"Label for incorrect answer\",\n    \"importance\": \"low\",\n    \"default\": \"Wrong answer\",\n    \"common\": true\n  },\n  {\n    \"name\": \"feedbackHeader\",\n    \"type\": \"text\",\n    \"label\": \"Header for panel containing feedback for correct/incorrect answers\",\n    \"importance\": \"low\",\n    \"default\": \"Feedback\",\n    \"common\": true\n  },\n  {\n    \"name\": \"scoreBarLabel\",\n    \"type\": \"text\",\n    \"label\": \"Textual representation of the score bar for those using a readspeaker\",\n    \"default\": \"You got :num out of :total points\",\n    \"importance\": \"low\",\n    \"common\": true\n  },\n  {\n    \"name\": \"scoreExplanationButtonLabel\",\n    \"type\": \"text\",\n    \"label\": \"Textual representation of the score explanation button\",\n    \"default\": \"Show score explanation\",\n    \"importance\": \"low\",\n    \"common\": true\n  },\n  {\n    \"name\": \"a11yCheck\",\n    \"type\": \"text\",\n    \"label\": \"Assistive technology label for \\\"Check\\\" button\",\n    \"default\": \"Check the answers. The responses will be marked as correct, incorrect, or unanswered.\",\n    \"importance\": \"low\",\n    \"common\": true\n  },\n  {\n    \"name\": \"a11yRetry\",\n    \"type\": \"text\",\n    \"label\": \"Assistive technology label for \\\"Retry\\\" button\",\n    \"default\": \"Retry the task. Reset all responses and start the task over again.\",\n    \"importance\": \"low\",\n    \"common\": true\n  }\n]\n', NULL, 1, 23, NULL, 'https://h5p.org/tutorial-drag-and-drop-question', 'https://h5p.org/drag-and-drop', 1),
(27, 'H5P.DragText', 'Drag the Words', 1, 10, 17, 1, 0, 'iframe', 'dist/h5p-drag-text.js', 'dist/h5p-drag-text.css', '', '[\n  {\n    \"name\": \"media\",\n    \"type\": \"group\",\n    \"label\": \"Media\",\n    \"importance\": \"medium\",\n    \"fields\": [\n      {\n        \"name\": \"type\",\n        \"type\": \"library\",\n        \"label\": \"Type\",\n        \"importance\": \"medium\",\n        \"options\": [\n          \"H5P.Image 1.1\",\n          \"H5P.Video 1.6\",\n          \"H5P.Audio 1.5\"\n        ],\n        \"optional\": true,\n        \"description\": \"Optional media to display above the question.\"\n      },\n      {\n        \"name\": \"disableImageZooming\",\n        \"type\": \"boolean\",\n        \"label\": \"Disable image zooming\",\n        \"importance\": \"low\",\n        \"default\": false,\n        \"optional\": true,\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"type\",\n              \"equals\": \"H5P.Image 1.1\"\n            }\n          ]\n        }\n      }\n    ]\n  },\n  {\n    \"label\": \"Task description\",\n    \"importance\": \"high\",\n    \"name\": \"taskDescription\",\n    \"type\": \"text\",\n    \"widget\": \"html\",\n    \"description\": \"Describe how the user should solve the task.\",\n    \"default\": \"Drag the words into the correct boxes\",\n    \"enterMode\": \"p\",\n    \"tags\": [\n      \"strong\",\n      \"em\",\n      \"u\",\n      \"a\",\n      \"ul\",\n      \"ol\",\n      \"h2\",\n      \"h3\",\n      \"hr\",\n      \"pre\",\n      \"code\"\n    ]\n  },\n  {\n    \"label\": \"Text\",\n    \"importance\": \"high\",\n    \"name\": \"textField\",\n    \"type\": \"text\",\n    \"widget\": \"textarea\",\n    \"placeholder\": \"*Oslo* is the capital of Norway, *Stockholm* is the capital of Sweden and *Copenhagen* is the capital of Denmark. All cities are located in the *Scandinavian:Northern Part of Europe* peninsula.\",\n    \"description\": \"\",\n    \"important\": {\n      \"description\": \"<ul><li>Droppable words are added with an asterisk (*) in front and behind the correct word/phrase.</li><li>You may add a textual tip, using a colon (:) in front of the tip.</li><li>For every empty spot there is only one correct word.</li><li>You may add feedback to be displayed when a task is completed. Use \'\\\\+\' for correct and \'\\\\-\' for incorrect feedback.</li></ul>\",\n      \"example\": \"H5P content may be edited using a *browser:What type of program is Chrome?*. </br> H5P content is *interactive\\\\+Correct! \\\\-Incorrect, try again!*\"\n    }\n  },\n  {\n    \"label\": \"Distractors\",\n    \"importance\": \"high\",\n    \"name\": \"distractors\",\n    \"type\": \"text\",\n    \"optional\": true,\n    \"placeholder\": \"*ReykjavĂ­k* *Helsinki*\",\n    \"description\": \"Enter extra solutions that are wrong as distractors. Use the same asterisk (*) scheme as for the text.\"\n  },\n  {\n    \"name\": \"overallFeedback\",\n    \"type\": \"group\",\n    \"label\": \"Overall Feedback\",\n    \"importance\": \"low\",\n    \"expanded\": true,\n    \"fields\": [\n      {\n        \"name\": \"overallFeedback\",\n        \"type\": \"list\",\n        \"widgets\": [\n          {\n            \"name\": \"RangeList\",\n            \"label\": \"Default\"\n          }\n        ],\n        \"importance\": \"high\",\n        \"label\": \"Define custom feedback for any score range\",\n        \"description\": \"Click the \\\"Add range\\\" button to add as many ranges as you need. Example: 0-20% Bad score, 21-91% Average Score, 91-100% Great Score!\",\n        \"entity\": \"range\",\n        \"min\": 1,\n        \"defaultNum\": 1,\n        \"optional\": true,\n        \"field\": {\n          \"name\": \"overallFeedback\",\n          \"type\": \"group\",\n          \"importance\": \"low\",\n          \"fields\": [\n            {\n              \"name\": \"from\",\n              \"type\": \"number\",\n              \"label\": \"Score Range\",\n              \"min\": 0,\n              \"max\": 100,\n              \"default\": 0,\n              \"unit\": \"%\"\n            },\n            {\n              \"name\": \"to\",\n              \"type\": \"number\",\n              \"min\": 0,\n              \"max\": 100,\n              \"default\": 100,\n              \"unit\": \"%\"\n            },\n            {\n              \"name\": \"feedback\",\n              \"type\": \"text\",\n              \"label\": \"Feedback for defined score range\",\n              \"importance\": \"low\",\n              \"placeholder\": \"Fill in the feedback\",\n              \"optional\": true\n            }\n          ]\n        }\n      }\n    ]\n  },\n  {\n    \"label\": \"Text for \\\"Check\\\" button\",\n    \"importance\": \"low\",\n    \"name\": \"checkAnswer\",\n    \"type\": \"text\",\n    \"default\": \"Check\",\n    \"common\": true\n  },\n  {\n    \"label\": \"Text for \\\"Submit\\\" button\",\n    \"importance\": \"low\",\n    \"name\": \"submitAnswer\",\n    \"type\": \"text\",\n    \"default\": \"Submit\",\n    \"common\": true\n  },\n  {\n    \"label\": \"Text for \\\"Retry\\\" button\",\n    \"importance\": \"low\",\n    \"name\": \"tryAgain\",\n    \"type\": \"text\",\n    \"default\": \"Retry\",\n    \"common\": true\n  },\n  {\n    \"label\": \"Text for \\\"Show Solution\\\" button\",\n    \"importance\": \"low\",\n    \"name\": \"showSolution\",\n    \"type\": \"text\",\n    \"default\": \"Show solution\",\n    \"common\": true\n  },\n  {\n    \"label\": \"Numbered Drop zone label\",\n    \"importance\": \"low\",\n    \"name\": \"dropZoneIndex\",\n    \"type\": \"text\",\n    \"default\": \"Drop Zone @index.\",\n    \"description\": \"Label used for accessibility, where the Read speaker will read the index of a drop zone. Variable available: @index\",\n    \"common\": true\n  },\n  {\n    \"label\": \"Empty Drop Zone label\",\n    \"importance\": \"low\",\n    \"name\": \"empty\",\n    \"type\": \"text\",\n    \"default\": \"Drop Zone @index is empty.\",\n    \"description\": \"Label used for accessibility, where the Read speaker will read that the drop zone is empty\",\n    \"common\": true\n  },\n  {\n    \"label\": \"Contains Drop Zone label\",\n    \"importance\": \"low\",\n    \"name\": \"contains\",\n    \"type\": \"text\",\n    \"default\": \"Drop Zone @index contains draggable @draggable.\",\n    \"description\": \"Label used for accessibility, where the Read speaker will read that the drop zone contains a draggable\",\n    \"common\": true\n  },\n  {\n    \"label\": \"Draggable elements label\",\n    \"importance\": \"low\",\n    \"name\": \"ariaDraggableIndex\",\n    \"type\": \"text\",\n    \"default\": \"@index of @count draggables.\",\n    \"description\": \"Label used for accessibility, where the Read speaker reads that this is a draggable element. Variable available: @index, @count\",\n    \"common\": true\n  },\n  {\n    \"label\": \"Label for show tip button\",\n    \"importance\": \"low\",\n    \"name\": \"tipLabel\",\n    \"type\": \"text\",\n    \"default\": \"Show tip\",\n    \"description\": \"Label used for accessibility, where the Read speaker reads it before the tip is read out\",\n    \"common\": true\n  },\n  {\n    \"name\": \"correctText\",\n    \"type\": \"text\",\n    \"label\": \"Readspeaker text for correct answer\",\n    \"importance\": \"low\",\n    \"default\": \"Correct!\",\n    \"common\": true\n  },\n  {\n    \"name\": \"incorrectText\",\n    \"type\": \"text\",\n    \"label\": \"Readspeaker text for incorrect answer\",\n    \"importance\": \"low\",\n    \"default\": \"Incorrect!\",\n    \"common\": true\n  },\n  {\n    \"name\": \"resetDropTitle\",\n    \"type\": \"text\",\n    \"label\": \"Confirmation dialog title that user wants to reset a droppable\",\n    \"importance\": \"low\",\n    \"default\": \"Reset drop\",\n    \"common\": true\n  },\n  {\n    \"name\": \"resetDropDescription\",\n    \"type\": \"text\",\n    \"label\": \"Confirmation dialog description that user wants to reset a droppable\",\n    \"importance\": \"low\",\n    \"default\": \"Are you sure you want to reset this drop zone?\",\n    \"common\": true\n  },\n  {\n    \"name\": \"grabbed\",\n    \"type\": \"text\",\n    \"label\": \"Label used for accessibility, where the read speaker indicates that dragging is initiated\",\n    \"importance\": \"low\",\n    \"default\": \"Draggable is grabbed.\",\n    \"common\": true\n  },\n  {\n    \"name\": \"cancelledDragging\",\n    \"type\": \"text\",\n    \"label\": \"Label used for accessibility, where the read speaker indicates that dragging is canceled\",\n    \"importance\": \"low\",\n    \"default\": \"Cancelled dragging.\",\n    \"common\": true\n  },\n  {\n    \"name\": \"correctAnswer\",\n    \"type\": \"text\",\n    \"label\": \"Label used for accessibility, where the read speaker indicates that a text is the correct answer\",\n    \"importance\": \"low\",\n    \"default\": \"Correct answer:\",\n    \"common\": true\n  },\n  {\n    \"name\": \"feedbackHeader\",\n    \"type\": \"text\",\n    \"label\": \"Header for panel containing feedback for correct/incorrect answers\",\n    \"importance\": \"low\",\n    \"default\": \"Feedback\",\n    \"common\": true\n  },\n  {\n    \"name\": \"behaviour\",\n    \"type\": \"group\",\n    \"label\": \"Behavioural settings.\",\n    \"importance\": \"low\",\n    \"description\": \"These options will let you control how the task behaves.\",\n    \"optional\": true,\n    \"fields\": [\n      {\n        \"label\": \"Enable \\\"Retry\\\"\",\n        \"importance\": \"low\",\n        \"name\": \"enableRetry\",\n        \"type\": \"boolean\",\n        \"default\": true\n      },\n      {\n        \"label\": \"Enable \\\"Show Solution\\\" button\",\n        \"importance\": \"low\",\n        \"name\": \"enableSolutionsButton\",\n        \"type\": \"boolean\",\n        \"default\": true\n      },\n      {\n        \"name\": \"enableCheckButton\",\n        \"type\": \"boolean\",\n        \"label\": \"Enable \\\"Check\\\" button\",\n        \"widget\": \"none\",\n        \"importance\": \"low\",\n        \"default\": true,\n        \"optional\": true\n      },\n      {\n        \"label\": \"Instant feedback\",\n        \"importance\": \"low\",\n        \"name\": \"instantFeedback\",\n        \"type\": \"boolean\",\n        \"default\": false,\n        \"optional\": true\n      }\n    ]\n  },\n  {\n    \"name\": \"scoreBarLabel\",\n    \"type\": \"text\",\n    \"label\": \"Textual representation of the score bar for those using a readspeaker\",\n    \"default\": \"You got :num out of :total points\",\n    \"importance\": \"low\",\n    \"common\": true\n  },\n  {\n    \"name\": \"a11yCheck\",\n    \"type\": \"text\",\n    \"label\": \"Assistive technology label for \\\"Check\\\" button\",\n    \"default\": \"Check the answers. The responses will be marked as correct, incorrect, or unanswered.\",\n    \"importance\": \"low\",\n    \"common\": true\n  },\n  {\n    \"name\": \"a11yShowSolution\",\n    \"type\": \"text\",\n    \"label\": \"Assistive technology label for \\\"Show Solution\\\" button\",\n    \"default\": \"Show the solution. The task will be marked with its correct solution.\",\n    \"importance\": \"low\",\n    \"common\": true\n  },\n  {\n    \"name\": \"a11yRetry\",\n    \"type\": \"text\",\n    \"label\": \"Assistive technology label for \\\"Retry\\\" button\",\n    \"default\": \"Retry the task. Reset all responses and start the task over again.\",\n    \"importance\": \"low\",\n    \"common\": true\n  }\n]', NULL, 1, 19, NULL, NULL, NULL, 1),
(28, 'H5P.ExportableTextArea', 'Exportable Text Area', 1, 3, 18, 0, 0, '', 'dist/h5p-exportable-text-area.js', '', '', '[\n  {\n    \"name\": \"label\",\n    \"type\": \"text\",\n    \"widget\": \"html\",\n    \"label\": \"Label\",\n    \"importance\": \"high\",\n    \"description\": \"Label/heading for answer when user exports all answers\",\n    \"enterMode\": \"p\",\n    \"tags\": [\n      \"strong\",\n      \"em\",\n      \"a\",\n      \"ul\",\n      \"ol\",\n      \"h2\",\n      \"h3\",\n      \"hr\",\n      \"pre\",\n      \"code\"\n    ]\n  },\n  {\n    \"name\": \"index\",\n    \"type\": \"number\",\n    \"widget\": \"none\"\n  },\n  {\n    \"name\": \"exportNotSupported\",\n    \"type\": \"text\",\n    \"importance\": \"low\",\n    \"label\": \"Export not supported label\",\n    \"default\": \"Export not supported on your device\",\n    \"common\": true\n  },\n  {\n    \"name\": \"exportComments\",\n    \"type\": \"boolean\",\n    \"importance\": \"low\",\n    \"label\": \"Include comments in the exported document\",\n    \"optional\": true,\n    \"default\": false\n  }\n]\n', NULL, 1, 19, '{\"disable\":false,\"disableExtraTitleField\":true}', NULL, NULL, 1),
(29, 'H5P.FreeTextQuestion', 'Free Text Question', 1, 0, 16, 0, 0, '', 'h5p-free-text-question.js', 'h5p-free-text-question.css', '', '[\n  {\n    \"label\": \"Question\",\n    \"name\": \"question\",\n    \"type\": \"text\",\n    \"importance\": \"high\"\n  },\n  {\n    \"label\": \"Placeholder text\",\n    \"name\": \"placeholder\",\n    \"type\": \"text\",\n    \"importance\": \"high\",\n    \"default\": \"Enter your response here\",\n    \"description\": \"Text that initially will be shown in the input field. Will be removed automatically when the user starts writing.\"\n  },\n  {\n    \"label\": \"Max score\",\n    \"name\": \"maxScore\",\n    \"type\": \"number\",\n    \"importance\": \"high\",\n    \"description\": \"Used for grading and not shown to the learner\",\n    \"default\": 1\n  },\n  {\n    \"label\": \"Required\",\n    \"name\": \"isRequired\",\n    \"type\": \"boolean\",\n    \"importance\": \"high\",\n    \"description\": \"Learners must provide an answer in order to proceed\"\n  },\n  {\n    \"label\": \"Localize Free Text Question buttons\",\n    \"name\": \"i10n\",\n    \"type\": \"group\",\n    \"common\": true,\n    \"collapsed\": true,\n    \"importance\": \"low\",\n    \"fields\": [\n      {\n        \"label\": \"Required text label\",\n        \"name\": \"requiredText\",\n        \"type\": \"text\",\n        \"description\": \"Text shown to notify learner that input is required before proceeding\",\n        \"default\": \"required\",\n        \"importance\": \"low\"\n      },\n      {\n        \"label\": \"Required message\",\n        \"name\": \"requiredMessage\",\n        \"type\": \"text\",\n        \"importance\": \"low\",\n        \"default\": \"This question requires an answer\",\n        \"description\": \"Will display if this field is unanswered and required by a wrapper content type\"\n      },\n      {\n        \"label\": \"Skip button label\",\n        \"name\": \"skipButtonLabel\",\n        \"type\": \"text\",\n        \"defau