    },\n          {\n            \"value\": \"en-gb\",\n            \"label\": \"English (United Kingdom)\"\n          },\n          {\n            \"value\": \"en\",\n            \"label\": \"English\"\n          },\n          {\n            \"value\": \"eo\",\n            \"label\": \"Esperanto\"\n          },\n          {\n            \"value\": \"es-mx\",\n            \"label\": \"Spanish (Mexico)\"\n          },\n          {\n            \"value\": \"es\",\n            \"label\": \"Spanish (Spain)\"\n          },\n          {\n            \"value\": \"et\",\n            \"label\": \"Estonian\"\n          },\n          {\n            \"value\": \"eu\",\n            \"label\": \"Basque\"\n          },\n          {\n            \"value\": \"fa\",\n            \"label\": \"Farsi\"\n          },\n          {\n            \"value\": \"fi\",\n            \"label\": \"Finnish\"\n          },\n          {\n            \"value\": \"fo\",\n            \"label\": \"Faeroese\"\n          },\n          {\n            \"value\": \"fr-ca\",\n            \"label\": \"French (Canada)\"\n          },\n          {\n            \"value\": \"fr\",\n            \"label\": \"French (Standard)\"\n          },\n          {\n            \"value\": \"gl\",\n            \"label\": \"Galician\"\n          },\n          {\n            \"value\": \"gu\",\n            \"label\": \"Gujarati\"\n          },\n          {\n            \"value\": \"he\",\n            \"label\": \"Hebrew (modern)\"\n          },\n          {\n            \"value\": \"hi\",\n            \"label\": \"Hindi\"\n          },\n          {\n            \"value\": \"hr\",\n            \"label\": \"Croatian\"\n          },\n          {\n            \"value\": \"hu\",\n            \"label\": \"Hungarian\"\n          },\n          {\n            \"value\": \"id\",\n            \"label\": \"Indonesian\"\n          },\n          {\n            \"value\": \"is\",\n            \"label\": \"Icelandic\"\n          },\n          {\n            \"value\": \"it\",\n            \"label\": \"Italian (Standard)\"\n          },\n          {\n            \"value\": \"ja\",\n            \"label\": \"Japanese\"\n          },\n          {\n            \"value\": \"ka\",\n            \"label\": \"Georgian\"\n          },\n          {\n            \"value\": \"km\",\n            \"label\": \"Central Khmer\"\n          },\n          {\n            \"value\": \"ko\",\n            \"label\": \"Korean\"\n          },\n          {\n            \"value\": \"ku\",\n            \"label\": \"Kurdish\"\n          },\n          {\n            \"value\": \"lt\",\n            \"label\": \"Lithuanian\"\n          },\n          {\n            \"value\": \"lv\",\n            \"label\": \"Latvian\"\n          },\n          {\n            \"value\": \"mk\",\n            \"label\": \"Macedonian\"\n          },\n          {\n            \"value\": \"mn\",\n            \"label\": \"Mongolian\"\n          },\n          {\n            \"value\": \"ms\",\n            \"label\": \"Malay\"\n          },\n          {\n            \"value\": \"nb\",\n            \"label\": \"Norwegian BokmĂĄl\"\n          },\n          {\n            \"value\": \"nl\",\n            \"label\": \"Dutch (Standard)\"\n          },\n          {\n            \"value\": \"no\",\n            \"label\": \"Norwegian\"\n          },\n          {\n            \"value\": \"oc\",\n            \"label\": \"Occitan\"\n          },\n          {\n            \"value\": \"pl\",\n            \"label\": \"Polish\"\n          },\n          {\n            \"value\": \"pt-br\",\n            \"label\": \"Portuguese (Brazil)\"\n          },\n          {\n            \"value\": \"pt\",\n            \"label\": \"Portuguese (Portugal)\"\n          },\n          {\n            \"value\": \"ro\",\n            \"label\": \"Romanian\"\n          },\n          {\n            \"value\": \"ru\",\n            \"label\": \"Russian\"\n          },\n          {\n            \"value\": \"si\",\n            \"label\": \"Sinhala/Sinhalese\"\n          },\n          {\n            \"value\": \"sk\",\n            \"label\": \"Slovak\"\n          },\n          {\n            \"value\": \"sl\",\n            \"label\": \"Slovenian\"\n          },\n          {\n            \"value\": \"sq\",\n            \"label\": \"Albanian\"\n          },\n          {\n            \"value\": \"sr-latn\",\n            \"label\": \"Serbian (Latin)\"\n          },\n          {\n            \"value\": \"sr\",\n            \"label\": \"Serbian\"\n          },\n          {\n            \"value\": \"sv\",\n            \"label\": \"Swedish\"\n          },\n          {\n            \"value\": \"th\",\n            \"label\": \"Thai\"\n          },\n          {\n            \"value\": \"tr\",\n            \"label\": \"Turkish\"\n          },\n          {\n            \"value\": \"tt\",\n            \"label\": \"Tatar\"\n          },\n          {\n            \"value\": \"ug\",\n            \"label\": \"Uighur/Uyghur\"\n          },\n          {\n            \"value\": \"uk\",\n            \"label\": \"Ukrainian\"\n          },\n          {\n            \"value\": \"vi\",\n            \"label\": \"Vietnamese\"\n          },\n          {\n            \"value\": \"zh-cn\",\n            \"label\": \"Chinese (PRC)\"\n          }\n        ],\n        \"default\": \"en\"\n      }\n    ]\n  }\n]\n', NULL, 1, 13, NULL, NULL, NULL, 1),
(30, 'H5P.GoalsAssessmentPage', 'Goals assessment page', 1, 4, 17, 0, 0, '', 'goals-assessment-page.js', 'goals-assessment-page.css', '', '[\n  {\n    \"name\": \"description\",\n    \"label\": \"Description\",\n    \"importance\": \"medium\",\n    \"type\": \"text\",\n    \"widget\": \"html\",\n    \"description\": \"Description of the goals assessment page.\",\n    \"default\": \"Rate the goals that you have chosen in the goals page.\",\n    \"enterMode\": \"p\",\n    \"tags\": [\n      \"strong\",\n      \"em\",\n      \"u\",\n      \"a\",\n      \"ul\",\n      \"ol\",\n      \"h2\",\n      \"h3\",\n      \"hr\",\n      \"pre\",\n      \"code\"\n    ],\n    \"optional\": true\n  },\n  {\n    \"name\": \"lowRating\",\n    \"label\": \"Low rating text\",\n    \"importance\": \"low\",\n    \"type\": \"text\",\n    \"description\": \"Text for worst rating.\",\n    \"default\": \"Learned little\"\n  },\n  {\n    \"name\": \"midRating\",\n    \"label\": \"Medium rating text\",\n    \"importance\": \"low\",\n    \"type\": \"text\",\n    \"description\": \"Text for middle rating.\",\n    \"default\": \"Learned something\"\n  },\n  {\n    \"name\": \"highRating\",\n    \"label\": \"High rating text\",\n    \"importance\": \"low\",\n    \"type\": \"text\",\n    \"description\": \"Text for great rating.\",\n    \"default\": \"Learned a lot\"\n  },\n  {\n    \"name\": \"noGoalsText\",\n    \"label\": \"No goals text\",\n    \"importance\": \"low\",\n    \"type\": \"text\",\n    \"description\": \"Feedback text when no goals have been created.\",\n    \"default\": \"You have not chosen any goals yet.\"\n  },\n  {\n    \"name\": \"helpTextLabel\",\n    \"label\": \"Label for help text\",\n    \"importance\": \"low\",\n    \"type\": \"text\",\n    \"description\": \"Label for showing additional helpful information to the user.\",\n    \"default\": \"More information\"\n  },\n  {\n    \"name\": \"helpText\",\n    \"label\": \"Fill in additional help information\",\n    \"importance\": \"low\",\n    \"type\": \"text\",\n    \"widget\": \"html\",\n    \"description\": \"Here you can fill in additional helpful information for the user.\",\n    \"enterMode\": \"p\",\n    \"optional\": true,\n    \"tags\": [\n      \"strong\",\n      \"em\",\n      \"u\",\n      \"a\",\n      \"ul\",\n      \"ol\",\n      \"h2\",\n      \"h3\",\n      \"hr\",\n      \"pre\",\n      \"code\"\n    ]\n  },\n  {\n    \"name\": \"legendHeader\",\n    \"label\": \"Legend header\",\n    \"importance\": \"low\",\n    \"type\": \"text\",\n    \"default\": \"Possible ratings:\"\n  },\n  {\n    \"name\": \"goalHeader\",\n    \"label\": \"Goal header\",\n    \"importance\": \"low\",\n    \"type\": \"text\",\n    \"default\": \"Goals\"\n  },\n  {\n    \"name\": \"ratingHeader\",\n    \"label\": \"Rating header\",\n    \"importance\": \"low\",\n    \"type\": \"text\",\n    \"default\": \"Rating\"\n  }\n]', NULL, 1, 19, NULL, NULL, NULL, 1);
