(31, 'H5P.GoalsPage', 'Goals page', 1, 5, 21, 0, 0, '', 'goals-page.js, goal-instance.js', 'goals-page.css', '', '[\n  {\n    \"name\": \"description\",\n    \"label\": \"Description\",\n    \"importance\": \"medium\",\n    \"type\": \"text\",\n    \"widget\": \"html\",\n    \"description\": \"Description of the goals page.\",\n    \"default\": \"Insert the goals that you have chosen to work with.\",\n    \"enterMode\": \"p\",\n    \"tags\": [\n      \"strong\",\n      \"em\",\n      \"u\",\n      \"a\",\n      \"ul\",\n      \"ol\",\n      \"h2\",\n      \"h3\",\n      \"hr\",\n      \"pre\",\n      \"code\"\n    ],\n    \"optional\": true\n  },\n  {\n    \"name\": \"defineGoalText\",\n    \"label\": \"Define goal link text\",\n    \"importance\": \"low\",\n    \"type\": \"text\",\n    \"description\": \"Text that will be displayed on the button for creating a new goal.\",\n    \"default\": \"Create a new goal\"\n  },\n  {\n    \"name\": \"definedGoalLabel\",\n    \"label\": \"Label for a user defined goal\",\n    \"importance\": \"low\",\n    \"type\": \"text\",\n    \"description\": \"Text that will be displayed as label on a user created goal.\",\n    \"default\": \"User defined goal\"\n  },\n  {\n    \"name\": \"defineGoalPlaceholder\",\n    \"label\": \"Define goal placeholder\",\n    \"importance\": \"low\",\n    \"type\": \"text\",\n    \"description\": \"Text that will be displayed as a placeholder when creating a new goal.\",\n    \"default\": \"Write here...\"\n  },\n  {\n    \"name\": \"goalsAddedText\",\n    \"label\": \"Text indicating how many goals has been added\",\n    \"importance\": \"low\",\n    \"type\": \"text\",\n    \"default\": \"Goals added:\",\n    \"description\": \"This text will follow after the amount of goals that is currently created, example: \'Goals added: 5\' where \'Goals added:\' is this text.\"\n  },\n  {\n    \"name\": \"specifyGoalText\",\n    \"label\": \"Text for \\\"Specify goal\\\"-button\",\n    \"importance\": \"low\",\n    \"type\": \"text\",\n    \"default\": \"Specification\"\n  },\n  {\n    \"name\": \"removeGoalText\",\n    \"label\": \"Text for \\\"Remove goal\\\"-button\",\n    \"importance\": \"low\",\n    \"type\": \"text\",\n    \"default\": \"Remove Goal\"\n  },\n  {\n    \"name\": \"helpTextLabel\",\n    \"label\": \"Label for help text\",\n    \"importance\": \"low\",\n    \"type\": \"text\",\n    \"description\": \"Label for showing additional helpful information to the user.\",\n    \"default\": \"More information\"\n  },\n  {\n    \"name\": \"helpText\",\n    \"label\": \"Fill in additional help information\",\n    \"importance\": \"low\",\n    \"type\": \"text\",\n    \"widget\": \"html\",\n    \"description\": \"Here you can fill in additional helpful information for the user.\",\n    \"enterMode\": \"p\",\n    \"optional\": true,\n    \"tags\": [\n      \"strong\",\n      \"em\",\n      \"u\",\n      \"a\",\n      \"ul\",\n      \"ol\",\n      \"h2\",\n      \"h3\",\n      \"hr\",\n      \"pre\",\n      \"code\"\n    ]\n  },\n  {\n    \"name\": \"goalDeletionConfirmation\",\n    \"type\": \"group\",\n    \"common\": true,\n    \"importance\": \"low\",\n    \"label\": \"Localize goal deletion confirmation\",\n    \"fields\": [\n      {\n        \"name\": \"header\",\n        \"type\": \"text\",\n        \"label\": \"Header\",\n        \"optional\": false,\n        \"default\": \"Confirm deletion\"\n      },\n      {\n        \"name\": \"message\",\n        \"type\": \"text\",\n        \"label\": \"Message\",\n        \"optional\": false,\n        \"default\": \"Are you sure you want to delete this goal?\"\n      },\n      {\n        \"name\": \"cancelLabel\",\n        \"type\": \"text\",\n        \"label\": \"Cancel button label\",\n        \"optional\": false,\n        \"default\": \"Cancel\"\n      },\n      {\n        \"name\": \"confirmLabel\",\n        \"type\": \"text\",\n        \"label\": \"Confirm button label\",\n        \"optional\": false,\n        \"default\": \"Confirm\"\n      }\n    ]\n  }\n]\n', NULL, 1, 19, NULL, NULL, NULL, 1),
(32, 'H5P.GoToQuestion', 'Crossroads', 1, 3, 15, 0, 0, '', 'scripts/go-to-question.js', 'styles/go-to-question.css', '', '[\n  {\n    \"name\": \"text\",\n    \"type\": \"text\",\n    \"label\": \"Question Text\",\n    \"importance\": \"high\",\n    \"description\": \"The question that the user will make a choice based upon.\"\n  },\n  {\n    \"name\": \"choices\",\n    \"type\": \"list\",\n    \"label\": \"Choices\",\n    \"importance\": \"high\",\n    \"entity\": \"choice\",\n    \"min\": 2,\n    \"field\": {\n      \"name\": \"choice\",\n      \"type\": \"group\",\n      \"fields\": [\n        {\n          \"name\": \"text\",\n          \"type\": \"text\",\n          \"label\": \"Choice Text\",\n          \"importance\": \"high\",\n          \"description\": \"The label that will displayed on the choice button.\"\n        },\n        {\n          \"name\": \"goTo\",\n          \"type\": \"number\",\n          \"widget\": \"timecode\",\n          \"label\": \"Go To\",\n          \"importance\": \"high\",\n          \"description\": \"The target time the user will be taken to upon pressing the choice button. Enter timecode in the format M:SS.\"\n        },\n        {\n          \"name\": \"ifChosenText\",\n          \"type\": \"text\",\n          \"optional\": true,\n          \"label\": \"If Chosen Text\",\n          \"importance\": \"low\",\n          \"description\": \"An optional confirmation text that will be displayed after the user has pressed the choice button.\"\n        }\n      ]\n    }\n  },\n  {\n    \"name\": \"continueButtonLabel\",\n    \"type\": \"text\",\n    \"label\": \"Continue Button Label\",\n    \"importance\": \"low\",\n    \"default\": \"Continue\",\n    \"common\": true\n  }\n]', NULL, 1, 6, '{\"disable\":true,\"disableExtraTitleField\":true}', NULL, NULL, 1),
(33, 'H5P.GuidedTour', 'Guided tour', 1, 0, 6, 0, 0, '', 'scripts/h5p-guided-tour.js', 'styles/h5p-guided-tour.css', '', '', NULL, NULL, NULL, NULL, NULL, NULL, 1),
(34, 'H5P.IFrameEmbed', 'Iframe Embedder', 1, 0, 29, 1, 1, '', 'iframe-embed.js', '', '', '[\n  {\n    \"label\": \"Width\",\n    \"importance\": \"high\",\n    \"name\": \"width\",\n    \"type\": \"text\",\n    \"description\": \"Width of iFrame in CSS compliant format. Default: \\\"500px\\\"\"\n  },\n  {\n    \"label\": \"Minimum width\",\n    \"importance\": \"high\",\n    \"name\": \"minWidth\",\n    \"type\": \"text\",\n    \"description\": \"Minimum width of iFrame in CSS compliant format. Default: \\\"300px\\\"\"\n  },\n  {\n    \"label\": \"Height\",\n    \"name\": \"height\",\n    \"type\": \"text\",\n    \"description\": \"Height of iFrame in CSS compliant format. Default: \\\"500px\\\"\"\n  },\n  {\n    \"label\": \"Source\",\n    \"importance\": \"high\",\n    \"name\": \"source\",\n    \"type\": \"text\",\n    \"description\": \"URI to external document, or path to document found inside H5P (under /content)\"\n  },\n  {\n    \"name\": \"resizeSupported\",\n    \"type\": \"boolean\",\n    \"label\": \"Resize supported\",\n    \"importance\": \"medium\",\n    \"description\": \"If enabled, fullscreen button will be displayed, and H5P will be resized to fit its surroundings\",\n    \"default\": true\n  }\n]\n', NULL, NULL, NULL, NULL, NULL, NULL, 1),
(35, 'H5P.Image', 'Image', 1, 1, 22, 0, 0, '', 'image.js', 'image.css', '', '[\n  {\n    \"name\": \"file\",\n    \"type\": \"image\",\n    \"label\": \"Image\",\n    \"importance\": \"high\",\n    \"disableCopyright\": true\n  },\n  {\n    \"name\": \"decorative\",\n    \"type\": \"boolean\",\n    \"label\": \"Decorative only\",\n    \"default\": false,\n    \"description\": \"Enable this option if the image is purely decorative and does not add any information to the content on the page. It will be ignored by screen readers and not given any alternative text.\"\n  },\n  {\n    \"name\": \"alt\",\n    \"type\": \"text\",\n    \"label\": \"Alternative text\",\n    \"importance\": \"high\",\n    \"description\": \"Required. If the browser can\'t load the image this text will be displayed instead. Also used by \\\"text-to-speech\\\" readers.\",\n    \"widget\": \"showWhen\",\n    \"showWhen\": {\n      \"rules\": [\n        {\n          \"field\": \"decorative\",\n          \"equals\": false\n        }\n      ],\n      \"nullWhenHidden\": true\n    }\n  },\n  {\n    \"name\": \"title\",\n    \"type\": \"text\",\n    \"label\": \"Hover text\",\n    \"importance\": \"low\",\n    \"description\": \"Optional. This text is displayed when the users hover their pointing device over the image.\",\n    \"optional\": true\n  },\n  {\n    \"name\": \"contentName\",\n    \"type\": \"text\",\n    \"label\": \"Image content name\",\n    \"importance\": \"low\",\n    \"common\": true,\n    \"default\": \"Image\"\n  },\n  {\n    \"name\": \"expandImage\",\n    \"type\": \"text\",\n    \"label\": \"Expand Image\",\n    \"importance\": \"low\",\n    \"common\": true,\n    \"default\": \"Expand Image\"\n  },\n  {\n    \"name\": \"minimizeImage\",\n    \"type\": \"text\",\n    \"label\": \"Minimize Image\",\n    \"importance\": \"low\",\n    \"common\": true,\n    \"default\": \"Minimize Image\"\n  }\n]\n', NULL, 1, 19, '{\"disable\":false,\"disableExtraTitleField\":true}', NULL, NULL, 1),
(36, 'H5P.ImageHotspotQuestion', 'Find the Hotspot', 1, 8, 22, 1, 0, '', 'image-hotspot-question.js', 'image-hotspot-question.css', '', '[\n  {\n    \"name\": \"imageHotspotQuestion\",\n    \"type\": \"group\",\n    \"widget\": \"wizard\",\n    \"label\": \"Image Hotspot Question Editor\",\n    \"importance\": \"high\",\n    \"fields\": [\n      {\n        \"name\": \"backgroundImageSettings\",\n        \"type\": \"group\",\n        \"label\": \"Background image\",\n        \"importance\": \"high\",\n        \"fields\": [\n          {\n            \"name\": \"backgroundImage\",\n            \"type\": \"image\",\n            \"label\": \"Background image\",\n            \"importance\": \"high\",\n            \"description\": \"Select an image to use as background for the image hotspot question.\"\n          }\n        ]\n      },\n      {\n        \"name\": \"hotspotSettings\",\n        \"type\": \"group\",\n        \"label\": \"Hotspots\",\n        \"importance\": \"high\",\n        \"widget\": \"imageHotspotQuestion\",\n        \"description\": \"Drag and drop the desired figure from the toolbar to create a new hotspot. Double-click to edit an existing hotspot. Drag the hotspot to move it. Pull the resize handler in the lower right corner to resize.\",\n        \"fields\": [\n          {\n            \"name\": \"taskDescription\",\n            \"type\": \"text\",\n            \"label\": \"Task description\",\n            \"importance\": \"high\",\n            \"description\": \"Instructions to the user.\",\n            \"optional\": true\n          },\n          {\n            \"name\": \"hotspot\",\n            \"type\": \"list\",\n            \"label\": \"Hotspot\",\n            \"importance\": \"high\",\n            \"entity\": \"Hotspot\",\n            \"field\": {\n              \"type\": \"group\",\n              \"label\": \"Hotspot\",\n              \"importance\": \"high\",\n              \"fields\": [\n                {\n                  \"name\": \"userSettings\",\n                  \"type\": \"group\",\n                  \"label\": \"userSettings\",\n                  \"importance\": \"low\",\n                  \"fields\": [\n                    {\n                      \"name\": \"correct\",\n                      \"type\": \"boolean\",\n                      \"label\": \"Correct\",\n                      \"importance\": \"low\",\n                      \"description\": \"There can be multiple correct hotspots. However, the user gets correct/incorrect feedback immediately after first click.\"\n                    },\n                    {\n                      \"name\": \"feedbackText\",\n                      \"type\": \"text\",\n                      \"label\": \"Feedback\",\n                      \"importance\": \"low\",\n                      \"optional\": true\n                    }\n                  ]\n                },\n                {\n                  \"name\": \"computedSettings\",\n                  \"type\": \"group\",\n                  \"label\": \"computedSettings\",\n                  \"importance\": \"low\",\n                  \"fields\": [\n                    {\n                      \"name\": \"x\",\n                      \"type\": \"number\",\n                      \"optional\": true\n                    },\n                    {\n                      \"name\": \"y\",\n                      \"type\": \"number\",\n                      \"optional\": true\n                    },\n                    {\n                      \"name\": \"width\",\n                      \"type\": \"number\",\n                      \"optional\": true\n                    },\n                    {\n                      \"name\": \"height\",\n                      \"type\": \"number\",\n                      \"optional\": true\n                    },\n                    {\n                      \"name\": \"figure\",\n                      \"type\": \"text\",\n                      \"optional\": true\n                    }\n                  ]\n                }\n              ]\n            }\n          },\n          {\n            \"name\": \"noneSelectedFeedback\",\n            \"type\": \"text\",\n            \"label\": \"Feedback if the user selects an empty spot:\",\n            \"importance\": \"low\",\n            \"placeholder\": \"You didn\'t locate any hotspots, try again!\",\n            \"optional\": true\n          },\n          {\n            \"name\": \"showFeedbackAsPopup\",\n            \"type\": \"boolean\",\n            \"label\": \"Show feedback as a popup\",\n            \"importance\": \"low\",\n            \"default\": true,\n            \"optional\": true\n          },\n          {\n            \"label\": \"Localization\",\n            \"name\": \"l10n\",\n            \"type\": \"group\",\n            \"fields\": [\n              {\n                \"name\": \"retryText\",\n                \"label\": \"Retry button text\",\n                \"type\": \"text\",\n                \"default\": \"Retry\",\n                \"optional\": true\n              },\n              {\n                \"name\": \"closeText\",\n                \"label\": \"Close button text\",\n                \"type\": \"text\",\n                \"default\": \"Close\",\n                \"optional\": true\n              }\n            ]\n          }\n        ]\n      }\n    ]\n  },\n  {\n    \"name\": \"scoreBarLabel\",\n    \"type\": \"text\",\n    \"label\": \"Textual representation of the score bar for those using a readspeaker\",\n    \"default\": \"You got :num out of :total points\",\n    \"importance\": \"low\",\n    \"common\": true\n  },\n  {\n    \"name\": \"a11yRetry\",\n    \"type\": \"text\",\n    \"label\": \"Assistive technology description for \\\"Retry\\\" button\",\n    \"default\": \"Retry the task. Reset all responses and start the task over again.\",\n    \"importance\": \"low\",\n    \"common\": true\n  }\n]', NULL, 1, 23, NULL, NULL, NULL, 1),
(37, 'H5P.ImageHotspots', 'Image Hotspots', 1, 10, 18, 1, 1, 'iframe', 'scripts/image-hotspots.js, scripts/hotspot.js, scripts/popup.js', 'styles/image-hotspots.css', '', '[\n  {\n    \"label\": \"Background image\",\n    \"importance\": \"high\",\n    \"name\": \"image\",\n    \"type\": \"image\",\n    \"description\": \"Image shown on background.\"\n  },\n  {\n    \"name\": \"backgroundImageAltText\",\n    \"type\": \"text\",\n    \"label\": \"Alternative text for background image\",\n    \"description\": \"If the browser can\'t load the image this text will be displayed instead. Also used by assistive technologies.\",\n    \"optional\": true\n  },\n  {\n    \"name\": \"iconType\",\n    \"type\": \"select\",\n    \"label\": \"Hotspot Icon\",\n    \"options\": [\n      {\n        \"value\": \"icon\",\n        \"label\": \"Predefined icon\"\n      },\n      {\n        \"value\": \"image\",\n        \"label\": \"Uploaded image\"\n      }\n    ],\n    \"default\": \"icon\"\n  },\n  {\n    \"name\": \"icon\",\n    \"type\": \"select\",\n    \"label\": \"Predefined icon\",\n    \"importance\": \"medium\",\n    \"description\": \"Using a predefined icon for the hotspot.\",\n    \"widget\": \"showWhen\",\n    \"showWhen\": {\n      \"rules\": [\n        {\n          \"field\": \"iconType\",\n          \"equals\": [\n            \"icon\"\n          ]\n        }\n      ]\n    },\n    \"options\": [\n      {\n        \"value\": \"plus\",\n        \"label\": \"Plus\"\n      },\n      {\n        \"value\": \"minus\",\n        \"label\": \"Minus\"\n      },\n      {\n        \"value\": \"times\",\n        \"label\": \"Times\"\n      },\n      {\n        \"value\": \"check\",\n        \"label\": \"Check\"\n      },\n      {\n        \"value\": \"question\",\n        \"label\": \"Question\"\n      },\n      {\n        \"value\": \"info\",\n        \"label\": \"Info\"\n      },\n      {\n        \"value\": \"exclamation\",\n        \"label\": \"Exclamation\"\n      }\n    ],\n    \"default\": \"plus\"\n  },\n  {\n    \"name\": \"iconImage\",\n    \"type\": \"image\",\n    \"label\": \"Uploaded image\",\n    \"optional\": false,\n    \"description\": \"Use your own image for the hotspot icon.<br />75px by 75px is recommended for your image.\",\n    \"widget\": \"showWhen\",\n    \"showWhen\": {\n      \"rules\": [\n        {\n          \"field\": \"iconType\",\n          \"equals\": [\n            \"image\"\n          ]\n        }\n      ]\n    }\n  },\n  {\n    \"name\": \"color\",\n    \"type\": \"text\",\n    \"label\": \"Hotspot color\",\n    \"importance\": \"medium\",\n    \"description\": \"The color of the hotspots\",\n    \"optional\": true,\n    \"default\": \"#981d99\",\n    \"widget\": \"showWhen\",\n    \"spectrum\": {\n      \"showInput\": true\n    },\n    \"showWhen\": {\n      \"widget\": \"colorSelector\",\n      \"rules\": [\n        {\n          \"field\": \"iconType\",\n          \"equals\": [\n            \"icon\"\n          ]\n        }\n      ]\n    }\n  },\n  {\n    \"name\": \"hotspots\",\n    \"type\": \"list\",\n    \"entity\": \"hotspot\",\n    \"label\": \"Hotspots\",\n    \"importance\": \"high\",\n    \"min\": 1,\n    \"defaultNum\": 1,\n    \"field\": {\n      \"name\": \"hotspot\",\n      \"type\": \"group\",\n      \"label\": \"Hotspot\",\n      \"importance\": \"high\",\n      \"fields\": [\n        {\n          \"name\": \"position\",\n          \"type\": \"group\",\n          \"widget\": \"imageCoordinateSelector\",\n          \"imageFieldPath\": \"../../image\",\n          \"label\": \"Hotspot position\",\n          \"importance\": \"high\",\n          \"description\": \"Click on the thumbnail image to place the hotspot\",\n          \"fields\": [\n            {\n              \"name\": \"x\",\n              \"type\": \"number\"\n            },\n            {\n              \"name\": \"y\",\n              \"type\": \"number\"\n            },\n            {\n              \"name\": \"legacyPositioning\",\n              \"type\": \"boolean\"\n            }\n          ]\n        },\n        {\n          \"name\": \"alwaysFullscreen\",\n          \"type\": \"boolean\",\n          \"label\": \"Cover entire background image\",\n          \"importance\": \"low\",\n          \"description\": \"When the user clicks the hotspot the popup will cover the entire background image\"\n        },\n        {\n          \"name\": \"header\",\n          \"type\": \"text\",\n          \"label\": \"Header\",\n          \"importance\": \"low\",\n          \"description\": \"Optional header for the popup. This is used by assistive technologies.\",\n          \"optional\": true\n        },\n        {\n          \"name\": \"content\",\n          \"type\": \"list\",\n          \"label\": \"Popup content\",\n          \"importance\": \"medium\",\n          \"field\": {\n            \"name\": \"action\",\n            \"type\": \"library\",\n            \"label\": \"Content Item\",\n            \"options\": [\n              \"H5P.Text 1.1\",\n              \"H5P.Video 1.6\",\n              \"H5P.Image 1.1\",\n              \"H5P.Audio 1.5\"\n            ]\n          }\n        }\n      ]\n    }\n  },\n  {\n    \"name\": \"hotspotNumberLabel\",\n    \"type\": \"text\",\n    \"label\": \"Hotspot label for assistive technologies\",\n    \"default\": \"Hotspot #num\",\n    \"description\": \"Will help announce what hotspot element has been navigated to if there is no header specified for a hotspot. #num can be used to replace the hotspot number.\",\n    \"common\": true\n  },\n  {\n    \"name\": \"closeButtonLabel\",\n    \"type\": \"text\",\n    \"label\": \"Close button label for assistive technologies\",\n    \"default\": \"Close\",\n    \"common\": true\n  },\n  {\n    \"name\": \"containsAudioVideoLabel\",\n    \"type\": \"text\",\n    \"label\": \"Label for assistive technologies denoting that hotspot contains Audio/Video\",\n    \"default\": \"Contains Audio/Video\",\n    \"common\": true\n  }\n]\n', NULL, 1, 19, NULL, NULL, NULL, 1);
INSERT INTO `mdl_h5p_libraries` (`id`, `machinename`, `title`, `majorversion`, `minorversion`, `patchversion`, `runnable`, `fullscreen`, `embedtypes`, `preloadedjs`, `preloadedcss`, `droplibrarycss`, `semantics`, `addto`, `coremajor`, `coreminor`, `metadatasettings`, `tutorial`, `example`, `enabled`) VALUES
(38, 'H5P.InteractiveVideo', 'Interactive Video', 1, 27, 9, 1, 1, 'iframe', 'dist/h5p-interactive-video.js', 'dist/h5p-interactive-video.css', '', '[\n  {\n    \"name\": \"interactiveVideo\",\n    \"type\": \"group\",\n    \"widget\": \"wizard\",\n    \"label\": \"Interactive Video Editor\",\n    \"importance\": \"high\",\n    \"fields\": [\n      {\n        \"name\": \"video\",\n        \"type\": \"group\",\n        \"label\": \"Upload/embed video\",\n        \"importance\": \"high\",\n        \"fields\": [\n          {\n            \"name\": \"files\",\n            \"type\": \"video\",\n            \"label\": \"Add a video\",\n            \"importance\": \"high\",\n            \"description\": \"Click below to add a video you wish to use in your interactive video. You can add a video link or upload video files. It is possible to add several versions of the video with different qualities. To ensure maximum support in browsers at least add a version in webm and mp4 formats.\",\n            \"extraAttributes\": [\n              \"metadata\"\n            ],\n            \"enableCustomQualityLabel\": true\n          },\n          {\n            \"name\": \"startScreenOptions\",\n            \"type\": \"group\",\n            \"label\": \"Start screen options (unsupported for YouTube videos)\",\n            \"importance\": \"low\",\n            \"fields\": [\n              {\n                \"name\": \"title\",\n                \"type\": \"text\",\n                \"label\": \"The title of this interactive video\",\n                \"importance\": \"low\",\n                \"maxLength\": 60,\n                \"default\": \"Interactive Video\",\n                \"description\": \"Used in summaries, statistics etc.\"\n              },\n              {\n                \"name\": \"hideStartTitle\",\n                \"type\": \"boolean\",\n                \"label\": \"Hide title on video start screen\",\n                \"importance\": \"low\",\n                \"optional\": true,\n                \"default\": false\n              },\n              {\n                \"name\": \"shortStartDescription\",\n                \"type\": \"text\",\n                \"label\": \"Short description (Optional)\",\n                \"importance\": \"low\",\n                \"optional\": true,\n                \"maxLength\": 120,\n                \"description\": \"Optional. Display a short description text on the video start screen. Does not work for YouTube videos.\"\n              },\n              {\n                \"name\": \"poster\",\n                \"type\": \"image\",\n                \"label\": \"Poster image\",\n                \"importance\": \"low\",\n                \"optional\": true,\n                \"description\": \"Image displayed before the user launches the video. Does not work for YouTube Videos.\"\n              }\n            ]\n          },\n          {\n            \"name\": \"textTracks\",\n            \"type\": \"group\",\n            \"label\": \"Text tracks (unsupported for YouTube videos)\",\n            \"importance\": \"low\",\n            \"fields\": [\n              {\n                \"name\": \"videoTrack\",\n                \"type\": \"list\",\n                \"label\": \"Available text tracks\",\n                \"importance\": \"low\",\n                \"optional\": true,\n                \"entity\": \"Track\",\n                \"min\": 0,\n                \"defaultNum\": 1,\n                \"field\": {\n                  \"name\": \"track\",\n                  \"type\": \"group\",\n                  \"label\": \"Track\",\n                  \"importance\": \"low\",\n                  \"expanded\": false,\n                  \"fields\": [\n                    {\n                      \"name\": \"label\",\n                      \"type\": \"text\",\n                      \"label\": \"Track label\",\n                      \"description\": \"Used if you offer multiple tracks and the user has to choose a track. For instance \'Spanish subtitles\' could be the label of a Spanish subtitle track.\",\n                      \"importance\": \"low\",\n                      \"default\": \"Subtitles\",\n                      \"optional\": true\n                    },\n                    {\n                      \"name\": \"kind\",\n                      \"type\": \"select\",\n                      \"label\": \"Type of text track\",\n                      \"importance\": \"low\",\n                      \"default\": \"subtitles\",\n                      \"options\": [\n                        {\n                          \"value\": \"subtitles\",\n                          \"label\": \"Subtitles\"\n                        },\n                        {\n                          \"value\": \"captions\",\n                          \"label\": \"Captions\"\n                        },\n                        {\n                          \"value\": \"descriptions\",\n                          \"label\": \"Descriptions\"\n                        }\n                      ]\n                    },\n                    {\n                      \"name\": \"srcLang\",\n                      \"type\": \"text\",\n                      \"label\": \"Source language, must be defined for subtitles\",\n                      \"importance\": \"low\",\n                      \"default\": \"en\",\n                      \"description\": \"Must be a valid BCP 47 language tag. If \'Subtitles\' is the type of text track selected, the source language of the track must be defined.\"\n                    },\n                    {\n                      \"name\": \"track\",\n                      \"type\": \"file\",\n                      \"label\": \"Track source (WebVTT file)\",\n                      \"importance\": \"low\"\n                    }\n                  ]\n                }\n              },\n              {\n                \"name\": \"defaultTrackLabel\",\n                \"type\": \"text\",\n                \"label\": \"Default text track\",\n                \"description\": \"If left empty or not matching any of the text tracks the first text track will be used as the default.\",\n                \"importance\": \"low\",\n                \"optional\": true\n              }\n            ]\n          }\n        ]\n      },\n      {\n        \"name\": \"assets\",\n        \"type\": \"group\",\n        \"label\": \"Add interactions\",\n        \"importance\": \"high\",\n        \"widget\": \"interactiveVideo\",\n        \"video\": \"video/files\",\n        \"poster\": \"video/startScreenOptions/poster\",\n        \"fields\": [\n          {\n            \"name\": \"interactions\",\n            \"type\": \"list\",\n            \"field\": {\n              \"name\": \"interaction\",\n              \"type\": \"group\",\n              \"fields\": [\n                {\n                  \"name\": \"duration\",\n                  \"type\": \"group\",\n                  \"widget\": \"duration\",\n                  \"label\": \"Display time\",\n                  \"importance\": \"low\",\n                  \"fields\": [\n                    {\n                      \"name\": \"from\",\n                      \"type\": \"number\"\n                    },\n                    {\n                      \"name\": \"to\",\n                      \"type\": \"number\"\n                    }\n                  ]\n                },\n                {\n                  \"name\": \"pause\",\n                  \"label\": \"Pause video\",\n                  \"importance\": \"low\",\n                  \"type\": \"boolean\"\n                },\n                {\n                  \"name\": \"displayType\",\n                  \"label\": \"Display as\",\n                  \"importance\": \"low\",\n                  \"description\": \"<b>Button</b> is a collapsed interaction the user must press to open. <b>Poster</b> is an expanded interaction displayed directly on top of the video\",\n                  \"type\": \"select\",\n                  \"widget\": \"imageRadioButtonGroup\",\n                  \"options\": [\n                    {\n                      \"value\": \"button\",\n                      \"label\": \"Button\"\n                    },\n                    {\n                      \"value\": \"poster\",\n                      \"label\": \"Poster\"\n                    }\n                  ],\n                  \"default\": \"button\"\n                },\n                {\n                  \"name\": \"buttonOnMobile\",\n                  \"label\": \"Turn into button on small screens\",\n                  \"importance\": \"low\",\n                  \"type\": \"boolean\",\n                  \"default\": false\n                },\n                {\n                  \"name\": \"label\",\n                  \"type\": \"text\",\n                  \"widget\": \"html\",\n                  \"label\": \"Label\",\n                  \"importance\": \"low\",\n                  \"description\": \"Label displayed next to interaction icon.\",\n                  \"optional\": true,\n                  \"enterMode\": \"p\",\n                  \"tags\": [\n                    \"p\"\n                  ]\n                },\n                {\n                  \"name\": \"x\",\n                  \"type\": \"number\",\n                  \"importance\": \"low\",\n                  \"widget\": \"none\"\n                },\n                {\n                  \"name\": \"y\",\n                  \"type\": \"number\",\n                  \"importance\": \"low\",\n                  \"widget\": \"none\"\n                },\n                {\n                  \"name\": \"width\",\n                  \"type\": \"number\",\n                  \"widget\": \"none\",\n                  \"importance\": \"low\",\n                  \"optional\": true\n                },\n                {\n                  \"name\": \"height\",\n                  \"type\": \"number\",\n                  \"widget\": \"none\",\n                  \"importance\": \"low\",\n                  \"optional\": true\n                },\n                {\n                  \"name\": \"libraryTitle\",\n                  \"type\": \"text\",\n                  \"importance\": \"low\",\n                  \"optional\": true,\n                  \"widget\": \"none\"\n                },\n                {\n                  \"name\": \"action\",\n                  \"type\": \"library\",\n                  \"importance\": \"low\",\n                  \"options\": [\n                    \"H5P.Nil 1.0\",\n                    \"H5P.Text 1.1\",\n                    \"H5P.Table 1.2\",\n                    \"H5P.Link 1.3\",\n                    \"H5P.Image 1.1\",\n                    \"H5P.Summary 1.10\",\n                    \"H5P.SingleChoiceSet 1.11\",\n                    \"H5P.MultiChoice 1.16\",\n                    \"H5P.TrueFalse 1.8\",\n                    \"H5P.Blanks 1.14\",\n                    \"H5P.DragQuestion 1.14\",\n                    \"H5P.MarkTheWords 1.11\",\n                    \"H5P.DragText 1.10\",\n                    \"H5P.GoToQuestion 1.3\",\n                    \"H5P.IVHotspot 1.2\",\n                    \"H5P.Questionnaire 1.3\",\n                    \"H5P.FreeTextQuestion 1.0\",\n                    \"H5P.MultiMediaChoice 0.3\"\n                  ]\n                },\n                {\n                  \"name\": \"adaptivity\",\n                  \"type\": \"group\",\n                  \"label\": \"Adaptivity\",\n                  \"importance\": \"low\",\n                  \"optional\": true,\n                  \"fields\": [\n                    {\n                      \"name\": \"correct\",\n                      \"type\": \"group\",\n                      \"label\": \"Action on all correct\",\n                      \"fields\": [\n                        {\n                          \"name\": \"seekTo\",\n                          \"type\": \"number\",\n                          \"widget\": \"timecode\",\n                          \"label\": \"Seek to\",\n                          \"description\": \"Enter timecode in the format M:SS\"\n                        },\n                        {\n                          \"name\": \"allowOptOut\",\n                          \"type\": \"boolean\",\n                          \"label\": \"Allow the user to opt out and continue\"\n                        },\n                        {\n                          \"name\": \"message\",\n                          \"type\": \"text\",\n                          \"widget\": \"html\",\n                          \"enterMode\": \"p\",\n                          \"tags\": [\n                            \"strong\",\n                            \"em\",\n                            \"del\",\n                            \"a\",\n                            \"code\"\n                          ],\n                          \"label\": \"Message\"\n                        },\n                        {\n                          \"name\": \"seekLabel\",\n                          \"type\": \"text\",\n                          \"label\": \"Label for seek button\"\n                        }\n                      ]\n                    },\n                    {\n                      \"name\": \"wrong\",\n                      \"type\": \"group\",\n                      \"label\": \"Action on wrong\",\n                      \"fields\": [\n                        {\n                          \"name\": \"seekTo\",\n                          \"type\": \"number\",\n                          \"widget\": \"timecode\",\n                          \"label\": \"Seek to\",\n                          \"description\": \"Enter timecode in the format M:SS\"\n                        },\n                        {\n                          \"name\": \"allowOptOut\",\n                          \"type\": \"boolean\",\n                          \"label\": \"Allow the user to opt out and continue\"\n                        },\n                        {\n                          \"name\": \"message\",\n                          \"type\": \"text\",\n                          \"widget\": \"html\",\n                          \"enterMode\": \"p\",\n                          \"tags\": [\n                            \"strong\",\n                            \"em\",\n                            \"del\",\n                            \"a\",\n                            \"code\"\n                          ],\n                          \"label\": \"Message\"\n                        },\n                        {\n                          \"name\": \"seekLabel\",\n                          \"type\": \"text\",\n                          \"label\": \"Label for seek button\"\n                        }\n                      ]\n                    },\n                    {\n                      \"name\": \"requireCompletion\",\n                      \"type\": \"boolean\",\n                      \"label\": \"Require full score for task before proceeding\",\n                      \"description\": \"For best functionality this option should be used in conjunction with the \\\"Disable navigation forward in a video\\\" option of Interactive Video.\"\n                    }\n                  ]\n                },\n                {\n                  \"name\": \"visuals\",\n                  \"label\": \"Visuals\",\n                  \"importance\": \"low\",\n                  \"type\": \"group\",\n                  \"fields\": [\n                    {\n                      \"name\": \"backgroundColor\",\n                      \"type\": \"text\",\n                      \"label\": \"Background color\",\n                      \"widget\": \"colorSelector\",\n                      \"default\": \"rgb(255, 255, 255)\",\n                      \"spectrum\": {\n                        \"showInput\": true,\n                        \"showAlpha\": true,\n                        \"preferredFormat\": \"rgb\",\n                        \"showPalette\": true,\n                        \"palette\": [\n                          [\n                            \"rgba(0, 0, 0, 0)\"\n                          ],\n                          [\n                            \"rgb(67, 67, 67)\",\n                            \"rgb(102, 102, 102)\",\n                            \"rgb(204, 204, 204)\",\n                            \"rgb(217, 217, 217)\",\n                            \"rgb(255, 255, 255)\"\n                          ],\n                          [\n                            \"rgb(152, 0, 0)\",\n                            \"rgb(255, 0, 0)\",\n                            \"rgb(255, 153, 0)\",\n                            \"rgb(255, 255, 0)\",\n                            \"rgb(0, 255, 0)\",\n                            \"rgb(0, 255, 255)\",\n                            \"rgb(74, 134, 232)\",\n                            \"rgb(0, 0, 255)\",\n                            \"rgb(153, 0, 255)\",\n                            \"rgb(255, 0, 255)\"\n                          ],\n                          [\n                            \"rgb(230, 184, 175)\",\n                            \"rgb(244, 204, 204)\",\n                            \"rgb(252, 229, 205)\",\n                            \"rgb(255, 242, 204)\",\n                            \"rgb(217, 234, 211)\",\n                            \"rgb(208, 224, 227)\",\n                            \"rgb(201, 218, 248)\",\n                            \"rgb(207, 226, 243)\",\n                            \"rgb(217, 210, 233)\",\n                            \"rgb(234, 209, 220)\",\n                            \"rgb(221, 126, 107)\",\n                            \"rgb(234, 153, 153)\",\n                            \"rgb(249, 203, 156)\",\n                            \"rgb(255, 229, 153)\",\n                            \"rgb(182, 215, 168)\",\n                            \"rgb(162, 196, 201)\",\n                            \"rgb(164, 194, 244)\",\n                            \"rgb(159, 197, 232)\",\n                            \"rgb(180, 167, 214)\",\n                            \"rgb(213, 166, 189)\",\n                            \"rgb(204, 65, 37)\",\n                            \"rgb(224, 102, 102)\",\n                            \"rgb(246, 178, 107)\",\n                            \"rgb(255, 217, 102)\",\n                            \"rgb(147, 196, 125)\",\n                            \"rgb(118, 165, 175)\",\n                            \"rgb(109, 158, 235)\",\n                            \"rgb(111, 168, 220)\",\n                            \"rgb(142, 124, 195)\",\n                            \"rgb(194, 123, 160)\",\n                            \"rgb(166, 28, 0)\",\n                            \"rgb(204, 0, 0)\",\n                            \"rgb(230, 145, 56)\",\n                            \"rgb(241, 194, 50)\",\n                            \"rgb(106, 168, 79)\",\n                            \"rgb(69, 129, 142)\",\n                            \"rgb(60, 120, 216)\",\n                            \"rgb(61, 133, 198)\",\n                            \"rgb(103, 78, 167)\",\n                            \"rgb(166, 77, 121)\",\n                            \"rgb(91, 15, 0)\",\n                            \"rgb(102, 0, 0)\",\n                            \"rgb(120, 63, 4)\",\n                            \"rgb(127, 96, 0)\",\n                            \"rgb(39, 78, 19)\",\n                            \"rgb(12, 52, 61)\",\n                            \"rgb(28, 69, 135)\",\n                            \"rgb(7, 55, 99)\",\n                            \"rgb(32, 18, 77)\",\n                            \"rgb(76, 17, 48)\"\n                          ]\n                        ]\n                      }\n                    },\n                    {\n                      \"name\": \"boxShadow\",\n                      \"type\": \"boolean\",\n                      \"label\": \"Box shadow\",\n                      \"default\": true,\n                      \"description\": \"Adds a subtle shadow around the interaction. You might want to disable this for completely transparent interactions\"\n                    }\n                  ]\n                },\n                {\n                  \"name\": \"goto\",\n                  \"label\": \"Go to on click\",\n                  \"importance\": \"low\",\n                  \"type\": \"group\",\n                  \"fields\": [\n                    {\n                      \"name\": \"type\",\n                      \"label\": \"Type\",\n                      \"type\": \"select\",\n                      \"widget\": \"selectToggleFields\",\n                      \"options\": [\n                        {\n                          \"value\": \"timecode\",\n                          \"label\": \"Timecode\",\n                          \"hideFields\": [\n                            \"url\"\n                          ]\n                        },\n                        {\n                          \"value\": \"url\",\n                          \"label\": \"Another page (URL)\",\n                          \"hideFields\": [\n                            \"time\"\n                          ]\n                        }\n                      ],\n                      \"optional\": true\n                    },\n                    {\n                      \"name\": \"time\",\n                      \"type\": \"number\",\n                      \"widget\": \"timecode\",\n                      \"label\": \"Go To\",\n                      \"description\": \"The target time the user will be taken to upon pressing the hotspot. Enter timecode in the format M:SS.\",\n                      \"optional\": true\n                    },\n                    {\n                      \"name\": \"url\",\n                      \"type\": \"group\",\n                      \"label\": \"URL\",\n  