    \"field\": {\n              \"name\": \"bookmark\",\n              \"type\": \"group\",\n              \"fields\": [\n                {\n                  \"name\": \"time\",\n                  \"type\": \"number\"\n                },\n                {\n                  \"name\": \"label\",\n                  \"type\": \"text\"\n                }\n              ]\n            }\n          },\n          {\n            \"name\": \"endscreens\",\n            \"importance\": \"low\",\n            \"type\": \"list\",\n            \"field\": {\n              \"name\": \"endscreen\",\n              \"type\": \"group\",\n              \"fields\": [\n                {\n                  \"name\": \"time\",\n                  \"type\": \"number\"\n                },\n                {\n                  \"name\": \"label\",\n                  \"type\": \"text\"\n                }\n              ]\n            }\n          }\n        ]\n      },\n      {\n        \"name\": \"summary\",\n        \"type\": \"group\",\n        \"label\": \"Summary task\",\n        \"importance\": \"high\",\n        \"fields\": [\n          {\n            \"name\": \"task\",\n            \"type\": \"library\",\n            \"options\": [\n              \"H5P.Summary 1.10\"\n            ],\n            \"default\": {\n              \"library\": \"H5P.Summary 1.10\",\n              \"params\": {}\n            }\n          },\n          {\n            \"name\": \"displayAt\",\n            \"type\": \"number\",\n            \"label\": \"Display at\",\n            \"description\": \"Number of seconds before the video ends.\",\n            \"default\": 3\n          }\n        ]\n      }\n    ]\n  },\n  {\n    \"name\": \"override\",\n    \"type\": \"group\",\n    \"label\": \"Behavioural settings\",\n    \"importance\": \"low\",\n    \"optional\": true,\n    \"fields\": [\n      {\n        \"name\": \"startVideoAt\",\n        \"type\": \"number\",\n        \"widget\": \"timecode\",\n        \"label\": \"Start video at\",\n        \"importance\": \"low\",\n        \"optional\": true,\n        \"description\": \"Enter timecode in the format M:SS\"\n      },\n      {\n        \"name\": \"autoplay\",\n        \"type\": \"boolean\",\n        \"label\": \"Auto-play video\",\n        \"default\": false,\n        \"optional\": true,\n        \"description\": \"Start playing the video automatically\"\n      },\n      {\n        \"name\": \"loop\",\n        \"type\": \"boolean\",\n        \"label\": \"Loop the video\",\n        \"default\": false,\n        \"optional\": true,\n        \"description\": \"Check if video should run in a loop\"\n      },\n      {\n        \"name\": \"showSolutionButton\",\n        \"type\": \"select\",\n        \"label\": \"Override \\\"Show Solution\\\" button\",\n        \"importance\": \"low\",\n        \"description\": \"This option determines if the \\\"Show Solution\\\" button will be shown for all questions, disabled for all or configured for each question individually.\",\n        \"optional\": true,\n        \"options\": [\n          {\n            \"value\": \"on\",\n            \"label\": \"Enabled\"\n          },\n          {\n            \"value\": \"off\",\n            \"label\": \"Disabled\"\n          }\n        ]\n      },\n      {\n        \"name\": \"retryButton\",\n        \"type\": \"select\",\n        \"label\": \"Override \\\"Retry\\\" button\",\n        \"importance\": \"low\",\n        \"description\": \"This option determines if the \\\"Retry\\\" button will be shown for all questions, disabled for all or configured for each question individually.\",\n        \"options\": [\n          {\n            \"value\": \"on\",\n            \"label\": \"Enabled\"\n          },\n          {\n            \"value\": \"off\",\n            \"label\": \"Disabled\"\n          }\n        ]\n      },\n      {\n        \"name\": \"showBookmarksmenuOnLoad\",\n        \"type\": \"boolean\",\n        \"label\": \"Start with bookmarks menu open\",\n        \"importance\": \"low\",\n        \"default\": false,\n        \"description\": \"This function is not available on iPad when using YouTube as video source.\"\n      },\n      {\n        \"name\": \"showRewind10\",\n        \"type\": \"boolean\",\n        \"label\": \"Show button for rewinding 10 seconds\",\n        \"importance\": \"low\",\n        \"default\": false\n      },\n      {\n        \"name\": \"preventSkippingMode\",\n        \"type\": \"select\",\n        \"label\": \"Disable navigation\",\n        \"importance\": \"low\",\n        \"description\": \"These options will disable user video navigation as specified.\",\n        \"optional\": true,\n        \"options\": [\n          {\n            \"label\": \"None\",\n            \"value\": \"none\"\n          },\n          {\n            \"label\": \"Forward\",\n            \"value\": \"forward\"\n          },\n          {\n            \"label\": \"Forward and backward\",\n            \"value\": \"both\"\n          }\n        ],\n        \"default\": \"none\"\n      },\n      {\n        \"name\": \"deactivateSound\",\n        \"type\": \"boolean\",\n        \"default\": false,\n        \"label\": \"Deactivate sound\",\n        \"importance\": \"low\",\n        \"description\": \"Enabling this option will deactivate the video\'s sound and prevent it from being switched on.\"\n      }\n    ]\n  },\n  {\n    \"name\": \"l10n\",\n    \"type\": \"group\",\n    \"label\": \"Localize\",\n    \"importance\": \"low\",\n    \"common\": true,\n    \"optional\": true,\n    \"fields\": [\n      {\n        \"name\": \"interaction\",\n        \"type\": \"text\",\n        \"label\": \"Interaction title\",\n        \"importance\": \"low\",\n        \"default\": \"Interaction\",\n        \"optional\": true\n      },\n      {\n        \"name\": \"play\",\n        \"type\": \"text\",\n        \"label\": \"Play title\",\n        \"importance\": \"low\",\n        \"default\": \"Play\",\n        \"optional\