     \"rgb(39, 78, 19)\",\n              \"rgb(12, 52, 61)\",\n              \"rgb(28, 69, 135)\",\n              \"rgb(7, 55, 99)\",\n              \"rgb(32, 18, 77)\",\n              \"rgb(76, 17, 48)\"\n            ]\n          ]\n        }\n      },\n      {\n        \"name\": \"pointerCursor\",\n        \"type\": \"boolean\",\n        \"label\": \"Use pointer cursor\",\n        \"importance\": \"low\",\n        \"default\": true\n      },\n      {\n        \"name\": \"animation\",\n        \"type\": \"boolean\",\n        \"label\": \"Add blinking effect\",\n        \"importance\": \"low\",\n        \"description\": \"Note: Blinking effect is always enabled in the editor so you are able to find transparent hotspots\"\n      }\n    ]\n  },\n  {\n    \"name\": \"texts\",\n    \"type\": \"group\",\n    \"label\": \"Texts\",\n    \"expanded\": true,\n    \"importance\": \"low\",\n    \"fields\": [\n      {\n        \"name\": \"alternativeText\",\n        \"type\": \"text\",\n        \"importance\": \"low\",\n        \"label\": \"Alternative Text\",\n        \"description\": \"Describe the subject the hotspot covers. Used for readspeakers\",\n        \"placeholder\": \"An apple on a table\",\n        \"optional\": false\n      },\n      {\n        \"name\": \"label\",\n        \"type\": \"text\",\n        \"importance\": \"low\",\n        \"label\": \"Hotspot Label\",\n        \"optional\": true\n      },\n      {\n        \"name\": \"showLabel\",\n        \"type\": \"boolean\",\n        \"label\": \"Show label\",\n        \"importance\": \"low\",\n        \"default\": false\n      },\n      {\n        \"name\": \"labelColor\",\n        \"type\": \"text\",\n        \"label\": \"Label color\",\n        \"widget\": \"showWhen\",\n        \"importance\": \"low\",\n        \"optional\": true,\n        \"default\": \"rgb(0, 0, 0)\",\n        \"showWhen\": {\n          \"detach\": false,\n          \"widget\": \"colorSelector\",\n          \"rules\": [\n            {\n              \"field\": \"showLabel\",\n              \"equals\": true\n            }\n          ]\n        },\n        \"spectrum\": {\n          \"showInput\": true,\n          \"showAlpha\": true,\n          \"preferredFormat\": \"rgb\",\n          \"showPalette\": true,\n          \"palette\": [\n            [\n              \"rgba(255, 255, 255, 0)\"\n            ],\n            [\n              \"rgb(67, 67, 67)\",\n              \"rgb(102, 102, 102)\",\n              \"rgb(204, 204, 204)\",\n              \"rgb(217, 217, 217)\",\n              \"rgb(255, 255, 255)\"\n            ],\n            [\n              \"rgb(152, 0, 0)\",\n              \"rgb(255, 0, 0)\",\n              \"rgb(255, 153, 0)\",\n              \"rgb(255, 255, 0)\",\n              \"rgb(0, 255, 0)\",\n              \"rgb(0, 255, 255)\",\n              \"rgb(74, 134, 232)\",\n              \"rgb(0, 0, 255)\",\n              \"rgb(153, 0, 255)\",\n              \"rgb(255, 0, 255)\"\n            ],\n            [\n              \"rgb(230, 184, 175)\",\n              \"rgb(244, 204, 204)\",\n              \"rgb(252, 229, 205)\",\n              \"rgb(255, 242, 204)\",\n              \"rgb(217, 234, 211)\",\n              \"rgb(208, 224, 227)\",\n              \"rgb(201, 218, 248)\",\n              \"rgb(207, 226, 243)\",\n              \"rgb(217, 210, 233)\",\n              \"rgb(234, 209, 220)\",\n              \"rgb(221, 126, 107)\",\n              \"rgb(234, 153, 153)\",\n              \"rgb(249, 203, 156)\",\n              \"rgb(255, 229, 153)\",\n              \"rgb(182, 215, 168)\",\n              \"rgb(162, 196, 201)\",\n              \"rgb(164, 194, 244)\",\n              \"rgb(159, 197, 232)\",\n              \"rgb(180, 167, 214)\",\n              \"rgb(213, 166, 189)\",\n              \"rgb(204, 65, 37)\",\n              \"rgb(224, 102, 102)\",\n              \"rgb(246, 178, 107)\",\n              \"rgb(255, 217, 102)\",\n              \"rgb(147, 196, 125)\",\n              \"rgb(118, 