(40, 'H5P.Link', 'Link', 1, 3, 18, 0, 0, '', 'link.js', '', '', '[\n  {\n    \"name\": \"title\",\n    \"type\": \"text\",\n    \"importance\": \"high\",\n    \"label\": \"Title\"\n  },\n  {\n    \"name\": \"linkWidget\",\n    \"type\": \"group\",\n    \"importance\": \"high\",\n    \"widget\": \"linkWidget\",\n    \"fields\": [\n      {\n        \"name\": \"protocol\",\n        \"type\": \"select\",\n        \"importance\": \"high\",\n        \"label\": \"Protocol\",\n        \"options\": [\n          {\n            \"value\": \"http://\",\n            \"label\": \"http://\"\n          },\n          {\n            \"value\": \"https://\",\n            \"label\": \"https://\"\n          },\n          {\n            \"value\": \"/\",\n            \"label\": \"(root relative)\"\n          },\n          {\n            \"value\": \"other\",\n            \"label\": \"other\"\n          }\n        ],\n        \"optional\": true,\n        \"default\": \"https://\"\n      },\n      {\n        \"name\": \"url\",\n        \"type\": \"text\",\n        \"importance\": \"high\",\n        \"label\": \"URL\"\n      }\n    ]\n  }\n]', NULL, NULL, NULL, '{\"disable\":true,\"disableExtraTitleField\":true}', NULL, NULL, 1),
(41, 'H5P.MarkTheWords', 'Mark the Words', 1, 11, 9, 1, 0, 'iframe', 'scripts/keyboard-nav.js, scripts/xAPI-generator.js, scripts/word.js, scripts/mark-the-words.js', 'styles/mark-the-words.css', '', '[\n  {\n    \"name\": \"media\",\n    \"type\": \"group\",\n    \"label\": \"Media\",\n    \"importance\": \"medium\",\n    \"fields\": [\n      {\n        \"name\": \"type\",\n        \"type\": \"library\",\n        \"label\": \"Type\",\n        \"importance\": \"medium\",\n        \"options\": [\n          \"H5P.Image 1.1\",\n          \"H5P.Video 1.6\",\n          \"H5P.Audio 1.5\"\n        ],\n        \"optional\": true,\n        \"description\": \"Optional media to display above the question.\"\n      },\n      {\n        \"name\": \"disableImageZooming\",\n        \"type\": \"boolean\",\n        \"label\": \"Disable image zooming\",\n        \"importance\": \"low\",\n        \"default\": false,\n        \"optional\": true,\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"type\",\n              \"equals\": \"H5P.Image 1.1\"\n            }\n          ]\n        }\n      }\n    ]\n  },\n  {\n    \"label\": \"Task description\",\n    \"importance\": \"high\",\n    \"name\": \"taskDescription\",\n    \"type\": \"text\",\n    \"widget\": \"html\",\n    \"description\": \"Describe how the user should solve the task.\",\n    \"placeholder\": \"Click on all the verbs in the text that follows.\",\n    \"enterMode\": \"p\",\n    \"tags\": [\n      \"strong\",\n      \"em\",\n      \"u\",\n      \"a\",\n      \"ul\",\n      \"ol\",\n      \"h2\",\n      \"h3\",\n      \"hr\",\n      \"pre\",\n      \"code\"\n    ]\n  },\n  {\n    \"label\": \"Textfield\",\n    \"importance\": \"high\",\n    \"name\": \"textField\",\n    \"type\": \"text\",\n    \"widget\": \"html\",\n    \"tags\": [\n      \"p\",\n      \"br\",\n      \"strong\",\n      \"em\",\n      \"code\"\n    ],\n    \"placeholder\": \"This is an answer: *answer*.\",\n    \"description\": \"\",\n    \"important\": {\n      \"description\": \"<ul><li>Correct words are marked with asterisks (*) before and after the word.</li><li>Asterisks can be added within marked words by adding another asterisk, *correctword*** =&gt; correctword*.</li><li>Only words may be marked as correct. Not phrases.</li></ul>\",\n      \"example\": \"The correct words are marked like this: *correctword*, an asterisk is written like this: *correctword***.\"\n    }\n  },\n  {\n    \"name\": \"overallFeedback\",\n    \"type\": \"group\",\n    \"label\": \"Overall Feedback\",\n    \"importance\": \"low\",\n    \"expanded\": true,\n    \"fields\": [\n      {\n        \"name\": \"overallFeedback\",\n        \"type\": \"list\",\n        \"widgets\": [\n          {\n            \"name\": \"RangeList\",\n            \"label\": \"Default\"\n          }\n        ],\n        \"importance\": \"high\",\n        \"label\": \"Define custom feedback for any score range\",\n        \"description\": \"Click the \\\"Add range\\\" button to add as many ranges as you need. Example: 0-20% Bad score, 21-91% Average Score, 91-100% Great Score!\",\n        \"entity\": \"range\",\n        \"min\": 1,\n        \"defaultNum\": 1,\n        \"optional\": true,\n        \"field\": {\n          \"name\": \"overallFeedback\",\n          \"type\": \"group\",\n          \"importance\": \"low\",\n          \"fields\": [\n            {\n              \"name\": \"from\",\n              \"type\": \"number\",\n              \"label\": \"Score Range\",\n              \"min\": 0,\n              \"max\": 100,\n              \"default\": 0,\n              \"unit\": \"%\"\n            },\n            {\n              \"name\": \"to\",\n              \"type\": \"number\",\n              \"min\": 0,\n              \"max\": 100,\n              \"default\": 100,\n              \"unit\": \"%\"\n            },\n            {\n              \"name\": \"feedback\",\n              \"type\": \"text\",\n              \"label\": \"Feedback for defined score range\",\n              \"importance\": \"low\",\n              \"placeholder\": \"Fill in the feedback\",\n              \"optional\": true\n            }\n          ]\n        }\n      }\n    ]\n  },\n  {\n    \"label\": \"Text for \\\"Check\\\" button\",\n    \"importance\": \"low\",\n    \"name\": \"checkAnswerButton\",\n    \"type\": \"text\",\n    \"default\": \"Check\",\n    \"common\": true\n  },\n  {\n    \"label\": \"Text for \\\"Submit\\\" button\",\n    \"importance\": \"low\",\n    \"name\": \"submitAnswerButton\",\n    \"type\": \"text\",\n    \"default\": \"Submit\",\n    \"common\": true\n  },\n  {\n    \"label\": \"Text for \\\"Retry\\\" button\",\n    \"importance\": \"low\",\n    \"name\": \"tryAgainButton\",\n    \"type\": \"text\",\n    \"default\": \"Retry\",\n    \"common\": true\n  },\n  {\n    \"label\": \"Text for \\\"Show solution\\\" button\",\n    \"importance\": \"low\",\n    \"name\": \"showSolutionButton\",\n    \"type\": \"text\",\n    \"default\": \"Show solution\",\n    \"common\": true\n  },\n  {\n    \"name\": \"behaviour\",\n    \"importance\": \"low\",\n    \"type\": \"group\",\n    \"label\": \"Behavioural settings.\",\n    \"description\": \"These options will let you control how the task behaves.\",\n    \"optional\": true,\n    \"fields\": [\n      {\n        \"name\": \"enableRetry\",\n        \"type\": \"boolean\",\n        \"label\": \"Enable \\\"Retry\\\"\",\n        \"importance\": \"low\",\n        \"default\": true\n      },\n      {\n        \"name\": \"enableSolutionsButton\",\n        \"type\": \"boolean\",\n        \"label\": \"Enable \\\"Show solution\\\" button\",\n        \"importance\": \"low\",\n        \"default\": true\n      },\n      {\n        \"name\": \"enableCheckButton\",\n        \"type\": \"boolean\",\n        \"label\": \"Enable \\\"Check\\\" button\",\n        \"widget\": \"none\",\n        \"importance\": \"low\",\n        \"default\": true,\n        \"optional\": true\n      },\n      {\n        \"name\": \"showScorePoints\",\n        \"type\": \"boolean\",\n        \"label\": \"Show score points\",\n        \"description\": \"Show points earned for each answer.\",\n        \"importance\": \"low\",\n        \"default\": true\n      }\n    ]\n  },\n  {\n    \"label\": \"Correct answer text\",\n    \"importance\": \"low\",\n    \"name\": \"correctAnswer\",\n    \"type\": \"text\",\n    \"default\": \"Correct!\",\n    \"description\": \"Text used to indicate that an answer is correct\",\n    \"common\": true\n  },\n  {\n    \"label\": \"Incorrect answer text\",\n    \"importance\": \"low\",\n    \"name\": \"incorrectAnswer\",\n    \"type\": \"text\",\n    \"default\": \"Incorrect!\",\n    \"description\": \"Text used to indicate that an answer is incorrect\",\n    \"common\": true\n  },\n  {\n    \"label\": \"Missed answer text\",\n    \"importance\": \"low\",\n    \"name\": \"missedAnswer\",\n    \"type\": \"text\",\n    \"default\": \"Answer not found!\",\n    \"description\": \"Text used to indicate that an answer is missing\",\n    \"common\": true\n  },\n  {\n    \"label\": \"Description for Display Solution\",\n    \"importance\": \"low\",\n    \"name\": \"displaySolutionDescription\",\n    \"type\": \"text\",\n    \"default\": \"Task is updated to contain the solution.\",\n    \"description\": \"This text tells the user that the tasks has been updated with the solution.\",\n    \"common\": true\n  },\n  {\n    \"name\": \"scoreBarLabel\",\n    \"type\": \"text\",\n    \"label\": \"Textual representation of the score bar for those using a readspeaker\",\n    \"default\": \"You got :num out of :total points\",\n    \"importance\": \"low\",\n    \"common\": true\n  },\n  {\n    \"name\": \"a11yFullTextLabel\",\n    \"type\": \"text\",\n    \"label\": \"Label for the full readable text for assistive technologies\",\n    \"default\": \"Full readable text\",\n    \"importance\": \"low\",\n    \"common\": true\n  },\n  {\n    \"name\": \"a11yClickableTextLabel\",\n    \"type\": \"text\",\n    \"label\": \"Label for the text where words can be marked for assistive technologies\",\n    \"default\": \"Full text where words can be marked\",\n    \"importance\": \"low\",\n    \"common\": true\n  },\n  {\n    \"name\": \"a11ySolutionModeHeader\",\n    \"type\": \"text\",\n    \"label\": \"Solution mode header for assistive technologies\",\n    \"default\": \"Solution mode\",\n    \"importance\": \"low\",\n    \"common\": true\n  },\n  {\n    \"name\": \"a11yCheckingHeader\",\n    \"type\": \"text\",\n    \"label\": \"Checking mode header for assistive technologies\",\n    \"default\": \"Checking mode\",\n    \"importance\": \"low\",\n    \"common\": true\n  },\n  {\n    \"name\": \"a11yCheck\",\n    \"type\": \"text\",\n    \"label\": \"Assistive technology description for \\\"Check\\\" button\",\n    \"default\": \"Check the answers. The responses will be marked as correct, incorrect, or unanswered.\",\n    \"importance\": \"low\",\n    \"common\": true\n  },\n  {\n    \"name\": \"a11yShowSolution\",\n    \"type\": \"text\",\n    \"label\": \"Assistive technology description for \\\"Show Solution\\\" button\",\n    \"default\": \"Show the solution. The task will be marked with its correct solution.\",\n    \"importance\": \"low\",\n    \"common\": true\n  },\n  {\n    \"name\": \"a11yRetry\",\n    \"type\": \"text\",\n    \"label\": \"Assistive technology description for \\\"Retry\\\" button\",\n    \"default\": \"Retry the task. Reset all responses and start the task over again.\",\n    \"importance\": \"low\",\n    \"common\": true\n  }\n]', NULL, 1, 27, NULL, NULL, NULL, 1),
(42, 'H5P.MaterialDesignIcons', 'Material Design Icons', 1, 0, 0, 0, 0, '', '', 'h5p-material-icons.css', '', '', NULL, NULL, NULL, NULL, NULL, NULL, 1),
(43, 'H5P.MemoryGame', 'Memory Game', 1, 3, 29, 1, 0, '', 'memory-game.js, card.js, counter.js, popup.js, timer.js, aria-live-region.js', 'memory-game.css', '', '[\n  {\n    \"name\": \"cards\",\n    \"type\": \"list\",\n    \"widgets\": [\n      {\n        \"name\": \"VerticalTabs\",\n        \"label\": \"Default\"\n      }\n    ],\n    \"label\": \"Cards\",\n    \"importance\": \"high\",\n    \"entity\": \"card\",\n    \"min\": 2,\n    \"max\": 100,\n    \"field\": {\n      \"type\": \"group\",\n      \"name\": \"card\",\n      \"label\": \"Card\",\n      \"importance\": \"high\",\n      \"fields\": [\n        {\n          \"name\": \"image\",\n          \"type\": \"image\",\n          \"label\": \"Image\",\n          \"importance\": \"high\",\n          \"ratio\": 1\n        },\n        {\n          \"name\": \"imageAlt\",\n          \"type\": \"text\",\n          \"label\": \"Alternative text for Image\",\n          \"importance\": \"high\",\n          \"description\": \"Describe what can be seen in the photo. The text is read by text-to-speech tools needed by visually impaired users.\"\n        },\n        {\n          \"name\": \"audio\",\n          \"type\": \"audio\",\n          \"importance\": \"high\",\n          \"label\": \"Audio Track\",\n          \"description\": \"An optional sound that plays when the card is turned.\",\n          \"optional\": true,\n          \"widgetExtensions\": [\n            \"AudioRecorder\"\n          ]\n        },\n        {\n          \"name\": \"match\",\n          \"type\": \"image\",\n          \"label\": \"Matching Image\",\n          \"importance\": \"low\",\n          \"optional\": true,\n          \"description\": \"An optional image to match against instead of using two cards with the same image.\",\n          \"ratio\": 1\n        },\n        {\n          \"name\": \"matchAlt\",\n          \"type\": \"text\",\n          \"label\": \"Alternative text for Matching Image\",\n          \"importance\": \"low\",\n          \"optional\": true,\n          \"description\": \"Describe what can be seen in the photo. The text is read by text-to-speech tools needed by visually impaired users.\"\n        },\n        {\n          \"name\": \"matchAudio\",\n          \"type\": \"audio\",\n          \"importance\": \"low\",\n          \"label\": \"Matching Audio Track\",\n          \"description\": \"An optional sound that plays when the second card is turned.\",\n          \"optional\": true,\n          \"widgetExtensions\": [\n            \"AudioRecorder\"\n          ]\n        },\n        {\n          \"name\": \"description\",\n          \"type\": \"text\",\n          \"label\": \"Description\",\n          \"importance\": \"low\",\n          \"maxLength\": 150,\n          \"optional\": true,\n          \"description\": \"An optional short text that will pop up once the two matching cards are found.\"\n        }\n      ]\n    }\n  },\n  {\n    \"name\": \"behaviour\",\n    \"type\": \"group\",\n    \"label\": \"Behavioural settings\",\n    \"importance\": \"low\",\n    \"description\": \"These options will let you control how the game behaves.\",\n    \"optional\": true,\n    \"fields\": [\n      {\n        \"name\": \"useGrid\",\n        \"type\": \"boolean\",\n        \"label\": \"Position the cards in a square\",\n        \"description\": \"Will try to match the number of columns and rows when laying out the cards. Afterward, the cards will be scaled to fit the container.\",\n        \"importance\": \"low\",\n        \"default\": true\n      },\n      {\n        \"name\": \"numCardsToUse\",\n        \"type\": \"number\",\n        \"label\": \"Number of cards to use\",\n        \"description\": \"Setting this to a number greater than 2 will make the game pick random cards from the list of cards.\",\n        \"importance\": \"low\",\n        \"optional\": true,\n        \"min\": 2\n      },\n      {\n        \"name\": \"allowRetry\",\n        \"type\": \"boolean\",\n        \"label\": \"Add button for retrying when the game is over\",\n        \"importance\": \"low\",\n        \"default\": true\n      }\n    ]\n  },\n  {\n    \"name\": \"lookNFeel\",\n    \"type\": \"group\",\n    \"label\": \"Look and feel\",\n    \"importance\": \"low\",\n    \"description\": \"Control the visuals of the game.\",\n    \"optional\": true,\n    \"fields\": [\n      {\n        \"name\": \"themeColor\",\n        \"type\": \"text\",\n        \"label\": \"Theme Color\",\n        \"importance\": \"low\",\n        \"description\": \"Choose a color to create a theme for your card game.\",\n        \"optional\": true,\n        \"default\": \"#707070\",\n        \"widget\": \"colorSelector\",\n        \"spectrum\": {\n          \"showInput\": true\n        }\n      },\n      {\n        \"name\": \"cardBack\",\n        \"type\": \"image\",\n        \"label\": \"Card Back\",\n        \"importance\": \"low\",\n        \"optional\": true,\n        \"description\": \"Use a custom back for your cards.\",\n        \"ratio\": 1\n      }\n    ]\n  },\n  {\n    \"label\": \"Localization\",\n    \"importance\": \"low\",\n    \"name\": \"l10n\",\n    \"type\": \"group\",\n    \"common\": true,\n    \"fields\": [\n      {\n        \"label\": \"Card turns text\",\n        \"importance\": \"low\",\n        \"name\": \"cardTurns\",\n        \"type\": \"text\",\n        \"default\": \"Card turns\"\n      },\n      {\n        \"label\": \"Time spent text\",\n        \"importance\": \"low\",\n        \"name\": \"timeSpent\",\n        \"type\": \"text\",\n        \"default\": \"Time spent\"\n      },\n      {\n        \"label\": \"Feedback text\",\n        \"importance\": \"low\",\n        \"name\": \"feedback\",\n        \"type\": \"text\",\n        \"default\": \"Good work!\"\n      },\n      {\n        \"label\": \"Try again button text\",\n        \"importance\": \"low\",\n        \"name\": \"tryAgain\",\n        \"type\": \"text\",\n        \"default\": \"Reset\"\n      },\n      {\n        \"label\": \"Close button label\",\n        \"importance\": \"low\",\n        \"name\": \"closeLabel\",\n        \"type\": \"text\",\n        \"default\": \"Close\"\n      },\n      {\n        \"label\": \"Game label\",\n        \"importance\": \"low\",\n        \"name\": \"label\",\n        \"type\": \"text\",\n        \"default\": \"Memory Game.Â Find the matching cards.\"\n      },\n      {\n        \"label\": \"Game instructions\",\n        \"importance\": \"low\",\n        \"name\": \"label\",\n        \"type\": \"text\",\n        \"default\": \"Use arrow keys left and right to navigate cards. Use space or enter key to turn card.\"\n      },\n      {\n        \"label\": \"Game finished label\",\n        \"importance\": \"low\",\n        \"name\": \"done\",\n        \"type\": \"text\",\n        \"default\": \"All of the cards have been found.\"\n      },\n      {\n        \"label\": \"Card indexing label\",\n        \"description\": \"%num and %total are placeholders and will be replaced with the respective values for the card.\",\n        \"importance\": \"low\",\n        \"name\": \"cardPrefix\",\n        \"type\": \"text\",\n        \"default\": \"Card %num of %total:\"\n      },\n      {\n        \"label\": \"Card unturned label\",\n        \"importance\": \"low\",\n        \"name\": \"cardUnturned\",\n        \"type\": \"text\",\n        \"default\": \"Unturned. Click to turn.\"\n      },\n      {\n        \"label\": \"Card turned label\",\n        \"importance\": \"low\",\n        \"name\": \"cardTurned\",\n        \"type\": \"text\",\n        \"default\": \"Turned.\"\n      },\n      {\n        \"label\": \"Card matched label\",\n        \"importance\": \"low\",\n        \"name\": \"cardMatched\",\n        \"type\": \"text\",\n        \"default\": \"Match found.\"\n      },\n      {\n        \"label\": \"Card matched announcement\",\n        \"importance\": \"low\",\n        \"name\": \"cardMatchedA11y\",\n        \"type\": \"text\",\n        \"default\": \"Your cards match!\"\n      },\n      {\n        \"label\": \"Card not matched announcement\",\n        \"importance\": \"low\",\n        \"name\": \"cardNotMatchedA11y\",\n        \"type\": \"text\",\n        \"default\": \"Your chosen cards do not match. Turn other cards to try again.\"\n      }\n    ]\n  }\n]\n', NULL, NULL, NULL, NULL, NULL, NULL, 1),
(44, 'H5P.MultiChoice', 'Multiple Choice', 1, 16, 14, 1, 0, 'iframe', 'js/multichoice.js', 'css/multichoice.css', '', '[\n  {\n    \"name\": \"media\",\n    \"type\": \"group\",\n    \"label\": \"Media\",\n    \"importance\": \"medium\",\n    \"fields\": [\n      {\n        \"name\": \"type\",\n        \"type\": \"library\",\n        \"label\": \"Type\",\n        \"importance\": \"medium\",\n        \"options\": [\n          \"H5P.Image 1.1\",\n          \"H5P.Video 1.6\",\n          \"H5P.Audio 1.5\"\n        ],\n        \"optional\": true,\n        \"description\": \"Optional media to display above the question.\"\n      },\n      {\n        \"name\": \"disableImageZooming\",\n        \"type\": \"boolean\",\n        \"label\": \"Disable image zooming\",\n        \"importance\": \"low\",\n        \"default\": false,\n        \"optional\": true,\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"type\",\n              \"equals\": \"H5P.Image 1.1\"\n            }\n          ]\n        }\n      }\n    ]\n  },\n  {\n    \"name\": \"question\",\n    \"type\": \"text\",\n    \"importance\": \"medium\",\n    \"widget\": \"html\",\n    \"label\": \"Question\",\n    \"enterMode\": \"p\",\n    \"tags\": [\n      \"strong\",\n      \"em\",\n      \"sub\",\n      \"sup\",\n      \"h2\",\n      \"h3\",\n      \"pre\",\n      \"code\"\n    ]\n  },\n  {\n    \"name\": \"answers\",\n    \"type\": \"list\",\n    \"importance\": \"high\",\n    \"label\": \"Available options\",\n    \"entity\": \"option\",\n    \"min\": 1,\n    \"defaultNum\": 2,\n    \"field\": {\n      \"name\": \"answer\",\n      \"type\": \"group\",\n      \"label\": \"Option\",\n      \"importance\": \"high\",\n      \"fields\": [\n        {\n          \"name\": \"text\",\n          \"type\": \"text\",\n          \"importance\": \"medium\",\n          \"widget\": \"html\",\n          \"label\": \"Text\",\n          \"tags\": [\n            \"strong\",\n            \"em\",\n            \"sub\",\n            \"sup\",\n            \"code\"\n          ]\n        },\n        {\n          \"name\": \"correct\",\n          \"type\": \"boolean\",\n          \"label\": \"Correct\",\n          \"importance\": \"low\"\n        },\n        {\n          \"name\": \"tipsAndFeedback\",\n          \"type\": \"group\",\n          \"label\": \"Tips and feedback\",\n          \"importance\": \"low\",\n          \"optional\": true,\n          \"fields\": [\n            {\n              \"name\": \"tip\",\n              \"type\": \"text\",\n              \"widget\": \"html\",\n              \"label\": \"Tip text\",\n              \"importance\": \"low\",\n              \"description\": \"Hint for the user. This will appear before user checks his answer/answers.\",\n              \"optional\": true,\n              \"tags\": [\n                \"p\",\n                \"br\",\n                \"strong\",\n                \"em\",\n                \"a\",\n                \"code\"\n              ]\n            },\n            {\n              \"name\": \"chosenFeedback\",\n              \"type\": \"text\",\n              \"widget\": \"html\",\n              \"label\": \"Message displayed if answer is selected\",\n              \"importance\": \"low\",\n              \"description\": \"Message will appear below the answer on \\\"check\\\" if this answer is selected.\",\n              \"optional\": true,\n              \"tags\": [\n                \"strong\",\n                \"em\",\n                \"sub\",\n                \"sup\",\n                \"a\",\n                \"code\"\n              ]\n            },\n            {\n              \"name\": \"notChosenFeedback\",\n              \"type\": \"text\",\n              \"widget\": \"html\",\n              \"label\": \"Message displayed if answer is not selected\",\n              \"importance\": \"low\",\n              \"description\": \"Message will appear below the answer on \\\"check\\\" if this answer is not selected.\",\n              \"optional\": true,\n              \"tags\": [\n                \"strong\",\n                \"em\",\n                \"sub\",\n                \"sup\",\n                \"a\",\n                \"code\"\n              ]\n            }\n          ]\n        }\n      ]\n    }\n  },\n  {\n    \"name\": \"overallFeedback\",\n    \"type\": \"group\",\n    \"label\": \"Overall Feedback\",\n    \"importance\": \"low\",\n    \"expanded\": true,\n    \"fields\": [\n      {\n        \"name\": \"overallFeedback\",\n        \"type\": \"list\",\n        \"widgets\": [\n          {\n            \"name\": \"RangeList\",\n            \"label\": \"Default\"\n          }\n        ],\n        \"importance\": \"high\",\n        \"label\": \"Define custom feedback for any score range\",\n        \"description\": \"Click the \\\"Add range\\\" button to add as many ranges as you need. Example: 0-20% Bad score, 21-91% Average Score, 91-100% Great Score!\",\n        \"entity\": \"range\",\n        \"min\": 1,\n        \"defaultNum\": 1,\n        \"optional\": true,\n        \"field\": {\n          \"name\": \"overallFeedback\",\n          \"type\": \"group\",\n          \"importance\": \"low\",\n          \"fields\": [\n            {\n              \"name\": \"from\",\n              \"type\": \"number\",\n              \"label\": \"Score Range\",\n              \"min\": 0,\n              \"max\": 100,\n              \"default\": 0,\n              \"unit\": \"%\"\n            },\n            {\n              \"name\": \"to\",\n              \"type\": \"number\",\n              \"min\": 0,\n              \"max\": 100,\n              \"default\": 100,\n              \"unit\": \"%\"\n            },\n            {\n              \"name\": \"feedback\",\n              \"type\": \"text\",\n              \"label\": \"Feedback for defined score range\",\n              \"importance\": \"low\",\n              \"placeholder\": \"Fill in the feedback\",\n              \"optional\": true\n            }\n          ]\n        }\n      }\n    ]\n  },\n  {\n    \"name\": \"UI\",\n    \"type\": \"group\",\n    \"label\": \"User interface translations for multichoice\",\n    \"importance\": \"low\",\n    \"common\": true,\n    \"fields\": [\n      {\n        \"name\": \"checkAnswerButton\",\n        \"type\": \"text\",\n        \"label\": \"Check answer button label\",\n        \"importance\": \"low\",\n        \"default\": \"Check\"\n      },\n      {\n        \"name\": \"submitAnswerButton\",\n        \"type\": \"text\",\n        \"label\": \"Submit answer button label\",\n        \"importance\": \"low\",\n        \"default\": \"Submit\"\n      },\n      {\n        \"name\": \"showSolutionButton\",\n        \"type\": \"text\",\n        \"label\": \"Show solution button label\",\n        \"importance\": \"low\",\n        \"default\": \"Show solution\"\n      },\n      {\n        \"name\": \"tryAgainButton\",\n        \"type\": \"text\",\n        \"label\": \"Retry button label\",\n        \"importance\": \"low\",\n        \"default\": \"Retry\",\n        \"optional\": true\n      },\n      {\n        \"name\": \"tipsLabel\",\n        \"type\": \"text\",\n        \"label\": \"Tip label\",\n        \"importance\": \"low\",\n        \"default\": \"Show tip\",\n        \"optional\": true\n      },\n      {\n        \"name\": \"scoreBarLabel\",\n        \"type\": \"text\",\n        \"label\": \"Textual representation of the score bar for those using a readspeaker\",\n        \"description\": \"Available variables are :num and :total\",\n        \"importance\": \"low\",\n        \"default\": \"You got :num out of :total points\",\n        \"optional\": true\n      },\n      {\n        \"name\": \"tipAvailable\",\n        \"type\": \"text\",\n        \"label\": \"Tip Available (not displayed)\",\n        \"importance\": \"low\",\n        \"default\": \"Tip available\",\n        \"description\": \"Accessibility text used for readspeakers\",\n        \"optional\": true\n      },\n      {\n        \"name\": \"feedbackAvailable\",\n        \"type\": \"text\",\n        \"label\": \"Feedback Available (not displayed)\",\n        \"importance\": \"low\",\n        \"default\": \"Feedback available\",\n        \"description\": \"Accessibility text used for readspeakers\",\n        \"optional\": true\n      },\n      {\n        \"name\": \"readFeedback\",\n        \"type\": \"text\",\n        \"label\": \"Read Feedback (not displayed)\",\n        \"importance\": \"low\",\n        \"default\": \"Read feedback\",\n        \"description\": \"Accessibility text used for readspeakers\",\n        \"optional\": true,\n        \"deprecated\": true\n      },\n      {\n        \"name\": \"wrongAnswer\",\n        \"type\": \"text\",\n        \"label\": \"Wrong Answer (not displayed)\",\n        \"importance\": \"low\",\n        \"default\": \"Wrong answer\",\n        \"description\": \"Accessibility text used for readspeakers\",\n        \"optional\": true,\n        \"deprecated\": true\n      },\n      {\n        \"name\": \"correctAnswer\",\n        \"type\": \"text\",\n        \"label\": \"Correct Answer (not displayed)\",\n        \"importance\": \"low\",\n        \"default\": \"Correct answer\",\n        \"description\": \"Accessibility text used for readspeakers\",\n        \"optional\": true\n      },\n      {\n        \"name\": \"shouldCheck\",\n        \"type\": \"text\",\n        \"label\": \"Option should have been checked\",\n        \"importance\": \"low\",\n        \"default\": \"Should have been checked\",\n        \"optional\": true\n      },\n      {\n        \"name\": \"shouldNotCheck\",\n        \"type\": \"text\",\n        \"label\": \"Option should not have been checked\",\n        \"importance\": \"low\",\n        \"default\": \"Should not have been checked\",\n        \"optional\": true\n      },\n      {\n        \"label\": \"Text for \\\"Requires answer\\\" message\",\n        \"importance\": \"low\",\n        \"name\": \"noInput\",\n        \"type\": \"text\",\n        \"default\": \"Please answer before viewing the solution\",\n        \"optional\": true\n      },\n      {\n        \"name\": \"a11yCheck\",\n        \"type\": \"text\",\n        \"label\": \"Assistive technology description for \\\"Check\\\" button\",\n        \"default\": \"Check the answers. The responses will be marked as correct, incorrect, or unanswered.\",\n        \"importance\": \"low\",\n        \"common\": true\n      },\n      {\n        \"name\": \"a11yShowSolution\",\n        \"type\": \"text\",\n        \"label\": \"Assistive technology description for \\\"Show Solution\\\" button\",\n        \"default\": \"Show the solution. The task will be marked with its correct solution.\",\n        \"importance\": \"low\",\n        \"common\": true\n      },\n      {\n        \"name\": \"a11yRetry\",\n        \"type\": \"text\",\n        \"label\": \"Assistive technology description for \\\"Retry\\\" button\",\n        \"default\": \"Retry the task. Reset all responses and start the task over again.\",\n        \"importance\": \"low\",\n        \"common\": true\n      }\n    ]\n  },\n  {\n    \"name\": \"behaviour\",\n    \"type\": \"group\",\n    \"label\": \"Behavioural settings\",\n    \"importance\": \"low\",\n    \"description\": \"These options will let you control how the task behaves.\",\n    \"optional\": true,\n    \"fields\": [\n      {\n        \"name\": \"enableRetry\",\n        \"type\": \"boolean\",\n        \"label\": \"Enable \\\"Retry\\\" button\",\n        \"importance\": \"low\",\n        \"default\": true,\n        \"optional\": true\n      },\n      {\n        \"name\": \"enableSolutionsButton\",\n        \"type\": \"boolean\",\n        \"label\": \"Enable \\\"Show Solution\\\" button\",\n        \"importance\": \"low\",\n        \"default\": true,\n        \"optional\": true\n      },\n      {\n        \"name\": \"enableCheckButton\",\n        \"type\": \"boolean\",\n        \"label\": \"Enable \\\"Check\\\" button\",\n        \"widget\": \"none\",\n        \"importance\": \"low\",\n        \"default\": true,\n        \"optional\": true\n      },\n      {\n        \"name\": \"type\",\n        \"type\": \"select\",\n        \"label\": \"Question Type\",\n        \"importance\": \"low\",\n        \"description\": \"Select the look and behaviour of the question.\",\n        \"default\": \"auto\",\n        \"options\": [\n          {\n            \"value\": \"auto\",\n            \"label\": \"Automatic\"\n          },\n          {\n            \"value\": \"multi\",\n            \"label\": \"Multiple Choice (Checkboxes)\"\n          },\n          {\n            \"value\": \"single\",\n            \"label\": \"Single Choice (Radio Buttons)\"\n          }\n        ]\n      },\n      {\n        \"name\": \"singlePoint\",\n        \"type\": \"boolean\",\n        \"label\": \"Give one point for the whole task\",\n        \"importance\": \"low\",\n        \"description\": \"Enable to give a total of one point for multiple correct answers. This will not be an option in \\\"Single answer\\\" mode.\",\n        \"default\": false\n      },\n      {\n        \"name\": \"randomAnswers\",\n        \"type\": \"boolean\",\n        \"label\": \"Randomize answers\",\n        \"importance\": \"low\",\n        \"description\": \"Enable to randomize the order of the answers on display.\",\n        \"default\": true\n      },\n      {\n        \"label\": \"Require answer before the solution can be viewed\",\n        \"importance\": \"low\",\n        \"name\": \"showSolutionsRequiresInput\",\n        \"type\": \"boolean\",\n        \"default\": true,\n        \"optional\": true\n      },\n      {\n        \"label\": \"Show confirmation dialog on \\\"Check\\\"\",\n        \"importance\": \"low\",\n        \"name\": \"confirmCheckDialog\",\n        \"type\": \"boolean\",\n        \"default\": false\n      },\n      {\n        \"label\": \"Show confirmation dialog on \\\"Retry\\\"\",\n        \"importance\": \"low\",\n        \"name\": \"confirmRetryDialog\",\n        \"type\": \"boolean\",\n        \"default\": false\n      },\n      {\n        \"label\": \"Automatically check answers\",\n        \"importance\": \"low\",\n        \"name\": \"autoCheck\",\n        \"type\": \"boolean\",\n        \"default\": false,\n        \"description\": \"Enabling this option will make accessibility suffer, make sure you know what you\'re doing.\"\n      },\n      {\n        \"label\": \"Pass percentage\",\n        \"name\": \"passPercentage\",\n        \"type\": \"number\",\n        \"description\": \"This setting often won\'t have any effect. It is the percentage of the total score required for getting 1 point when one point for the entire task is enabled, and for getting result.success in xAPI statements.\",\n        \"min\": 0,\n        \"max\": 100,\n        \"step\": 1,\n        \"default\": 100\n      },\n      {\n        \"name\": \"showScorePoints\",\n        \"type\": \"boolean\",\n        \"label\": \"Show score points\",\n        \"description\": \"Show points earned for each answer. This will not be an option in \'Single answer\' mode or if \'Give one point for the whole task\' option is enabled.\",\n        \"importance\": \"low\",\n        \"default\": true\n      }\n    ]\n  },\n  {\n    \"label\": \"Check confirmation dialog\",\n    \"importance\": \"low\",\n    \"name\": \"confirmCheck\",\n    \"type\": \"group\",\n    \"common\": true,\n    \"fields\": [\n      {\n        \"label\": \"Header text\",\n        \"importance\": \"low\",\n        \"name\": \"header\",\n        \"type\": \"text\",\n        \"default\": \"Finish ?\"\n      },\n      {\n        \"label\": \"Body text\",\n        \"importance\": \"low\",\n        \"name\": \"body\",\n        \"type\": \"text\",\n        \"default\": \"Are you sure you wish to finish ?\",\n        \"widget\": \"html\",\n        \"enterMode\": \"p\",\n        \"tags\": [\n          \"strong\",\n          \"em\",\n          \"del\",\n          \"u\",\n          \"code\"\n        ]\n      },\n      {\n        \"label\": \"Cancel button label\",\n        \"importance\": \"low\",\n        \"name\": \"cancelLabel\",\n        \"type\": \"text\",\n        \"default\": \"Cancel\"\n      },\n      {\n        \"label\": \"Confirm button label\",\n        \"importance\": \"low\",\n        \"name\": \"confirmLabel\",\n        \"type\": \"text\",\n        \"default\": \"Finish\"\n      }\n    ]\n  },\n  {\n    \"label\": \"Retry confirmation dialog\",\n    \"importance\": \"low\",\n    \"name\": \"confirmRetry\",\n    \"type\": \"group\",\n    \"common\": true,\n    \"fields\": [\n      {\n        \"label\": \"Header text\",\n        \"importance\": \"low\",\n        \"name\": \"header\",\n        \"type\": \"text\",\n        \"default\": \"Retry ?\"\n      },\n      {\n        \"label\": \"Body text\",\n        \"importance\": \"low\",\n        \"name\": \"body\",\n        \"type\": \"text\",\n        \"default\": \"Are you sure you wish to retry ?\",\n        \"widget\": \"html\",\n        \"enterMode\": \"p\",\n        \"tags\": [\n          \"strong\",\n          \"em\",\n          \"del\",\n          \"u\",\n          \"code\"\n        ]\n      },\n      {\n        \"label\": \"Cancel button label\",\n        \"importance\": \"low\",\n        \"name\": \"cancelLabel\",\n        \"type\": \"text\",\n        \"default\": \"Cancel\"\n      },\n      {\n        \"label\": \"Confirm button label\",\n        \"importance\": \"low\",\n        \"name\": \"confirmLabel\",\n        \"type\": \"text\",\n        \"default\": \"Confirm\"\n      }\n    ]\n  }\n]\n', NULL, 1, 27, NULL, NULL, NULL, 1);
