(45, 'H5P.MultiMediaChoice', 'Multimedia Choice', 0, 3, 44, 1, 0, 'iframe', 'dist/h5p-multi-media-choice.js', 'dist/h5p-multi-media-choice.css', '', '[\n  {\n    \"name\": \"media\",\n    \"type\": \"group\",\n    \"label\": \"Media\",\n    \"importance\": \"medium\",\n    \"fields\": [\n      {\n        \"name\": \"type\",\n        \"type\": \"library\",\n        \"label\": \"Type\",\n        \"importance\": \"medium\",\n        \"options\": [\n          \"H5P.Image 1.1\",\n          \"H5P.Video 1.6\",\n          \"H5P.Audio 1.5\"\n        ],\n        \"optional\": true,\n        \"description\": \"Optional media to display above the question.\"\n      },\n      {\n        \"name\": \"disableImageZooming\",\n        \"type\": \"boolean\",\n        \"label\": \"Disable image zooming\",\n        \"importance\": \"low\",\n        \"default\": false,\n        \"optional\": true,\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"type\",\n              \"equals\": \"H5P.Image 1.1\"\n            }\n          ]\n        }\n      }\n    ]\n  },\n  {\n    \"name\": \"question\",\n    \"type\": \"text\",\n    \"importance\": \"high\",\n    \"widget\": \"html\",\n    \"label\": \"Question\",\n    \"enterMode\": \"p\",\n    \"tags\": [\n      \"strong\",\n      \"em\",\n      \"sub\",\n      \"sup\",\n      \"h2\",\n      \"h3\",\n      \"pre\",\n      \"code\"\n    ]\n  },\n  {\n    \"name\": \"options\",\n    \"type\": \"list\",\n    \"importance\": \"high\",\n    \"label\": \"Available options\",\n    \"entity\": \"option\",\n    \"min\": 2,\n    \"max\": 20,\n    \"defaultNum\": 2,\n    \"field\": {\n      \"name\": \"option\",\n      \"type\": \"group\",\n      \"label\": \"Option\",\n      \"importance\": \"high\",\n      \"fields\": [\n        {\n          \"name\": \"media\",\n          \"type\": \"library\",\n          \"label\": \"Media\",\n          \"optional\": false,\n          \"description\": \"Media to display as a choice.\",\n          \"options\": [\n            \"H5P.Image 1.1\",\n            \"H5P.Video 1.6\",\n            \"H5P.Audio 1.5\"\n          ]\n        },\n        {\n          \"name\": \"poster\",\n          \"type\": \"image\",\n          \"label\": \"Poster image\",\n          \"importance\": \"low\",\n          \"widget\": \"showWhen\",\n          \"showWhen\": {\n            \"rules\": [\n              {\n                \"field\": \"media\",\n                \"equals\": \"H5P.Audio 1.5\"\n              }\n            ]\n          }\n        },\n        {\n          \"name\": \"correct\",\n          \"type\": \"boolean\",\n          \"label\": \"Correct\",\n          \"importance\": \"low\"\n        }\n      ]\n    }\n  },\n  {\n    \"name\": \"overallFeedback\",\n    \"type\": \"group\",\n    \"label\": \"Overall Feedback\",\n    \"importance\": \"low\",\n    \"expanded\": true,\n    \"fields\": [\n      {\n        \"name\": \"overallFeedback\",\n        \"type\": \"list\",\n        \"widgets\": [\n          {\n            \"name\": \"RangeList\",\n            \"label\": \"Default\"\n          }\n        ],\n        \"importance\": \"high\",\n        \"label\": \"Define custom feedback for any score range\",\n        \"description\": \"Click the \\\"Add range\\\" button to add as many ranges as you need. Example: 0-20% Bad score, 21-91% Average Score, 91-100% Great Score!\",\n        \"entity\": \"range\",\n        \"min\": 1,\n        \"defaultNum\": 1,\n        \"optional\": true,\n        \"field\": {\n          \"name\": \"overallFeedback\",\n          \"type\": \"group\",\n          \"importance\": \"low\",\n          \"fields\": [\n            {\n              \"name\": \"from\",\n              \"type\": \"number\",\n              \"label\": \"Score Range\",\n              \"min\": 0,\n              \"max\": 100,\n              \"default\": 0,\n              \"unit\": \"%\"\n            },\n            {\n              \"name\": \"to\",\n              \"type\": \"number\",\n              \"min\": 0,\n              \"max\": 100,\n              \"default\": 100,\n              \"unit\": \"%\"\n            },\n            {\n              \"name\": \"feedback\",\n              \"type\": \"text\",\n              \"label\": \"Feedback for defined score range\",\n              \"importance\": \"low\",\n              \"placeholder\": \"Fill in the feedback\",\n              \"optional\": true\n            }\n          ]\n        }\n      }\n    ]\n  },\n  {\n    \"name\": \"behaviour\",\n    \"type\": \"group\",\n    \"label\": \"Behavioural settings\",\n    \"importance\": \"low\",\n    \"description\": \"These options will let you control how the task behaves.\",\n    \"fields\": [\n      {\n        \"name\": \"enableRetry\",\n        \"label\": \"Enable \\\"Retry\\\" button\",\n        \"type\": \"boolean\",\n        \"importance\": \"low\",\n        \"default\": true,\n        \"optional\": true\n      },\n      {\n        \"name\": \"enableSolutionsButton\",\n        \"label\": \"Enable \\\"Show Solution\\\" button\",\n        \"type\": \"boolean\",\n        \"importance\": \"low\",\n        \"default\": true,\n        \"optional\": true\n      },\n      {\n        \"name\": \"confirmCheckDialog\",\n        \"label\": \"Show confirmation dialog on \\\"Check\\\"\",\n        \"importance\": \"low\",\n        \"type\": \"boolean\",\n        \"default\": false,\n        \"optional\": true\n      },\n      {\n        \"name\": \"confirmRetryDialog\",\n        \"label\": \"Show confirmation dialog on \\\"Retry\\\"\",\n        \"importance\": \"low\",\n        \"type\": \"boolean\",\n        \"default\": false,\n        \"optional\": true\n      },\n      {\n        \"name\": \"singlePoint\",\n        \"type\": \"boolean\",\n        \"label\": \"Give one point for the whole question\",\n        \"importance\": \"low\",\n        \"description\": \"Awards one point to the question if the percentage score is higher than the pass percentage\",\n        \"default\": false\n      },\n      {\n        \"label\": \"Require answer before the solution can be viewed\",\n        \"importance\": \"low\",\n        \"name\": \"showSolutionsRequiresInput\",\n        \"type\": \"boolean\",\n        \"default\": true,\n        \"optional\": true\n      },\n      {\n        \"name\": \"questionType\",\n        \"type\": \"select\",\n        \"label\": \"Question Type\",\n        \"importance\": \"low\",\n        \"description\": \"Select the look and behaviour of the question.\",\n        \"default\": \"auto\",\n        \"options\": [\n          {\n            \"value\": \"auto\",\n            \"label\": \"Automatic\"\n          },\n          {\n            \"value\": \"multi\",\n            \"label\": \"Multiple Choice (Checkboxes)\"\n          },\n          {\n            \"value\": \"single\",\n            \"label\": \"Single Choice (Radio Buttons)\"\n          }\n        ]\n      },\n      {\n        \"name\": \"aspectRatio\",\n        \"type\": \"select\",\n        \"label\": \"Aspect ratio\",\n        \"importance\": \"low\",\n        \"description\": \"Select the aspect ratio of the alternatives\",\n        \"default\": \"auto\",\n        \"options\": [\n          {\n            \"value\": \"auto\",\n            \"label\": \"Automatic\"\n          },\n          {\n            \"value\": \"16to9\",\n            \"label\": \"16:9\"\n          },\n          {\n            \"value\": \"4to3\",\n            \"label\": \"4:3\"\n          },\n          {\n            \"value\": \"3to2\",\n            \"label\": \"3:2\"\n          },\n          {\n            \"value\": \"1to1\",\n            \"label\": \"1:1\"\n          }\n        ]\n      },\n      {\n        \"name\": \"maxAlternativesPerRow\",\n        \"type\": \"select\",\n        \"label\": \"Maximum alternatives per row\",\n        \"description\": \"Set the maximum number of alternatives per row to ensure the questions look alright.\",\n        \"default\": \"4\",\n        \"options\": [\n          {\n            \"value\": \"1\",\n            \"label\": \"1\"\n          },\n          {\n            \"value\": \"2\",\n            \"label\": \"2\"\n          },\n          {\n            \"value\": \"3\",\n            \"label\": \"3\"\n          },\n          {\n            \"value\": \"4\",\n            \"label\": \"4\"\n          }\n        ]\n      },\n      {\n        \"label\": \"Pass percentage\",\n        \"name\": \"passPercentage\",\n        \"type\": \"number\",\n        \"description\": \"This setting often won\'t have any effect. It is the percentage of the total score required for getting 1 point when one point for the entire task is enabled, and for getting result.success in xAPI statements.\",\n        \"min\": 0,\n        \"max\": 100,\n        \"step\": 1,\n        \"default\": 100\n      }\n    ]\n  },\n  {\n    \"name\": \"l10n\",\n    \"type\": \"group\",\n    \"common\": true,\n    \"label\": \"User interface\",\n    \"importance\": \"low\",\n    \"fields\": [\n      {\n        \"name\": \"checkAnswerButtonText\",\n        \"type\": \"text\",\n        \"label\": \"Text for \\\"Check\\\" button\",\n        \"importance\": \"low\",\n        \"default\": \"Check\"\n      },\n      {\n        \"name\": \"submitAnswerButtonText\",\n        \"type\": \"text\",\n        \"label\": \"Text for \\\"Submit\\\" button\",\n        \"importance\": \"low\",\n        \"default\": \"Submit\"\n      },\n      {\n        \"name\": \"checkAnswer\",\n        \"type\": \"text\",\n        \"label\": \"Assistive technology description for \\\"Check\\\" button\",\n        \"importance\": \"low\",\n        \"default\": \"Check the answers. The responses will be marked as correct, incorrect, or unanswered.\"\n      },\n      {\n        \"name\": \"showSolutionButtonText\",\n        \"type\": \"text\",\n        \"label\": \"Text for \\\"Show solution\\\" button\",\n        \"importance\": \"low\",\n        \"default\": \"Show solution\"\n      },\n      {\n        \"name\": \"showSolution\",\n        \"type\": \"text\",\n        \"label\": \"Assistive technology description for \\\"Show Solution\\\" button\",\n        \"importance\": \"low\",\n        \"default\": \"Show the solution. The correct options will be marked.\"\n      },\n      {\n        \"name\": \"correctAnswer\",\n        \"type\": \"text\",\n        \"label\": \"Correct Answer (not displayed)\",\n        \"importance\": \"low\",\n        \"default\": \"Correct answer\"\n      },\n      {\n        \"name\": \"wrongAnswer\",\n        \"type\": \"text\",\n        \"label\": \"Wrong Answer (not displayed)\",\n        \"importance\": \"low\",\n        \"default\": \"Wrong answer\"\n      },\n      {\n        \"name\": \"shouldCheck\",\n        \"type\": \"text\",\n        \"label\": \"Option should have been checked\",\n        \"importance\": \"low\",\n        \"default\": \"Should have been checked\",\n        \"optional\": true\n      },\n      {\n        \"name\": \"shouldNotCheck\",\n        \"type\": \"text\",\n        \"label\": \"Option should not have been checked\",\n        \"importance\": \"low\",\n        \"default\": \"Should not have been checked\",\n        \"optional\": true\n      },\n      {\n        \"label\": \"Text for \\\"Requires answer\\\" message\",\n        \"importance\": \"low\",\n        \"name\": \"noAnswer\",\n        \"type\": \"text\",\n        \"default\": \"Please answer before viewing the solution\",\n        \"optional\": true\n      },\n      {\n        \"name\": \"retryText\",\n        \"type\": \"text\",\n        \"label\": \"Text for \\\"Retry\\\" button\",\n        \"importance\": \"low\",\n        \"default\": \"Retry\"\n      },\n      {\n        \"name\": \"retry\",\n        \"type\": \"text\",\n        \"label\": \"Assistive technology description for \\\"Retry\\\" button\",\n        \"importance\": \"low\",\n        \"default\": \"Retry the task. Reset all responses and start the task over again.\"\n      },\n      {\n        \"name\": \"result\",\n        \"type\": \"text\",\n        \"label\": \"Your result\",\n        \"description\": \":num and :total are variables and will be replaced by their respective values.\",\n        \"importance\": \"low\",\n        \"default\": \"You got :num out of :total points\"\n      },\n      {\n        \"label\": \"Check confirmation dialog\",\n        \"importance\": \"low\",\n        \"name\": \"confirmCheck\",\n        \"type\": \"group\",\n        \"common\": true,\n        \"fields\": [\n          {\n            \"label\": \"Header text\",\n            \"importance\": \"low\",\n            \"name\": \"header\",\n            \"type\": \"text\",\n            \"default\": \"Finish?\"\n          },\n          {\n            \"label\": \"Body text\",\n            \"importance\": \"low\",\n            \"name\": \"body\",\n            \"type\": \"text\",\n            \"default\": \"Are you sure you want to finish?\",\n            \"widget\": \"html\",\n            \"enterMode\": \"p\",\n            \"tags\": [\n              \"strong\",\n              \"em\",\n              \"del\",\n              \"u\",\n              \"code\"\n            ]\n          },\n          {\n            \"label\": \"Cancel button label\",\n            \"importance\": \"low\",\n            \"name\": \"cancelLabel\",\n            \"type\": \"text\",\n            \"default\": \"Cancel\"\n          },\n          {\n            \"label\": \"Confirm button label\",\n            \"importance\": \"low\",\n            \"name\": \"confirmLabel\",\n            \"type\": \"text\",\n            \"default\": \"Finish\"\n          }\n        ]\n      },\n      {\n        \"label\": \"Retry confirmation dialog\",\n        \"importance\": \"low\",\n        \"name\": \"confirmRetry\",\n        \"type\": \"group\",\n        \"common\": true,\n        \"fields\": [\n          {\n            \"label\": \"Header text\",\n            \"importance\": \"low\",\n            \"name\": \"header\",\n            \"type\": \"text\",\n            \"default\": \"Retry?\"\n          },\n          {\n            \"label\": \"Body text\",\n            \"importance\": \"low\",\n            \"name\": \"body\",\n            \"type\": \"text\",\n            \"default\": \"Are you sure you wish to retry?\",\n            \"widget\": \"html\",\n            \"enterMode\": \"p\",\n            \"tags\": [\n              \"strong\",\n              \"em\",\n              \"del\",\n              \"u\",\n              \"code\"\n            ]\n          },\n          {\n            \"label\": \"Cancel button label\",\n            \"importance\": \"low\",\n            \"name\": \"cancelLabel\",\n            \"type\": \"text\",\n            \"default\": \"Cancel\"\n          },\n          {\n            \"label\": \"Confirm button label\",\n            \"importance\": \"low\",\n            \"name\": \"confirmLabel\",\n            \"type\": \"text\",\n            \"default\": \"Retry\"\n          }\n        ]\n      },\n      {\n        \"label\": \"Text if alt text is missing for an image\",\n        \"importance\": \"low\",\n        \"name\": \"missingAltText\",\n        \"type\": \"text\",\n        \"default\": \"Alt text missing\"\n      },\n      {\n        \"label\": \"Close modal button label\",\n        \"importance\": \"low\",\n        \"name\": \"closeModalText\",\n        \"type\": \"text\",\n        \"default\": \"Close modal\"\n      }\n    ]\n  }\n]\n', NULL, 1, 27, NULL, NULL, NULL, 1),
