(49, 'H5P.Questionnaire', 'Questionnaire', 1, 3, 11, 1, 0, 'iframe', 'dist/dist.js', 'dist/styles.css', '', '[\n  {\n    \"name\": \"questionnaireElements\",\n    \"label\": \"Questionnaire elements\",\n    \"importance\": \"high\",\n    \"type\": \"list\",\n    \"widgets\": [\n      {\n        \"name\": \"VerticalTabs\",\n        \"label\": \"Default\",\n        \"importance\": \"high\"\n      }\n    ],\n    \"entity\": \"element\",\n    \"min\": 1,\n    \"defaultNum\": 1,\n    \"field\": {\n      \"name\": \"libraryGroup\",\n      \"label\": \"Choose library\",\n      \"importance\": \"high\",\n      \"type\": \"group\",\n      \"fields\": [\n        {\n          \"name\": \"library\",\n          \"type\": \"library\",\n          \"label\": \"Library\",\n          \"importance\": \"high\",\n          \"description\": \"Choose a library\",\n          \"options\": [\n            \"H5P.OpenEndedQuestion 1.0\",\n            \"H5P.SimpleMultiChoice 1.1\"\n          ]\n        },\n        {\n          \"name\": \"requiredField\",\n          \"type\": \"boolean\",\n          \"label\": \"Required field\",\n          \"importance\": \"low\",\n          \"default\": false\n        }\n      ]\n    }\n  },\n  {\n    \"name\": \"successScreenOptions\",\n    \"label\": \"Success screen options\",\n    \"importance\": \"low\",\n    \"type\": \"group\",\n    \"fields\": [\n      {\n        \"name\": \"enableSuccessScreen\",\n        \"label\": \"Enable success screen\",\n        \"importance\": \"low\",\n        \"type\": \"boolean\",\n        \"default\": true\n      },\n      {\n        \"name\": \"successScreenImage\",\n        \"label\": \"Add success screen image\",\n        \"importance\": \"low\",\n        \"type\": \"group\",\n        \"fields\": [\n          {\n            \"name\": \"successScreenImage\",\n            \"label\": \"Replace success icon with image\",\n            \"importance\": \"low\",\n            \"type\": \"library\",\n            \"optional\": true,\n            \"options\": [\n              \"H5P.Image 1.1\"\n            ]\n          }\n        ]\n      },\n      {\n        \"name\": \"successMessage\",\n        \"type\": \"text\",\n        \"label\": \"Text to display on submit\",\n        \"importance\": \"low\",\n        \"default\": \"You have completed the questionnaire.\"\n      }\n    ]\n  },\n  {\n    \"name\": \"uiElements\",\n    \"label\": \"UI Elements\",\n    \"importance\": \"low\",\n    \"type\": \"group\",\n    \"fields\": [\n      {\n        \"name\": \"buttonLabels\",\n        \"type\": \"group\",\n        \"label\": \"Button labels\",\n        \"importance\": \"low\",\n        \"fields\": [\n          {\n            \"name\": \"prevLabel\",\n            \"type\": \"text\",\n            \"label\": \"Previous button label\",\n            \"importance\": \"low\",\n            \"default\": \"Back\"\n          },\n          {\n            \"name\": \"continueLabel\",\n            \"type\": \"text\",\n            \"label\": \"Continue button label\",\n            \"importance\": \"low\",\n            \"default\": \"Continue\"\n          },\n          {\n            \"name\": \"nextLabel\",\n            \"type\": \"text\",\n            \"label\": \"Next button label\",\n            \"importance\": \"low\",\n            \"default\": \"Next\"\n          },\n          {\n            \"name\": \"submitLabel\",\n            \"type\": \"text\",\n            \"label\": \"Submit button label\",\n            \"importance\": \"low\",\n            \"default\": \"Submit\"\n          }\n        ]\n      },\n      {\n        \"name\": \"accessibility\",\n        \"type\": \"group\",\n        \"label\": \"Accessibility\",\n        \"importance\": \"low\",\n        \"fields\": [\n          {\n            \"name\": \"requiredTextExitLabel\",\n            \"type\": \"text\",\n            \"label\": \"Required message exit button label\",\n            \"importance\": \"low\",\n            \"default\": \"Close error