(50, 'H5P.QuestionSet', 'Question Set', 1, 20, 31, 1, 0, 'iframe', 'js/questionset.js', 'css/questionset.css', '', '[\n  {\n    \"name\": \"introPage\",\n    \"type\": \"group\",\n    \"label\": \"Quiz introduction\",\n    \"importance\": \"medium\",\n    \"fields\": [\n      {\n        \"name\": \"showIntroPage\",\n        \"type\": \"boolean\",\n        \"label\": \"Display introduction\",\n        \"importance\": \"low\"\n      },\n      {\n        \"name\": \"title\",\n        \"type\": \"text\",\n        \"label\": \"Title\",\n        \"importance\": \"high\",\n        \"optional\": true,\n        \"description\": \"This title will be displayed above the introduction text.\",\n        \"tags\": [\n          \"sub\",\n          \"sup\",\n          \"strong\",\n          \"em\",\n          \"code\"\n        ]\n      },\n      {\n        \"name\": \"introduction\",\n        \"type\": \"text\",\n        \"widget\": \"html\",\n        \"label\": \"Introduction text\",\n        \"importance\": \"medium\",\n        \"optional\": true,\n        \"description\": \"This text will be displayed before the quiz starts.\",\n        \"enterMode\": \"p\",\n        \"tags\": [\n          \"sub\",\n          \"sup\",\n          \"strong\",\n          \"em\",\n          \"p\",\n          \"code\"\n        ]\n      },\n      {\n        \"name\": \"startButtonText\",\n        \"type\": \"text\",\n        \"label\": \"Start button text\",\n        \"importance\": \"low\",\n        \"optional\": true,\n        \"default\": \"Start Quiz\"\n      },\n      {\n        \"name\": \"backgroundImage\",\n        \"type\": \"image\",\n        \"label\": \"Background image\",\n        \"importance\": \"low\",\n        \"optional\": true,\n        \"description\": \"An optional background image for the introduction.\"\n      }\n    ]\n  },\n  {\n    \"name\": \"backgroundImage\",\n    \"type\": \"image\",\n    \"label\": \"Background image\",\n    \"importance\": \"low\",\n    \"optional\": true,\n    \"description\": \"An optional background image for the Question set.\"\n  },\n  {\n    \"name\": \"progressType\",\n    \"type\": \"select\",\n    \"label\": \"Progress indicator\",\n    \"importance\": \"low\",\n    \"description\": \"Question set progress indicator style.\",\n    \"options\": [\n      {\n        \"value\": \"textual\",\n        \"label\": \"Textual\"\n      },\n      {\n        \"value\": \"dots\",\n        \"label\": \"Dots\"\n      }\n    ],\n    \"default\": \"dots\"\n  },\n  {\n    \"name\": \"passPercentage\",\n    \"type\": \"number\",\n    \"label\": \"Pass percentage\",\n    \"importance\": \"low\",\n    \"description\": \"Percentage of Total score required for passing the quiz.\",\n    \"min\": 0,\n    \"max\": 100,\n    \"step\": 1,\n    \"default\": 50\n  },\n  {\n    \"name\": \"questions\",\n    \"label\": \"Questions\",\n    \"importance\": \"high\",\n    \"type\": \"list\",\n    \"widgets\": [\n      {\n        \"name\": \"VerticalTabs\",\n        \"label\": \"Default\"\n      },\n      {\n        \"name\": \"QuestionSetTextualEditor\",\n        \"label\": \"Textual\"\n      }\n    ],\n    \"min\": 1,\n    \"entity\": \"question\",\n    \"field\": {\n      \"name\": \"question\",\n      \"type\": \"library\",\n      \"label\": \"Question type\",\n      \"importance\": \"high\",\n      \"description\": \"Library for this question.\",\n      \"options\": [\n        \"H5P.MultiChoice 1.16\",\n        \"H5P.DragQuestion 1.14\",\n        \"H5P.Blanks 1.14\",\n        \"H5P.MarkTheWords 1.11\",\n        \"H5P.DragText 1.10\",\n        \"H5P.TrueFalse 1.8\",\n        \"H5P.Essay 1.5\",\n        \"H5P.MultiMediaChoice 0.3\"\n      ]\n    }\n  },\n  {\n    \"name\": \"texts\",\n    \"type\": \"group\",\n    \"label\": \"Interface texts in quiz\",\n    \"importance\": \"low\",\n    \"common\": true,\n    \"fields\": [\n      {\n        \"name\": \"prevButton\",\n        \"type\": \"text\",\n        \"label\": \"Back button\",\n        \"importance\": \"low\",\n        \"default\": \"Previous question\"\n      },\n      {\n        \"name\": \"nextButton\",\n        \"type\": \"text\",\n        \"label\": \"Next button\",\n        \"importance\": \"low\",\n        \"default\": \"Next question\"\n      },\n      {\n        \"name\": \"finishButton\",\n        \"type\": \"text\",\n        \"label\": \"Finish button\",\n        \"importance\": \"low\",\n        \"default\": \"Finish\"\n      },\n      {\n        \"name\": \"submitButton\",\n        \"type\": \"text\",\n        \"label\": \"Submit button\",\n        \"importance\": \"low\",\n        \"default\": \"Submit\"\n      },\n      {\n        \"name\": \"textualProgress\",\n        \"type\": \"text\",\n        \"label\": \"Progress text\",\n        \"importance\": \"low\",\n        \"description\": \"Text used if textual progress is selected.\",\n        \"default\": \"Question: @current of @total questions\",\n        \"tags\": [\n          \"strong\",\n          \"em\",\n          \"code\"\n        ]\n      },\n      {\n        \"name\": \"jumpToQuestion\",\n        \"type\": \"text\",\n        \"label\": \"Label for jumping to a certain question\",\n        \"importance\": \"low\",\n        \"description\": \"You must use the placeholder \'%d\' instead of the question number, and %total instead of total amount of questions.\",\n        \"default\": \"Question %d of %total\"\n      },\n      {\n        \"name\": \"questionLabel\",\n        \"type\": \"text\",\n        \"label\": \"Copyright dialog question label\",\n        \"importance\": \"low\",\n        \"default\": \"Question\"\n      },\n      {\n        \"name\": \"readSpeakerProgress\",\n        \"type\": \"text\",\n        \"label\": \"Readspeaker progress\",\n        \"importance\": \"low\",\n        \"description\": \"May use @current and @total question variables\",\n        \"default\": \"Question @current of @total\"\n      },\n      {\n        \"name\": \"unansweredText\",\n        \"type\": \"text\",\n        \"label\": \"Unanswered question text\",\n        \"importance\": \"low\",\n        \"default\": \"Unanswered\"\n      },\n      {\n        \"name\": \"answeredText\",\n        \"type\": \"text\",\n        \"label\": \"Answered question text\",\n        \"importance\": \"low\",\n        \"default\": \"Answered\"\n      },\n      {\n        \"name\": \"currentQuestionText\",\n        \"type\": \"text\",\n        \"label\": \"Current question text\",\n        \"importance\": \"low\",\n        \"default\": \"Current question\"\n      },\n      {\n        \"name\": \"navigationLabel\",\n        \"type\": \"text\",\n        \"label\": \"Navigation label for readspeakers\",\n        \"importance\": \"low\",\n        \"default\": \"Questions\"\n      },\n      {\n        \"name\": \"questionSetInstruction\",\n        \"type\": \"text\",\n        \"label\": \"Instruction for navigating question set with screenreader\",\n        \"importance\": \"low\",\n        \"default\": \"Choose question to display\",\n        \"state\": \"new\"\n      }\n    ]\n  },\n  {\n    \"name\": \"disableBackwardsNavigation\",\n    \"type\": \"boolean\",\n    \"label\": \"Disable backwards navigation\",\n    \"importance\": \"low\",\n    \"description\": \"This option will only allow you to move forward in Question Set\",\n    \"optional\": true,\n    \"default\": false\n  },\n  {\n    \"name\": \"randomQuestions\",\n    \"type\": \"boolean\",\n    \"label\": \"Randomize questions\",\n    \"importance\": \"low\",\n    \"description\": \"Enable to randomize the order of questions on display.\",\n    \"default\": false\n  },\n  {\n    \"name\": \"poolSize\",\n    \"type\": \"number\",\n    \"min\": 1,\n    \"label\": \"Number of questions to be shown:\",\n    \"importance\": \"low\",\n    \"description\": \"Create a randomized batch of questions from the total.\",\n    \"optional\": true\n  },\n  {\n    \"name\": \"endGame\",\n    \"type\": \"group\",\n    \"label\": \"Quiz finished\",\n    \"importance\": \"medium\",\n    \"fields\": [\n      {\n        \"name\": \"showResultPage\",\n        \"type\": \"boolean\",\n        \"label\": \"Display results\",\n        \"importance\": \"low\",\n        \"default\": true\n      },\n      {\n        \"name\": \"showSolutionButton\",\n        \"type\": \"boolean\",\n        \"label\": \"Display solution button\",\n        \"default\": true\n      },\n      {\n        \"name\": \"showRetryButton\",\n        \"type\": \"boolean\",\n        \"label\": \"Display retry button\",\n        \"default\": true\n      },\n      {\n        \"name\": \"noResultMessage\",\n        \"type\": \"text\",\n        \"label\": \"No results message\",\n        \"importance\": \"low\",\n        \"description\": \"Text displayed on end page when \\\"Display results\\\" is disabled\",\n        \"default\": \"Finished\",\n        \"optional\": true\n      },\n      {\n        \"name\": \"message\",\n        \"type\": \"text\",\n        \"label\": \"Feedback heading\",\n        \"importance\": \"low\",\n        \"default\": \"Your result:\",\n        \"description\": \"This heading will be displayed at the end of the quiz when the user has answered all questions.\",\n        \"tags\": [\n          \"strong\",\n          \"em\",\n          \"code\"\n        ]\n      },\n      {\n        \"name\": \"scoreBarLabel\",\n        \"type\": \"text\",\n        \"label\": \"Score announcer\",\n        \"importance\": \"low\",\n        \"description\": \"This label will be used for announcing the final score to the user on the end screen\",\n        \"default\": \"You got @finals out of @totals points\"\n      },\n      {\n        \"name\": \"overallFeedback\",\n        \"type\": \"group\",\n        \"label\": \"Overall Feedback\",\n        \"importance\": \"low\",\n        \"expanded\": true,\n        \"fields\": [\n          {\n            \"name\": \"overallFeedback\",\n            \"type\": \"list\",\n            \"widgets\": [\n              {\n                \"name\": \"RangeList\",\n                \"label\": \"Default\"\n              }\n            ],\n            \"importance\": \"high\",\n            \"label\": \"Define custom feedback for any score range\",\n            \"description\": \"Click the \\\"Add range\\\" button to add as many ranges as you need. Example: 0-20% Bad score, 21-91% Average Score, 91-100% Great Score!\",\n            \"entity\": \"range\",\n            \"min\": 1,\n            \"defaultNum\": 1,\n            \"optional\": true,\n            \"field\": {\n              \"name\": \"overallFeedback\",\n              \"type\": \"group\",\n              \"importance\": \"low\",\n              \"fields\": [\n                {\n                  \"name\": \"from\",\n                  \"type\": \"number\",\n                  \"label\": \"Score Range\",\n                  \"min\": 0,\n                  \"max\": 100,\n                  \"default\": 0,\n                  \"unit\": \"%\"\n                },\n                {\n                  \"name\": \"to\",\n                  \"type\": \"number\",\n                  \"min\": 0,\n                  \"max\": 100,\n                  \"default\": 100,\n                  \"unit\": \"%\"\n                },\n                {\n                  \"name\": \"feedback\",\n                  \"type\": \"text\",\n                  \"label\": \"Feedback for defined score range\",\n                  \"importance\": \"low\",\n                  \"placeholder\": \"Fill in the feedback\",\n                  \"optional\": true\n                }\n              ]\n            }\n          }\n        ]\n      },\n      {\n        \"name\": \"oldFeedback\",\n        \"type\": \"group\",\n        \"label\": \"Old Feedback\",\n        \"importance\": \"low\",\n        \"deprecated\": true,\n        \"fields\": [\n          {\n            \"name\": \"successGreeting\",\n            \"type\": \"text\",\n            \"label\": \"Quiz passed greeting\",\n            \"importance\": \"low\",\n            \"optional\": true,\n            \"description\": \"This text will be displayed above the score if the user has successfully passed the quiz.\",\n            \"tags\": [\n              \"strong\",\n              \"em\",\n              \"code\"\n            ]\n          },\n          {\n            \"name\": \"successComment\",\n            \"type\": \"text\",\n            \"widget\": \"html\",\n            \"label\": \"Passed comment\",\n            \"importance\": \"low\",\n            \"optional\": true,\n            \"description\": \"This comment will be displayed after the score if the user has successfully passed the quiz.\",\n            \"tags\": [\n              \"sub\",\n              \"sup\",\n              \"strong\",\n              \"em\",\n              \"a\",\n              \"p\",\n              \"code\"\n            ]\n          },\n          {\n            \"name\": \"failGreeting\",\n            \"type\": \"text\",\n            \"label\": \"Quiz failed title\",\n            \"importance\": \"low\",\n            \"optional\": true,\n            \"description\": \"This text will be displayed above the score if the user has failed the quiz.\",\n            \"tags\": [\n              \"strong\",\n              \"em\",\n              \"code\"\n            ]\n          },\n          {\n            \"name\": \"failComment\",\n            \"type\": \"text\",\n            \"widget\": \"html\",\n            \"label\": \"Failed comment\",\n            \"importance\": \"low\",\n            \"optional\": true,\n            \"description\": \"This comment will be displayed after the score if the user has failed the quiz.\",\n            \"tags\": [\n              \"sub\",\n              \"sup\",\n              \"strong\",\n              \"em\",\n              \"a\",\n              \"p\",\n              \"code\"\n            ]\n          }\n        ]\n      },\n      {\n        \"name\": \"solutionButtonText\",\n        \"type\": \"text\",\n        \"label\": \"Solution button label\",\n        \"importance\": \"low\",\n        \"default\": \"Show solution\",\n        \"description\": \"Text for the solution button.\"\n      },\n      {\n        \"name\": \"retryButtonText\",\n        \"type\": \"text\",\n        \"label\": \"Retry button label\",\n        \"importance\": \"low\",\n        \"default\": \"Retry\",\n        \"description\": \"Text for the retry button.\"\n      },\n      {\n        \"name\": \"finishButtonText\",\n        \"type\": \"text\",\n        \"label\": \"Finish button text\",\n        \"importance\": \"low\",\n        \"default\": \"Finish\"\n      },\n      {\n        \"name\": \"submitButtonText\",\n        \"type\": \"text\",\n        \"label\": \"Submit button text\",\n        \"importance\": \"low\",\n        \"default\": \"Submit\"\n      },\n      {\n        \"name\": \"showAnimations\",\n        \"type\": \"boolean\",\n        \"label\": \"Display video before quiz results\",\n        \"importance\": \"low\"\n      },\n      {\n        \"name\": \"skippable\",\n        \"type\": \"boolean\",\n        \"label\": \"Enable skip video button\",\n        \"importance\": \"low\"\n      },\n      {\n        \"name\": \"skipButtonText\",\n        \"type\": \"text\",\n        \"label\": \"Skip video button label\",\n        \"importance\": \"low\",\n        \"default\": \"Skip video\"\n      },\n      {\n        \"name\": \"successVideo\",\n        \"type\": \"video\",\n        \"label\": \"Passed video\",\n        \"importance\": \"low\",\n        \"optional\": true,\n        \"description\": \"This video will be played if the user successfully passed the quiz.\"\n      },\n      {\n        \"name\": \"failVideo\",\n        \"type\": \"video\",\n        \"label\": \"Fail video\",\n        \"importance\": \"low\",\n        \"optional\": true,\n        \"description\": \"This video will be played if the user fails the quiz.\"\n      }\n    ]\n  },\n  {\n    \"name\": \"override\",\n    \"type\": \"group\",\n    \"label\": \"Settings for \\\"Check\\\", \\\"Show solution\\\" and \\\"Retry\\\"\",\n    \"importance\": \"low\",\n    \"optional\": true,\n    \"fields\": [\n      {\n        \"name\": \"checkButton\",\n        \"type\": \"boolean\",\n        \"label\": \"Show \\\"Check\\\" buttons\",\n        \"importance\": \"low\",\n        \"description\": \"This option determines if the \\\"Check\\\" button will be shown for all questions.\",\n        \"optional\": true,\n        \"default\": true\n      },\n      {\n        \"name\": \"showSolutionButton\",\n        \"type\": \"select\",\n        \"label\": \"Override \\\"Show Solution\\\" button\",\n        \"importance\": \"low\",\n        \"description\": \"This option determines if the \\\"Show Solution\\\" button will be shown for all questions, disabled for all or configured for each question individually.\",\n        \"optional\": true,\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"checkButton\",\n              \"equals\": true\n            }\n          ]\n        },\n        \"options\": [\n          {\n            \"value\": \"on\",\n            \"label\": \"Enabled\"\n          },\n          {\n            \"value\": \"off\",\n            \"label\": \"Disabled\"\n          }\n        ]\n      },\n      {\n        \"name\": \"retryButton\",\n        \"type\": \"select\",\n        \"label\": \"Override \\\"Retry\\\" button\",\n        \"importance\": \"low\",\n        \"description\": \"This option determines if the \\\"Retry\\\" button will be shown for all questions, disabled for all or configured for each question individually.\",\n        \"optional\": true,\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"checkButton\",\n              \"equals\": true\n            }\n          ]\n        },\n        \"options\": [\n          {\n            \"value\": \"on\",\n            \"label\": \"Enabled\"\n          },\n          {\n            \"value\": \"off\",\n            \"label\": \"Disabled\"\n          }\n        ]\n      }\n    ]\n  }\n]', NULL, 1, 26, NULL, NULL, NULL, 1),
(51, 'H5P.Row', 'Row', 1, 0, 12, 0, 0, 'iframe', 'h5p-row.js', 'h5p-row.css', '', '[\n  {\n    \"name\": \"columns\",\n    \"type\": \"list\",\n    \"label\": \"Columns\",\n    \"importance\": \"high\",\n    \"max\": 4,\n    \"field\": {\n      \"name\": \"column\",\n      \"type\": \"group\",\n      \"importance\": \"high\",\n      \"fields\": [\n        {\n          \"name\": \"width\",\n          \"label\": \"Width\",\n          \"type\": \"number\",\n          \"description\": \"Column width in percentage.\",\n          \"optional\": true,\n          \"max\": 100\n        },\n        {\n          \"name\": \"content\",\n          \"label\": \"Column\",\n          \"type\": \"library\",\n          \"options\": [\n            \"H5P.RowColumn 1.0\"\n          ]\n        }\n      ]\n    }\n  }\n]\n', NULL, 1, 24, NULL, NULL, NULL, 1),
(52, 'H5P.RowColumn', 'Column', 1, 0, 4, 0, 0, 'iframe', 'scripts/h5p-column.js', 'styles/h5p-column.css', '', '[\n  {\n    \"name\": \"content\",\n    \"label\": \"List of Column Content\",\n    \"importance\": \"high\",\n    \"type\": \"list\",\n    \"min\": 1,\n    \"entity\": \"content\",\n    \"field\": {\n      \"name\": \"content\",\n      \"type\": \"group\",\n      \"fields\": [\n        {\n          \"name\": \"content\",\n          \"type\": \"library\",\n          \"importance\": \"high\",\n          \"label\": \"Content\",\n          \"options\": [\n            \"H5P.Accordion 1.0\",\n            \"H5P.Agamotto 1.6\",\n            \"H5P.Audio 1.5\",\n            \"H5P.AudioRecorder 1.0\",\n            \"H5P.Blanks 1.14\",\n            \"H5P.Chart 1.2\",\n            \"H5P.Collage 0.3\",\n            \"H5P.CoursePresentation 1.26\",\n            \"H5P.Dialogcards 1.9\",\n            \"H5P.DocumentationTool 1.8\",\n            \"H5P.DragQuestion 1.14\",\n            \"H5P.DragText 1.10\",\n            \"H5P.Essay 1.5\",\n            \"H5P.GuessTheAnswer 1.5\",\n            \"H5P.Table 1.2\",\n            \"H5P.AdvancedText 1.1\",\n            \"H5P.IFrameEmbed 1.0\",\n            \"H5P.Image 1.1\",\n            \"H5P.ImageHotspots 1.10\",\n            \"H5P.ImageHotspotQuestion 1.8\",\n            \"H5P.ImageSlider 1.1\",\n            \"H5P.InteractiveVideo 1.27\",\n            \"H5P.Link 1.3\",\n            \"H5P.MarkTheWords 1.11\",\n            \"H5P.MemoryGame 1.3\",\n            \"H5P.MultiChoice 1.16\",\n            \"H5P.Questionnaire 1.3\",\n            \"H5P.QuestionSet 1.20\",\n            \"H5P.SingleChoiceSet 1.11\",\n            \"H5P.Summary 1.10\",\n            \"H5P.Timeline 1.1\",\n            \"H5P.TrueFalse 1.8\",\n            \"H5P.Video 1.6\",\n            \"H5P.MultiMediaChoice 0.3\"\n          ]\n        }\n      ]\n    }\n  }\n]\n', NULL, 1, 27, NULL, NULL, NULL, 1);
