(53, 'H5P.Shape', 'Shapes', 1, 0, 5, 0, 0, '', 'js/h5p-shape.js', 'css/h5p-shape.css', '', '[\n  {\n    \"name\": \"type\",\n    \"type\": \"select\",\n    \"label\": \"Type\",\n    \"importance\": \"low\",\n    \"widget\": \"radioGroup\",\n    \"alignment\": \"horizontal\",\n    \"options\": [\n      {\n        \"value\": \"rectangle\",\n        \"label\": \"Rectangle\"\n      },\n      {\n        \"value\": \"circle\",\n        \"label\": \"Circle\"\n      },\n      {\n        \"value\": \"vertical-line\",\n        \"label\": \"Vertical line\"\n      },\n      {\n        \"value\": \"horizontal-line\",\n        \"label\": \"Horizontal line\"\n      }\n    ],\n    \"default\": \"rectangle\"\n  },\n  {\n    \"type\": \"group\",\n    \"name\": \"shape\",\n    \"widget\": \"showWhen\",\n    \"expanded\": true,\n    \"showWhen\": {\n      \"rules\": [\n        {\n          \"field\": \"type\",\n          \"equals\": [\n            \"rectangle\",\n            \"circle\"\n          ]\n        }\n      ]\n    },\n    \"fields\": [\n      {\n        \"name\": \"fillColor\",\n        \"type\": \"text\",\n        \"label\": \"Fill color\",\n        \"importance\": \"medium\",\n        \"optional\": true,\n        \"default\": \"#ffffff\",\n        \"widget\": \"colorSelector\",\n        \"showAplha\": true,\n        \"spectrum\": {\n          \"showInput\": true,\n          \"showAlpha\": true,\n          \"preferredFormat\": \"rgb\"\n        },\n        \"optional\": true\n      },\n      {\n        \"name\": \"borderColor\",\n        \"type\": \"text\",\n        \"label\": \"Border color\",\n        \"importance\": \"medium\",\n        \"optional\": true,\n        \"default\": \"#000000\",\n        \"widget\": \"colorSelector\",\n        \"spectrum\": {\n          \"showInput\": true,\n          \"showAlpha\": true,\n          \"preferredFormat\": \"rgb\"\n        },\n        \"optional\": true\n      },\n      {\n        \"name\": \"borderWidth\",\n        \"type\": \"select\",\n        \"label\": \"Border width\",\n        \"importance\": \"low\",\n        \"default\": \"0\",\n        \"optional\": false,\n        \"options\": [\n          {\n            \"value\": \"0\",\n            \"label\": \"0\"\n          },\n          {\n            \"value\": \"1\",\n            \"label\": \"1\"\n          },\n          {\n            \"value\": \"2\",\n            \"label\": \"2\"\n          },\n          {\n            \"value\": \"3\",\n            \"label\": \"3\"\n          },\n          {\n            \"value\": \"4\",\n            \"label\": \"4\"\n          },\n          {\n            \"value\": \"5\",\n            \"label\": \"5\"\n          },\n          {\n            \"value\": \"6\",\n            \"label\": \"6\"\n          },\n          {\n            \"value\": \"7\",\n            \"label\": \"7\"\n          },\n          {\n            \"value\": \"8\",\n            \"label\": \"8\"\n          },\n          {\n            \"value\": \"9\",\n            \"label\": \"9\"\n          },\n          {\n            \"value\": \"10\",\n            \"label\": \"10\"\n          },\n          {\n            \"value\": \"11\",\n            \"label\": \"11\"\n          },\n          {\n            \"value\": \"12\",\n            \"label\": \"12\"\n          },\n          {\n            \"value\": \"13\",\n            \"label\": \"13\"\n          },\n          {\n            \"value\": \"14\",\n            \"label\": \"14\"\n          },\n          {\n            \"value\": \"15\",\n            \"label\": \"15\"\n          },\n          {\n            \"value\": \"16\",\n            \"label\": \"16\"\n          },\n          {\n            \"value\": \"17\",\n            \"label\": \"17\"\n          },\n          {\n            \"value\": \"18\",\n            \"label\": \"18\"\n          },\n          {\n            \"value\": \"19\",\n            \"label\": \"19\"\n          },\n          {\n            \"value\": \"20\",\n            