         },\n          {\n            \"value\": \"6\",\n            \"label\": \"6\"\n          },\n          {\n            \"value\": \"7\",\n            \"label\": \"7\"\n          },\n          {\n            \"value\": \"8\",\n            \"label\": \"8\"\n          },\n          {\n            \"value\": \"9\",\n            \"label\": \"9\"\n          },\n          {\n            \"value\": \"10\",\n            \"label\": \"10\"\n          },\n          {\n            \"value\": \"11\",\n            \"label\": \"11\"\n          },\n          {\n            \"value\": \"12\",\n            \"label\": \"12\"\n          },\n          {\n            \"value\": \"13\",\n            \"label\": \"13\"\n          },\n          {\n            \"value\": \"14\",\n            \"label\": \"14\"\n          },\n          {\n            \"value\": \"15\",\n            \"label\": \"15\"\n          },\n          {\n            \"value\": \"16\",\n            \"label\": \"16\"\n          },\n          {\n            \"value\": \"17\",\n            \"label\": \"17\"\n          },\n          {\n            \"value\": \"18\",\n            \"label\": \"18\"\n          },\n          {\n            \"value\": \"19\",\n            \"label\": \"19\"\n          },\n          {\n            \"value\": \"20\",\n            \"label\": \"20\"\n          }\n        ],\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"../type\",\n              \"equals\": \"rectangle\"\n            }\n          ]\n        }\n      }\n    ]\n  },\n  {\n    \"type\": \"group\",\n    \"name\": \"line\",\n    \"widget\": \"showWhen\",\n    \"expanded\": true,\n    \"showWhen\": {\n      \"rules\": [\n        {\n          \"field\": \"type\",\n          \"equals\": [\n            \"vertical-line\",\n            \"horizontal-line\"\n          ]\n        }\n      ]\n    },\n    \"fields\": [\n      {\n        \"name\": \"borderColor\",\n   