(55, 'H5P.SingleChoiceSet', 'Single Choice Set', 1, 11, 44, 1, 0, 'iframe', 'scripts/stop-watch.js, scripts/sound-effects.js, scripts/xapi-event-builder.js, scripts/result-slide.js, scripts/solution-view.js, scripts/single-choice-alternative.js, scripts/single-choice.js, scripts/single-choice-set.js', 'styles/single-choice-set.css', '', '[\n  {\n    \"name\": \"choices\",\n    \"type\": \"list\",\n    \"label\": \"List of questions\",\n    \"importance\": \"high\",\n    \"entity\": \"question\",\n    \"min\": 1,\n    \"defaultNum\": 2,\n    \"widgets\": [\n      {\n        \"name\": \"ListEditor\",\n        \"label\": \"Default\"\n      },\n      {\n        \"name\": \"SingleChoiceSetTextualEditor\",\n        \"label\": \"Textual\"\n      }\n    ],\n    \"field\": {\n      \"name\": \"choice\",\n      \"type\": \"group\",\n      \"isSubContent\": true,\n      \"label\": \"Question & alternatives\",\n      \"importance\": \"high\",\n      \"fields\": [\n        {\n          \"name\": \"question\",\n          \"type\": \"text\",\n          \"widget\": \"html\",\n          \"tags\": [\n            \"p\",\n            \"br\",\n            \"strong\",\n            \"em\",\n            \"code\"\n          ],\n          \"label\": \"Question\",\n          \"importance\": \"high\"\n        },\n        {\n          \"name\": \"answers\",\n          \"type\": \"list\",\n          \"label\": \"Alternatives - first alternative is the correct one.\",\n          \"importance\": \"medium\",\n          \"entity\": \"answer\",\n          \"min\": 2,\n          \"max\": 4,\n          \"defaultNum\": 2,\n          \"field\": {\n            \"name\": \"answer\",\n            \"type\": \"text\",\n            \"widget\": \"html\",\n            \"tags\": [\n              \"p\",\n              \"br\",\n              \"strong\",\n              \"em\",\n              \"code\"\n            ],\n            \"label\": \"Alternative\",\n            \"importance\": \"medium\"\n          }\n      