"text\",\n              \"label\": \"Feedback for defined score range\",\n              \"importance\": \"low\",\n              \"placeholder\": \"Fill in the feedback\",\n              \"optional\": true\n            }\n          ]\n        }\n      }\n    ]\n  },\n  {\n    \"name\": \"solvedLabel\",\n    \"type\": \"text\",\n    \"label\": \"Text displayed before number of statements solved in the summary task.\",\n    \"importance\": \"low\",\n    \"default\": \"Progress:\",\n    \"description\": \"Will be displayed above the statements. Example: \'Progress: 2/5\'\",\n    \"common\": true\n  },\n  {\n    \"name\": \"scoreLabel\",\n    \"type\": \"text\",\n    \"label\": \"Text displayed before number of wrong statements selected in the summary task.\",\n    \"importance\": \"low\",\n    \"default\": \"Wrong answers:\",\n    \"description\": \"Will be displayed above the statements. Example: \'Wrong answers: 4\'\",\n    \"common\": true\n  },\n  {\n    \"name\": \"resultLabel\",\n    \"type\": \"text\",\n    \"label\": \"Summary feedback header\",\n    \"importance\": \"low\",\n    \"default\": \"Your result\",\n    \"description\": \"Will be displayed above the summary feedback.\",\n    \"common\": true\n  },\n  {\n    \"name\": \"labelCorrect\",\n    \"type\": \"text\",\n    \"label\": \"Readspeaker text for correct answer\",\n    \"importance\": \"low\",\n    \"default\": \"Correct.\",\n    \"common\": true\n  },\n  {\n    \"name\": \"labelIncorrect\",\n    \"type\": \"text\",\n    \"label\": \"Readspeaker text for announcing incorrect answer\",\n    \"importance\": \"low\",\n    \"default\": \"Incorrect! Please try again.\",\n    \"common\": true\n  },\n  {\n    \"name\": \"alternativeIncorrectLabel\",\n    \"type\": \"text\",\n    \"label\": \"Readspeaker label for incorrect answer\",\n    \"importance\": \"low\",\n    \"default\": \"Incorrect\",\n    \"common\": true\n  },\n  {\n    \"name\": \"labelCorrectAnswers\",\n    \"type\": \"text\",\n    \"label\": \"Label list of correct answers\",\n    \"importance\": \"low\",\n    \"default\": \"Correct answers.\",\n    \"common\": true\n  },\n  {\n    \"name\": \"tipButtonLabel\",\n    \"type\": \"text\",\n    \"label\": \"Label for the show tip button\",\n    \"importance\": \"low\",\n    \"default\": \"Show tip\",\n    \"common\": true\n  },\n  {\n    \"name\": \"scoreBarLabel\",\n    \"type\": \"text\",\n    \"label\": \"Textual representation of the score bar for those using a readspeaker\",\n    \"description\": \":num and :total are special keywords which are programmatically updated\",\n    \"default\": \"You got :num out of :total points\",\n    \"importance\": \"low\",\n    \"common\": true\n  },\n  {\n    \"name\": \"progressText\",\n    \"type\": \"text\",\n    \"label\": \"Text used for readspeakers to communicate progress\",\n    \"description\": \":num and :total are special keywords which are programmatically updated\",\n    \"default\": \"Progress :num of :total\",\n    \"importance\": \"low\",\n    \"common\": true\n  }\n]\n', NULL, 1, 19, NULL, NULL, NULL, 1),
(58, 'H5P.Table', 'Table', 1, 2, 2, 0, 0, '', 'scripts/table.js', 'styles/table.css', '', '[\n  {\n    \"name\": \"text\",\n    \"type\": \"text\",\n    \"widget\": \"html\",\n    \"label\": \"Table\",\n    \"importance\": \"high\",\n    \"default\": \"<figure class=\\\"table\\\"><table class=\\\"h5p-table\\\"><thead><tr><th>Heading Column 1</th><th>Heading Column 2</th></tr></thead><tbody><tr><td>Row 1 Col 1</td><td>Row 1 Col 2</td></tr><tr><td>Row 2 Col 1</td><td>Row 2 Col 2</td></tr></tbody></table></figure>\",\n    \"tags\": [\n      \"strong\",\n      \"em\",\n      \"del\",\n      \"a\",\n      \"table\",\n      \"code\"\n    ],\n    \"font\": {\n      \"color\": true\n    }\n  }\n]\n', NULL, 1, 27, NULL, NULL, NULL, 1),
(59, 'H5P.Text', 'Text', 1, 1, 17, 0, 0, '', 'scripts/text.js', 'styles/text.css', '', '[\n  {\n    \"name\": \"text\",\n    \"type\": \"text\",\n    \"widget\": \"html\",\n    \"importance\": \"high\",\n    \"label\": \"Text\",\n    \"enterMode\": \"p\",\n    \"tags\": [\n      \"strong\",\n      \"em\",\n      \"del\",\n      \"a\",\n      \"ul\",\n      \"ol\",\n      \"h2\",\n      \"h3\",\n      \"hr\",\n      \"pre\",\n      \"code\"\n    ]\n  }\n]\n', NULL, NULL, NULL, '{\"disable\":false,\"disableExtraTitleField\":true}', NULL, NULL, 1),
(60, 'H5P.TextInputField', 'Text input field editor element', 1, 2, 17, 0, 0, '', 'text-input-field.js, xapi-generator.js', 'text-input-field.css', '', '[\n  {\n    \"name\": \"taskDescription\",\n    \"label\": \"Description of inputfield\",\n    \"type\": \"text\",\n    \"widget\": \"html\",\n    \"importance\": \"high\",\n    \"description\": \"Description of what the user should input.\",\n    \"enterMode\": \"div\",\n    \"tags\": [\n      \"strong\",\n      \"em\",\n      \"u\",\n      \"a\",\n      \"ul\",\n      \"ol\",\n      \"h2\",\n      \"h3\",\n      \"hr\",\n      \"pre\",\n      \"code\"\n    ],\n    \"optional\": true\n  },\n  {\n    \"name\": \"placeholderText\",\n    \"label\": \"Placeholder text\",\n    \"type\": \"text\",\n    \"description\": \"Example value or other placeholder text. Should not be used to replace the description of input-field, this value may not be available for screen-readers and also disappears when users start typing.\",\n    \"importance\": \"low\",\n    \"optional\": true\n  },\n  {\n    \"name\": \"maximumLength\",\n    \"label\": \"Maximum text length\",\n    \"type\": \"number\",\n    \"description\": \"Maximum number of characters for the text.\",\n    \"importance\": \"low\",\n    \"optional\": true,\n    \"min\": \"0\"\n  },\n  {\n    \"name\": \"inputFieldSize\",\n    \"label\": \"Input field size\",\n    \"type\": \"select\",\n    \"importance\": \"low\",\n    \"description\": \"The size of the input field in amount of lines it will cover.\",\n    \"options\": [\n      {\n        \"value\": \"1\",\n        \"label\": \"1 line\"\n      },\n      {\n        \"value\": \"3\",\n        \"label\": \"3 lines\"\n      },\n      {\n        \"value\": \"10\",\n        \"label\": \"10 lines\"\n      }\n    ],\n    \"default\": \"1\"\n  },\n  {\n    \"name\": \"requiredField\",\n    \"label\": \"Required field\",\n    \"type\": \"boolean\",\n    \"importance\": \"low\",\n    \"default\": false,\n    \"optional\": true,\n    \"description\": \"Check to make this field required, the user must answer all required fields to be able to export a document.\"\n  },\n  {\n    \"name\": \"remainingChars\",\n    \"type\": \"text\",\n    \"label\": \"Remaining characters\",\n    \"importance\": \"low\",\n    \"common\": true,\n    \"default\": \"Remaining characters: @chars\",\n    \"description\": \"Message for remaining characters. You can use @chars which will be replaced by the corresponding number.\"\n  }\n]', NULL, 1, 27, '{\"disable\":true,\"disableExtraTitleField\":true}', NULL, NULL, 1),
(61, 'H5P.TextUtilities', 'Text Utilities', 1, 3, 0, 0, 0, '', 'scripts/text-utilities.js', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, 1);
INSERT INTO `mdl_h5p_libraries` (`id`, `machinename`, `title`, `majorversion`, `minorversion`, `patchversion`, `runnable`, `fullscreen`, `embedtypes`, `preloadedjs`, `preloadedcss`, `droplibrarycss`, `semantics`, `addto`, `coremajor`, `coreminor`, `metadatasettings`, `tutorial`, `example`, `enabled`) VALUES
(62, 'H5P.Timeline', 'Timeline', 1, 1, 25, 1, 1, 'iframe', 'timeline.js', 'timeline.css', '', '[\n  {\n    \"name\": \"timeline\",\n    \"label\": \"Timeline\",\n    \"importance\": \"high\",\n    \"type\": \"group\",\n    \"expanded\": true,\n    \"fields\": [\n      {\n        \"name\": \"headline\",\n        \"type\": \"text\",\n        \"label\": \"Headline\",\n        \"importance\": \"high\",\n        \"description\": \"Main timeline heading goes here (first page)\"\n      },\n      {\n        \"name\": \"text\",\n        \"type\": \"text\",\n        \"label\": \"Body Text\",\n        \"importance\": \"medium\",\n        \"widget\": \"html\",\n        \"description\": \"The main timeline body goes here (first page).\",\n        \"optional\": true,\n        \"tags\": [\n          \"strong\",\n          \"em\",\n          \"del\",\n          \"a\",\n          \"ul\",\n          \"ol\",\n          \"hr\",\n          \"code\"\n        ]\n      },\n      {\n        \"name\": \"defaultZoomLevel\",\n        \"type\": \"text\",\n        \"label\": \"Default zoom level\",\n        \"importance\": \"low\",\n        \"default\": \"0\",\n        \"optional\": true,\n        \"description\": \"This will tweak the default zoom level. Equivilent to pressing the zoom in or zoom out button the specified number of times. Negative numbers zoom out. default is 0\"\n      },\n      {\n        \"name\": \"backgroundImage\",\n        \"type\": \"image\",\n        \"label\": \"Background image\",\n        \"importance\": \"low\",\n        \"optional\": true,\n        \"description\": \"An image to display as background.\"\n      },\n      {\n        \"name\": \"height\",\n        \"type\": \"number\",\n        \"label\": \"Height\",\n        \"importance\": \"low\",\n        \"description\": \"The height in pixels\",\n        \"default\": 600\n      },\n      {\n        \"name\": \"asset\",\n        \"type\": \"group\",\n        \"label\": \"Asset\",\n        \"importance\": \"low\",\n        \"description\": \"Here you can add an asset to your timeline \\\"front page\\\"\",\n        \"optional\": true,\n        \"fields\": [\n          {\n            \"name\": \"media\",\n            \"type\": \"text\",\n            \"label\": \"Media\",\n            \"importance\": \"low\",\n            \"description\": \"Link to media URL (Twitter, YouTube, Flickr, Vimeo, Google Maps and SoundCloud are currently supported)\",\n            \"optional\": true\n          },\n          {\n            \"name\": \"credit\",\n            \"type\": \"text\",\n            \"label\": \"Credits\",\n            \"importance\": \"low\",\n            \"description\": \"Credits to the media\",\n            \"optional\": true\n          },\n          {\n            \"name\": \"caption\",\n            \"type\": \"text\",\n            \"label\": \"Caption\",\n            \"importance\": \"low\",\n            \"description\": \"Caption description goes here\",\n            \"optional\": true\n          }\n        ]\n      },\n      {\n        \"name\": \"date\",\n        \"type\": \"list\",\n        \"label\": \"Dates\",\n        \"importance\": \"medium\",\n        \"min\": 1,\n        \"description\": \"Add some dates to your timeline!\",\n        \"field\": {\n          \"name\": \"adate\",\n          \"type\": \"group\",\n          \"label\": \"Date\",\n          \"importance\": \"medium\",\n          \"description\": \"Date\",\n          \"fields\": [\n            {\n              \"name\": \"startDate\",\n              \"type\": \"text\",\n              \"label\": \"Start date\",\n              \"importance\": \"medium\",\n              \"description\": \"YYYY,MM,DD (Minimum YYYY required)\",\n              \"regexp\": {\n                \"pattern\": \"^-?\\\\d{1,}(,(1[012]|[0]?[1-9])(,([12][0-9]|3[01]|[0]?[1-9]))?)?$\"\n              }\n            },\n            {\n              \"name\": \"endDate\",\n              \"type\": \"text\",\n              \"label\": \"End date\",\n              \"importance\": \"medium\",\n              \"description\": \"YYYY,MM,DD (Minimum YYYY required)\",\n              \"optional\": true,\n              \"regexp\": {\n                \"pattern\": \"^-?\\\\d{1,}(,(1[012]|[0]?[1-9])(,([12][0-9]|3[01]|[0]?[1-9]))?)?$\"\n              }\n            },\n            {\n              \"name\": \"headline\",\n              \"type\": \"text\",\n              \"label\": \"Headline\",\n              \"importance\": \"medium\",\n              \"description\": \"Headline for the date entry\"\n            },\n            {\n              \"name\": \"text\",\n              \"type\": \"text\",\n              \"label\": \"Body text\",\n              \"importance\": \"medium\",\n              \"widget\": \"html\",\n              \"optional\": true,\n              \"description\": \"Body for the date entry\",\n              \"tags\": [\n                \"strong\",\n                \"em\",\n                \"del\",\n                \"a\",\n                \"ul\",\n                \"ol\",\n                \"h2\",\n                \"h3\",\n                \"hr\",\n                \"pre\",\n                \"code\"\n              ]\n            },\n            {\n              \"name\": \"tag\",\n              \"type\": \"text\",\n              \"label\": \"Tags\",\n              \"importance\": \"medium\",\n              \"description\": \"Enter Tags (categories)\",\n              \"optional\": true\n            },\n            {\n              \"name\": \"asset\",\n              \"type\": \"group\",\n              \"label\": \"Asset\",\n              \"importance\": \"low\",\n              \"description\": \"\",\n              \"optional\": true,\n              \"fields\": [\n                {\n                  \"name\": \"media\",\n                  \"type\": \"text\",\n                  \"label\": \"Media\",\n                  \"importance\": \"low\",\n                  \"description\": \"URL to the media (Twitter, YouTube, Flickr, Vimeo, Wikipedia, Google Maps and SoundCloud are currently supported).\",\n                  \"optional\": true\n                },\n                {\n                  \"name\": \"thumbnail\",\n                  \"type\": \"image\",\n                  \"label\": \"Thumbnail\",\n                  \"importance\": \"low\",\n                  \"description\": \"Add a thumbnail if needed, 32x32\",\n                  \"optional\": true\n                },\n                {\n                  \"name\": \"credit\",\n                  \"type\": \"text\",\n                  \"label\": \"Credit\",\n                  \"importance\": \"low\",\n                  \"description\": \"Credits to the media\",\n                  \"optional\": true\n                },\n                {\n                  \"name\": \"caption\",\n                  \"type\": \"text\",\n                  \"label\": \"Caption\",\n                  \"importance\": \"low\",\n                  \"description\": \"Caption text\",\n                  \"optional\": true\n                }\n              ]\n            }\n          ]\n        }\n      },\n      {\n        \"name\": \"era\",\n        \"type\": \"list\",\n        \"label\": \"Eras\",\n        \"importance\": \"medium\",\n        \"description\": \"Add an era to your timeline\",\n        \"min\": 0,\n        \"optional\": true,\n        \"field\": {\n          \"name\": \"anera\",\n          \"type\": \"group\",\n          \"label\": \"Era\",\n          \"importance\": \"medium\",\n          \"description\": \"\",\n          \"fields\": [\n            {\n              \"name\": \"startDate\",\n              \"type\": \"text\",\n              \"label\": \"Start date\",\n              \"importance\": \"medium\",\n              \"description\": \"YYYY,MM,DD (Minimum YYYY required)\",\n              \"regexp\": {\n                \"pattern\": \"^-?\\\\d{1,}(,(1[012]|[0]?[1-9])(,([12][0-9]|3[01]|[0]?[1-9]))?)?$\"\n              }\n            },\n            {\n              \"name\": \"endDate\",\n              \"type\": \"text\",\n              \"label\": \"End date\",\n              \"importance\": \"medium\",\n              \"description\": \"YYYY,MM,DD (Minimum YYYY required)\",\n              \"optional\": true,\n              \"regexp\": {\n                \"pattern\": \"^-?\\\\d{1,}(,(1[012]|[0]?[1-9])(,([12][0-9]|3[01]|[0]?[1-9]))?)?$\"\n              }\n            },\n            {\n              \"name\": \"headline\",\n              \"type\": \"text\",\n              \"label\": \"Headline\",\n              \"importance\": \"medium\",\n              \"description\": \"Era headline\"\n            },\n            {\n              \"name\": \"text\",\n              \"type\": \"text\",\n              \"label\": \"Text\",\n              \"importance\": \"medium\",\n              \"widget\": \"html\",\n              \"optional\": true,\n              \"description\": \"Era body\",\n              \"tags\": [\n                \"strong\",\n                \"em\",\n                \"del\",\n                \"a\",\n                \"ul\",\n                \"ol\",\n                \"hr\",\n                \"code\"\n              ]\n            },\n            {\n              \"name\": \"tag\",\n              \"type\": \"text\",\n              \"label\": \"Tag\",\n              \"importance\": \"medium\",\n              \"description\": \"Era tags (categories)\",\n              \"optional\": true\n            }\n          ]\n        }\n      },\n      {\n        \"name\": \"language\",\n        \"type\": \"select\",\n        \"label\": \"Language\",\n        \"importance\": \"medium\",\n        \"optional\": true,\n        \"description\": \"The language of the user interface\",\n        \"options\": [\n          {\n            \"value\": \"af\",\n            \"label\": \"Afrikaans\"\n          },\n          {\n            \"value\": \"ar\",\n            \"label\": \"Arabic\"\n          },\n          {\n            \"value\": \"hy\",\n            \"label\": \"Armenian\"\n          },\n          {\n            \"value\": \"eu\",\n            \"label\": \"Basque\"\n          },\n          {\n            \"value\": \"bg\",\n            \"label\": \"Bulgarian\"\n          },\n          {\n            \"value\": \"ca\",\n            \"label\": \"Catalan\"\n          },\n          {\n            \"value\": \"zh-cn\",\n            \"label\": \"Chinese\"\n          },\n          {\n            \"value\": \"hr\",\n            \"label\": \"Croatian / Hrvatski\"\n          },\n          {\n            \"value\": \"cz\",\n            \"label\": \"Czech\"\n          },\n          {\n            \"value\": \"da\",\n            \"label\": \"Danish\"\n          },\n          {\n            \"value\": \"nl\",\n            \"label\": \"Dutch\"\n          },\n          {\n            \"value\": \"en\",\n            \"label\": \"English\"\n          },\n          {\n            \"value\": \"en-24hr\",\n            \"label\": \"English (24-hour time)\"\n          },\n          {\n            \"value\": \"eo\",\n            \"label\": \"Esperanto\"\n          },\n          {\n            \"value\": \"et\",\n            \"label\": \"Estonian\"\n          },\n          {\n            \"value\": \"fo\",\n            \"label\": \"Faroese\"\n          },\n          {\n            \"value\": \"fa\",\n            \"label\": \"Farsi\"\n          },\n          {\n            \"value\": \"fi\",\n            \"label\": \"Finnish\"\n          },\n          {\n            \"value\": \"fr\",\n            \"label\": \"French\"\n          },\n          {\n            \"value\": \"gl\",\n            \"label\": \"Galician\"\n          },\n          {\n            \"value\": \"ka\",\n            \"label\": \"Georgian\"\n          },\n          {\n            \"value\": \"de\",\n            \"label\": \"German / Deutsch\"\n          },\n          {\n            \"value\": \"el\",\n            \"label\": \"Greek\"\n          },\n          {\n            \"value\": \"he\",\n            \"label\": \"Hebrew\"\n          },\n          {\n            \"value\": \"hu\",\n            \"label\": \"Hungarian\"\n          },\n          {\n            \"value\": \"is\",\n            \"label\": \"Icelandic\"\n          },\n          {\n            \"value\": \"id\",\n            \"label\": \"Indonesian\"\n          },\n          {\n            \"value\": \"it\",\n            \"label\": \"Italian\"\n          },\n          {\n            \"value\": \"ja\",\n            \"label\": \"Japanese\"\n          },\n          {\n            \"value\": \"ko\",\n            \"label\": \"Korean\"\n          },\n          {\n            \"value\": \"lv\",\n            \"label\": \"Latvian\"\n          },\n          {\n            \"value\": \"lt\",\n            \"label\": \"Lithuanian\"\n          },\n          {\n            \"value\": \"lb\",\n            \"label\": \"Luxembourgish\"\n          },\n          {\n            \"value\": \"ms\",\n            \"label\": \"Malay\"\n          },\n          {\n            \"value\": \"ne\",\n            \"label\": \"Nepali\"\n          },\n          {\n            \"value\": \"no\",\n            \"label\": \"Norwegian\"\n          },\n          {\n            \"value\": \"pl\",\n            \"label\": \"Polish\"\n          },\n          {\n            \"value\": \"pt\",\n            \"label\": \"Portuguese\"\n          },\n          {\n            \"value\": \"pt-br\",\n            \"label\": \"Portuguese (Brazilian)\"\n          },\n          {\n            \"value\": \"rm\",\n            \"label\": \"Romansh\"\n          },\n          {\n            \"value\": \"ru\",\n            \"label\": \"Russian\"\n          },\n          {\n            \"value\": \"sr-cy\",\n            \"label\": \"Serbian - Cyrillic\"\n          },\n          {\n            \"value\": \"sr\",\n            \"label\": \"Serbian - Latin\"\n          },\n          {\n            \"value\": \"si\",\n            \"label\": \"Sinhalese\"\n          },\n          {\n            \"value\": \"sk\",\n            \"label\": \"Slovak\"\n          },\n          {\n            \"value\": \"sl\",\n            \"label\": \"Slovenian\"\n          },\n          {\n            \"value\": \"es\",\n            \"label\": \"Spanish\"\n          },\n          {\n            \"value\": \"sv\",\n            \"label\": \"Swedish\"\n          },\n          {\n            \"value\": \"tl\",\n            \"label\": \"Tagalog\"\n          },\n          {\n            \"value\": \"ta\",\n            \"label\": \"Tamil\"\n          },\n          {\n            \"value\": \"zh-tw\",\n            \"label\": \"Taiwanese\"\n          },\n          {\n            \"value\": \"te\",\n            \"label\": \"Telugu\"\n          },\n          {\n            \"value\": \"tr\",\n            \"label\": \"Turkish\"\n          },\n          {\n            \"value\": \"uk\",\n            \"label\": \"Ukrainian\"\n          }\n        ],\n        \"default\": \"en\"\n      }\n    ]\n  }\n]\n', NULL, NULL, NULL, NULL, NULL, NULL, 1),
(63, 'H5P.Timer', 'Timer', 0, 4, 2, 0, 0, '', 'scripts/timer.js', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, 1),
(64, 'H5P.TrueFalse', 'True/False Question', 1, 8, 11, 1, 0, 'iframe', 'scripts/h5p-true-false.js, scripts/h5p-true-false-answer-group.js, scripts/h5p-true-false-answer.js', 'styles/h5p-true-false.css', '', '[\n  {\n    \"name\": \"media\",\n    \"type\": \"group\",\n    \"label\": \"Media\",\n    \"importance\": \"medium\",\n    \"fields\": [\n      {\n        \"name\": \"type\",\n        \"type\": \"library\",\n        \"label\": \"Type\",\n        \"importance\": \"medium\",\n        \"options\": [\n          \"H5P.Image 1.1\",\n          \"H5P.Video 1.6\",\n          \"H5P.Audio 1.5\"\n        ],\n        \"optional\": true,\n        \"description\": \"Optional media to display above the question.\"\n      },\n      {\n        \"name\": \"disableImageZooming\",\n        \"type\": \"boolean\",\n        \"label\": \"Disable image zooming\",\n        \"importance\": \"low\",\n        \"default\": false,\n        \"optional\": true,\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"type\",\n              \"equals\": \"H5P.Image 1.1\"\n            }\n          ]\n        }\n      }\n    ]\n  },\n  {\n    \"name\": \"question\",\n    \"type\": \"text\",\n    \"widget\": \"html\",\n    \"label\": \"Question\",\n    \"importance\": \"high\",\n    \"enterMode\": \"p\",\n    \"tags\": [\n      \"strong\",\n      \"em\",\n      \"sub\",\n      \"sup\",\n      \"h2\",\n      \"h3\",\n      \"pre\",\n      \"code\"\n    ]\n  },\n  {\n    \"name\": \"correct\",\n    \"type\": \"select\",\n    \"widget\": \"radioGroup\",\n    \"alignment\": \"horizontal\",\n    \"label\": \"Correct answer\",\n    \"importance\": \"high\",\n    \"options\": [\n      {\n        \"value\": \"true\",\n        \"label\": \"True\"\n      },\n      {\n        \"value\": \"false\",\n        \"label\": \"False\"\n      }\n    ],\n    \"default\": \"true\"\n  },\n  {\n    \"name\": \"l10n\",\n    \"type\": \"group\",\n    \"common\": true,\n    \"label\": \"User interface translations for True/False Questions\",\n    \"importance\": \"low\",\n    \"fields\": [\n      {\n        \"name\": \"trueText\",\n        \"type\": \"text\",\n        \"label\": \"Label for true button\",\n        \"importance\": \"low\",\n        \"default\": \"True\"\n      },\n      {\n        \"name\": \"falseText\",\n        \"type\": \"text\",\n        \"label\": \"Label for false button\",\n        \"importance\": \"low\",\n        \"default\": \"False\"\n      },\n      {\n        \"label\": \"Feedback text\",\n        \"importance\": \"low\",\n        \"name\": \"score\",\n        \"type\": \"text\",\n        \"default\": \"You got @score of @total points\",\n        \"description\": \"Feedback text, variables available: @score and @total. Example: \'You got @score of @total possible points\'\"\n      },\n      {\n        \"label\": \"Text for \\\"Check\\\" button\",\n        \"importance\": \"low\",\n        \"name\": \"checkAnswer\",\n        \"type\": \"text\",\n        \"default\": \"Check\"\n      },\n      {\n        \"label\": \"Text for \\\"Submit\\\" button\",\n        \"importance\": \"low\",\n        \"name\": \"submitAnswer\",\n        \"type\": \"text\",\n        \"default\": \"Submit\"\n      },\n      {\n        \"label\": \"Text for \\\"Show solution\\\" button\",\n        \"importance\": \"low\",\n        \"name\": \"showSolutionButton\",\n        \"type\": \"text\",\n        \"default\": \"Show solution\"\n      },\n      {\n        \"label\": \"Text for \\\"Retry\\\" button\",\n        \"importance\": \"low\",\n        \"name\": \"tryAgain\",\n        \"type\": \"text\",\n        \"default\": \"Retry\"\n      },\n      {\n        \"name\": \"wrongAnswerMessage\",\n        \"type\": \"text\",\n        \"label\": \"Wrong Answer\",\n        \"importance\": \"low\",\n        \"default\": \"Wrong answer\"\n      },\n      {\n        \"name\": \"correctAnswerMessage\",\n        \"type\": \"text\",\n        \"label\": \"Correct Answer\",\n        \"importance\": \"low\",\n        \"default\": \"Correct answer\"\n      },\n      {\n        \"name\": \"scoreBarLabel\",\n        \"type\": \"text\",\n        \"label\": \"Textual representation of the score bar for those using a readspeaker\",\n        \"default\": \"You got :num out of :total points\",\n        \"importance\": \"low\"\n      },\n      {\n        \"name\": \"a11yCheck\",\n        \"type\": \"text\",\n        \"label\": \"Assistive technology description for \\\"Check\\\" button\",\n        \"default\": \"Check the answers. The responses will be marked as correct, incorrect, or unanswered.\",\n        \"importance\": \"low\"\n      },\n      {\n        \"name\": \"a11yShowSolution\",\n        \"type\": \"text\",\n        \"label\": \"Assistive technology description for \\\"Show Solution\\\" button\",\n        \"default\": \"Show the solution. The task will be marked with its correct solution.\",\n        \"importance\": \"low\"\n      },\n      {\n        \"name\": \"a11yRetry\",\n        \"type\": \"text\",\n        \"label\": \"Assistive technology description for \\\"Retry\\\" button\",\n        \"default\": \"Retry the task. Reset all responses and start the task over again.\",\n        \"importance\": \"low\"\n      }\n    ]\n  },\n  {\n    \"name\": \"behaviour\",\n    \"type\": \"group\",\n    \"label\": \"Behavioural settings\",\n    \"importance\": \"low\",\n    \"description\": \"These options will let you control how the task behaves.\",\n    \"fields\": [\n      {\n        \"name\": \"enableRetry\",\n        \"type\": \"boolean\",\n        \"label\": \"Enable \\\"Retry\\\" button\",\n        \"importance\": \"low\",\n        \"default\": true\n      },\n      {\n        \"name\": \"enableSolutionsButton\",\n        \"type\": \"boolean\",\n        \"label\": \"Enable \\\"Show Solution\\\" button\",\n        \"importance\": \"low\",\n        \"default\": true\n      },\n      {\n        \"name\": \"enableCheckButton\",\n        \"type\": \"boolean\",\n        \"label\": \"Enable \\\"Check\\\" button\",\n        \"widget\": \"none\",\n        \"importance\": \"low\",\n        \"default\": true,\n        \"optional\": true\n      },\n      {\n        \"label\": \"Show confirmation dialog on \\\"Check\\\"\",\n        \"importance\": \"low\",\n        \"name\": \"confirmCheckDialog\",\n        \"type\": \"boolean\",\n        \"default\": false\n      },\n      {\n        \"label\": \"Show confirmation dialog on \\\"Retry\\\"\",\n        \"importance\": \"low\",\n        \"name\": \"confirmRetryDialog\",\n        \"type\": \"boolean\",\n        \"default\": false\n      },\n      {\n        \"label\": \"Automatically check answer\",\n        \"importance\": \"low\",\n        \"description\": \"Note that accessibility will suffer if enabling this option\",\n        \"name\": \"autoCheck\",\n        \"type\": \"boolean\",\n        \"default\": false\n      },\n      {\n        \"name\": \"feedbackOnCorrect\",\n        \"label\": \"Feedback on correct answer\",\n        \"importance\": \"low\",\n        \"description\": \"This will override the default feedback text. Variables available: @score and @total\",\n        \"type\": \"text\",\n        \"maxLength\": 2048,\n        \"optional\": true\n      },\n      {\n        \"name\": \"feedbackOnWrong\",\n        \"label\": \"Feedback on wrong answer\",\n        \"importance\": \"low\",\n        \"description\": \"This will override the default feedback text. Variables available: @score and @total\",\n        \"type\": \"text\",\n        \"maxLength\": 2048,\n        \"optional\": true\n      }\n    ]\n  },\n  {\n    \"label\": \"Check confirmation dialog\",\n    \"importance\": \"low\",\n    \"name\": \"confirmCheck\",\n    \"type\": \"group\",\n    \"common\": true,\n    \"fields\": [\n      {\n        \"label\": \"Header text\",\n        \"importance\": \"low\",\n        \"name\": \"header\",\n        \"type\": \"text\",\n        \"default\": \"Finish ?\"\n      },\n      {\n        \"label\": \"Body text\",\n        \"importance\": \"low\",\n        \"name\": \"body\",\n        \"type\": \"text\",\n        \"default\": \"Are you sure you wish to finish ?\",\n        \"widget\": \"html\",\n        \"enterMode\": \"p\",\n        \"tags\": [\n          \"strong\",\n          \"em\",\n          \"del\",\n          \"u\",\n          \"code\"\n        ]\n      },\n      {\n        \"label\": \"Cancel button label\",\n        \"importance\": \"low\",\n        \"name\": \"cancelLabel\",\n        \"type\": \"text\",\n        \"default\": \"Cancel\"\n      },\n      {\n        \"label\": \"Confirm button label\",\n        \"importance\": \"low\",\n        \"name\": \"confirmLabel\",\n        \"type\": \"text\",\n        \"default\": \"Finish\"\n      }\n    ]\n  },\n  {\n    \"label\": \"Retry confirmation dialog\",\n    \"importance\": \"low\",\n    \"name\": \"confirmRetry\",\n    \"type\": \"group\",\n    \"common\": true,\n    \"fields\": [\n      {\n        \"label\": \"Header text\",\n        \"importance\": \"low\",\n        \"name\": \"header\",\n        \"type\": \"text\",\n        \"default\": \"Retry ?\"\n      },\n      {\n        \"label\": \"Body text\",\n        \"importance\": \"low\",\n        \"name\": \"body\",\n        \"type\": \"text\",\n        \"default\": \"Are you sure you wish to retry ?\",\n        \"widget\": \"html\",\n        \"enterMode\": \"p\",\n        \"tags\": [\n          \"strong\",\n          \"em\",\n          \"del\",\n          \"u\",\n          \"code\"\n        ]\n      },\n      {\n        \"label\": \"Cancel button label\",\n        \"importance\": \"low\",\n        \"name\": \"cancelLabel\",\n        \"type\": \"text\",\n        \"default\": \"Cancel\"\n      },\n      {\n        \"label\": \"Confirm button label\",\n        \"importance\": \"low\",\n        \"name\": \"confirmLabel\",\n        \"type\": \"text\",\n        \"default\": \"Confirm\"\n      }\n    ]\n  }\n]', NULL, 1, 19, NULL, NULL, NULL, 1),
(65, 'H5P.TwitterUserFeed', 'Twitter User Feed', 1, 0, 21, 1, 0, '', 'twitter-user-feed.js', 'twitter-user-feed.css', '', '[\n  {\n    \"label\": \"Username on Twitter\",\n    \"importance\": \"high\",\n    \"name\": \"userName\",\n    \"type\": \"text\",\n    \"description\": \"The username we\'ll be fetching tweets from\"\n  },\n  {\n    \"label\": \"Show replies\",\n    \"importance\": \"low\",\n    \"name\": \"showReplies\",\n    \"type\": \"boolean\"\n  },\n  {\n    \"label\": \"Number of tweets\",\n    \"importance\": \"medium\",\n    \"name\": \"numTweets\",\n    \"type\": \"number\",\n    \"default\": 5,\n    \"min\": 1,\n    \"max\": 20\n  }\n]\n', NULL, NULL, NULL, '{\"disable\":true,\"disableExtraTitleField\":true}', NULL, NULL, 1),
(66, 'H5P.Video', 'Video', 1, 6, 66, 0, 0, '', 'scripts/vimeo.js, scripts/youtube.js, scripts/panopto.js, scripts/echo360.js, scripts/html5.js, scripts/video.js', 'styles/video.css', '', '[\n  {\n    \"name\": \"sources\",\n    \"type\": \"video\",\n    \"label\": \"Video sources\",\n    \"importance\": \"high\",\n    \"description\": \"To ensure that the video works in all browsers you should add both WebM and MP4 formatted sources.\",\n    \"disableCopyright\": true\n  },\n  {\n    \"name\": \"visuals\",\n    \"type\": \"group\",\n    \"label\": \"Visuals\",\n    \"importance\": \"medium\",\n    \"fields\": [\n      {\n        \"name\": \"poster\",\n        \"type\": \"image\",\n        \"label\": \"Poster image\",\n        \"importance\": \"low\"\n      },\n      {\n        \"name\": \"fit\",\n        \"type\": \"boolean\",\n        \"label\": \"Fit video player to use all available space\",\n        \"importance\": \"low\",\n        \"default\": true,\n        \"description\": \"If not set the video player will have the same aspect ratio as the video.\"\n      },\n      {\n        \"name\": \"controls\",\n        \"type\": \"boolean\",\n        \"label\": \"Show video player controls\",\n        \"importance\": \"low\",\n        \"default\": true,\n        \"description\": \"Add controls to the video player. This allows users to play, pause, etc.\"\n      }\n    ]\n  },\n  {\n    \"name\": \"playback\",\n    \"type\": \"group\",\n    \"label\": \"Playback\",\n    \"importance\": \"medium\",\n    \"fields\": [\n      {\n        \"name\": \"autoplay\",\n        \"type\": \"boolean\",\n        \"label\": \"Auto-play video\",\n        \"importance\": \"low\",\n        \"default\": false,\n        \"description\": \"Start playing the video automatically. May not work on mobile devices.\"\n      },\n      {\n        \"name\": \"loop\",\n        \"type\": \"boolean\",\n        \"label\": \"Loop video\",\n        \"importance\": \"low\",\n        \"default\": false,\n        \"description\": \"Automatically start the video over again when it ends.\"\n      }\n    ]\n  },\n  {\n    \"name\": \"l10n\",\n    \"type\": \"group\",\n    \"label\": \"Video localization\",\n    \"importance\": \"low\",\n    \"common\": true,\n    \"fields\": [\n      {\n        \"name\": \"name\",\n        \"type\": \"text\",\n        \"label\": \"Name\",\n        \"importance\": \"low\",\n        \"default\": \"Video\",\n        \"description\": \"Helps identify content of this type.\"\n      },\n      {\n        \"name\": \"loading\",\n        \"type\": \"text\",\n        \"label\": \"Loading\",\n        \"importance\": \"low\",\n        \"default\": \"Video player loading...\"\n      },\n      {\n        \"name\": \"noPlayers\",\n        \"type\": \"text\",\n        \"label\": \"No players found\",\n        \"importance\": \"low\",\n        \"default\": \"Found no video players that supports the given video format.\"\n      },\n      {\n        \"name\": \"noSources\",\n        \"type\": \"text\",\n        \"label\": \"No sources\",\n        \"importance\": \"low\",\n        \"default\": \"Video is missing sources.\"\n      },\n      {\n        \"name\": \"aborted\",\n        \"type\": \"text\",\n        \"label\": \"Aborted\",\n        \"importance\": \"low\",\n        \"default\": \"Media playback has been aborted.\"\n      },\n      {\n        \"name\": \"networkFailure\",\n        \"type\": \"text\",\n        \"label\": \"Network failure\",\n        \"importance\": \"low\",\n        \"default\": \"Network failure.\"\n      },\n      {\n        \"name\": \"cannotDecode\",\n        \"type\": \"text\",\n        \"label\": \"Cannot decode video source\",\n        \"importance\": \"low\",\n        \"default\": \"Unable to decode media.\"\n      },\n      {\n        \"name\": \"formatNotSupported\",\n        \"type\": \"text\",\n        \"label\": \"Format not supported\",\n        \"importance\": \"low\",\n        \"default\": \"Video format not supported.\"\n      },\n      {\n        \"name\": \"mediaEncrypted\",\n        \"type\": \"text\",\n        \"label\": \"Media encrypted\",\n        \"importance\": \"low\",\n        \"default\": \"Media encrypted.\"\n      },\n      {\n        \"name\": \"unknownError\",\n        \"type\": \"text\",\n        \"label\": \"Unknown error\",\n        \"importance\": \"low\",\n        \"default\": \"Unknown error.\"\n      },\n      {\n        \"name\": \"invalidYtId\",\n        \"type\": \"text\",\n        \"label\": \"Invalid YouTube ID\",\n        \"importance\": \"low\",\n        \"default\": \"Invalid YouTube ID.\"\n      },\n      {\n        \"name\": \"unknownYtId\",\n        \"type\": \"text\",\n        \"label\": \"Unknown YouTube ID\",\n        \"importance\": \"low\",\n        \"default\": \"Unable to find video with the given YouTube ID.\"\n      },\n      {\n        \"name\": \"restrictedYt\",\n        \"type\": \"text\",\n        \"label\": \"Restricted YouTube video\",\n        \"importance\": \"low\",\n        \"default\": \"The owner of this video does not allow it to be embedded.\"\n      }\n    ]\n  },\n  {\n    \"name\": \"a11y\",\n    \"type\": \"group\",\n    \"label\": \"Accessibility\",\n    \"importance\": \"medium\",\n    \"fields\": [\n      {\n        \"name\": \"videoTrack\",\n        \"type\": \"list\",\n        \"label\": \"Add video track\",\n        \"importance\": \"low\",\n        \"optional\": true,\n        \"entity\": \"Track\",\n        \"min\": 0,\n        \"field\": {\n          \"name\": \"track\",\n          \"type\": \"group\",\n          \"label\": \"Track\",\n          \"importance\": \"low\",\n          \"expanded\": false,\n          \"fields\": [\n            {\n              \"name\": \"label\",\n              \"type\": \"text\",\n              \"label\": \"Track label\",\n              \"importance\": \"low\",\n              \"optional\": true\n            },\n            {\n              \"name\": \"kind\",\n              \"type\": \"select\",\n              \"label\": \"Type kind, refer to <a target=\\\"_blank\\\" href=\\\"https://html.spec.whatwg.org/multipage/embedded-content.html#the-track-element\\\">HTML living standard</a>\",\n              \"importance\": \"low\",\n              \"default\": \"descriptions\",\n              \"options\": [\n                {\n                  \"value\": \"subtitles\",\n                  \"label\": \"Subtitles\"\n                },\n                {\n                  \"value\": \"captions\",\n                  \"label\": \"Captions\"\n                },\n                {\n                  \"value\": \"descriptions\",\n                  \"label\": \"Descriptions\"\n                },\n                {\n                  \"value\": \"chapters\",\n                  \"label\": \"Chapters\"\n                }\n              ]\n            },\n            {\n              \"name\": \"srcLang\",\n              \"type\": \"text\",\n              \"label\": \"Source language, must be defined for subtitles\",\n              \"importance\": \"low\",\n              \"default\": \"en\",\n              \"description\": \"Must be a valid BCP 47 language tag. If the kind attribute is set to subtitles, then srclang must be defined.\"\n            },\n            {\n              \"name\": \"track\",\n              \"type\": \"file\",\n              \"label\": \"Track file (WebVTT)\",\n              \"importance\": \"low\"\n            }\n          ]\n        }\n      }\n    ]\n  }\n]\n', NULL, 1, 19, NULL, NULL, NULL, 1),
