(97, 'H5P.ImageJuxtaposition', 'Image Juxtaposition', 1, 5, 4, 1, 1, 'iframe', 'dist/h5p-image-juxtaposition.js', 'dist/h5p-image-juxtaposition.css', '', '[\n  {\n    \"name\": \"taskDescription\",\n    \"label\": \"Task description\",\n    \"importance\": \"high\",\n    \"type\": \"text\",\n    \"widget\": \"html\",\n    \"description\": \"Put the heading/instructions you\'d like to show above the before/after image here.\",\n    \"placeholder\": \"Here you can add an optional heading and/or instructions.\",\n    \"enterMode\": \"div\",\n    \"tags\": [\n      \"strong\",\n      \"em\",\n      \"u\",\n      \"a\",\n      \"ul\",\n      \"ol\",\n      \"h2\",\n      \"h3\",\n      \"hr\",\n      \"pre\",\n      \"code\"\n    ],\n    \"optional\": true\n  },\n  {\n    \"name\": \"imageBefore\",\n    \"type\": \"group\",\n    \"label\": \"First image\",\n    \"importance\": \"high\",\n    \"expanded\": true,\n    \"fields\": [\n      {\n        \"name\": \"imageBefore\",\n        \"label\": \"First image\",\n        \"importance\": \"low\",\n        \"type\": \"library\",\n        \"options\": [\n          \"H5P.Image 1.1\"\n        ],\n        \"optional\": false,\n        \"description\": \"The first image. Please make sure that it has the same size as the second image.\"\n      },\n      {\n        \"name\": \"labelBefore\",\n        \"label\": \"Label for first image\",\n        \"importance\": \"low\",\n        \"type\": \"text\",\n        \"optional\": true,\n        \"description\": \"Label to put over first image\"\n      }\n    ]\n  },\n  {\n    \"name\": \"imageAfter\",\n    \"type\": \"group\",\n    \"label\": \"Second image\",\n    \"importance\": \"high\",\n    \"expanded\": true,\n    \"fields\": [\n      {\n        \"name\": \"imageAfter\",\n        \"label\": \"Second image\",\n        \"importance\": \"low\",\n        \"type\": \"library\",\n        \"options\": [\n          \"H5P.Image 1.1\"\n        ],\n        \"optional\": false,\n        \"description\": \"The second image. Please make sure that it has the same size as the first image.\"\n      },\n      {\n        \"name\": \"labelAfter\",\n        \"label\": \"Label for second image\",\n        \"importance\": \"low\",\n        \"type\": \"text\",\n        \"optional\": true,\n        \"description\": \"Label to put over second image\"\n      }\n    ]\n  },\n  {\n    \"name\": \"behavior\",\n    \"type\": \"group\",\n    \"label\": \"Behavioral settings\",\n    \"importance\": \"low\",\n    \"description\": \"These options will let you set some details\",\n    \"optional\": true,\n    \"fields\": [\n      {\n        \"name\": \"startingPosition\",\n        \"type\": \"number\",\n        \"label\": \"Slider start position in %\",\n        \"description\": \"Sets the start position of the slider\",\n        \"default\": 50,\n        \"min\": 0,\n        \"max\": 100,\n        \"optional\": false\n      },\n      {\n        \"name\": \"sliderOrientation\",\n        \"type\": \"select\",\n        \"label\": \"Slider orientation\",\n        \"description\": \"Horizontal will move left and right, vertical will move up and down.\",\n        \"options\": [\n          {\n            \"value\": \"horizontal\",\n            \"label\": \"Horizontal\"\n          },\n          {\n            \"value\": \"vertical\",\n            \"label\": \"Vertical\"\n          }\n        ],\n        \"default\": \"horizontal\"\n      },\n      {\n        \"name\": \"sliderColor\",\n        \"type\": \"text\",\n        \"label\": \"Slider color\",\n        \"importance\": \"medium\",\n        \"optional\": true,\n        \"default\": \"#f3f3f3\",\n        \"widget\": \"colorSelector\",\n        \"spectrum\": {\n          \"showInput\": true\n        }\n      }\n    ]\n  },\n  {\n    \"name\": \"a11y\",\n    \"type\": \"group\",\n    \"label\": \"Accessibility texts\",\n    \"common\": true,\n    \"fields\": [\n      {\n        \"name\": \"imageVisibleMessage\",\n        \"type\": \"text\",\n        \"label\": \"Image visible message\",\n        \"default\": \"Image @percentage % visible\",\n        \"description\": \"@percentage is a placeholder and will be replaced with the respective value.\"\n      },\n      {\n        \"name\": \"Dummy\",\n        \"type\": \"text\",\n        \"label\": \"Dummy\",\n        \"widget\": \"none\"\n      }\n    ]\n  }\n]\n', NULL, 1, 15, NULL, NULL, 'https://h5p.org/image-juxtaposition', 1),
(98, 'H5P.SpeakTheWords', 'Speak the Words', 1, 5, 7, 1, 0, 'iframe', 'dist/h5p-speak-the-words.js', 'dist/h5p-speak-the-words.css', '', '[\n  {\n    \"name\": \"media\",\n    \"type\": \"group\",\n    \"label\": \"Media\",\n    \"importance\": \"medium\",\n    \"fields\": [\n      {\n        \"name\": \"type\",\n        \"type\": \"library\",\n        \"label\": \"Type\",\n        \"importance\": \"medium\",\n        \"options\": [\n          \"H5P.Image 1.1\",\n          \"H5P.Video 1.6\",\n          \"H5P.Audio 1.5\"\n        ],\n        \"optional\": true,\n        \"description\": \"Optional media to display above the question.\"\n      },\n      {\n        \"name\": \"disableImageZooming\",\n        \"type\": \"boolean\",\n        \"label\": \"Disable image zooming\",\n        \"importance\": \"low\",\n        \"default\": false,\n        \"optional\": true,\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"type\",\n              \"equals\": \"H5P.Image 1.1\"\n            }\n          ]\n        }\n      }\n    ]\n  },\n  {\n    \"name\": \"question\",\n    \"label\": \"Describe task\",\n    \"type\": \"text\",\n    \"placeholder\": \"How do you say \'Yes\' in Spanish?\"\n  },\n  {\n    \"name\": \"acceptedAnswers\",\n    \"label\": \"Accepted answers\",\n    \"type\": \"list\",\n    \"min\": 1,\n    \"field\": {\n      \"name\": \"acceptedAnswer\",\n      \"label\": \"Accepted answer\",\n      \"type\": \"text\"\n    }\n  },\n  {\n    \"name\": \"incorrectAnswerText\",\n    \"label\": \"Incorrect answer text\",\n    \"type\": \"text\",\n    \"default\": \"Incorrect answer\"\n  },\n  {\n    \"name\": \"correctAnswerText\",\n    \"label\": \"Correct answer text\",\n    \"type\": \"text\",\n    \"default\": \"Correct answer\"\n  },\n  {\n    \"name\": \"inputLanguage\",\n    \"label\": \"Language of speech input\",\n    \"type\": \"select\",\n    \"options\": [\n      {\n        \"label\": \"Afrikaans\",\n        \"value\": \"af-ZA\"\n      },\n      {\n        \"label\": \"Amharic\",\n        \"value\": \"am-ET\"\n      },\n      {\n        \"label\": \"Arabic (Algeria)\",\n        \"value\": \"ar-DZ\"\n      },\n      {\n        \"label\": \"Arabic (Bahrain)\",\n        \"value\": \"ar-BH\"\n      },\n      {\n        \"label\": \"Arabic (Egypt)\",\n        \"value\": \"ar-EG\"\n      },\n      {\n        \"label\": \"Arabic (Iraq)\",\n        \"value\": \"ar-IQ\"\n      },\n      {\n        \"label\": \"Arabic (Jordan)\",\n        \"value\": \"ar-JO\"\n      },\n      {\n        \"label\": \"Arabic (Kuwait)\",\n        \"value\": \"ar-KW\"\n      },\n      {\n        \"label\": \"Arabic (Lebanon)\",\n        \"value\": \"ar-LB\"\n      },\n      {\n        \"label\": \"Arabic (Lybia)\",\n        \"value\": \"ar-LY\"\n      },\n      {\n        \"label\": \"Arabic (Morocco)\",\n        \"value\": \"ar-MA\"\n      },\n      {\n        \"label\": \"Arabic (Oman)\",\n        \"value\": \"ar-OM\"\n      },\n      {\n        \"label\": \"Arabic (Qatar)\",\n        \"value\": \"ar-QA\"\n      },\n      {\n        \"label\": \"Arabic (Saudi Arabia)\",\n        \"value\": \"ar-SA\"\n      },\n      {\n        \"label\": \"Arabic (Tunisia)\",\n        \"value\": \"ar-TN\"\n      },\n      {\n        \"label\": \"Arabic (UAE)\",\n        \"value\": \"ar-AE\"\n      },\n      {\n        \"label\": \"Arabic (Yemen)\",\n        \"value\": \"ar-YE\"\n      },\n      {\n        \"label\": \"Armenian\",\n        \"value\": \"hy-AM\"\n      },\n      {\n        \"label\": \"Azerbaijani\",\n        \"value\": \"az-AZ\"\n      },\n      {\n        \"label\": \"Basque\",\n        \"value\": \"eu-ES\"\n      },\n      {\n        \"label\": \"Bengali (Bangladesh)\",\n        \"value\": \"bn-BD\"\n      },\n      {\n        \"label\": \"Bengali (India)\",\n        \"value\": \"bn-IN\"\n      },\n      {\n        \"label\": \"Bulgarian\",\n        \"value\": \"bg-BG\"\