(99, 'H5P.Agamotto', 'Agamotto', 1, 6, 11, 1, 0, 'iframe', 'dist/h5p-agamotto.js', 'dist/h5p-agamotto.css', '', '[\n  {\n    \"name\": \"title\",\n    \"label\": \"Heading\",\n    \"importance\": \"high\",\n    \"type\": \"text\",\n    \"optional\": true,\n    \"placeholder\": \"Here you can add an optional heading.\",\n    \"description\": \"The heading you\'d like to show above the image\"\n  },\n  {\n    \"name\": \"items\",\n    \"type\": \"list\",\n    \"label\": \"Items\",\n    \"entity\": \"item\",\n    \"widgets\": [\n      {\n        \"name\": \"VerticalTabs\",\n        \"label\": \"Default\"\n      }\n    ],\n    \"importance\": \"medium\",\n    \"min\": 2,\n    \"max\": 50,\n    \"field\": {\n      \"name\": \"item\",\n      \"type\": \"group\",\n      \"label\": \"Item\",\n      \"importance\": \"low\",\n      \"expanded\": true,\n      \"fields\": [\n        {\n          \"name\": \"image\",\n          \"type\": \"library\",\n          \"label\": \"Image\",\n          \"importance\": \"low\",\n          \"options\": [\n            \"H5P.Image 1.1\"\n          ],\n          \"optional\": false\n        },\n        {\n          \"name\": \"labelText\",\n          \"label\": \"Label\",\n          \"importance\": \"low\",\n          \"type\": \"text\",\n          \"optional\": true,\n          \"description\": \"Optional label for a tick. Please make sure it\'s not too long, or it will be hidden.\"\n        },\n        {\n          \"name\": \"description\",\n          \"type\": \"text\",\n          \"importance\": \"low\",\n          \"widget\": \"html\",\n          \"label\": \"Description\",\n          \"optional\": true,\n          \"placeholder\": \"My image description ...\",\n          \"description\": \"Optional description for the image\",\n          \"enterMode\": \"p\",\n          \"tags\": [\n            \"strong\",\n            \"em\",\n            \"sub\",\n            \"sup\",\n            \"h3\",\n            \"h4\",\n            \"ul\",\n            \"ol\",\n            \"a\",\n            \"pre\",\n            \"code\"\n          ]\n        },\n        {\n          \"name\": \"audio\",\n          \"type\": \"audio\",\n          \"importance\": \"low\",\n          \"label\": \"Audio\",\n          \"description\": \"Optional audio that plays when an image is shown.\",\n          \"optional\": true,\n          \"widgetExtensions\": [\n            \"AudioRecorder\"\n          ]\n        }\n      ]\n    }\n  },\n  {\n    \"name\": \"behaviour\",\n    \"type\": \"group\",\n    \"label\": \"Behavioural settings\",\n    \"importance\": \"low\",\n    \"description\": \"These options will let you control how the task behaves.\",\n    \"fields\": [\n      {\n        \"name\": \"startImage\",\n        \"importance\": \"medium\",\n        \"type\": \"number\",\n        \"label\": \"Start image\",\n        \"description\": \"Set the number of the image to start with.\",\n        \"default\": 1,\n        \"min\": 1,\n        \"max\": 50\n      },\n      {\n        \"name\": \"snap\",\n        \"importance\": \"medium\",\n        \"type\": \"boolean\",\n        \"label\": \"Snap slider\",\n        \"description\": \"If activated, the slider will snap to an image\'s position.\",\n        \"default\": true\n      },\n      {\n        \"name\": \"ticks\",\n        \"importance\": \"medium\",\n        \"type\": \"boolean\",\n        \"label\": \"Display tick marks\",\n        \"description\": \"If activated, the slider bar will display a tick mark for each image.\",\n        \"default\": false\n      },\n      {\n        \"name\": \"labels\",\n        \"importance\": \"medium\",\n        \"type\": \"boolean\",\n        \"label\": \"Display labels\",\n        \"description\": \"If activated, the slider bar will display a label instead of/in addition to tick marks.\",\n        \"default\": false\n      },\n      {\n        \"name\": \"transparencyReplacementColor\",\n        \"importance\": \"medium\",\n        \"type\": \"text\",\n        \"label\": \"Transparency Replacement Color\",\n        \"description\": \"Set the color that will replace transparent areas of the images.\",\n        \"optional\": true,\n        \"default\": \"#000000\",\n        \"widget\": \"colorSelector\",\n        \"spectrum\": {\n          \"showInput\": true\n        }\n      },\n      {\n        \"name\": \"imagesDescriptionsRatio\",\n        \"importance\": \"medium\",\n        \"type\": \"number\",\n        \"label\": \"Image space in fullscreen mode\",\n        \"description\": \"If you have descriptions in addition to the images, set the the percentage of space that the images should use in fullscreen mode.\",\n        \"default\": 70,\n        \"min\": 50,\n        \"max\": 100\n      }\n    ]\n  },\n  {\n    \"name\": \"a11y\",\n    \"type\": \"group\",\n    \"common\": true,\n    \"label\": \"Readspeaker\",\n    \"importance\": \"low\",\n    \"fields\": [\n      {\n        \"name\": \"image\",\n        \"type\": \"text\",\n        \"label\": \"Image\",\n        \"importance\": \"low\",\n        \"default\": \"Image\"\n      },\n      {\n        \"name\": \"imageSlider\",\n        \"type\": \"text\",\n        \"label\": \"Image Slider\",\n        \"importance\": \"low\",\n        \"default\": \"Image Slider\"\n      },\n      {\n        \"name\": \"mute\",\n        \"type\": \"text\",\n        \"label\": \"Mute title\",\n        \"importance\": \"low\",\n        \"default\": \"Mute, currently unmuted\"\n      },\n      {\n        \"name\": \"unmute\",\n        \"type\": \"text\",\n        \"label\": \"Unmute title\",\n        \"importance\": \"low\",\n        \"default\": \"Unmute, currently muted\"\n      },\n      {\n        \"name\": \"buttonFullscreenEnter\",\n        \"type\": \"text\",\n        \"label\": \"Title for fullscreen button (enter)\",\n        \"importance\": \"low\",\n        \"default\": \"Enter fullscreen mode\"\n      },\n      {\n        \"name\": \"buttonFullscreenExit\",\n        \"type\": \"text\",\n        \"label\": \"Title for fullscreen button (exit)\",\n        \"importance\": \"low\",\n        \"default\": \"Exit fullscreen mode\"\n      }\n    ]\n  }\n]\n', NULL, 1, 27, NULL, 'https://h5p.org/agamotto-tutorial', 'https://h5p.org/node/79243', 1),
