(101, 'H5P.Audio', 'Audio', 1, 2, 14, 1, 0, 'iframe', 'scripts/audio.js', 'styles/audio.css', '', '[\n  {\n    \"name\": \"files\",\n    \"type\": \"audio\",\n    \"importance\": \"high\",\n    \"label\": \"Source files\"\n  },\n  {\n    \"name\": \"playerMode\",\n    \"type\": \"select\",\n    \"importance\": \"low\",\n    \"label\": \"Player mode\",\n    \"description\": \"Select the layout of the player.\",\n    \"options\": [\n      {\n        \"value\": \"minimalistic\",\n        \"label\": \"Minimalistic\"\n      },\n      {\n        \"value\": \"full\",\n        \"label\": \"Full\"\n      },\n      {\n        \"value\": \"transparent\",\n        \"label\": \"Transparent\"\n      }\n    ],\n    \"default\": \"minimalistic\"\n  },\n  {\n    \"name\": \"fitToWrapper\",\n    \"type\": \"boolean\",\n    \"importance\": \"low\",\n    \"label\": \"Fit to wrapper\",\n    \"default\": false,\n    \"descriptions\": \"Adjust audioplayer size to use available space\"\n  },\n  {\n    \"name\": \"controls\",\n    \"type\": \"boolean\",\n    \"importance\": \"low\",\n    \"label\": \"Enable controls\",\n    \"default\": true,\n    \"description\": \"Controls allow the user to for instance pause the audio\"\n  },\n  {\n    \"name\": \"autoplay\",\n    \"type\": \"boolean\",\n    \"importance\": \"low\",\n    \"label\": \"Enable autoplay\",\n    \"description\": \"With autoplay the audio starts to play immediately. If autoplay is disabled the user presses a play button to start the audio.\"\n  },\n  {\n    \"name\": \"copyright\",\n    \"type\": \"group\",\n    \"importance\": \"low\",\n    \"label\": \"Copyright information\",\n    \"deprecated\": true,\n    \"optional\": true,\n    \"fields\": [\n      {\n        \"name\": \"title\",\n        \"type\": \"text\",\n        \"label\": \"Title\",\n        \"placeholder\": \"FĂĽr Elise\",\n        \"optional\": true\n      },\n      {\n        \"name\": \"author\",\n        \"type\": \"text\",\n        \"label\": \"Author\",\n        \"placeholder\": \"Ludwig van Beethoven\",\n        \"optional\": true\n      },\n      {\n        \"name\": \"source\",\n        \"type\": \"text\",\n        \"label\": \"Source\",\n        \"placeholder\": \"http://en.wikipedia.org/wiki/F%C3%BCr_Elise\",\n        \"optional\": true,\n        \"regexp\": {\n          \"pattern\": \"^http[s]?://.+\",\n          \"modifiers\": \"i\"\n        }\n      },\n      {\n        \"name\": \"license\",\n        \"type\": \"select\",\n        \"label\": \"License\",\n        \"default\": \"U\",\n        \"options\": [\n          {\n            \"value\": \"U\",\n            \"label\": \"Undisclosed\"\n          },\n          {\n            \"value\": \"CC BY\",\n            \"label\": \"Attribution\"\n          },\n          {\n            \"value\": \"CC BY-SA\",\n            \"label\": \"Attribution-ShareAlike\"\n          },\n          {\n            \"value\": \"CC BY-ND\",\n            \"label\": \"Attribution-NoDerivs\"\n          },\n          {\n            \"value\": \"CC BY-NC\",\n            \"label\": \"Attribution-NonCommercial\"\n          },\n          {\n            \"value\": \"CC BY-NC-SA\",\n            \"label\": \"Attribution-NonCommercial-ShareAlike\"\n          },\n          {\n            \"value\": \"CC BY-NC-ND\",\n            \"label\": \"Attribution-NonCommercial-NoDerivs\"\n          },\n          {\n            \"value\": \"GNU GPL\",\n            \"label\": \"General Public License\"\n          },\n          {\n            \"value\": \"PD\",\n            \"label\": \"Public Domain\"\n          },\n          {\n            \"value\": \"ODC PDDL\",\n            \"label\": \"Public Domain Dedication and Licence\"\n          },\n          {\n            \"value\": \"CC PDM\",\n            \"label\": \"Public Domain Mark\"\n          },\n          {\n            \"value\": \"C\",\n            \"label\": \"Copyright\"\n          }\n        ]\n      }\n    ]\n  },\n  {\n    \"name\": \"contentName\",\n    \"type\": \"text\",\n    \"importance\": \"low\",\n    \"label\": \"Audio content name\",\n    \"common\": true,\n    \"default\": \"Audio\"\n  },\n  {\n    \"name\": \"audioNotSupported\",\n    \"type\": \"text\",\n    \"label\": \"Audio not supported message\",\n    \"importance\": \"low\",\n    \"common\": true,\n    \"default\": \"Your browser does not support this audio\"\n  }\n]', NULL, 1, 4, NULL, NULL, NULL, 1);
