(102, 'H5P.ImageSequencing', 'Image Sequencing', 1, 1, 0, 1, 0, 'iframe', 'scripts/h5p-image-sequencing.js, scripts/h5p-image-sequencing-card.js, scripts/h5p-image-sequencing-counter.js, scripts/h5p-image-sequencing-timer.js', 'styles/h5p-image-sequencing.css', '', '[\n  {\n    \"label\": \"Task Description\",\n    \"name\": \"taskDescription\",\n    \"type\": \"text\",\n    \"default\": \"Drag to arrange the images in the correct sequence\",\n    \"description\": \"A guide telling the user how to solve this task.\",\n    \"importance\": \"high\"\n  },\n  {\n    \"label\": \"Alternate Task Description\",\n    \"name\": \"altTaskDescription\",\n    \"type\": \"text\",\n    \"default\": \"Make the following list be ordered correctly. Use the cursor keys to navigate through the list items, use space to activate or deactivate an item and the cursor keys to move it\",\n    \"description\": \"A guide intended for visually impaired users on how to solve this task.\",\n    \"importance\": \"high\"\n  },\n  {\n    \"name\": \"sequenceImages\",\n    \"type\": \"list\",\n    \"widgets\": [\n      {\n        \"name\": \"VerticalTabs\",\n        \"label\": \"Default\"\n      }\n    ],\n    \"label\": \"Images\",\n    \"importance\": \"high\",\n    \"entity\": \"image\",\n    \"min\": 3,\n    \"field\": {\n      \"type\": \"group\",\n      \"name\": \"imageElement\",\n      \"label\": \"Image Element\",\n      \"importance\": \"high\",\n      \"fields\": [\n        {\n          \"name\": \"image\",\n          \"type\": \"image\",\n          \"label\": \"Image\",\n          \"importance\": \"high\"\n        },\n        {\n          \"name\": \"imageDescription\",\n          \"type\": \"text\",\n          \"label\": \"Image Description\",\n          \"importance\": \"low\",\n          \"description\": \"An image description for users who cannot recognize the image\"\n        },\n        {\n          \"name\": \"audio\",\n          \"description\": \"An optional audio for the card to play\",\n          \"type\": \"audio\",\n          \"label\": \"Audio files\",\n          \"importance\": \"low\",\n          \"optional\": true\n        }\n      ]\n    }\n  },\n  {\n    \"name\": \"behaviour\",\n    \"type\": \"group\",\n    \"label\": \"Behavioural settings\",\n    \"importance\": \"low\",\n    \"description\": \"These options will let you control how the game behaves.\",\n    \"optional\": true,\n    \"fields\": [\n      {\n        \"name\": \"enableSolution\",\n        \"type\": \"boolean\",\n        \"label\": \"Add a show solution button for the game\",\n        \"importance\": \"low\",\n        \"default\": true\n      },\n      {\n        \"name\": \"enableRetry\",\n        \"type\": \"boolean\",\n        \"label\": \"Add button for retrying when the game is over\",\n        \"importance\": \"low\",\n        \"default\": true\n      },\n      {\n        \"name\": \"enableResume\",\n        \"type\": \"boolean\",\n        \"label\": \"Add button for resuming from the current state \",\n        \"importance\": \"low\",\n        \"default\": true\n      }\n    ]\n  },\n  {\n    \"label\": \"Localization\",\n    \"importance\": \"low\",\n    \"name\": \"l10n\",\n    \"type\": \"group\",\n    \"common\": true,\n    \"fields\": [\n      {\n        \"label\": \"Total Moves text\",\n        \"importance\": \"low\",\n        \"name\": \"totalMoves\",\n        \"type\": \"text\",\n        \"default\": \"Total Moves\"\n      },\n      {\n        \"label\": \"Time spent text\",\n        \"importance\": \"low\",\n        \"name\": \"timeSpent\",\n        \"type\": \"text\",\n        \"default\": \"Time spent\"\n      },\n      {\n        \"label\": \"Feedback text\",\n        \"importance\": \"low\",\n        \"name\": \"score\",\n        \"type\": \"text\",\n        \"default\": \"You got @score of @total points\",\n        \"description\": \"Feedback text, variables available: @score and @total. Example: \'You got @score of @total possible points\'\"\n      },\n      {\n        \"label\": \"Text for \\\"Check\\\" button\",\n        \"importance\": \"low\",\n        \"name\": \"checkAnswer\",\n        \"type\": \"text\",\n        \"default\": \"Check\"\n      },\n      {\n        \"label\": \"Text for \\\"Retry\\\" button\",\n        \"importance\": \"low\",\n        \"name\": \"tryAgain\",\n        \"type\": \"text\",\n        \"default\": \"Retry\"\n      },\n      {\n        \"label\": \"Text for \\\"Show Solution\\\" button\",\n        \"importance\": \"low\",\n        \"name\": \"showSolution\",\n        \"type\": \"text\",\n        \"default\": \"ShowSolution\"\n      },\n      {\n        \"label\": \"Text for \\\"Resume\\\" button\",\n        \"importance\": \"low\",\n        \"name\": \"resume\",\n        \"type\": \"text\",\n        \"default\": \"Resume\"\n      },\n      {\n        \"name\": \"audioNotSupported\",\n        \"type\": \"text\",\n        \"label\": \"Audio not supported message\",\n        \"importance\": \"low\",\n        \"common\": true,\n        \"default\": \"Audio Error\"\n      },\n      {\n        \"name\": \"ariaPlay\",\n        \"type\": \"text\",\n        \"label\": \"Play button (text for readspeakers)\",\n        \"importance\": \"low\",\n        \"common\": true,\n        \"default\": \"Play the corresponding audio\"\n      },\n      {\n        \"name\": \"ariaMoveDescription\",\n        \"type\": \"text\",\n        \"label\": \"Card moving description (text for readspeakers)\",\n        \"description\": \"@posSrc : card initial position, @posDes : card final position\",\n        \"importance\": \"low\",\n        \"common\": true,\n        \"default\": \"Moved @cardDesc from @posSrc to @posDes\"\n      },\n      {\n        \"name\": \"ariaCardDesc\",\n        \"type\": \"text\",\n        \"label\": \"Default Card Description (text for readspeakers)\",\n        \"importance\": \"low\",\n        \"common\": true,\n        \"default\": \"sequencing item\"\n      }\n    ]\n  }\n]\n', NULL, NULL, NULL, NULL, 'https://h5p.org/tutorial-image-sequencing', 'https://h5p.org/content-types/image-sequencing', 1),
(103, 'H5P.Flashcards', 'Flashcards', 1, 7, 10, 1, 0, 'iframe', 'js/xapi.js, js/flashcards.js', 'css/flashcards.css', '', '[\n  {\n    \"name\": \"description\",\n    \"type\": \"text\",\n    \"label\": \"Task description\",\n    \"importance\": \"high\"\n  },\n  {\n    \"name\": \"cards\",\n    \"type\": \"list\",\n    \"widgets\": [\n      {\n        \"name\": \"VerticalTabs\",\n        \"label\": \"Default\"\n      }\n    ],\n    \"label\": \"Cards\",\n    \"entity\": \"card\",\n    \"importance\": \"high\",\n    \"min\": 1,\n    \"defaultNum\": 1,\n    \"field\": {\n      \"name\": \"card\",\n      \"type\": \"group\",\n      \"label\": \"Card\",\n      \"importance\": \"high\",\n      \"fields\": [\n        {\n          \"name\": \"text\",\n          \"type\": \"text\",\n          \"label\": \"Question\",\n          \"importance\": \"high\",\n          \"optional\": true,\n          \"description\": \"Optional textual question for the card. (The card may use just an image, just a text or both)\"\n        },\n        {\n          \"name\": \"answer\",\n          \"type\": \"text\",\n          \"label\": \"Answer\",\n          \"importance\": \"high\",\n          \"optional\": true,\n          \"description\": \"Answer (solution) for the card. Use a forward slash / to split alternative solutions. Use \\\\/ if a solution should contain a /.\"\n        },\n        {\n          \"name\": \"image\",\n          \"type\": \"image\",\n          \"label\": \"Image\",\n          \"importance\": \"high\",\n          \"optional\": true,\n          \"description\": \"Optional image for the card. (The card may use just an image, just a text or both)\"\n        },\n        {\n          \"name\": \"imageAltText\",\n          \"type\": \"text\",\n          \"label\": \"Alternative text for image\",\n          \"importance\": \"high\",\n          \"optional\": true\n        },\n        {\n          \"name\": \"tip\",\n          \"type\": \"group\",\n          \"label\": \"Tip\",\n          \"importance\": \"low\",\n          \"optional\": true,\n          \"fields\": [\n            {\n              \"name\": \"tip\",\n              \"label\": \"Tip text\",\n              \"importance\": \"low\",\n              \"type\": \"text\",\n              \"widget\": \"html\",\n              \"tags\": [\n                \"p\",\n                \"br\",\n                \"strong\",\n                \"em\",\n                \"code\"\n              ],\n              \"optional\": true\n            }\n          ]\n        }\n      ]\n    }\n  },\n  {\n    \"label\": \"Progress text\",\n    \"name\": \"progressText\",\n    \"type\": \"text\",\n    \"default\": \"Card @card of @total\",\n    \"importance\": \"low\",\n    \"description\": \"Progress text, variables available: @card and @total. Example: \'Card @card of @total\'\",\n    \"common\": true\n  },\n  {\n    \"label\": \"Text for the next button\",\n    \"name\": \"next\",\n    \"type\": \"text\",\n    \"default\": \"Next\",\n    \"importance\": \"low\",\n    \"common\": true\n  },\n  {\n    \"label\": \"Text for the previous button\",\n    \"name\": \"previous\",\n    \"type\": \"text\",\n    \"default\": \"Previous\",\n    \"importance\": \"low\",\n    \"common\": true\n  },\n  {\n    \"label\": \"Text for the check answers button\",\n    \"name\": \"checkAnswerText\",\n    \"type\": \"text\",\n    \"default\": \"Check\",\n    \"importance\": \"low\",\n    \"common\": true\n  },\n  {\n    \"label\": \"Require user input before the solution can be viewed\",\n    \"name\": \"showSolutionsRequiresInput\",\n    \"type\": \"boolean\",\n    \"default\": true,\n    \"importance\": \"low\",\n    \"optional\": true\n  },\n  {\n    \"label\": \"Text for the answer input field\",\n    \"name\": \"defaultAnswerText\",\n    \"type\": \"text\",\n    \"default\": \"Your answer\",\n    \"importance\": \"low\",\n    \"common\": true\n  },\n  {\n    \"label\": \"Text for correct answer\",\n    \"name\": \"correctAnswerText\",\n    \"type\": \"text\",\n    \"default\": \"Correct\",\n    \"importance\": \"low\",\n    \"common\": true\n  },\n  {\n    \"label\": \"Text for incorrect answer\",\n    \"name\": \"incorrectAnswerText\",\n    \"type\": \"text\",\n    \"default\": \"Incorrect\",\n    \"importance\": \"low\",\n    \"common\": true\n  },\n  {\n    \"label\": \"Show solution text\",\n    \"name\": \"showSolutionText\",\n    \"type\": \"text\",\n    \"default\": \"Correct answer(s)\",\n    \"importance\": \"low\",\n    \"common\": true\n  },\n  {\n    \"label\": \"Text for results title\",\n    \"name\": \"results\",\n    \"type\": \"text\",\n    \"default\": \"Results\",\n    \"importance\": \"low\",\n    \"common\": true\n  },\n  {\n    \"label\": \"Text for number of correct\",\n    \"name\": \"ofCorrect\",\n    \"type\": \"text\",\n    \"default\": \"@score of @total correct\",\n    \"importance\": \"low\",\n    \"description\": \"Result text, variables available: @score and @total. Example: \'@score of @total correct\'\",\n    \"common\": true\n  },\n  {\n    \"label\": \"Text for show results\",\n    \"name\": \"showResults\",\n    \"type\": \"text\",\n    \"default\": \"Show results\",\n    \"importance\": \"low\",\n    \"common\": true\n  },\n  {\n    \"label\": \"Text for short answer label\",\n    \"name\": \"answerShortText\",\n    \"type\": \"text\",\n    \"default\": \"A:\",\n    \"importance\": \"low\",\n    \"common\": true\n  },\n  {\n    \"label\": \"Text for \\\"retry\\\" button\",\n    \"name\": \"retry\",\n    \"type\": \"text\",\n    \"default\": \"Retry\",\n    \"importance\": \"low\",\n    \"common\": true\n  },\n  {\n    \"label\": \"Case sensitive\",\n    \"name\": \"caseSensitive\",\n    \"type\": \"boolean\",\n    \"default\": false,\n    \"description\": \"Makes sure the user input has to be exactly the same as the answer.\"\n  },\n  {\n    \"label\": \"Incorrect text for assistive technologies\",\n    \"name\": \"cardAnnouncement\",\n    \"type\": \"text\",\n    \"default\": \"Incorrect answer. Correct answer was @answer\",\n    \"description\": \"Text that will be announced to assistive technologies. Use @answer as variable.\",\n    \"common\": true\n  },\n  {\n    \"label\": \"Correct feedback text for assistive technologies\",\n    \"name\": \"correctAnswerAnnouncement\",\n    \"type\": \"text\",\n    \"default\": \"@answer is correct.\",\n    \"description\": \"Text that will be announced to assistive technologies when a card is answered correctly. Use @answer as variable.\",\n    \"common\": true\n  },\n  {\n    \"label\": \"Card change for assistive technologies\",\n    \"name\": \"pageAnnouncement\",\n    \"type\": \"text\",\n    \"default\": \"Page @current of @total\",\n    \"description\": \"Text that will be announced to assistive technologies when navigating between cards. Use @current and @total as variables.\",\n    \"common\": true\n  },\n  {\n    \"name\": \"randomCards\",\n    \"type\": \"boolean\",\n    \"label\": \"Randomize cards\",\n    \"importance\": \"low\",\n    \"description\": \"Enable to randomize the order of cards on display.\",\n    \"default\": false\n  }\n]\n', NULL, 1, 4, NULL, 'https://h5p.org/tutorial-flashcards', 'https://h5p.org/flashcards', 1),
(104, 'H5P.SpeakTheWordsSet', 'Speak the Words Set', 1, 3, 4, 1, 0, 'iframe', 'dist/dist.js', '', '', '[\n  {\n    \"name\": \"introduction\",\n    \"label\": \"Introduction\",\n    \"type\": \"group\",\n    \"fields\": [\n      {\n        \"name\": \"showIntroPage\",\n        \"type\": \"boolean\",\n        \"optional\": true,\n        \"default\": false,\n        \"label\": \"Display introduction\",\n        \"importance\": \"low\"\n      },\n      {\n        \"name\": \"introductionImage\",\n        \"type\": \"image\",\n        \"label\": \"Introduction image\",\n        \"optional\": true,\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"showIntroPage\",\n              \"equals\": true\n            }\n          ]\n        }\n      },\n      {\n        \"name\": \"introductionImageAltText\",\n        \"type\": \"text\",\n        \"label\": \"Alternative text for introduction image\",\n        \"optional\": true,\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"showIntroPage\",\n              \"equals\": true\n            }\n          ]\n        }\n      },\n      {\n        \"name\": \"introductionTitle\",\n        \"type\": \"text\",\n        \"label\": \"Title\",\n        \"optional\": true,\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"showIntroPage\",\n              \"equals\": true\n            }\n          ]\n        }\n      },\n      {\n        \"name\": \"introductionText\",\n        \"type\": \"text\",\n        \"label\": \"Introduction text\",\n        \"optional\": true,\n        \"description\": \"This title will be displayed above the introduction text.\",\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"widget\": \"html\",\n          \"rules\": [\n            {\n              \"field\": \"showIntroPage\",\n              \"equals\": true\n            }\n          ]\n        },\n        \"tags\": [\n          \"sub\",\n          \"sup\",\n          \"strong\",\n          \"em\",\n          \"code\"\n        ]\n      }\n    ]\n  },\n  {\n    \"name\": \"questions\",\n    \"label\": \"Questions\",\n    \"importance\": \"high\",\n    \"type\": \"list\",\n    \"widgets\": [\n      {\n        \"name\": \"VerticalTabs\",\n        \"label\": \"Default\"\n      }\n    ],\n    \"min\": 1,\n    \"entity\": \"Question\",\n    \"field\": {\n      \"name\": \"question\",\n      \"type\": \"library\",\n      \"label\": \"Question\",\n      \"importance\": \"high\",\n      \"options\": [\n        \"H5P.SpeakTheWords 1.5\"\n      ]\n    }\n  },\n  {\n    \"name\": \"overallFeedback\",\n    \"type\": \"group\",\n    \"label\": \"Overall Feedback\",\n    \"importance\": \"low\",\n    \"expanded\": true,\n    \"fields\": [\n      {\n        \"name\": \"overallFeedback\",\n        \"type\": \"list\",\n        \"widgets\": [\n          {\n            \"name\": \"RangeList\",\n            \"label\": \"Default\"\n          }\n        ],\n        \"importance\": \"high\",\n        \"label\": \"Define custom feedback for any score range\",\n        \"description\": \"Click the \\\"Add range\\\" button to add as many ranges as you need. Example: 0-20% Bad score, 21-91% Average Score, 91-100% Great Score!\",\n        \"entity\": \"range\",\n        \"min\": 1,\n        \"defaultNum\": 1,\n        \"optional\": true,\n        \"field\": {\n          \"name\": \"overallFeedback\",\n          \"type\": \"group\",\n          \"importance\": \"low\",\n          \"fields\": [\n            {\n              \"name\": \"from\",\n              \"type\": \"number\",\n              \"label\": \"Score Range\",\n              \"min\": 0,\n              \"max\": 100,\n              \"default\": 0,\n              \"unit\": \"%\"\n            },\n            {\n              \"name\": \"to\",\n              \"type\": \"number\",\n              \"min\": 0,\n              \"max\": 100,\n              \"default\": 100,\n              \"unit\": \"%\"\n            },\n            {\n              \"name\": \"feedback\",\n              \"type\": \"text\",\n              \"label\": \"Feedback for defined score range\",\n              \"importance\": \"low\",\n              \"placeholder\": \"Fill in the feedback\",\n              \"optional\": true\n            }\n          ]\n        }\n      }\n    ]\n  },\n  {\n    \"name\": \"l10n\",\n    \"type\": \"group\",\n    \"label\": \"Speak The Words Set labels and texts\",\n    \"importance\": \"low\",\n    \"common\": true,\n    \"fields\": [\n      {\n        \"name\": \"introductionButtonLabel\",\n        \"label\": \"Introduction button label\",\n        \"type\": \"text\",\n        \"default\": \"Start Course!\"\n      },\n      {\n        \"name\": \"solutionScreenResultsLabel\",\n        \"label\": \"Solution screen results label\",\n        \"type\": \"text\",\n        \"default\": \"Your results:\"\n      },\n      {\n        \"name\": \"showSolutionsButtonLabel\",\n        \"label\": \"Show solutions button label\",\n        \"type\": \"text\",\n        \"default\": \"Show solution\"\n      },\n      {\n        \"name\": \"retryButtonLabel\",\n        \"label\": \"Retry button label\",\n        \"type\": \"text\",\n        \"default\": \"Retry\"\n      },\n      {\n        \"name\": \"finishButtonLabel\",\n        \"label\": \"Finish button label\",\n        \"type\": \"text\",\n        \"default\": \"Finish\"\n      },\n      {\n        \"name\": \"nextQuestionAriaLabel\",\n        \"label\": \"Next question accessibility label\",\n        \"type\": \"text\",\n        \"default\": \"Next question\"\n      },\n      {\n        \"name\": \"previousQuestionAriaLabel\",\n        \"label\": \"Previous question accessibility label\",\n        \"type\": \"text\",\n        \"default\": \"Previous question\"\n      },\n      {\n        \"name\": \"navigationBarTitle\",\n        \"label\": \"Navigation bar title\",\n        \"description\": \"Titles for questions in navigation bar. \\\":num\\\" will be replaced with the actual slide number.\",\n        \"type\": \"text\",\n        \"default\": \"Slide :num\"\n      },\n      {\n        \"name\": \"answeredSlideAriaLabel\",\n        \"label\": \"Answered slide accessibility label\",\n        \"type\": \"text\",\n        \"default\": \"Answered\"\n      },\n      {\n        \"name\": \"activeSlideAriaLabel\",\n        \"label\": \"Active slide accessibility label\",\n        \"type\": \"text\",\n        \"default\": \"Currently active\"\n      }\n    ]\n  }\n]\n', NULL, NULL, NULL, NULL, NULL, 'https://h5p.org/speak-the-words-set', 1),
(105, 'H5P.ImageSlide', 'Image Slide', 1, 1, 4, 0, 0, '', 'image-slide.js', 'image-slide.css', '', '[\n  {\n    \"label\": \"Image\",\n    \"name\": \"image\",\n    \"type\": \"library\",\n    \"options\": [\n      \"H5P.Image 1.1\"\n    ]\n  }\n]', NULL, NULL, NULL, NULL, NULL, NULL, 1),
(106, 'H5P.ImageSlider', 'Image Slider', 1, 1, 9, 1, 1, 'iframe', 'image-slider.js', 'image-slider.css', '', '[\n  {\n    \"label\": \"Images\",\n    \"name\": \"imageSlides\",\n    \"type\": \"list\",\n    \"field\": {\n      \"label\": \"Image Slide\",\n      \"name\": \"imageSlide\",\n      \"type\": \"group\",\n      \"fields\": [\n        {\n          \"label\": \"Image Slide\",\n          \"name\": \"imageSlide\",\n          \"type\": \"library\",\n          \"options\": [\n            \"H5P.ImageSlide 1.1\"\n          ]\n        }\n      ]\n    }\n  },\n  {\n    \"label\": \"Aspect ratio\",\n    \"name\": \"aspectRatioMode\",\n    \"type\": \"select\",\n    \"description\": \"Automatic means fixed aspect ratio automatically determined based on the images\",\n    \"default\": \"auto\",\n    \"options\": [\n      {\n        \"value\": \"auto\",\n        \"label\": \"Automatic\"\n      },\n      {\n        \"value\": \"custom\",\n        \"label\": \"Custom\"\n      },\n      {\n        \"value\": \"notFixed\",\n        \"label\": \"Not fixed\"\n      }\n    ]\n  },\n  {\n    \"label\": \"Aspect Ratio Settings\",\n    \"name\": \"aspectRatio\",\n    \"type\": \"group\",\n    \"widget\": \"showWhen\",\n    \"expanded\": true,\n    \"showWhen\": {\n      \"rules\": [\n        {\n          \"field\": \"aspectRatioMode\",\n          \"equals\": \"custom\"\n        }\n      ]\n    },\n    \"fields\": [\n      {\n        \"label\": \"Aspect ratio width\",\n        \"name\": \"aspectWidth\",\n        \"type\": \"number\",\n        \"default\": 4,\n        \"description\": \"If you use 4 here, and 3 for the height the aspect ratio will be 4:3\"\n      },\n      {\n        \"label\": \"Aspect ratio height\",\n        \"name\": \"aspectHeight\",\n        \"type\": \"number\",\n        \"default\": 3,\n        \"description\": \"If you use 3 here, and 4 for the width the aspect ratio will be 4:3\"\n      }\n    ]\n  },\n  {\n    \"name\": \"a11y\",\n    \"type\": \"group\",\n    \"label\": \"Image slider accessibility\",\n    \"importance\": \"low\",\n    \"common\": true,\n    \"fields\": [\n      {\n        \"name\": \"nextSlide\",\n        \"type\": \"text\",\n        \"label\": \"Label for next slide buttons\",\n        \"importance\": \"low\",\n        \"default\": \"Next Image\",\n        \"description\": \"This is only used for read-speakers. It won\'t be displayed.\"\n      },\n      {\n        \"name\": \"prevSlide\",\n        \"type\": \"text\",\n        \"label\": \"Label for previous slide buttons\",\n        \"importance\": \"low\",\n        \"default\": \"Previous Image\",\n        \"description\": \"This is only used for read-speakers. It won\'t be displayed.\"\n      },\n      {\n        \"name\": \"gotoSlide\",\n        \"type\": \"text\",\n        \"label\": \"Label for slide buttons\",\n        \"importance\": \"low\",\n        \"default\": \"Go to image %slide\",\n        \"description\": \"This is only used for read-speakers. It won\'t be displayed. %slide is a variable and will be replaced with the image number.\"\n      }\n    ]\n  }\n]', NULL, NULL, NULL, NULL, 'https://h5p.org/tutorial-image-slider', 'https://h5p.org/image-slider', 1),
(107, 'H5P.Essay', 'Essay', 1, 5, 13, 1, 0, 'iframe', 'scripts/essay.js, scripts/inputfield.js', 'styles/essay.css', '', '[\n  {\n    \"name\": \"media\",\n    \"type\": \"group\",\n    \"label\": \"Media\",\n    \"importance\": \"medium\",\n    \"fields\": [\n      {\n        \"name\": \"type\",\n        \"type\": \"library\",\n        \"label\": \"Type\",\n        \"importance\": \"medium\",\n        \"options\": [\n          \"H5P.Image 1.1\",\n          \"H5P.Video 1.6\",\n          \"H5P.Audio 1.5\"\n        ],\n        \"optional\": true,\n        \"description\": \"Optional media to display above the question.\"\n      },\n      {\n        \"name\": \"disableImageZooming\",\n        \"type\": \"boolean\",\n        \"label\": \"Disable image zooming\",\n        \"importance\": \"low\",\n        \"default\": false,\n        \"optional\": true,\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"type\",\n              \"equals\": \"H5P.Image 1.1\"\n            }\n          ]\n        }\n      }\n    ]\n  },\n  {\n    \"name\": \"taskDescription\",\n    \"label\": \"Task description\",\n    \"type\": \"text\",\n    \"widget\": \"html\",\n    \"importance\": \"high\",\n    \"description\": \"Describe your task here. The task description will appear above text input area.\",\n    \"placeholder\": \"Summarize the book in 500 characters ...\",\n    \"enterMode\": \"div\",\n    \"tags\": [\n      \"strong\",\n      \"em\",\n      \"u\",\n      \"a\",\n      \"ul\",\n      \"ol\",\n      \"h2\",\n      \"h3\",\n      \"hr\",\n      \"pre\",\n      \"code\"\n    ]\n  },\n  {\n    \"name\": \"placeholderText\",\n    \"label\": \"Help text\",\n    \"type\": \"text\",\n    \"description\": \"This text should help the user to get started.\",\n    \"placeholder\": \"This book is about ...\",\n    \"importance\": \"low\",\n    \"optional\": true\n  },\n  {\n    \"name\": \"solution\",\n    \"type\": \"group\",\n    \"label\": \"Sample solution\",\n    \"importance\": \"high\",\n    \"expanded\": true,\n    \"description\": \"You can optionally add a sample solution that\'s shown after the student created a text. It\'s called sample solution because there probably is not only one solution.\",\n    \"fields\": [\n      {\n        \"name\": \"introduction\",\n        \"type\": \"text\",\n        \"label\": \"Introduction\",\n        \"importance\": \"low\",\n        \"description\": \"You can optionally leave the students some explanations about your example. The explanation will only show up if you add an example, too.\",\n        \"placeholder\": \"Please remember that you were not expected to come up with the exact same solution. It\'s just a good example.\",\n        \"optional\": true,\n        \"widget\": \"html\",\n        \"enterMode\": \"div\",\n        \"tags\": [\n          \"strong\",\n          \"em\",\n          \"u\",\n          \"a\",\n          \"ul\",\n          \"ol\",\n          \"hr\",\n          \"code\"\n        ]\n      },\n      {\n        \"name\": \"sample\",\n        \"type\": \"text\",\n        \"label\": \"Sample solution text\",\n        \"importance\": \"low\",\n        \"description\": \"The student will see a \\\"Show solution\\\" button after submitting if you provide some text here.\",\n        \"optional\": true,\n        \"widget\": \"html\",\n        \"enterMode\": \"div\",\n        \"tags\": [\n          \"strong\",\n          \"a\"\n        ]\n      }\n    ]\n  },\n  {\n    \"name\": \"keywords\",\n    \"label\": \"Keywords\",\n    \"importance\": \"high\",\n    \"type\": \"list\",\n    \"widgets\": [\n      {\n        \"name\": \"VerticalTabs\",\n        \"label\": \"Default\"\n      }\n    ],\n    \"min\": 1,\n    \"entity\": \"Keyword\",\n    \"field\": {\n      \"name\": \"groupy\",\n      \"type\": \"group\",\n      \"label\": \"Keyword\",\n      \"fields\": [\n        {\n          \"name\": \"keyword\",\n          \"type\": \"text\",\n          \"label\": \"Keyword\",\n          \"description\": \"Keyword or phrase to look for. Use an asterisk \'*\' as a wildcard for one or more characters. Use a slash \'/\' at the beginning and the end to use a regular expression.\",\n          \"importance\": \"medium\"\n        },\n        {\n          \"name\": \"alternatives\",\n          \"type\": \"list\",\n          \"label\": \"Variations\",\n          \"description\": \"Add optional variations for this keyword. Example: For a \'city\' add alternatives \'town\', \'municipality\' etc. Points will be awarded if the user includes any of the specified alternatives.\",\n          \"importance\": \"medium\",\n          \"entity\": \"variation\",\n          \"optional\": true,\n          \"min\": 0,\n          \"field\": {\n            \"name\": \"alternative\",\n            \"type\": \"text\",\n            \"label\": \"Keyword variation\"\n          }\n        },\n        {\n          \"name\": \"options\",\n          \"type\": \"group\",\n          \"label\": \"Points, Options and Feedback\",\n          \"importance\": \"low\",\n          \"fields\": [\n            {\n              \"name\": \"points\",\n              \"type\": \"number\",\n              \"label\": \"Points\",\n              \"default\": 1,\n              \"description\": \"Points that the user will get if he/she includes this keyword or its alternatives in the answer.\",\n              \"min\": 0\n            },\n            {\n              \"name\": \"occurrences\",\n              \"type\": \"number\",\n              \"label\": \"Occurrences\",\n              \"default\": 1,\n              \"description\": \"Define how many occurrences of the keyword or its variations should be awarded with points.\",\n              \"min\": 1\n            },\n            {\n              \"name\": \"caseSensitive\",\n              \"type\": \"boolean\",\n              \"label\": \"Case sensitive\",\n              \"default\": true,\n              \"description\": \"Makes sure the user input has to be exactly the same as the answer.\"\n            },\n            {\n              \"name\": \"forgiveMistakes\",\n              \"type\": \"boolean\",\n              \"label\": \"Forgive minor mistakes\",\n              \"description\": \"This will accept minor spelling mistakes (3-9 characters: 1 mistake, more than 9 characters: 2 mistakes).\"\n            },\n            {\n              \"name\": \"feedbackIncluded\",\n              \"type\": \"text\",\n              \"label\": \"Feedback if keyword included\",\n              \"description\": \"This feedback will be displayed if the user includes this keyword or its alternatives in the answer.\",\n              \"optional\": true,\n              \"maxLength\": 1000\n            },\n            {\n              \"name\": \"feedbackMissed\",\n              \"type\": \"text\",\n              \"label\": \"Feedback if keyword missing\",\n              \"description\": \"This feedback will be displayed if the user doesnâ€™t include this keyword or its alternatives in the answer.\",\n              \"optional\": true,\n              \"maxLength\": 1000\n            },\n            {\n              \"name\": \"feedbackIncludedWord\",\n              \"type\": \"select\",\n              \"label\": \"Feedback word shown if keyword included\",\n              \"importance\": \"low\",\n              \"description\": \"This option allows you to specify which word should be shown in front of your feedback if a keyword was found in the text.\",\n              \"optional\": false,\n              \"default\": \"keyword\",\n              \"options\": [\n                {\n                  \"value\": \"keyword\",\n                  \"label\": \"keyword\"\n                },\n                {\n                  \"value\": \"alternative\",\n                  \"label\": \"alternative found\"\n                },\n                {\n                  \"value\": \"answer\",\n                  \"label\": \"answer given\"\n                },\n                {\n                  \"value\": \"none\",\n                  \"label\": \"none\"\n                }\n              ]\n            },\n            {\n              \"name\": \"feedbackMissedWord\",\n              \"type\": \"select\",\n              \"label\": \"Feedback word shown if keyword missing\",\n              \"importance\": \"low\",\n              \"description\": \"This option allows you to specify which word should be shown in front of your feedback if a keyword was not found in the text.\",\n              \"optional\": false,\n              \"default\": \"none\",\n              \"options\": [\n                {\n                  \"value\": \"keyword\",\n                  \"label\": \"keyword\"\n                },\n                {\n                  \"value\": \"none\",\n                  \"label\": \"none\"\n                }\n              ]\n            }\n          ]\n        }\n      ]\n    }\n  },\n  {\n    \"name\": \"overallFeedback\",\n    \"type\": \"group\",\n    \"label\": \"Overall Feedback\",\n    \"importance\": \"low\",\n    \"expanded\": true,\n    \"fields\": [\n      {\n        \"name\": \"overallFeedback\",\n        \"type\": \"list\",\n        \"widgets\": [\n          {\n            \"name\": \"RangeList\",\n            \"label\": \"Default\"\n          }\n        ],\n        \"importance\": \"high\",\n        \"label\": \"Define custom feedback for any score range\",\n        \"description\": \"Click the \\\"Add range\\\" button to add as many ranges as you need. Example: 0-20% Bad score, 21-91% Average Score, 91-100% Great Score!\",\n        \"entity\": \"range\",\n        \"min\": 1,\n        \"defaultNum\": 1,\n        \"optional\": true,\n        \"field\": {\n          \"name\": \"overallFeedback\",\n          \"type\": \"group\",\n          \"importance\": \"low\",\n          \"fields\": [\n            {\n              \"name\": \"from\",\n              \"type\": \"number\",\n              \"label\": \"Score Range\",\n              \"min\": 0,\n              \"max\": 100,\n              \"default\": 0,\n              \"unit\": \"%\"\n            },\n            {\n              \"name\": \"to\",\n              \"type\": \"number\",\n              \"min\": 0,\n              \"max\": 100,\n              \"default\": 100,\n              \"unit\": \"%\"\n            },\n            {\n              \"name\": \"feedback\",\n              \"type\": \"text\",\n              \"label\": \"Feedback for defined score range\",\n              \"importance\": \"low\",\n              \"placeholder\": \"Fill in the feedback\",\n              \"optional\": true\n            }\n          ]\n        }\n      }\n    ]\n  },\n  {\n    \"name\": \"behaviour\",\n    \"type\": \"group\",\n    \"label\": \"Behavioural settings\",\n    \"importance\": \"low\",\n    \"description\": \"These options will let you control how the task behaves.\",\n    \"fields\": [\n      {\n        \"name\": \"minimumLength\",\n        \"label\": \"Minimum number of characters\",\n        \"type\": \"number\",\n        \"description\": \"Specify the minimum number of characters that the user must enter.\",\n        \"importance\": \"low\",\n        \"optional\": true,\n        \"min\": \"0\"\n      },\n      {\n        \"name\": \"maximumLength\",\n        \"label\": \"Maximum number of characters\",\n        \"type\": \"number\",\n        \"description\": \"Specify the maximum number of characters that the user can enter.\",\n        \"importance\": \"low\",\n        \"optional\": true,\n        \"min\": \"0\"\n      },\n      {\n        \"name\": \"inputFieldSize\",\n        \"label\": \"Input field size\",\n        \"type\": \"select\",\n        \"importance\": \"low\",\n        \"description\": \"The size of the input field in amount of lines it will cover\",\n        \"options\": [\n          {\n            \"value\": \"1\",\n            \"label\": \"1 line\"\n          },\n          {\n            \"value\": \"3\",\n            \"label\": \"3 lines\"\n          },\n          {\n            \"value\": \"10\",\n            \"label\": \"10 lines\"\n          }\n        ],\n        \"default\": \"10\"\n      },\n      {\n        \"name\": \"enableRetry\",\n        \"label\": \"Enable \\\"Retry\\\"\",\n        \"type\": \"boolean\",\n        \"importance\": \"low\",\n        \"description\": \"If checked, learners can retry the task.\",\n        \"default\": true,\n        \"optional\": true\n      },\n      {\n        \"name\": \"ignoreScoring\",\n        \"label\": \"Ignore scoring\",\n        \"type\": \"boolean\",\n        \"importance\": \"low\",\n        \"description\": \"If checked, learners will only see the feedback that you provided for the keywords, but no score.\",\n        \"default\": false,\n        \"optional\": true\n      },\n      {\n        \"name\": \"pointsHost\",\n        \"label\": \"Points in host environment\",\n        \"type\": \"number\",\n        \"importance\": \"low\",\n        \"description\": \"Used to award points in host environment merely for answering (not shown to learner).\",\n        \"min\": 0,\n        \"default\": 1,\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"ignoreScoring\",\n              \"equals\": true\n            }\n          ]\n        }\n      },\n      {\n        \"name\": \"percentagePassing\",\n        \"type\": \"number\",\n        \"label\": \"Passing percentage\",\n        \"description\": \"Percentage that\'s necessary for passing\",\n        \"optional\": true,\n        \"min\": 0,\n        \"max\": 100,\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"ignoreScoring\",\n              \"equals\": false\n            }\n          ]\n        }\n      },\n      {\n        \"name\": \"percentageMastering\",\n        \"type\": \"number\",\n        \"label\": \"Mastering percentage\",\n        \"description\": \"Percentage that\'s necessary for mastering. Setting the mastering percentage below 100 % will lower the maximum possible score accordingly. It\'s intended to give some leeway to students, not to \\\"graciously accept\\\" solutions that do not contain all keywords.\",\n        \"optional\": true,\n        \"min\": 0,\n        \"max\": 100,\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"ignoreScoring\",\n              \"equals\": false\n            }\n          ]\n        }\n      },\n      {\n        \"name\": \"overrideCaseSensitive\",\n        \"type\": \"select\",\n        \"label\": \"Override case sensitive\",\n        \"importance\": \"low\",\n        \"description\": \"This option determines if the \\\"Case sensitive\\\" option will be activated for all keywords.\",\n        \"optional\": true,\n        \"options\": [\n          {\n            \"value\": \"on\",\n            \"label\": \"Enabled\"\n          },\n          {\n            \"value\": \"off\",\n            \"label\": \"Disabled\"\n          }\n        ]\n      },\n      {\n        \"name\": \"overrideForgiveMistakes\",\n        \"type\": \"select\",\n        \"label\": \"Override forgive mistakes\",\n        \"importance\": \"low\",\n        \"description\": \"This option determines if the \\\"Forgive mistakes\\\" option will be activated for all keywords.\",\n        \"optional\": true,\n        \"options\": [\n          {\n            \"value\": \"on\",\n            \"label\": \"Enabled\"\n          },\n          {\n            \"value\": \"off\",\n            \"label\": \"Disabled\"\n          }\n        ]\n      },\n      {\n        \"name\": \"linebreakReplacement\",\n        \"type\": \"select\",\n        \"label\": \"Replacement for line breaks\",\n        \"importance\": \"low\",\n        \"description\": \"By default, line breaks will be replaced with a space character. If you want to check for line breaks, e.g. in regular expressions, you can set a different replacement here.\",\n        \"options\": [\n          {\n            \"value\": \" \",\n            \"label\": \"space\"\n          },\n          {\n            \"value\": \"\\n\",\n            \"label\": \"line break (\\\\n)\"\n          }\n        ],\n        \"default\": \" \"\n      }\n    ]\n  },\n  {\n    \"name\": \"checkAnswer\",\n    \"type\": \"text\",\n    \"label\": \"Text for \\\"Check\\\" button\",\n    \"importance\": \"low\",\n    \"default\": \"Check\",\n    \"common\": true\n  },\n  {\n    \"name\": \"submitAnswer\",\n    \"type\": \"text\",\n    \"label\": \"Text for \\\"Submit\\\" button\",\n    \"importance\": \"low\",\n    \"default\": \"Submit\",\n    \"common\": true\n  },\n  {\n    \"name\": \"tryAgain\",\n    \"label\": \"Text for \\\"Retry\\\" button\",\n    \"type\": \"text\",\n    \"importance\": \"low\",\n    \"default\": \"Retry\",\n    \"common\": true\n  },\n  {\n    \"name\": \"showSolution\",\n    \"type\": \"text\",\n    \"label\": \"Text for \\\"Show solution\\\" button\",\n    \"importance\": \"low\",\n    \"default\": \"Show solution\",\n    \"common\": true\n  },\n  {\n    \"name\": \"feedbackHeader\",\n    \"type\": \"text\",\n    \"label\": \"Header for panel containing feedback for included/missing keywords\",\n    \"importance\": \"low\",\n    \"default\": \"Feedback\",\n    \"common\": true\n  },\n  {\n    \"name\": \"solutionTitle\",\n    \"type\": \"text\",\n    \"label\": \"Label for solution\",\n    \"importance\": \"low\",\n    \"default\": \"Sample solution\",\n    \"common\": true\n  },\n  {\n    \"name\": \"remainingChars\",\n    \"type\": \"text\",\n    \"label\": \"Remaining characters\",\n    \"importance\": \"low\",\n    \"common\": true,\n    \"default\": \"Remaining characters: @chars\",\n    \"description\": \"Message for remaining characters. You can use @chars which will be replaced by the corresponding number.\"\n  },\n  {\n    \"name\": \"notEnoughChars\",\n    \"type\": \"text\",\n    \"label\": \"Not enough characters\",\n    \"importance\": \"low\",\n    \"common\": true,\n    \"default\": \"You must enter at least @chars characters!\",\n    \"description\": \"Message to indicate that the text doesn\'t contain enough characters. You can use @chars which will be replaced by the corresponding number.\"\n  },\n  {\n    \"name\": \"messageSave\",\n    \"type\": \"text\",\n    \"label\": \"Save message\",\n    \"description\": \"Message indicating that the text has been saved\",\n    \"importance\": \"low\",\n    \"common\": true,\n    \"default\": \"saved\"\n  },\n  {\n    \"name\": \"ariaYourResult\",\n    \"type\": \"text\",\n    \"label\": \"Your result (not displayed)\",\n    \"description\": \"Accessibility text used for readspeakers. @score will be replaced by the number of points. @total will be replaced by the maximum possible points.\",\n    \"importance\": \"low\",\n    \"common\": true,\n    \"default\": \"You got @score out of @total points\"\n  },\n  {\n    \"name\": \"ariaNavigatedToSolution\",\n    \"type\": \"text\",\n    \"label\": \"Navigation message (not displayed)\",\n    \"description\": \"Accessibility text used for readspeakers\",\n    \"importance\": \"low\",\n    \"common\": true,\n    \"default\": \"Navigated to newly included sample solution after textarea.\"\n  },\n  {\n    \"name\": \"ariaCheck\",\n    \"type\": \"text\",\n    \"label\": \"Assistive technology description for \\\"Check\\\" button\",\n    \"importance\": \"low\",\n    \"common\": true,\n    \"default\": \"Check the answers.\"\n  },\n  {\n    \"name\": \"ariaShowSolution\",\n    \"type\": \"text\",\n    \"label\": \"Assistive technology description for \\\"Show Solution\\\" button\",\n    \"importance\": \"low\",\n    \"common\": true,\n    \"default\": \"Show the solution. You will be provided with a sample solution.\"\n  },\n  {\n    \"name\": \"ariaRetry\",\n    \"type\": \"text\",\n    \"label\": \"Assistive technology description for \\\"Retry\\\" button\",\n    \"importance\": \"low\",\n    \"common\": true,\n    \"default\": \"Retry the task. You can improve your previous answer if the author allowed that.\"\n  }\n]', NULL, 1, 27, NULL, 'https://h5p.org/tutorial-essay', 'https://h5p.org/content-types/essay', 1),
(108, 'H5P.ImagePair', 'Image Pair', 1, 4, 0, 1, 0, 'iframe', 'h5p-image-pair.js, h5p-image-pair-card.js', 'h5p-image-pair.css', '', '[\n  {\n    \"label\": \"Task Description\",\n    \"name\": \"taskDescription\",\n    \"type\": \"text\",\n    \"default\": \"Drag images from the left to match them with corresponding images on the right\",\n    \"description\": \"A guide telling the user how to solve this task.\",\n    \"importance\": \"high\"\n  },\n  {\n    \"name\": \"cards\",\n    \"type\": \"list\",\n    \"widgets\": [\n      {\n        \"name\": \"VerticalTabs\",\n        \"label\": \"Default\"\n      }\n    ],\n    \"label\": \"Cards\",\n    \"importance\": \"high\",\n    \"entity\": \"card\",\n    \"min\": 2,\n    \"max\": 100,\n    \"field\": {\n      \"type\": \"group\",\n      \"name\": \"card\",\n      \"label\": \"Card\",\n      \"importance\": \"high\",\n      \"fields\": [\n        {\n          \"name\": \"image\",\n          \"type\": \"image\",\n          \"label\": \"Image\",\n          \"importance\": \"high\",\n          \"ratio\": 1\n        },\n        {\n          \"name\": \"imageAlt\",\n          \"type\": \"text\",\n          \"label\": \"Alternative text for Image\",\n          \"importance\": \"high\",\n          \"description\": \"Describe what can be seen in the photo. The text is read by text-to-speech tools needed by visually impaired users.\"\n        },\n        {\n          \"name\": \"match\",\n          \"type\": \"image\",\n          \"label\": \"Matching Image\",\n          \"importance\": \"low\",\n          \"optional\": true,\n          \"description\": \"An optional image to match against instead of using two cards with the same image.\",\n          \"ratio\": 1\n        },\n        {\n          \"name\": \"matchAlt\",\n          \"type\": \"text\",\n          \"label\": \"Alternative text for Matching Image\",\n          \"importance\": \"low\",\n          \"optional\": true,\n          \"description\": \"Describe what can be seen in the photo. The text is read by text-to-speech tools needed by visually impaired users.\"\n        }\n      ]\n    }\n  },\n  {\n    \"name\": \"behaviour\",\n    \"type\": \"group\",\n    \"label\": \"Behavioural settings\",\n    \"importance\": \"low\",\n    \"description\": \"These options will let you control how the game behaves.\",\n    \"optional\": true,\n    \"fields\": [\n      {\n        \"name\": \"allowRetry\",\n        \"type\": \"boolean\",\n        \"label\": \"Add button for retrying when the game is over\",\n        \"importance\": \"low\",\n        \"default\": true\n      }\n    ]\n  },\n  {\n    \"label\": \"Localization\",\n    \"importance\": \"low\",\n    \"name\": \"l10n\",\n    \"type\": \"group\",\n    \"common\": true,\n    \"fields\": [\n      {\n        \"label\": \"Text for \\\"Check\\\" button\",\n        \"importance\": \"low\",\n        \"name\": \"checkAnswer\",\n        \"type\": \"text\",\n        \"default\": \"Check\"\n      },\n      {\n        \"label\": \"Text for \\\"Retry\\\" button\",\n        \"importance\": \"low\",\n        \"name\": \"tryAgain\",\n        \"type\": \"text\",\n        \"default\": \"Retry\"\n      },\n      {\n        \"label\": \"Text for \\\"ShowSolution\\\" button\",\n        \"importance\": \"low\",\n        \"name\": \"showSolution\",\n        \"type\": \"text\",\n        \"default\": \"Show Solution\"\n      },\n      {\n        \"label\": \"Feedback text\",\n        \"importance\": \"low\",\n        \"name\": \"score\",\n        \"type\": \"text\",\n        \"default\": \"You got @score of @total points\",\n        \"description\": \"Feedback text, variables available: @score and @total. Example: \'You got @score of @total possible points\'\"\n      }\n    ]\n  }\n]\n', NULL, NULL, NULL, NULL, 'https://h5p.org/tutorial-image-pairing', 'https://h5p.org/image-pairing', 1);
INSERT INTO `mdl_h5p_libraries` (`id`, `machinename`, `title`, `majorversion`, `minorversion`, `patchversion`, `runnable`, `fullscreen`, `embedtypes`, `preloadedjs`, `preloadedcss`, `droplibrarycss`, `semantics`, `addto`, `coremajor`, `coreminor`, `metadatasettings`, `tutorial`, `example`, `enabled`) VALUES
(109, 'H5P.Dictation', 'Dictation', 1, 3, 3, 1, 0, 'iframe', 'dist/h5p-dictation.js', 'dist/h5p-dictation.css', '', '[\n  {\n    \"name\": \"media\",\n    \"type\": \"group\",\n    \"label\": \"Media\",\n    \"importance\": \"medium\",\n    \"fields\": [\n      {\n        \"name\": \"type\",\n        \"type\": \"library\",\n        \"label\": \"Type\",\n        \"importance\": \"medium\",\n        \"options\": [\n          \"H5P.Image 1.1\",\n          \"H5P.Video 1.6\",\n          \"H5P.Audio 1.5\"\n        ],\n        \"optional\": true,\n        \"description\": \"Optional media to display above the question.\"\n      },\n      {\n        \"name\": \"disableImageZooming\",\n        \"type\": \"boolean\",\n        \"label\": \"Disable image zooming\",\n        \"importance\": \"low\",\n        \"default\": false,\n        \"optional\": true,\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"type\",\n              \"equals\": \"H5P.Image 1.1\"\n            }\n          ]\n        }\n      }\n    ]\n  },\n  {\n    \"name\": \"taskDescription\",\n    \"label\": \"Task description\",\n    \"type\": \"text\",\n    \"widget\": \"html\",\n    \"importance\": \"high\",\n    \"description\": \"Describe your task here.\",\n    \"placeholder\": \"Please listen carefully and write what you hear.\",\n    \"enterMode\": \"div\",\n    \"tags\": [\n      \"strong\",\n      \"em\",\n      \"u\",\n      \"a\",\n      \"ul\",\n      \"ol\",\n      \"h2\",\n      \"h3\",\n      \"hr\",\n      \"pre\",\n      \"code\"\n    ]\n  },\n  {\n    \"name\": \"sentences\",\n    \"label\": \"Sentences\",\n    \"importance\": \"high\",\n    \"type\": \"list\",\n    \"widgets\": [\n      {\n        \"name\": \"VerticalTabs\",\n        \"label\": \"Default\"\n      }\n    ],\n    \"min\": 1,\n    \"entity\": \"Sentence\",\n    \"field\": {\n      \"name\": \"sentence\",\n      \"type\": \"group\",\n      \"label\": \"Sentence\",\n      \"fields\": [\n        {\n          \"name\": \"description\",\n          \"type\": \"text\",\n          \"label\": \"Description\",\n          \"description\": \"You can optionally put a simple description above the text input field, useful e.g. for dialogues.\",\n          \"importance\": \"medium\",\n          \"optional\": true\n        },\n        {\n          \"name\": \"sample\",\n          \"type\": \"audio\",\n          \"label\": \"Sound sample\",\n          \"description\": \"Sentence spoken in normal speed\",\n          \"importance\": \"medium\",\n          \"widgetExtensions\": [\n            \"AudioRecorder\"\n          ]\n        },\n        {\n          \"name\": \"sampleAlternative\",\n          \"type\": \"audio\",\n          \"label\": \"Sound sample slow\",\n          \"description\": \"Sentence spoken in slow speed\",\n          \"importance\": \"medium\",\n          \"optional\": true,\n          \"widgetExtensions\": [\n            \"AudioRecorder\"\n          ]\n        },\n        {\n          \"name\": \"text\",\n          \"type\": \"text\",\n          \"label\": \"Text\",\n          \"description\": \"Text that should be written. You can add alternate spellings to a word by adding a vertical line (|) behind followed by an alternative.\",\n          \"importance\": \"medium\",\n          \"maxLength\": 1000\n        }\n      ]\n    }\n  },\n  {\n    \"name\": \"overallFeedback\",\n    \"type\": \"group\",\n    \"label\": \"Overall Feedback\",\n    \"importance\": \"low\",\n    \"expanded\": true,\n    \"fields\": [\n      {\n        \"name\": \"overallFeedback\",\n        \"type\": \"list\",\n        \"widgets\": [\n          {\n            \"name\": \"RangeList\",\n            \"label\": \"Default\"\n          }\n        ],\n        \"importance\": \"high\",\n        \"label\": \"Define custom feedback for any score range\",\n        \"description\": \"Click the \\\"Add range\\\" button to add as many ranges as you need. Example: 0-20% Bad score, 21-91% Average Score, 91-100% Great Score!\",\n        \"entity\": \"range\",\n        \"min\": 1,\n        \"defaultNum\": 1,\n        \"optional\": true,\n        \"field\": {\n          \"name\": \"overallFeedback\",\n          \"type\": \"group\",\n          \"importance\": \"low\",\n          \"fields\": [\n            {\n              \"name\": \"from\",\n              \"type\": \"number\",\n              \"label\": \"Score Range\",\n              \"min\": 0,\n              \"max\": 100,\n              \"default\": 0,\n              \"unit\": \"%\"\n            },\n            {\n              \"name\": \"to\",\n              \"type\": \"number\",\n              \"min\": 0,\n              \"max\": 100,\n              \"default\": 100,\n              \"unit\": \"%\"\n            },\n            {\n              \"name\": \"feedback\",\n              \"type\": \"text\",\n              \"label\": \"Feedback for defined score range\",\n              \"importance\": \"low\",\n              \"placeholder\": \"Fill in the feedback\",\n              \"optional\": true\n            }\n          ]\n        }\n      }\n    ]\n  },\n  {\n    \"name\": \"behaviour\",\n    \"type\": \"group\",\n    \"label\": \"Behavioural settings\",\n    \"importance\": \"low\",\n    \"description\": \"These options will let you control how the task behaves.\",\n    \"fields\": [\n      {\n        \"name\": \"tries\",\n        \"type\": \"number\",\n        \"label\": \"Maximum tries\",\n        \"description\": \"Will limit the number of times the samples for each sentence can be listened to.\",\n        \"optional\": true,\n        \"min\": 1\n      },\n      {\n        \"name\": \"triesAlternative\",\n        \"type\": \"number\",\n        \"label\": \"Maximum tries for slow speed\",\n        \"description\": \"Will limit the number of times the slow samples for each sentence can be listened to.\",\n        \"optional\": true,\n        \"min\": 1\n      },\n      {\n        \"name\": \"disablePause\",\n        \"type\": \"boolean\",\n        \"label\": \"Disable pause option\",\n        \"description\": \"If checked, pausing the audio while playing is not possible.\",\n        \"default\": false,\n        \"optional\": true\n      },\n      {\n        \"name\": \"playButtonDelay\",\n        \"type\": \"number\",\n        \"label\": \"Play button delay\",\n        \"description\": \"Optionally set a time period of up to three seconds that playing a button should be delayed. This is useful if you want to allow students to enter the text field before they start listening.\",\n        \"optional\": true,\n        \"min\": 0,\n        \"max\": 3\n      },\n      {\n        \"name\": \"shuffleSentences\",\n        \"type\": \"select\",\n        \"label\": \"Shuffle sentences\",\n        \"description\": \"Define when the sentences should be shuffled.\",\n        \"options\": [\n          {\n            \"value\": \"never\",\n            \"label\": \"Never\"\n          },\n          {\n            \"value\": \"once\",\n            \"label\": \"Once when starting exercise\"\n          },\n          {\n            \"value\": \"onRetry\",\n            \"label\": \"On every try\"\n          }\n        ],\n        \"default\": \"never\"\n      },\n      {\n        \"name\": \"scoring\",\n        \"type\": \"group\",\n        \"label\": \"Scoring\",\n        \"expanded\": false,\n        \"fields\": [\n          {\n            \"name\": \"ignorePunctuation\",\n            \"type\": \"boolean\",\n            \"label\": \"Ignore Punctuation marks\",\n            \"description\": \"If checked, punctuation marks will not be considered for scoring.\",\n            \"optional\": false,\n            \"default\": true\n          },\n          {\n            \"name\": \"zeroMistakeMode\",\n            \"type\": \"boolean\",\n            \"label\": \"Zero mistakes mode\",\n            \"description\": \"If checked, only correct answers will be considered for scoring. Mistakes will not be punished.\",\n            \"default\": false,\n            \"optional\": false\n          },\n          {\n            \"name\": \"typoFactor\",\n            \"type\": \"select\",\n            \"label\": \"Value of typos\",\n            \"description\": \"Determine to which extent typing errors (word with 3-9 characters: up to 1 mistake, word with more than 9 characters: up to 2 mistakes) count as a real mistake.\",\n            \"options\": [\n              {\n                \"value\": \"100\",\n                \"label\": \"100 %\"\n              },\n              {\n                \"value\": \"50\",\n                \"label\": \"50 %\"\n              },\n              {\n                \"value\": \"0\",\n                \"label\": \"0 %\"\n              }\n            ],\n            \"default\": \"100\"\n          }\n        ]\n      },\n      {\n        \"name\": \"textual\",\n        \"type\": \"group\",\n        \"label\": \"Text\",\n        \"expanded\": false,\n        \"fields\": [\n          {\n            \"name\": \"wordSeparator\",\n            \"type\": \"text\",\n            \"label\": \"Word separator\",\n            \"description\": \"Define the separator of words different than space character to support alternate solutions with different number of words.\",\n            \"optional\": true,\n            \"default\": \" \"\n          },\n          {\n            \"name\": \"overrideRTL\",\n            \"type\": \"select\",\n            \"label\": \"Writing direction\",\n            \"description\": \"Set whether the sentences\' language is right-to-left or left-to-right.\",\n            \"options\": [\n              {\n                \"value\": \"auto\",\n                \"label\": \"Automatic detection\"\n              },\n              {\n                \"value\": \"on\",\n                \"label\": \"Right-to-left\"\n              },\n              {\n                \"value\": \"off\",\n                \"label\": \"Left-to-right\"\n              }\n            ],\n            \"default\": \"auto\"\n          },\n          {\n            \"name\": \"autosplit\",\n            \"type\": \"boolean\",\n            \"label\": \"Splitting of characters\",\n            \"description\": \"Activate if particular characters (e.g. Chinese Han characters) should be split into separate words automatically.\",\n            \"importance\": \"low\",\n            \"default\": true\n          }\n        ]\n      },\n      {\n        \"name\": \"feedbackPresentation\",\n        \"type\": \"group\",\n        \"label\": \"Presentation of feedback\",\n        \"expanded\": false,\n        \"fields\": [\n          {\n            \"name\": \"customTypoDisplay\",\n            \"type\": \"boolean\",\n            \"label\": \"Custom typo display\",\n            \"description\": \"If checked, typos will be displayed in a custom style distinguishing them from clear mistakes.\",\n            \"default\": false,\n            \"optional\": false\n          },\n          {\n            \"name\": \"alternateSolution\",\n            \"type\": \"select\",\n            \"label\": \"Presentation of alternate solutions\",\n            \"description\": \"Define which alternatives should be presented for wrong or missing words in the solution.\",\n            \"options\": [\n              {\n                \"value\": \"first\",\n                \"label\": \"Show only first alternative\"\n              },\n              {\n                \"value\": \"all\",\n                \"label\": \"Show all alternatives\"\n              }\n            ],\n            \"default\": \"first\"\n          }\n        ]\n      },\n      {\n        \"name\": \"enableRetry\",\n        \"label\": \"Enable \\\"Retry\\\"\",\n        \"type\": \"boolean\",\n        \"importance\": \"low\",\n        \"default\": true,\n        \"optional\": true\n      },\n      {\n        \"name\": \"enableSolutionsButton\",\n        \"label\": \"Enable \\\"Show solution\\\" button\",\n        \"type\": \"boolean\",\n        \"importance\": \"low\",\n        \"default\": true,\n        \"optional\": true\n      },\n      {\n        \"name\": \"enableSolutionOnCheck\",\n        \"label\": \"Show solution on check\",\n        \"type\": \"boolean\",\n        \"importance\": \"low\",\n        \"default\": false,\n        \"optional\": true,\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"enableSolutionsButton\",\n              \"equals\": true\n            }\n          ]\n        }\n      }\n    ]\n  },\n  {\n    \"name\": \"l10n\",\n    \"type\": \"group\",\n    \"common\": true,\n    \"label\": \"User interface\",\n    \"importance\": \"low\",\n    \"fields\": [\n      {\n        \"name\": \"generalFeedback\",\n        \"type\": \"text\",\n        \"label\": \"General feedback\",\n        \"description\": \"You can use several placeholders that will be replaced with the adequate number: @matches = number of matches, @total = total mistakes, @capped = capped total mistakes, @wrong = wrong words, @added = additional words, @missing = missing words, @typo = typing errors\",\n        \"importance\": \"low\",\n        \"default\": \"You have made @total mistake(s).\"\n      },\n      {\n        \"name\": \"generalFeedbackZeroMistakesMode\",\n        \"type\": \"text\",\n        \"label\": \"General feedback (zero mistakes mode)\",\n        \"description\": \"You can use several placeholders that will be replaced with the adequate number: @matches = number of matches, @total = total score, @wrong = wrong words, @added = additional words, @missing = missing words, @typo = typing errors\",\n        \"importance\": \"low\",\n        \"default\": \"You have entered @total word(s) correctly and @typo word(s) with minor mistakes.\"\n      },\n      {\n        \"name\": \"checkAnswer\",\n        \"type\": \"text\",\n        \"label\": \"Text for \\\"Check\\\" button\",\n        \"importance\": \"low\",\n        \"default\": \"Check\"\n      },\n      {\n        \"name\": \"submitAnswer\",\n        \"type\": \"text\",\n        \"label\": \"Text for \\\"Submit\\\" button\",\n        \"importance\": \"low\",\n        \"default\": \"Submit\"\n      },\n      {\n        \"name\": \"tryAgain\",\n        \"label\": \"Text for \\\"Retry\\\" button\",\n        \"type\": \"text\",\n        \"importance\": \"low\",\n        \"default\": \"Retry\"\n      },\n      {\n        \"name\": \"showSolution\",\n        \"type\": \"text\",\n        \"label\": \"Text for \\\"Show solution\\\" button\",\n        \"importance\": \"low\",\n        \"default\": \"Show solution\"\n      },\n      {\n        \"name\": \"audioNotSupported\",\n        \"type\": \"text\",\n        \"label\": \"Audio not supported message\",\n        \"importance\": \"low\",\n        \"default\": \"Your browser does not support this audio.\"\n      }\n    ]\n  },\n  {\n    \"name\": \"a11y\",\n    \"type\": \"group\",\n    \"common\": true,\n    \"label\": \"Readspeaker\",\n    \"importance\": \"low\",\n    \"fields\": [\n      {\n        \"name\": \"check\",\n        \"type\": \"text\",\n        \"label\": \"Assistive technology description for \\\"Check\\\" button\",\n        \"importance\": \"low\",\n        \"default\": \"Check the answers. The responses will be marked as correct, incorrect, or unanswered.\"\n      },\n      {\n        \"name\": \"showSolution\",\n        \"type\": \"text\",\n        \"label\": \"Assistive technology description for \\\"Show Solution\\\" button\",\n        \"importance\": \"low\",\n        \"default\": \"Show the solution. The task will be marked with its correct solution.\"\n      },\n      {\n        \"name\": \"retry\",\n        \"type\": \"text\",\n        \"label\": \"Assistive technology description for \\\"Retry\\\" button\",\n        \"importance\": \"low\",\n        \"default\": \"Retry the task. Reset all responses and start the task over again.\"\n      },\n      {\n        \"name\": \"play\",\n        \"type\": \"text\",\n        \"label\": \"Play button\",\n        \"importance\": \"low\",\n        \"default\": \"Play\"\n      },\n      {\n        \"name\": \"playSlowly\",\n        \"type\": \"text\",\n        \"label\": \"Play slowly button\",\n        \"importance\": \"low\",\n        \"default\": \"Play slowly\"\n      },\n      {\n        \"name\": \"triesLeft\",\n        \"type\": \"text\",\n        \"label\": \"Tries left (text for readspeakers and hover text)\",\n        \"description\": \"@number will be replaced by the current number of tries left.\",\n        \"importance\": \"low\",\n        \"default\": \"Number of tries left: @number\"\n      },\n      {\n        \"name\": \"infinite\",\n        \"type\": \"text\",\n        \"label\": \"Infinite (text for readspeakers and hover text)\",\n        \"importance\": \"low\",\n        \"default\": \"infinite\"\n      },\n      {\n        \"name\": \"enterText\",\n        \"type\": \"text\",\n        \"label\": \"Enter text field\",\n        \"importance\": \"low\",\n        \"default\": \"Enter what you have heard.\"\n      },\n      {\n        \"name\": \"yourResult\",\n        \"type\": \"text\",\n        \"label\": \"Your result\",\n        \"description\": \"@score will be replaced by the number of points. @total will be replaced by the maximum possible points.\",\n        \"importance\": \"low\",\n        \"default\": \"You got @score out of @total points\"\n      },\n      {\n        \"name\": \"solution\",\n        \"type\": \"text\",\n        \"label\": \"Solution\",\n        \"importance\": \"low\",\n        \"default\": \"Solution\"\n      },\n      {\n        \"name\": \"sentence\",\n        \"type\": \"text\",\n        \"label\": \"Sentence\",\n        \"importance\": \"low\",\n        \"default\": \"Sentence\"\n      },\n      {\n        \"name\": \"item\",\n        \"type\": \"text\",\n        \"label\": \"Item\",\n        \"importance\": \"low\",\n        \"default\": \"Item\"\n      },\n      {\n        \"name\": \"correct\",\n        \"type\": \"text\",\n        \"label\": \"Correct\",\n        \"importance\": \"low\",\n        \"default\": \"correct\"\n      },\n      {\n        \"name\": \"wrong\",\n        \"type\": \"text\",\n        \"label\": \"Wrong\",\n        \"importance\": \"low\",\n        \"default\": \"wrong\"\n      },\n      {\n        \"name\": \"typo\",\n        \"type\": \"text\",\n        \"label\": \"Small mistake\",\n        \"importance\": \"low\",\n        \"default\": \"small mistake\"\n      },\n      {\n        \"name\": \"missing\",\n        \"type\": \"text\",\n        \"label\": \"Missing word or symbol\",\n        \"importance\": \"low\",\n        \"default\": \"missing\"\n      },\n      {\n        \"name\": \"added\",\n        \"type\": \"text\",\n        \"label\": \"Added word or symbol\",\n        \"importance\": \"low\",\n        \"default\": \"added\"\n      },\n      {\n        \"name\": \"shouldHaveBeen\",\n        \"type\": \"text\",\n        \"label\": \"Correct solution\",\n        \"importance\": \"low\",\n        \"default\": \"Should have been\"\n      },\n      {\n        \"name\": \"or\",\n        \"type\": \"text\",\n        \"label\": \"Or\",\n        \"importance\": \"low\",\n        \"default\": \"or\"\n      },\n      {\n        \"name\": \"point\",\n        \"type\": \"text\",\n        \"label\": \"Point\",\n        \"importance\": \"low\",\n        \"default\": \"point\"\n      },\n      {\n        \"name\": \"points\",\n        \"type\": \"text\",\n        \"label\": \"Points\",\n        \"importance\": \"low\",\n        \"default\": \"points\"\n      },\n      {\n        \"name\": \"period\",\n        \"type\": \"text\",\n        \"label\": \"Period\",\n        \"importance\": \"low\",\n        \"default\": \"period\"\n      },\n      {\n        \"name\": \"exclamationPoint\",\n        \"type\": \"text\",\n        \"label\": \"Exclamation point\",\n        \"importance\": \"low\",\n        \"default\": \"exclamation point\"\n      },\n      {\n        \"name\": \"questionMark\",\n        \"type\": \"text\",\n        \"label\": \"Question mark\",\n        \"importance\": \"low\",\n        \"default\": \"question mark\"\n      },\n      {\n        \"name\": \"comma\",\n        \"type\": \"text\",\n        \"label\": \"Comma\",\n        \"importance\": \"low\",\n        \"default\": \"comma\"\n      },\n      {\n        \"name\": \"singleQuote\",\n        \"type\": \"text\",\n        \"label\": \"Single quote\",\n        \"importance\": \"low\",\n        \"default\": \"single quote\"\n      },\n      {\n        \"name\": \"doubleQuote\",\n        \"type\": \"text\",\n        \"label\": \"Double quote\",\n        \"importance\": \"low\",\n        \"default\": \"double quote\"\n      },\n      {\n        \"name\": \"colon\",\n        \"type\": \"text\",\n        \"label\": \"Colon\",\n        \"importance\": \"low\",\n        \"default\": \"colon\"\n      },\n      {\n        \"name\": \"semicolon\",\n        \"type\": \"text\",\n        \"label\": \"Semicolon\",\n        \"importance\": \"low\",\n        \"default\": \"semicolon\"\n      },\n      {\n        \"name\": \"plus\",\n        \"type\": \"text\",\n        \"label\": \"Plus\",\n        \"importance\": \"low\",\n        \"default\": \"plus\"\n      },\n      {\n        \"name\": \"minus\",\n        \"type\": \"text\",\n        \"label\": \"Minus\",\n        \"importance\": \"low\",\n        \"default\": \"minus\"\n      },\n      {\n        \"name\": \"asterisk\",\n        \"type\": \"text\",\n        \"label\": \"Asterisk\",\n        \"importance\": \"low\",\n        \"default\": \"asterisk\"\n      },\n      {\n        \"name\": \"forwardSlash\",\n        \"type\": \"text\",\n        \"label\": \"Forward slash\",\n        \"importance\": \"low\",\n        \"default\": \"forward slash\"\n      }\n    ]\n  }\n]\n', NULL, 1, 13, NULL, 'https://h5p.org/tutorial-dictation', 'https://h5p.org/dictation', 1),
(110, 'H5P.BranchingQuestion', 'Branching Question', 1, 0, 20, 0, 0, '', 'branchingQuestion.js', 'branchingQuestion.css', '', '[\n  {\n    \"name\": \"branchingQuestion\",\n    \"type\": \"group\",\n    \"widget\": \"branchingQuestion\",\n    \"label\": \"Branching Question Editor\",\n    \"importance\": \"high\",\n    \"fields\": [\n      {\n        \"name\": \"question\",\n        \"type\": \"text\",\n        \"importance\": \"medium\",\n        \"widget\": \"html\",\n        \"label\": \"Question\",\n        \"enterMode\": \"p\",\n        \"optional\": true,\n        \"tags\": [\n          \"strong\",\n          \"em\",\n          \"sub\",\n          \"sup\",\n          \"h2\",\n          \"h3\",\n          \"pre\",\n          \"code\"\n        ]\n      },\n      {\n        \"name\": \"alternatives\",\n        \"type\": \"list\",\n        \"importance\": \"high\",\n        \"label\": \"Available alternatives\",\n        \"entity\": \"alternative\",\n        \"min\": 2,\n        \"defaultNum\": 2,\n        \"field\": {\n          \"name\": \"answer\",\n          \"type\": \"group\",\n          \"label\": \"Alternative\",\n          \"importance\": \"high\",\n          \"fields\": [\n            {\n              \"name\": \"text\",\n              \"type\": \"text\",\n              \"importance\": \"medium\",\n              \"label\": \"Text\"\n            },\n            {\n              \"name\": \"nextContentId\",\n              \"type\": \"number\",\n              \"label\": \"Next Content ID (end screens are defined by negative numbers)\",\n              \"importance\": \"high\",\n              \"default\": -1\n            },\n            {\n              \"name\": \"feedback\",\n              \"type\": \"group\",\n              \"label\": \"Feedback\",\n              \"expanded\": true,\n              \"fields\": [\n                {\n                  \"name\": \"title\",\n                  \"type\": \"text\",\n                  \"label\": \"Feedback title\",\n                  \"optional\": true,\n                  \"widget\": \"html\",\n                  \"enterMode\": \"p\",\n                  \"tags\": [\n                    \"strong\",\n                    \"em\",\n                    \"del\",\n                    \"code\",\n                    \"a\"\n                  ]\n                },\n                {\n                  \"name\": \"subtitle\",\n                  \"type\": \"text\",\n                  \"label\": \"Feedback text\",\n                  \"optional\": true,\n                  \"widget\": \"html\",\n                  \"enterMode\": \"p\",\n                  \"tags\": [\n                    \"strong\",\n                    \"em\",\n                    \"del\",\n                    \"code\",\n                    \"a\"\n                  ]\n                },\n                {\n                  \"name\": \"image\",\n                  \"type\": \"image\",\n                  \"label\": \"Feedback image\",\n                  \"optional\": true\n                },\n                {\n                  \"name\": \"endScreenScore\",\n                  \"type\": \"number\",\n                  \"label\": \"Score for this scenario\",\n                  \"description\": \"The score will be sent to any LMS, LRS or any other connected service that receives scores from H5P for users who reach this scenario\",\n                  \"optional\": true\n                }\n              ]\n            }\n          ]\n        }\n      }\n    ]\n  }\n]\n', NULL, NULL, NULL, NULL, NULL, NULL, 1),
(111, 'H5P.BranchingScenario', 'Branching Scenario', 1, 8, 14, 1, 0, 'iframe', 'dist/h5p-branching-scenario.js', 'dist/h5p-branching-scenario.css', '', '[\n  {\n    \"name\": \"branchingScenario\",\n    \"type\": \"group\",\n    \"widget\": \"branchingScenario\",\n    \"label\": \"Branching Scenario Editor\",\n    \"importance\": \"high\",\n    \"fields\": [\n      {\n        \"name\": \"title\",\n        \"label\": \"Title\",\n        \"type\": \"text\",\n        \"importance\": \"high\"\n      },\n      {\n        \"name\": \"startScreen\",\n        \"label\": \"Start screen\",\n        \"type\": \"group\",\n        \"importance\": \"low\",\n        \"fields\": [\n          {\n            \"name\": \"startScreenTitle\",\n            \"label\": \"Course Title\",\n            \"placeholder\": \"Title for your course\",\n            \"type\": \"text\",\n            \"importance\": \"medium\",\n            \"optional\": true,\n            \"widget\": \"html\",\n            \"enterMode\": \"p\",\n            \"tags\": [\n              \"strong\",\n              \"em\",\n              \"del\",\n              \"code\",\n              \"a\"\n            ]\n          },\n          {\n            \"name\": \"startScreenSubtitle\",\n            \"label\": \"Course Details\",\n            \"placeholder\": \"Details about the course\",\n            \"type\": \"text\",\n            \"importance\": \"medium\",\n            \"optional\": true,\n            \"widget\": \"html\",\n            \"enterMode\": \"p\",\n            \"tags\": [\n              \"strong\",\n              \"em\",\n              \"del\",\n              \"code\",\n              \"a\"\n            ]\n          },\n          {\n            \"name\": \"startScreenImage\",\n            \"label\": \"Course image\",\n            \"type\": \"image\",\n            \"optional\": true,\n            \"importance\": \"medium\"\n          },\n          {\n            \"name\": \"startScreenAltText\",\n            \"label\": \"Image alternative text\",\n            \"type\": \"text\",\n            \"optional\": true,\n            \"importance\": \"medium\"\n          }\n        ]\n      },\n      {\n        \"name\": \"endScreens\",\n        \"label\": \"List of end screens\",\n        \"type\": \"list\",\n        \"importance\": \"medium\",\n        \"field\": {\n          \"name\": \"endScreen\",\n          \"label\": \"End screen\",\n          \"type\": \"group\",\n          \"importance\": \"low\",\n          \"fields\": [\n            {\n              \"name\": \"endScreenTitle\",\n              \"label\": \"Title\",\n              \"type\": \"text\",\n              \"importance\": \"medium\",\n              \"optional\": true,\n              \"widget\": \"html\",\n              \"enterMode\": \"p\",\n              \"tags\": [\n                \"strong\",\n                \"em\",\n                \"del\",\n                \"code\",\n                \"a\"\n              ]\n            },\n            {\n              \"name\": \"endScreenSubtitle\",\n              \"label\": \"Text\",\n              \"type\": \"text\",\n              \"importance\": \"medium\",\n              \"optional\": true,\n              \"widget\": \"html\",\n              \"enterMode\": \"p\",\n              \"tags\": [\n                \"strong\",\n                \"em\",\n                \"del\",\n                \"code\",\n                \"a\"\n              ]\n            },\n            {\n              \"name\": \"endScreenImage\",\n              \"label\": \"Image\",\n              \"type\": \"image\",\n              \"importance\": \"medium\",\n              \"optional\": true\n            },\n            {\n              \"name\": \"endScreenScore\",\n              \"label\": \"Score\",\n              \"description\": \"The score will be sent to any LMS, LRS or any other connected service that receives scores from H5P for users who reach the default end scenario.\",\n              \"type\": \"number\",\n              \"default\": 0,\n              \"optional\": true\n            },\n            {\n              \"name\": \"contentId\",\n              \"label\": \"Content ID\",\n              \"type\": \"number\",\n              \"max\": 0,\n              \"widget\": \"none\"\n            }\n          ]\n        }\n      },\n      {\n        \"name\": \"content\",\n        \"label\": \"List of branching scenario content\",\n        \"importance\": \"high\",\n        \"type\": \"list\",\n        \"min\": 1,\n        \"entity\": \"content\",\n        \"field\": {\n          \"name\": \"content\",\n          \"type\": \"group\",\n          \"fields\": [\n            {\n              \"name\": \"type\",\n              \"type\": \"library\",\n              \"importance\": \"high\",\n              \"options\": [\n                \"H5P.BranchingQuestion 1.0\",\n                \"H5P.CoursePresentation 1.25\",\n                \"H5P.AdvancedText 1.1\",\n                \"H5P.Image 1.1\",\n                \"H5P.ImageHotspots 1.10\",\n                \"H5P.InteractiveVideo 1.26\",\n                \"H5P.Video 1.6\"\n              ]\n            },\n            {\n              \"name\": \"showContentTitle\",\n              \"label\": \"Show content title in view\",\n              \"description\": \"If selected, the user will see the content title in the top bar above this content.\",\n              \"type\": \"boolean\",\n              \"importance\": \"high\"\n            },\n            {\n              \"name\": \"proceedButtonText\",\n              \"label\": \"Text for the proceed button (max length: 50 characters)\",\n              \"type\": \"text\",\n              \"importance\": \"low\",\n              \"default\": \"Proceed\",\n              \"maxLength\": 50\n            },\n            {\n              \"name\": \"forceContentFinished\",\n              \"type\": \"select\",\n              \"label\": \"Override require content finished\",\n              \"description\": \"Override the individual settings for requiring the content to be finished before activating the \\\"Proceed\\\" button. Will not have any effect if the content doesn\'t indicate if it was \\\"finished\\\", e.g. images or course presentations with just one slide.\",\n              \"optional\": \"true\",\n              \"options\": [\n                {\n                  \"value\": \"useBehavioural\",\n                  \"label\": \"Use behavioural setting\"\n                },\n                {\n                  \"value\": \"enabled\",\n                  \"label\": \"Enabled\"\n                },\n                {\n                  \"value\": \"disabled\",\n                  \"label\": \"Disabled\"\n                }\n              ],\n              \"default\": \"useBehavioural\"\n            },\n            {\n              \"name\": \"nextContentId\",\n              \"type\": \"number\",\n              \"importance\": \"high\",\n              \"widget\": \"none\"\n            },\n            {\n              \"name\": \"feedback\",\n              \"type\": \"group\",\n              \"label\": \"Feedback\",\n              \"expanded\": true,\n              \"fields\": [\n                {\n                  \"name\": \"title\",\n                  \"type\": \"text\",\n                  \"label\": \"Feedback title\",\n                  \"optional\": true,\n                  \"widget\": \"html\",\n                  \"enterMode\": \"p\",\n                  \"tags\": [\n                    \"strong\",\n                    \"em\",\n                    \"del\",\n                    \"code\",\n                    \"a\"\n                  ]\n                },\n                {\n                  \"name\": \"subtitle\",\n                  \"type\": \"text\",\n                  \"label\": \"Feedback text\",\n                  \"optional\": true,\n                  \"widget\": \"html\",\n                  \"enterMode\": \"p\",\n                  \"tags\": [\n                    \"strong\",\n                    \"em\",\n                    \"del\",\n                    \"code\",\n                    \"a\"\n                  ]\n                },\n                {\n                  \"name\": \"image\",\n                  \"type\": \"image\",\n                  \"label\": \"Feedback image\",\n                  \"optional\": true\n                },\n                {\n                  \"name\": \"endScreenScore\",\n                  \"type\": \"number\",\n                  \"label\": \"Score for this scenario\",\n                  \"description\": \"The score will be sent to any LMS, LRS or any other connected service that receives scores from H5P for users who reach this scenario\",\n                  \"optional\": true\n                }\n              ]\n            },\n            {\n              \"name\": \"contentBehaviour\",\n              \"label\": \"Navigate back\",\n              \"type\": \"select\",\n              \"description\": \"This will allow user to go back and see the previous content/question in the scenario.\",\n              \"options\": [\n                {\n                  \"value\": \"useBehavioural\",\n                  \"label\": \"Use behavioural setting\"\n                },\n                {\n                  \"value\": \"enabled\",\n                  \"label\": \"Enabled\"\n                },\n                {\n                  \"value\": \"disabled\",\n                  \"label\": \"Disabled\"\n                }\n              ],\n              \"default\": \"useBehavioural\"\n            }\n          ]\n        }\n      },\n      {\n        \"name\": \"scoringOptionGroup\",\n        \"type\": \"group\",\n        \"label\": \"Scoring options\",\n        \"importance\": \"low\",\n        \"fields\": [\n          {\n            \"name\": \"scoringOption\",\n            \"label\": \"Scoring options\",\n            \"type\": \"select\",\n            \"description\": \"Select type of scoring.\",\n            \"options\": [\n              {\n                \"value\": \"static-end-score\",\n                \"label\": \"Statically set score for each end scenario\"\n              },\n              {\n                \"value\": \"dynamic-score\",\n                \"label\": \"Dynamically calculate score from user answers\"\n              },\n              {\n                \"value\": \"no-score\",\n                \"label\": \"No scoring\"\n              }\n            ],\n            \"default\": \"no-score\"\n          },\n          {\n            \"name\": \"includeInteractionsScores\",\n            \"label\": \"Include scores from interactions within the Branching Scenario\",\n            \"description\": \"If chosen scores from for instance Interactive Videos will be added to the total score obtained. If not chosen only scores specified in the feedback sections of the content items, branching questions and end scenarios will count.\",\n            \"type\": \"boolean\",\n            \"default\": true,\n            \"optional\": true,\n            \"widget\": \"showWhen\",\n            \"showWhen\": {\n              \"rules\": [\n                {\n                  \"field\": \"scoringOption\",\n                  \"equals\": \"dynamic-score\"\n                }\n              ]\n            }\n          }\n        ]\n      },\n      {\n        \"name\": \"behaviour\",\n        \"type\": \"group\",\n        \"label\": \"Behavioural settings\",\n        \"importance\": \"low\",\n        \"fields\": [\n          {\n            \"name\": \"enableBackwardsNavigation\",\n            \"label\": \"Navigate back\",\n            \"description\": \"This will allow user to go back and see the previous content/question in the scenario. This can be overridden on a content level.\",\n            \"type\": \"boolean\",\n            \"optional\": true,\n            \"default\": false\n          },\n          {\n            \"name\": \"forceContentFinished\",\n            \"label\": \"Required to watch\",\n            \"description\": \"Urges viewers to complete the Video, Interactive Video and Course Presentation before proceeding with the scenario. This can be overridden on a content level.\",\n            \"type\": \"boolean\",\n            \"optional\": true,\n            \"default\": false\n          },\n          {\n            \"name\": \"randomizeBranchingQuestions\",\n            \"label\": \"Randomize Branching Questions\",\n            \"description\": \"Branching questions will be displayed in random order.\",\n            \"type\": \"boolean\",\n            \"optional\": true,\n            \"default\": false\n          }\n        ]\n      },\n      {\n        \"name\": \"l10n\",\n        \"type\": \"group\",\n        \"label\": \"Localization\",\n        \"importance\": \"low\",\n        \"common\": true,\n        \"fields\": [\n          {\n            \"name\": \"startScreenButtonText\",\n            \"label\": \"Text for the button on the start screen\",\n            \"type\": \"text\",\n            \"importance\": \"low\",\n            \"default\": \"Start the course\"\n          },\n          {\n            \"name\": \"endScreenButtonText\",\n            \"label\": \"Text for the button on the end screen\",\n            \"type\": \"text\",\n            \"importance\": \"low\",\n            \"default\": \"Restart the course\"\n          },\n          {\n            \"name\": \"backButtonText\",\n            \"label\": \"Text for the back button on each of the library screens and branching questions\",\n            \"type\": \"text\",\n            \"importance\": \"low\",\n            \"default\": \"Back\"\n          },\n          {\n            \"name\": \"disableProceedButtonText\",\n            \"label\": \"Text for the disabled button on the library screens\",\n            \"type\": \"text\",\n            \"importance\": \"low\",\n            \"default\": \"Require to complete the current module\"\n          },\n          {\n            \"name\": \"replayButtonText\",\n            \"label\": \"Text for the button used to replay a video\",\n            \"type\": \"text\",\n            \"importance\": \"low\",\n            \"default\": \"Replay the video\"\n          },\n          {\n            \"name\": \"scoreText\",\n            \"label\": \"Label for score on the end screen\",\n            \"type\": \"text\",\n            \"importance\": \"low\",\n            \"default\": \"Your score:\"\n          },\n          {\n            \"name\": \"fullscreenAria\",\n            \"label\": \"Aria label for fullscreen button\",\n            \"type\": \"text\",\n            \"importance\": \"low\",\n            \"default\": \"Fullscreen\"\n          }\n        ]\n      }\n    ]\n  }\n]\n', NULL, 1, 26, NULL, 'https://h5p.org/tutorial-branching-scenario', 'https://h5p.org/branching-scenario', 1);
