(112, 'H5P.CoursePresentation', 'Course Presentation', 1, 25, 31, 1, 1, 'iframe', 'dist/h5p-course-presentation.js', 'dist/h5p-course-presentation.css', '', '[\n  {\n    \"name\": \"presentation\",\n    \"type\": \"group\",\n    \"importance\": \"high\",\n    \"widget\": \"coursepresentation\",\n    \"fields\": [\n      {\n        \"name\": \"slides\",\n        \"importance\": \"high\",\n        \"type\": \"list\",\n        \"field\": {\n          \"name\": \"slide\",\n          \"importance\": \"high\",\n          \"type\": \"group\",\n          \"fields\": [\n            {\n              \"name\": \"elements\",\n              \"importance\": \"high\",\n              \"type\": \"list\",\n              \"field\": {\n                \"name\": \"element\",\n                \"importance\": \"high\",\n                \"type\": \"group\",\n                \"fields\": [\n                  {\n                    \"name\": \"x\",\n                    \"importance\": \"low\",\n                    \"type\": \"number\",\n                    \"widget\": \"none\"\n                  },\n                  {\n                    \"name\": \"y\",\n                    \"importance\": \"low\",\n                    \"type\": \"number\",\n                    \"widget\": \"none\"\n                  },\n                  {\n                    \"name\": \"width\",\n                    \"importance\": \"low\",\n                    \"type\": \"number\",\n                    \"widget\": \"none\",\n                    \"optional\": true\n                  },\n                  {\n                    \"name\": \"height\",\n                    \"importance\": \"low\",\n                    \"type\": \"number\",\n                    \"widget\": \"none\",\n                    \"optional\": true\n                  },\n                  {\n                    \"name\": \"action\",\n                    \"type\": \"library\",\n                    \"importance\": \"high\",\n                    \"option