             },\n                  {\n                    \"name\": \"alwaysDisplayComments\",\n                    \"type\": \"boolean\",\n                    \"label\": \"Always display comments\",\n                    \"importance\": \"low\",\n                    \"optional\": true\n                  },\n                  {\n                    \"name\": \"backgroundOpacity\",\n                    \"type\": \"number\",\n                    \"label\": \"Background Opacity\",\n                    \"importance\": \"low\",\n                    \"min\": 0,\n                    \"max\": 100,\n                    \"step\": 5,\n                    \"default\": 0,\n                    \"optional\": true\n                  },\n                  {\n                    \"name\": \"displayAsButton\",\n                    \"type\": \"boolean\",\n                    \"label\": \"Display as button\",\n                    \"importance\": \"medium\",\n                    \"default\": false,\n                    \"optional\": true\n                  },\n                  {\n                    \"name\": \"buttonSize\",\n                    \"type\": \"select\",\n                    \"label\": \"Button size\",\n                    \"importance\": \"low\",\n                    \"optional\": false,\n                    \"default\": \"big\",\n                    \"options\": [\n                      {\n                        \"value\": \"small\",\n                        \"label\": \"Small\"\n                      },\n                      {\n                        \"value\": \"big\",\n                        \"label\": \"Big\"\n                      }\n                    ]\n                  },\n                  {\n                    \"name\": \"title\",\n                    \"type\": \"text\",\n                    \"optional\": true,\n                    \"label\": \"Title\",\n                    \"importance\": \"medium\"\n                  },\n                  {\n                    \"name\": \"goToSlideType\",\n                    \"type\": \"select\",\n                    \"label\": \"Go to\",\n                    \"importance\": \"medium\",\n                    \"optional\": false,\n                    \"options\": [\n                      {\n                        \"value\": \"specified\",\n                        \"label\": \"Specific slide number\"\n                      },\n                      {\n                        \"value\": \"next\",\n                        \"label\": \"Next slide\"\n                      },\n                      {\n                        \"value\": \"previous\",\n                        \"label\": \"Previous slide\"\n                      }\n                    ],\n                    \"default\": \"specified\"\n                  },\n                  {\n                    \"name\": \"goToSlide\",\n                    \"type\": \"number\",\n                    \"label\": \"Specific slide number\",\n                    \"description\": \"Only applicable when \'Specific slide number\' is selected\",\n                    \"importance\": \"low\",\n                    \"min\": 1,\n                    \"optional\": true\n                  },\n                  {\n                    \"name\": \"invisible\",\n                    \"type\": \"boolean\",\n                    \"label\": \"Invisible\",\n                    \"importance\": \"low\",\n                    \"description\": \"Default cursor, no title and no tab index. Warning: Users with disabilities or keyboard only users will have trouble using this element.\",\n                    \"default\": false\n                  }\n                ]\n              }\n            },\n            {\n              \"name\": \"keywords\",\n              \"importance\": \"low\",\n              \"type\": \"list\",\n              \"optional\": true,\n              \"field\": {\n                \"name\": \"keyword\",\n                \"importance\": \"low\",\n     