            \"label\": \"Pick a color\",\n            \"importance\": \"medium\",\n            \"spectrum\": {\n              \"flat\": true,\n              \"showInput\": true,\n              \"allowEmpty\": true,\n              \"showButtons\": false\n            },\n            \"default\": null,\n            \"optional\": true\n          }\n        ]\n      }\n    ]\n  },\n  {\n    \"name\": \"l10n\",\n    \"type\": \"group\",\n    \"label\": \"Localize\",\n    \"importance\": \"low\",\n    \"common\": true,\n    \"fields\": [\n      {\n        \"name\": \"slide\",\n        \"type\": \"text\",\n        \"label\": \"Translation for \\\"Slide\\\"\",\n        \"importance\": \"low\",\n        \"default\": \"Slide\"\n      },\n      {\n        \"name\": \"score\",\n        \"type\": \"text\",\n        \"label\": \"Translation for \\\"Score\\\"\",\n        \"importance\": \"low\",\n        \"default\": \"Score\"\n      },\n      {\n        \"name\": \"yourScore\",\n        \"type\": \"text\",\n        \"label\": \"Translation for \\\"Your Score\\\"\",\n        \"importance\": \"low\",\n        \"default\": \"Your Score\"\n      },\n      {\n        \"name\": \"maxScore\",\n        \"type\": \"text\",\n        \"label\": \"Translation for \\\"Max Score\\\"\",\n        \"importance\": \"low\",\n        \"default\": \"Max Score\"\n      },\n      {\n        \"name\": \"total\",\n        \"type\": \"text\",\n        \"label\": \"Translation for \\\"Total\\\"\",\n        \"importance\": \"low\",\n        \"default\": \"Total\"\n      },\n      {\n        \"name\": \"totalScore\",\n        \"type\": \"text\",\n        \"label\": \"Translation for \\\"Total Score\\\"\",\n        \"importance\": \"low\",\n        \"default\": \"Total Score\"\n      },\n      {\n        \"name\": \"showSolutions\",\n        \"type\": \"text\",\n        \"label\": \"Title for show solutions button\",\n        \"importance\": \"low\",\n        \"default\": \"Show solutions\"\n      },\n      {\n        \"name\": \"retry\",\n        \"type\": \"text\",\n        \"label\": \"Text for the retry button\",\n        \"importance\": \"low\",\n        \"default\": \"Retry\",\n        \"optional\": true\n      },\n      {\n        \"name\": \"exportAnswers\",\n        \"type\": \"text\",\n        \"label\": \"Text for the export text button\",\n        \"importance\": \"low\",\n        \"default\": \"Export text\"\n      },\n      {\n        \"name\": \"hideKeywords\",\n        \"type\": \"text\",\n        \"label\": \"Hide sidebar navigation menu button title\",\n        \"importance\": \"low\",\n        \"default\": \"Hide sidebar navigation menu\"\n      },\n      {\n        \"name\": \"showKeywords\",\n        \"type\": \"text\",\n        \"label\": \"Show sidebar navigation menu button title\",\n        \"importance\": \"low\",\n        \"default\": \"Show sidebar navigation menu\"\n      },\n      {\n        \"name\": \"fullscreen\",\n        \"type\": \"text\",\n        \"label\": \"Fullscreen label\",\n        \"importance\": \"low\",\n        \"default\": \"Fullscreen\"\n      },\n      {\n        \"name\": \"exitFullscreen\",\n        \"type\": \"text\",\n        \"label\": \"Exit fullscreen label\",\n        \"importance\": \"low\",\n        \"default\": \"Exit fullscreen\"\n      },\n      {\n        \"name\": \"prevSlide\",\n        \"type\": \"text\",\n        \"label\": \"Previous slide label\",\n        \"importance\": \"low\",\n        \"default\": \"Previous slide\"\n      },\n      {\n        \"name\": \"nextSlide\",\n        \"type\": \"text\",\n        \"label\": \"Next slide label\",\n        \"importance\": \"low\",\n        \"default\": \"Next slide\"\n      },\n      {\n        \"name\": \"currentSlide\",\n        \"type\": \"text\",\n        \"label\": \"Current slide label\",\n        \"importance\": \"low\",\n        \"default\": \"Current slide\"\n      },\n      {\n        \"name\": \"lastSlide\",\n        \"type\": \"text\",\n        \"label\": \"Last slide label\",\n        \"importance\": \"low\",\n        \"default\": \"Last slide\"\n      },\n      {\n        \"name\": \"solutionModeTitle\",\n        \"type\": \"text\",\n        \"label\": \"Exit solution mode text\",\n        \"importance\": \"low\",\n        \"default\": \"Exit solution mode\"\n      },\n      {\n        \"name\": \"solutionModeText\",\n        \"type\": \"text\",\n        \"label\": \"Solution mode text\",\n        \"importance\": \"low\",\n        \"default\": \"Solution Mode\"\n      },\n      {\n        \"name\": \"summaryMultipleTaskText\",\n        \"type\": \"text\",\n        \"label\": \"Text when multiple tasks on a page\",\n        \"importance\": \"low\",\n        \"default\": \"Multiple tasks\"\n      },\n      {\n        \"name\": \"scoreMessage\",\n        \"type\": \"text\",\n        \"label\": \"Score message text\",\n        \"importance\": \"low\",\n        \"default\": \"You achieved:\"\n      },\n      {\n        \"name\": \"shareFacebook\",\n        \"type\": \"text\",\n        \"label\": \"Share to Facebook text\",\n        \"importance\": \"low\",\n        \"default\": \"Share on Facebook\"\n      },\n      {\n        \"name\": \"shareTwitter\",\n        \"type\": \"text\",\n        \"label\": \"Share to Twitter text\",\n        \"importance\": \"low\",\n        \"default\": \"Share on Twitter\"\n      },\n      {\n        \"name\": \"shareGoogle\",\n        \"type\": \"text\",\n        \"label\": \"Share to Google text\",\n        \"importance\": \"low\",\n        \"default\": \"Share on Google+\"\n      },\n      {\n        \"name\": \"summary\",\n        \"type\": \"text\",\n        \"label\": \"Title for summary slide\",\n        \"importance\": \"low\",\n        \"default\": \"Summary\"\n      },\n      {\n        \"name\": \"solutionsButtonTitle\",\n        \"type\": \"text\",\n        \"label\": \"Title for the comments icon\",\n        \"importance\": \"low\",\n        \"default\": \"Show comments\"\n      },\n      {\n        \"name\": \"printTitle\",\n        \"type\": \"text\",\n        \"label\": \"Title for print button\",\n        \"importance\": \"low\",\n        \"default\": \"Print\"\n      },\n      {\n        \"name\": \"printIngress\",\n        \"type\": \"text\",\n        \"label\": \"Print dialog ingress\",\n        \"importance\": \"low\",\n        \"default\": \"How would you like to print this presentation?\"\n      },\n      {\n        \"name\": \"printAllSlides\",\n        \"type\": \"text\",\n        \"label\": \"Label for \\\"Print all slides\\\" button\",\n        \"importance\": \"low\",\n        \"default\": \"Print all slides\"\n      },\n      {\n        \"name\": \"printCurrentSlide\",\n        \"type\": \"text\",\n        \"label\": \"Label for \\\"Print current slide\\\" button\",\n        \"importance\": \"low\",\n        \"default\": \"Print current slide\"\n      },\n      {\n        \"name\": \"noTitle\",\n        \"type\": \"text\",\n        \"label\": \"Label for slides without a title\",\n        \"importance\": \"low\",\n        \"default\": \"No title\"\n      },\n      {\n        \"name\": \"accessibilitySlideNavigationExplanation\",\n        \"type\": \"text\",\n        \"label\": \"Explanation of slide navigation for assistive technologies\",\n        \"importance\": \"low\",\n        \"default\": \"Use left and right arrow to change slide in that direction whenever canvas is selected.\"\n      },\n      {\n        \"name\": \"accessibilityCanvasLabel\",\n        \"type\": \"text\",\n        \"label\": \"Canvas label for assistive technologies\",\n        \"importance\": \"low\",\n        \"default\": \"Presentation canvas. Use left and right arrow to move between slides.\"\n      },\n      {\n        \"name\": \"accessibilityProgressBarLabel\",\n        \"type\": \"text\",\n        \"label\": \"Progressbar label for assistive technologies\",\n        \"importance\": \"low\",\n        \"default\": \"Choose slide to display\"\n      },\n      {\n        \"name\": \"containsNotCompleted\",\n        \"type\": \"text\",\n        \"label\": \"Label for uncompleted interactions\",\n        \"importance\": \"low\",\n        \"default\": \"@slideName contains not completed interaction\"\n      },\n      {\n        \"name\": \"containsCompleted\",\n        \"type\": \"text\",\n        \"label\": \"Label for completed interactions\",\n        \"importance\": \"low\",\n        \"default\": \"@slideName contains completed interaction\"\n      },\n      {\n        \"name\": \"slideCount\",\n        \"type\": \"text\",\n        \"label\": \"Label for slide counter. Variables are @index, @total\",\n        \"importance\": \"low\",\n        \"default\": \"Slide @index of @total\"\n      },\n      {\n        \"name\": \"containsOnlyCorrect\",\n        \"type\": \"text\",\n        \"label\": \"Label for slides that only contains correct answers\",\n        \"importance\": \"low\",\n        \"default\": \"@slideName only has correct answers\"\n      },\n      {\n        \"name\": \"containsIncorrectAnswers\",\n        \"type\": \"text\",\n        \"label\": \"Label for slides that has incorrect answers\",\n        \"importance\": \"low\",\n        \"default\": \"@slideName has incorrect answers\"\n      },\n      {\n        \"name\": \"shareResult\",\n        \"type\": \"text\",\n        \"label\": \"Label for social sharing bar\",\n        \"importance\": \"low\",\n        \"default\": \"Share Result\"\n      },\n      {\n        \"name\": \"accessibilityTotalScore\",\n        \"type\": \"text\",\n        \"label\": \"Total score announcement for assistive technologies\",\n        \"default\": \"You got @score of @maxScore points in total\",\n        \"description\": \"Available variables are @score and @maxScore\"\n      },\n      {\n        \"name\": \"accessibilityEnteredFullscreen\",\n        \"type\": \"text\",\n        \"label\": \"Entered fullscreen announcement for assistive technologies\",\n        \"default\": \"Entered fullscreen\"\n      },\n      {\n        \"name\": \"accessibilityExitedFullscreen\",\n        \"type\": \"text\",\n        \"label\": \"Exited fullscreen announcement for assistive technologies\",\n        \"default\": \"Exited fullscreen\"\n      },\n      {\n        \"name\": \"confirmDialogHeader\",\n        \"type\": \"text\",\n        \"label\": \"Header of submit result confirmation dialog\",\n        \"default\": \"Submit your answers\"\n      },\n      {\n        \"name\": \"confirmDialogText\",\n        \"type\": \"text\",\n        \"label\": \"Text of submit result confirmation dialog\",\n        \"default\": \"This will submit your results, do you want to continue?\"\n      },\n      {\n        \"name\": \"confirmDialogConfirmText\",\n        \"type\": \"text\",\n        \"label\": \"Confirmation button of submit result confirmation dialog\",\n        \"default\": \"Submit and see results\"\n      },\n      {\n        \"name\": \"slideshowNavigationLabel\",\n        \"type\": \"text\",\n        \"label\": \"Label for Slideshow navigation\",\n        \"default\": \"Slideshow navigation\"\n      },\n      {\n        \"name\": \"confirmDialogConfirmLabel\",\n        \"type\": \"text\",\n        \"label\": \"Confirm button label\",\n        \"default\": \"Confirm\"\n      },\n      {\n        \"name\": \"confirmDialogCancelLabel\",\n        \"type\": \"text\",\n        \"label\": \"Cancel button label\",\n        \"default\": \"Cancel\"\n      }\n    ]\n  },\n  {\n    \"name\": \"override\",\n    \"type\": \"group\",\n    \"label\": \"Behaviour settings.\",\n    \"importance\": \"low\",\n    \"description\": \"These options will let you override behaviour settings.\",\n    \"optional\": true,\n    \"fields\": [\n      {\n        \"name\": \"activeSurface\",\n        \"type\": \"boolean\",\n        \"widget\": \"disposableBoolean\",\n        \"label\": \"Activate Active Surface Mode\",\n        \"importance\": \"low\",\n        \"description\": \"Removes navigation controls for the end user. Use Go To Slide to navigate. Summary is not available in this mode.\",\n        \"default\": false\n      },\n      {\n        \"name\": \"hideSummarySlide\",\n        \"type\": \"boolean\",\n        \"label\": \"Hide Summary Slide\",\n        \"importance\": \"low\",\n        \"description\": \"Hides the summary slide.\",\n        \"default\": false\n      },\n      {\n        \"name\": \"showSolutionButton\",\n        \"type\": \"select\",\n        \"label\": \"Override \\\"Show Solution\\\" button\",\n        \"importance\": \"low\",\n        \"description\": \"This option determines if the \\\"Show Solution\\\" button will be configured for each question individually (default) shown for all questions (Enabled) or disabled for all questions (Disabled) \",\n        \"optional\": true,\n        \"options\": [\n          {\n            \"value\": \"on\",\n            \"label\": \"Enabled\"\n          },\n          {\n            \"value\": \"off\",\n            \"label\": \"Disabled\"\n          }\n        ]\n      },\n      {\n        \"name\": \"retryButton\",\n        \"type\": \"select\",\n        \"label\": \"Override \\\"Retry\\\" button\",\n        \"importance\": \"low\",\n        \"description\": \"This option determines if the \\\"Retry\\\" button will be configured for each question individually (default) shown for all questions (Enabled) or disabled for all questions (Disabled)\",\n        \"optional\": true,\n        \"options\": [\n          {\n            \"value\": \"on\",\n            \"label\": \"Enabled\"\n          },\n          {\n            \"value\": \"off\",\n            \"label\": \"Disabled\"\n          }\n        ]\n      },\n      {\n        \"name\": \"summarySlideSolutionButton\",\n        \"type\": \"boolean\",\n        \"label\": \"Show \\\"Show solution\\\" button in the summary slide\",\n        \"description\": \"If enabled, the learner will be able to show the solutions for all question when they reach the summary slide\",\n        \"default\": true,\n        \"importance\": \"low\",\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"hideSummarySlide\",\n              \"equals\": false\n            }\n          ]\n        }\n      },\n      {\n        \"name\": \"summarySlideRetryButton\",\n        \"type\": \"boolean\",\n        \"label\": \"Show \\\"Retry\\\" button in the summary slide\",\n        \"description\": \"If enabled, the learner will be able to retry all questions when they reach the summary slide. Be advised that by refreshing the page the learners will be able to retry even if this button isn\'t showing.\",\n        \"default\": true,\n        \"importance\": \"low\",\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"hideSummarySlide\",\n              \"equals\": false\n            }\n          ]\n        }\n      },\n      {\n        \"name\": \"enablePrintButton\",\n        \"type\": \"boolean\",\n        \"label\": \"Enable print button\",\n        \"importance\": \"low\",\n        \"description\": \"Enables the print button.\",\n        \"default\": false\n      },\n      {\n        \"name\": \"social\",\n        \"type\": \"group\",\n        \"label\": \"Social Settings\",\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"hideSummarySlide\",\n              \"equals\": false\n            }\n          ]\n        },\n        \"importance\": \"low\",\n        \"description\": \"These options will let you override social behaviour settings. Empty values will be filled in automatically if a link is provided, otherwise all values will be generated.\",\n        \"optional\": true,\n        \"fields\": [\n          {\n            \"name\": \"showFacebookShare\",\n            \"type\": \"boolean\",\n            \"label\": \"Display Facebook share icon\",\n            \"importance\": \"low\",\n            \"default\": false\n          },\n          {\n            \"name\": \"facebookShare\",\n            \"importance\": \"low\",\n            \"type\": \"group\",\n            \"expanded\": true,\n            \"label\": \"Facebook share settings\",\n            \"widget\": \"showWhen\",\n            \"showWhen\": {\n              \"rules\": [\n                {\n                  \"field\": \"showFacebookShare\",\n                  \"equals\": true\n                }\n              ]\n            },\n            \"fields\": [\n              {\n                \"name\": \"url\",\n                \"type\": \"text\",\n                \"label\": \"Share to Facebook link\",\n                \"importance\": \"low\",\n                \"default\": \"@currentpageurl\"\n              },\n              {\n                \"name\": \"quote\",\n                \"type\": \"text\",\n                \"label\": \"Share to Facebook quote\",\n                \"importance\": \"low\",\n                \"default\": \"I scored @score out of @maxScore on a task at @currentpageurl.\"\n              }\n            ]\n          },\n          {\n            \"name\": \"showTwitterShare\",\n            \"type\": \"boolean\",\n            \"label\": \"Display Twitter share icon\",\n            \"importance\": \"low\",\n            \"default\": false\n          },\n          {\n            \"name\": \"twitterShare\",\n            \"importance\": \"low\",\n            \"type\": \"group\",\n            \"expanded\": true,\n            \"label\": \"Twitter share settings\",\n            \"widget\": \"showWhen\",\n            \"showWhen\": {\n              \"rules\": [\n                {\n                  \"field\": \"showTwitterShare\",\n                  \"equals\": true\n                }\n              ]\n            },\n            \"fields\": [\n              {\n                \"name\": \"statement\",\n                \"type\": \"text\",\n                \"label\": \"Share to Twitter statement\",\n                \"importance\": \"low\",\n                \"default\": \"I scored @score out of @maxScore on a task at @currentpageurl.\"\n              },\n              {\n                \"name\": \"url\",\n                \"type\": \"text\",\n                \"label\": \"Share to Twitter link\",\n                \"importance\": \"low\",\n                \"default\": \"@currentpageurl\"\n              },\n              {\n                \"name\": \"hashtags\",\n                \"type\": \"text\",\n                \"label\": \"Share to Twitter hashtags\",\n                \"importance\": \"low\",\n                \"default\": \"h5p, course\"\n              }\n            ]\n          },\n          {\n            \"name\": \"showGoogleShare\",\n            \"type\": \"boolean\",\n            \"label\": \"Display Google+ share icon\",\n            \"importance\": \"low\",\n            \"default\": false\n          },\n          {\n            \"name\": \"googleShareUrl\",\n            \"type\": \"text\",\n            \"label\": \"Share to Google link\",\n            \"importance\": \"low\",\n            \"default\": \"@currentpageurl\",\n            \"widget\": \"showWhen\",\n            \"showWhen\": {\n              \"rules\": [\n                {\n                  \"field\": \"showGoogleShare\",\n                  \"equals\": true\n                }\n              ]\n            }\n          }\n        ]\n      }\n    ]\n  }\n]\n', NULL, 1, 26, NULL, NULL, NULL, 1);
INSERT INTO `mdl_h5p_libraries` (`id`, `machinename`, `title`, `majorversion`, `minorversion`, `patchversion`, `runnable`, `fullscreen`, `embedtypes`, `preloadedjs`, `preloadedcss`, `droplibrarycss`, `semantics`, `addto`, `coremajor`, `coreminor`, `metadatasettings`, `tutorial`, `example`, `enabled`) VALUES
(113, 'H5P.InteractiveVideo', 'Interactive Video', 1, 26, 35, 1, 1, 'iframe', 'dist/h5p-interactive-video.js', 'dist/h5p-interactive-video.css', '', '[\n  {\n    \"name\": \"interactiveVideo\",\n    \"type\": \"group\",\n    \"widget\": \"wizard\",\n    \"label\": \"Interactive Video Editor\",\n    \"importance\": \"high\",\n    \"fields\": [\n      {\n        \"name\": \"video\",\n        \"type\": \"group\",\n        \"label\": \"Upload/embed video\",\n        \"importance\": \"high\",\n        \"fields\": [\n          {\n            \"name\": \"files\",\n            \"type\": \"video\",\n            \"label\": \"Add a video\",\n            \"importance\": \"high\",\n            \"description\": \"Click below to add a video you wish to use in your interactive video. You can add a video link or upload video files. It is possible to add several versions of the video with different qualities. To ensure maximum support in browsers at least add a version in webm and mp4 formats.\",\n            \"extraAttributes\": [\n              \"metadata\"\n            ],\n            \"enableCustomQualityLabel\": true\n          },\n          {\n            \"name\": \"startScreenOptions\",\n            \"type\": \"group\",\n            \"label\": \"Start screen options (unsupported for YouTube videos)\",\n            \"importance\": \"low\",\n            \"fields\": [\n              {\n                \"name\": \"title\",\n                \"type\": \"text\",\n                \"label\": \"The title of this interactive video\",\n                \"importance\": \"low\",\n                \"maxLength\": 60,\n                \"default\": \"Interactive Video\",\n                \"description\": \"Used in summaries, statistics etc.\"\n              },\n              {\n                \"name\": \"hideStartTitle\",\n                \"type\": \"boolean\",\n                \"label\": \"Hide title on video start screen\",\n                \"importance\": \"low\",\n                \"optional\": true,\n                \"default\": false\n              },\n              {\n                \"name\": \"shortStartDescription\",\n                \"type\": \"text\",\n                \"label\": \"Short description (Optional)\",\n                \"importance\": \"low\",\n                \"optional\": true,\n                \"maxLength\": 120,\n                \"description\": \"Optional. Display a short description text on the video start screen. Does not work for YouTube videos.\"\n              },\n              {\n                \"name\": \"poster\",\n                \"type\": \"image\",\n                \"label\": \"Poster image\",\n                \"importance\": \"low\",\n                \"optional\": true,\n                \"description\": \"Image displayed before the user launches the video. Does not work for YouTube Videos.\"\n              }\n            ]\n          },\n          {\n            \"name\": \"textTracks\",\n            \"type\": \"group\",\n            \"label\": \"Text tracks (unsupported for YouTube videos)\",\n            \"importance\": \"low\",\n            \"fields\": [\n              {\n                \"name\": \"videoTrack\",\n                \"type\": \"list\",\n                \"label\": \"Available text tracks\",\n                \"importance\": \"low\",\n                \"optional\": true,\n                \"entity\": \"Track\",\n                \"min\": 0,\n                \"defaultNum\": 1,\n                \"field\": {\n                  \"name\": \"track\",\n                  \"type\": \"group\",\n                  \"label\": \"Track\",\n                  \"importance\": \"low\",\n                  \"expanded\": false,\n                  \"fields\": [\n                    {\n                      \"name\": \"label\",\n                      \"type\": \"text\",\n                      \"label\": \"Track label\",\n                      \"description\": \"Used if you offer multiple tracks and the user has to choose a track. For instance \'Spanish subtitles\' could be the label of a Spanish subtitle track.\",\n                      \"importance\": \"low\",\n                      \"default\": \"Subtitles\",\n                      \"optional\": true\n                    },\n                    {\n                      \"name\": \"kind\",\n                      \"type\": \"select\",\n                      \"label\": \"Type of text track\",\n                      \"importance\": \"low\",\n                      \"default\": \"subtitles\",\n                      \"options\": [\n                        {\n                          \"value\": \"subtitles\",\n                          \"label\": \"Subtitles\"\n                        },\n                        {\n                          \"value\": \"captions\",\n                          \"label\": \"Captions\"\n                        },\n                        {\n                          \"value\": \"descriptions\",\n                          \"label\": \"Descriptions\"\n                        }\n                      ]\n                    },\n                    {\n                      \"name\": \"srcLang\",\n                      \"type\": \"text\",\n                      \"label\": \"Source language, must be defined for subtitles\",\n                      \"importance\": \"low\",\n                      \"default\": \"en\",\n                      \"description\": \"Must be a valid BCP 47 language tag. If \'Subtitles\' is the type of text track selected, the source language of the track must be defined.\"\n                    },\n                    {\n                      \"name\": \"track\",\n                      \"type\": \"file\",\n                      \"label\": \"Track source (WebVTT file)\",\n                      \"importance\": \"low\"\n                    }\n                  ]\n                }\n              },\n              {\n                \"name\": \"defaultTrackLabel\",\n                \"type\": \"text\",\n                \"label\": \"Default text track\",\n                \"description\": \"If left empty or not matching any of the text tracks the first text track will be used as the default.\",\n                \"importance\": \"low\",\n                \"optional\": true\n              }\n            ]\n          }\n        ]\n      },\n      {\n        \"name\": \"assets\",\n        \"type\": \"group\",\n        \"label\": \"Add interactions\",\n        \"importance\": \"high\",\n        \"widget\": \"interactiveVideo\",\n        \"video\": \"video/files\",\n        \"poster\": \"video/startScreenOptions/poster\",\n        \"fields\": [\n          {\n            \"name\": \"interactions\",\n            \"type\": \"list\",\n            \"field\": {\n              \"name\": \"interaction\",\n              \"type\": \"group\",\n              \"fields\": [\n                {\n                  \"name\": \"duration\",\n                  \"type\": \"group\",\n                  \"widget\": \"duration\",\n                  \"label\": \"Display time\",\n                  \"importance\": \"low\",\n                  \"fields\": [\n                    {\n                      \"name\": \"from\",\n                      \"type\": \"number\"\n                    },\n                    {\n                      \"name\": \"to\",\n                      \"type\": \"number\"\n                    }\n                  ]\n                },\n                {\n                  \"name\": \"pause\",\n                  \"label\": \"Pause video\",\n                  \"importance\": \"low\",\n                  \"type\": \"boolean\"\n                },\n                {\n                  \"name\": \"displayType\",\n                  \"label\": \"Display as\",\n                  \"importance\": \"low\",\n                  \"description\": \"<b>Button</b> is a collapsed interaction the user must press to open. <b>Poster</b> is an expanded interaction displayed directly on top of the video\",\n                  \"type\": \"select\",\n                  \"widget\": \"imageRadioButtonGroup\",\n                  \"options\": [\n                    {\n                      \"value\": \"button\",\n                      \"label\": \"Button\"\n                    },\n                    {\n                      \"value\": \"poster\",\n                      \"label\": \"Poster\"\n                    }\n                  ],\n                  \"default\": \"button\"\n                },\n                {\n                  \"name\": \"buttonOnMobile\",\n                  \"label\": \"Turn into button on small screens\",\n                  \"importance\": \"low\",\n                  \"type\": \"boolean\",\n                  \"default\": false\n                },\n                {\n                  \"name\": \"label\",\n                  \"type\": \"text\",\n                  \"widget\": \"html\",\n                  \"label\": \"Label\",\n                  \"importance\": \"low\",\n                  \"description\": \"Label displayed next to interaction icon.\",\n                  \"optional\": true,\n                  \"enterMode\": \"p\",\n                  \"tags\": [\n                    \"p\"\n                  ]\n                },\n                {\n                  \"name\": \"x\",\n                  \"type\": \"number\",\n                  \"importance\": \"low\",\n                  \"widget\": \"none\"\n                },\n                {\n                  \"name\": \"y\",\n                  \"type\": \"number\",\n                  \"importance\": \"low\",\n                  \"widget\": \"none\"\n                },\n                {\n                  \"name\": \"width\",\n                  \"type\": \"number\",\n                  \"widget\": \"none\",\n                  \"importance\": \"low\",\n                  \"optional\": true\n                },\n                {\n                  \"name\": \"height\",\n                  \"type\": \"number\",\n                  \"widget\": \"none\",\n                  \"importance\": \"low\",\n                  \"optional\": true\n                },\n                {\n                  \"name\": \"libraryTitle\",\n                  \"type\": \"text\",\n                  \"importance\": \"low\",\n                  \"optional\": true,\n                  \"widget\": \"none\"\n                },\n                {\n                  \"name\": \"action\",\n                  \"type\": \"library\",\n                  \"importance\": \"low\",\n                  \"options\": [\n                    \"H5P.Nil 1.0\",\n                    \"H5P.Text 1.1\",\n                    \"H5P.Table 1.1\",\n                    \"H5P.Link 1.3\",\n                    \"H5P.Image 1.1\",\n                    \"H5P.Summary 1.10\",\n                    \"H5P.SingleChoiceSet 1.11\",\n                    \"H5P.MultiChoice 1.16\",\n                    \"H5P.TrueFalse 1.8\",\n                    \"H5P.Blanks 1.14\",\n                    \"H5P.DragQuestion 1.14\",\n                    \"H5P.MarkTheWords 1.11\",\n                    \"H5P.DragText 1.10\",\n                    \"H5P.GoToQuestion 1.3\",\n                    \"H5P.IVHotspot 1.2\",\n                    \"H5P.Questionnaire 1.3\",\n                    \"H5P.FreeTextQuestion 1.0\",\n                    \"H5P.MultiMediaChoice 0.3\"\n                  ]\n                },\n                {\n                  \"name\": \"adaptivity\",\n                  \"type\": \"group\",\n                  \"label\": \"Adaptivity\",\n                  \"importance\": \"low\",\n                  \"optional\": true,\n                  \"fields\": [\n                    {\n                      \"name\": \"correct\",\n                      \"type\": \"group\",\n                      \"label\": \"Action on all correct\",\n                      \"fields\": [\n                        {\n                          \"name\": \"seekTo\",\n                          \"type\": \"number\",\n                          \"widget\": \"timecode\",\n                          \"label\": \"Seek to\",\n                          \"description\": \"Enter timecode in the format M:SS\"\n                        },\n                        {\n                          \"name\": \"allowOptOut\",\n                          \"type\": \"boolean\",\n                          \"label\": \"Allow the user to opt out and continue\"\n                        },\n                        {\n                          \"name\": \"message\",\n                          \"type\": \"text\",\n                          \"widget\": \"html\",\n                          \"enterMode\": \"p\",\n                          \"tags\": [\n                            \"strong\",\n                            \"em\",\n                            \"del\",\n                            \"a\",\n                            \"code\"\n                          ],\n                          \"label\": \"Message\"\n                        },\n                        {\n                          \"name\": \"seekLabel\",\n                          \"type\": \"text\",\n                          \"label\": \"Label for seek button\"\n                        }\n                      ]\n                    },\n                    {\n                      \"name\": \"wrong\",\n                      \"type\": \"group\",\n                      \"label\": \"Action on wrong\",\n                      \"fields\": [\n                        {\n                          \"name\": \"seekTo\",\n                          \"type\": \"number\",\n                          \"widget\": \"timecode\",\n                          \"label\": \"Seek to\",\n                          \"description\": \"Enter timecode in the format M:SS\"\n                        },\n                        {\n                          \"name\": \"allowOptOut\",\n                          \"type\": \"boolean\",\n                          \"label\": \"Allow the user to opt out and continue\"\n                        },\n                        {\n                          \"name\": \"message\",\n                          \"type\": \"text\",\n                          \"widget\": \"html\",\n                          \"enterMode\": \"p\",\n                          \"tags\": [\n                            \"strong\",\n                            \"em\",\n                            \"del\",\n                            \"a\",\n                            \"code\"\n                          ],\n                          \"label\": \"Message\"\n                        },\n                        {\n                          \"name\": \"seekLabel\",\n                          \"type\": \"text\",\n                          \"label\": \"Label for seek button\"\n                        }\n                      ]\n                    },\n                    {\n                      \"name\": \"requireCompletion\",\n                      \"type\": \"boolean\",\n                      \"label\": \"Require full score for task before proceeding\",\n                      \"description\": \"For best functionality this option should be used in conjunction with the \\\"Disable navigation forward in a video\\\" option of Interactive Video.\"\n                    }\n                  ]\n                },\n                {\n                  \"name\": \"visuals\",\n                  \"label\": \"Visuals\",\n                  \"importance\": \"low\",\n                  \"type\": \"group\",\n                  \"fields\": [\n                    {\n                      \"name\": \"backgroundColor\",\n                      \"type\": \"text\",\n                      \"label\": \"Background color\",\n                      \"widget\": \"colorSelector\",\n                      \"default\": \"rgb(255, 255, 255)\",\n                      \"spectrum\": {\n                        \"showInput\": true,\n                        \"showAl