INSERT INTO `mdl_h5p_libraries` (`id`, `machinename`, `title`, `majorversion`, `minorversion`, `patchversion`, `runnable`, `fullscreen`, `embedtypes`, `preloadedjs`, `preloadedcss`, `droplibrarycss`, `semantics`, `addto`, `coremajor`, `coreminor`, `metadatasettings`, `tutorial`, `example`, `enabled`) VALUES
(118, 'H5P.ThreeImage', 'Virtual Tour (360)', 0, 5, 8, 1, 1, 'iframe', 'dist/h5p-three-image.js', 'dist/h5p-three-image.css', '', '[\n  {\n    \"name\": \"threeImage\",\n    \"type\": \"group\",\n    \"widget\": \"threeImage\",\n    \"label\": \"Three Image Editor\",\n    \"importance\": \"high\",\n    \"fields\": [\n      {\n        \"name\": \"scenes\",\n        \"type\": \"list\",\n        \"label\": \"Scenes\",\n        \"entity\": \"Scene\",\n        \"min\": 0,\n        \"field\": {\n          \"name\": \"scene\",\n          \"type\": \"group\",\n          \"fields\": [\n            {\n              \"name\": \"sceneType\",\n              \"type\": \"select\",\n              \"label\": \"Scene type\",\n              \"widget\": \"radioGroup\",\n              \"alignment\": \"horizontal\",\n              \"options\": [\n                {\n                  \"value\": \"360\",\n                  \"label\": \"360 image\"\n                },\n                {\n                  \"value\": \"static\",\n                  \"label\": \"Static image\"\n                }\n              ],\n              \"default\": \"360\"\n            },\n            {\n              \"name\": \"showBackButton\",\n              \"type\": \"boolean\",\n              \"label\": \"Display \\\"Back\\\" button\",\n              \"description\": \"Display button for navigating back to your previous scene\",\n              \"default\": true,\n              \"widget\": \"showWhen\",\n              \"showWhen\": {\n                \"rules\": [\n                  {\n                    \"field\": \"sceneType\",\n                    \"equals\": \"static\"\n                  }\n                ]\n              }\n            },\n            {\n              \"name\": \"sceneId\",\n              \"type\": \"number\"\n            },\n            {\n              \"name\": \"scenename\",\n              \"type\": \"text\",\n              \"label\": \"Scene Title\",\n              \"description\": \"Used to identify the scene\"\n            },\n            {\n              \"name\": \"scenesrc\",\n              \"type\": \"image\",\n              \"label\": \"Scene Background\"\n            },\n            {\n              \"name\": \"scenedescription\",\n              \"type\": \"text\",\n              \"widget\": \"html\",\n              \"label\": \"Scene Description\",\n              \"description\": \"A text that can describe the scene for the end-user\",\n              \"optional\": true,\n              \"tags\": [\n                \"p\",\n                \"br\",\n                \"strong\",\n                \"em\",\n                \"code\"\n              ]\n            },\n            {\n              \"name\": \"cameraStartPosition\",\n              \"type\": \"text\"\n            },\n            {\n              \"name\": \"interactions\",\n              \"type\": \"list\",\n              \"min\": 0,\n              \"field\": {\n                \"name\": \"interaction\",\n                \"type\": \"group\",\n                \"fields\": [\n                  {\n                    \"name\": \"labelText\",\n                    \"type\": \"text\",\n                    \"label\": \"Label\",\n                    \"optional\": true,\n                    \"description\": \"If left blank no label will be displayed and we\'ll try to use the title field for screen readers\"\n                  },\n                  {\n                    \"name\": \"label\",\n                    \"type\": \"group\",\n                    \"label\": \"Label Settings\",\n                    \"importance\": \"low\",\n                    \"fields\": [\n                      {\n                        \"name\": \"labelPosition\",\n                        \"type\": \"select\",\n                        \"label\": \"Label position\",\n                        \"description\": \"Choose where the label should appear\",\n                        \"options\": [\n                          {\n                            \"value\": \"inherit\",\n                            \"label\": \"Use behavioral setting\"\n                          },\n                          {\n                            \"value\": \"right\",\n                            \"label\": \"Right aligned\"\n                          },\n                          {\n                            \"value\": \"left\",\n                            \"label\": \"Left aligned\"\n                          },\n                          {\n                            \"value\": \"top\",\n                            \"label\": \"Top aligned\"\n                          },\n                          {\n                            \"value\": \"bottom\",\n                            \"label\": \"Bottom aligned\"\n                          }\n                        ],\n                        \"default\": \"inherit\"\n                      },\n                      {\n                        \"name\": \"showLabel\",\n                        \"type\": \"select\",\n                        \"label\": \"Display Label\",\n                        \"description\": \"If hidden - labels will show only on mouse over\",\n                        \"options\": [\n                          {\n                            \"value\": \"inherit\",\n                            \"label\": \"Use behavioral setting\"\n                          },\n                          {\n                            \"value\": \"show\",\n                            \"label\": \"Show\"\n                          },\n                          {\n                            \"value\": \"hide\",\n                            \"label\": \"Hide\"\n                          }\n                        ],\n                        \"default\": \"inherit\"\n                      }\n                    ]\n                  },\n                  {\n                    \"name\": \"action\",\n                    \"type\": \"library\",\n                    \"options\": [\n                      \"H5P.GoToScene 0.1\",\n                      \"H5P.AdvancedText 1.1\",\n                      \"H5P.Image 1.1\",\n                      \"H5P.Audio 1.5\",\n                      \"H5P.Video 1.6\",\n                      \"H5P.Summary 1.10\",\n                      \"H5P.SingleChoiceSet 1.11\"\n                    ]\n                  },\n                  {\n                    \"name\": \"interactionpos\",\n                    \"type\": \"text\"\n                  }\n                ]\n              }\n            },\n            {\n              \"name\": \"iconType\",\n              \"type\": \"select\",\n              \"label\": \"Button style\",\n              \"description\": \"Decide how buttons pointing to this scene should look. For scenes that are static and does not lead to new scenes, we recommend the \\\"More information\\\" button.\",\n              \"widget\": \"radioGroup\",\n              \"alignment\": \"horizontal\",\n              \"options\": [\n                {\n                  \"value\": \"arrow\",\n                  \"label\": \"New scene (arrow)\"\n                },\n                {\n                  \"value\": \"plus\",\n                  \"label\": \"More information (plus)\"\n                }\n              ],\n              \"default\": \"arrow\"\n            },\n            {\n              \"name\": \"audio\",\n              \"type\": \"audio\",\n              \"label\": \"Audio Track\",\n              \"description\": \"Add an audio track that\'s specific for this scene.\",\n              \"optional\": true,\n              \"widgetExtensions\": [\n                \"AudioRecorder\"\n              ]\n            }\n          ]\n        }\n      },\n      {\n        \"name\": \"startSceneId\",\n        \"type\": \"number\",\n        \"default\": 0\n      },\n      {\n        \"name\": \"audio\",\n        \"type\": \"audio\",\n        \"label\": \"Audio track\",\n        \"optional\": true\n      }\n    ]\n  },\n  {\n    \"name\": \"behaviour\",\n    \"type\": \"group\",\n    \"label\": \"Behavioral settings\",\n    \"importance\": \"low\",\n    \"description\": \"These options will let you control how the world behaves.\",\n    \"fields\": [\n      {\n        \"name\": \"audio\",\n        \"type\": \"audio\",\n        \"label\": \"Global Audio\",\n        \"description\": \"Add an audio track that\'s available for all of the scenes by default.\",\n        \"optional\": true,\n        \"widgetExtensions\": [\n          \"AudioRecorder\"\n        ]\n      },\n      {\n        \"name\": \"sceneRenderingQuality\",\n        \"type\": \"select\",\n        \"label\": \"Scene rendering quality\",\n        \"description\": \"Choose the amount of width and height segments used to render a scene. This directly affects the quality level of the scene, try increasing the quality if a scene looks \\\"blocky\\\" or \\\"waves\\\" are seen within the scenes. Note that higher quality rendering takes more time to load.\",\n        \"options\": [\n          {\n            \"value\": \"high\",\n            \"label\": \"High Quality (128x128)\"\n          },\n          {\n            \"value\": \"medium\",\n            \"label\": \"Medium Quality (64x64)\"\n          },\n          {\n            \"value\": \"low\",\n            \"label\": \"Low Quality (16x16)\"\n          }\n        ],\n        \"default\": \"high\"\n      },\n      {\n        \"name\": \"label\",\n        \"type\": \"group\",\n        \"label\": \"Label settings\",\n        \"importance\": \"low\",\n        \"expanded\": true,\n        \"fields\": [\n          {\n            \"name\": \"labelPosition\",\n            \"type\": \"select\",\n            \"label\": \"Label position\",\n            \"description\": \"The default label position. The position may be overriden per interaction\",\n            \"options\": [\n              {\n                \"value\": \"right\",\n                \"label\": \"Right aligned\"\n              },\n              {\n                \"value\": \"left\",\n                \"label\": \"Left aligned\"\n              },\n              {\n                \"value\": \"top\",\n                \"label\": \"Top aligned\"\n              },\n              {\n                \"value\": \"bottom\",\n                \"label\": \"Bottom aligned\"\n              }\n            ],\n            \"default\": \"right\"\n          },\n          {\n            \"name\": \"showLabel\",\n            \"type\": \"boolean\",\n            \"label\": \"Display Labels\",\n            \"description\": \"If unchecked - labels will show only on mouse over\",\n            \"default\": true\n          }\n        ]\n      }\n    ]\n  },\n  {\n    \"name\": \"l10n\",\n    \"type\": \"group\",\n    \"common\": true,\n    \"label\": \"Localize\",\n    \"fields\": [\n      {\n        \"name\": \"title\",\n        \"type\": \"text\",\n        \"label\": \"Aria label for content type\",\n        \"default\": \"Virtual Tour\"\n      },\n      {\n        \"name\": \"playAudioTrack\",\n        \"type\": \"text\",\n        \"label\": \"Label for to play audio\",\n        \"default\": \"Play Audio Track\"\n      },\n      {\n        \"name\": \"pauseAudioTrack\",\n        \"type\": \"text\",\n        \"label\": \"Label to pause audio\",\n        \"default\": \"Pause Audio Track\"\n      },\n      {\n        \"name\": \"sceneDescription\",\n        \"type\": \"text\",\n        \"label\": \"Title to scene dialog\",\n        \"default\": \"Scene Description\"\n      },\n      {\n        \"name\": \"resetCamera\",\n        \"type\": \"text\",\n        \"label\": \"Label for button to reset camera\",\n        \"default\": \"Reset Camera\"\n      },\n      {\n        \"name\": \"submitDialog\",\n        \"type\": \"text\",\n        \"label\": \"Label for the submit dialog button\",\n        \"default\": \"Submit Dialog\"\n      },\n      {\n        \"name\": \"closeDialog\",\n        \"type\": \"text\",\n        \"label\": \"Label for the close dialog button\",\n        \"default\": \"Close Dialog\"\n      },\n      {\n        \"name\": \"expandButtonAriaLabel\",\n        \"type\": \"text\",\n        \"label\": \"Aria label for the expand label button\",\n        \"default\": \"Expand the visual label\"\n      },\n      {\n        \"name\": \"backgroundLoading\",\n        \"type\": \"text\",\n        \"label\": \"Label for when background image is loading in 360 scene\",\n        \"default\": \"Loading background image...\"\n      },\n      {\n        \"name\": \"noContent\",\n        \"type\": \"text\",\n        \"label\": \"Label for when there is no content\",\n        \"default\": \"No content\"\n      }\n    ]\n  }\n]', NULL, 1, 20, NULL, 'https://h5p.org/tutorial-virtual-tour', 'https://h5p.org/virtual-tour-360', 1),
(119, 'H5P.ThreeJS', 'three.js', 1, 0, 108, 0, 0, '', 'dist/three.min.js', '', '', '', NULL, 1, 12, NULL, NULL, NULL, 1),
(120, 'H5P.ThreeSixty', 'Three Sixty', 0, 3, 7, 0, 0, '', 'scripts/three-sixty.js', 'styles/three-sixty.css', '', '', NULL, 1, 12, NULL, NULL, NULL, 1),
(121, 'H5PEditor.ThreeImage', 'Three Image Editor', 0, 5, 2, 0, 0, '', 'dist/h5p-editor-three-image.js', '', '', '', NULL, NULL, NULL, NULL, NULL, NULL, 1),
(122, 'H5P.FindTheWords', 'Find The Words', 1, 4, 4, 1, 0, 'iframe', 'scripts/h5p-find-the-words.js, scripts/h5p-find-the-words-word-grid.js, scripts/h5p-find-the-words-vocabulary.js, scripts/h5p-find-the-words-timer.js, scripts/h5p-find-the-words-counter.js', 'styles/h5p-find-the-words.css', '', '[\n  {\n    \"label\": \"Task description\",\n    \"name\": \"taskDescription\",\n    \"type\": \"text\",\n    \"description\": \"Description of the Game\",\n    \"default\": \"Find the words from the grid\",\n    \"importance\": \"high\"\n  },\n  {\n    \"name\": \"wordList\",\n    \"type\": \"text\",\n    \"label\": \"Word list\",\n    \"description\": \"Comma Separated list of words. Special Characters, White Spaces and Numbers Not allowed\",\n    \"default\": \"one,two,three\",\n    \"regexp\": {\n      \"pattern\": \"^(?!(?:.*[\\\"!#$%&./:;<=>?@\\\\[\\\\]^_`\\\\{|}~\'()\\\\-*+\\\\d]|^[,])).*$\"\n    },\n    \"importance\": \"high\"\n  },\n  {\n    \"name\": \"behaviour\",\n    \"type\": \"group\",\n    \"label\": \"Behavioural settings\",\n    \"importance\": \"low\",\n    \"description\": \"These options will let you control how the game behaves.\",\n    \"optional\": true,\n    \"fields\": [\n      {\n        \"name\": \"orientations\",\n        \"type\": \"group\",\n        \"label\": \"Orientations\",\n        \"description\": \"An array containing the names of the word directions that should be used when creating the puzzle\",\n        \"fields\": [\n          {\n            \"name\": \"horizontal\",\n            \"type\": \"boolean\",\n            \"label\": \"Horizontal- left to right\",\n            \"default\": true\n          },\n          {\n            \"name\": \"horizontalBack\",\n            \"type\": \"boolean\",\n            \"label\": \"Horizontal- right to left\",\n            \"default\": true\n          },\n          {\n            \"name\": \"vertical\",\n            \"type\": \"boolean\",\n            \"label\": \"Vertical downwards\",\n            \"default\": true\n          },\n          {\n            \"name\": \"verticalUp\",\n            \"type\": \"boolean\",\n            \"label\": \"Vertical upwards\",\n            \"default\": true\n          },\n          {\n            \"name\": \"diagonal\",\n            \"type\": \"boolean\",\n            \"label\": \"Diagonal downwards- left to right\",\n            \"default\": true\n          },\n          {\n            \"name\": \"diagonalBack\",\n            \"type\": \"boolean\",\n            \"label\": \"Diagonal downwards- right to left\",\n            \"default\": true\n          },\n          {\n            \"name\": \"diagonalUp\",\n            \"type\": \"boolean\",\n            \"label\": \"Diagonal upwards- left to right\",\n            \"default\": true\n          },\n          {\n            \"name\": \"diagonalUpBack\",\n            \"type\": \"boolean\",\n            \"label\": \"Diagonal upwards- right to left\",\n            \"default\": true\n          }\n        ]\n      },\n      {\n        \"name\": \"fillPool\",\n        \"type\": \"text\",\n        \"label\": \"Vertical downwards\",\n        \"description\": \"pool of letters from which the blanks to be filled\",\n        \"default\": \"abcdefghijklmnopqrstuvwxyz\",\n        \"regexp\": {\n          \"pattern\": \"^[^\\t\\n .<>?;:\\\"\'`!@#$%^&*()\\\\[\\\\]{}_+=|\\\\-]*$\"\n        }\n      },\n      {\n        \"name\": \"preferOverlap\",\n        \"type\": \"boolean\",\n        \"label\": \"Prefer overlap\",\n        \"description\": \"Determines how wordfind decides where to place a word within the puzzle.   When true, it randomly selects amongst the positions the highest number of letters that overlap creating a more compact puzzle.   When false, it randomly selects amongst all valid positions creating a less compact puzzle.\",\n        \"default\": true\n      },\n      {\n        \"name\": \"showVocabulary\",\n        \"type\": \"boolean\",\n        \"label\": \"Show vocabulary\",\n        \"description\": \"Determines whether to show vocabularies to the player\",\n        \"default\": true\n      },\n      {\n        \"name\": \"enableShowSolution\",\n        \"type\": \"boolean\",\n        \"label\": \"Enable show solution\",\n        \"description\": \"Add a show solution button for the game\",\n        \"default\": true\n      },\n      {\n        \"name\": \"enableRetry\",\n        \"type\": \"boolean\",\n        \"label\": \"Enable retry\",\n        \"description\": \"Add a retry button for the game\",\n        \"default\": true\n      }\n    ]\n  },\n  {\n    \"label\": \"Localization\",\n    \"importance\": \"low\",\n    \"name\": \"l10n\",\n    \"type\": \"group\",\n    \"common\": true,\n    \"fields\": [\n      {\n        \"label\": \"Text for \\\"Check\\\" button\",\n        \"importance\": \"low\",\n        \"name\": \"check\",\n        \"type\": \"text\",\n        \"default\": \"Check\"\n      },\n      {\n        \"label\": \"Text for \\\"Retry\\\" button\",\n        \"importance\": \"low\",\n        \"name\": \"tryAgain\",\n        \"type\": \"text\",\n        \"default\": \"Retry\"\n      },\n      {\n        \"label\": \"Text for \\\"Show Solution\\\" button\",\n        \"importance\": \"low\",\n        \"name\": \"showSolution\",\n        \"type\": \"text\",\n        \"default\": \"Show Solution\"\n      },\n      {\n        \"label\": \"Counter text\",\n        \"importance\": \"low\",\n        \"name\": \"found\",\n        \"type\": \"text\",\n        \"default\": \"@found of @totalWords found\",\n        \"description\": \"Feedback text, variables available: @found and @totalWords. Example: \'@found of @totalWords found\'\"\n      },\n      {\n        \"label\": \"Time spent text\",\n        \"importance\": \"low\",\n        \"name\": \"timeSpent\",\n        \"type\": \"text\",\n        \"default\": \"Time Spent\",\n        \"description\": \"label for showing the time spent while playing the game\"\n      },\n      {\n        \"label\": \"Feedback text\",\n        \"importance\": \"low\",\n        \"name\": \"score\",\n        \"type\": \"text\",\n        \"default\": \"You got @score of @total points\",\n        \"description\": \"Feedback text, variables available: @score and @total. Example: \'You got @score of @total possible points\'\"\n      },\n      {\n        \"label\": \"Word list header\",\n        \"importance\": \"low\",\n        \"name\": \"wordListHeader\",\n        \"type\": \"text\",\n        \"default\": \"Find the words\",\n        \"maxLength\": 20\n      }\n    ]\n  }\n]\n', NULL, NULL, NULL, NULL, NULL, 'https://h5p.org/find-the-words', 1),
(123, 'H5P.InteractiveBook', 'Interactive Book', 1, 11, 11, 1, 1, 'iframe', 'dist/h5p-interactive-book.js', 'dist/h5p-interactive-book.css', '', '[\n  {\n    \"name\": \"showCoverPage\",\n    \"type\": \"boolean\",\n    \"label\": \"Enable book cover\",\n    \"description\": \"A cover that shows info regarding the book before access\",\n    \"importance\": \"low\",\n    \"default\": false\n  },\n  {\n    \"name\": \"bookCover\",\n    \"type\": \"group\",\n    \"label\": \"Cover Page\",\n    \"importance\": \"medium\",\n    \"widget\": \"showWhen\",\n    \"showWhen\": {\n      \"rules\": [\n        {\n          \"field\": \"showCoverPage\",\n          \"equals\": true\n        }\n      ]\n    },\n    \"fields\": [\n      {\n        \"name\": \"coverDescription\",\n        \"type\": \"text\",\n        \"widget\": \"html\",\n        \"label\": \"Cover description\",\n        \"importance\": \"medium\",\n        \"optional\": true,\n        \"description\": \"This text will be the description of your book.\",\n        \"default\": \"<p style=\\\"text-align: center;\\\"></p>\",\n        \"enterMode\": \"p\",\n        \"tags\": [\n          \"sub\",\n          \"sup\",\n          \"strong\",\n          \"em\",\n          \"p\",\n          \"code\",\n          \"u\",\n          \"del\",\n          \"a\",\n          \"ul\",\n          \"ol\",\n          \"h1\",\n          \"h2\",\n          \"h3\",\n          \"h4\",\n          \"h5\",\n          \"h6\",\n          \"pre\",\n          \"hr\",\n          \"table\"\n        ],\n        \"font\": {\n          \"size\": true,\n          \"color\": true,\n          \"background\": true\n        }\n      },\n      {\n        \"name\": \"coverMedium\",\n        \"type\": \"library\",\n        \"label\": \"Cover media\",\n        \"description\": \"Optional media to display on the cover.\",\n        \"optional\": true,\n        \"options\": [\n          \"H5P.Image 1.1\",\n          \"H5P.Video 1.6\"\n        ]\n      }\n    ]\n  },\n  {\n    \"name\": \"chapters\",\n    \"type\": \"list\",\n    \"label\": \"Pages\",\n    \"entity\": \"Page\",\n    \"widgets\": [\n      {\n        \"name\": \"VerticalTabs\",\n        \"label\": \"Default\"\n      }\n    ],\n    \"importance\": \"high\",\n    \"min\": 1,\n    \"max\": 50,\n    \"field\": {\n      \"name\": \"item\",\n      \"type\": \"group\",\n      \"label\": \"Item\",\n      \"importance\": \"low\",\n      \"expanded\": true,\n      \"fields\": [\n        {\n          \"label\": \"Page\",\n          \"name\": \"chapter\",\n          \"type\": \"library\",\n          \"options\": [\n            \"H5P.Column 1.18\"\n          ]\n        }\n      ]\n    }\n  },\n  {\n    \"name\": \"behaviour\",\n    \"type\": \"group\",\n    \"importance\": \"low\",\n    \"label\": \"Behavioural settings\",\n    \"fields\": [\n      {\n        \"name\": \"baseColor\",\n        \"type\": \"text\",\n        \"label\": \"Base color\",\n        \"description\": \"Set the base color that will define the overall color scheme of the book. Please ensure a high enough contrast.\",\n        \"optional\": true,\n        \"widget\": \"colorSelector\",\n        \"default\": \"#1768c4\",\n        \"spectrum\": {\n          \"showInput\": true,\n          \"showInitial\": true,\n          \"showPalette\": true,\n          \"palette\": [\n            [\n              \"#1768C4\"\n            ],\n            [\n              \"#D9B323\"\n            ],\n            [\n              \"#D32F2F\"\n            ],\n            [\n              \"#1EB224\"\n            ],\n            [\n              \"#7E57C2\"\n            ]\n          ]\n        }\n      },\n      {\n        \"name\": \"defaultTableOfContents\",\n        \"type\": \"boolean\",\n        \"label\": \"Display table of contents as default\",\n        \"description\": \"When enabled the table of contents is showed when opening the book\",\n        \"default\": true\n      },\n      {\n        \"name\": \"progressIndicators\",\n        \"type\": \"boolean\",\n        \"label\": \"Display Progress Indicators\",\n        \"description\": \"When enabled there will be indicators per page showing the user if he is done with the page or not.\",\n        \"default\": true\n      },\n      {\n        \"name\": \"progressAuto\",\n        \"type\": \"boolean\",\n        \"label\": \"Enable automatic progress\",\n        \"description\": \"If enabled a page without tasks is considered done when viewed. A page with tasks when all tasks are done. If disabled there will be a button at the bottom of every page for the user to click when done with the page.\",\n        \"default\": true,\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"progressIndicators\",\n              \"equals\": true\n            }\n          ]\n        }\n      },\n      {\n        \"name\": \"displaySummary\",\n        \"type\": \"boolean\",\n        \"label\": \"Display summary\",\n        \"description\": \"When enabled the user can see a summary and submit the progress/answers\",\n        \"default\": true\n      },\n      {\n        \"name\": \"enableRetry\",\n        \"type\": \"boolean\",\n        \"label\": \"Enable \\\"Restart\\\" button\",\n        \"description\": \"When enabled the user can initiate a restart on the summary page.\",\n        \"default\": true,\n        \"optional\": true\n      }\n    ]\n  },\n  {\n    \"name\": \"read\",\n    \"type\": \"text\",\n    \"label\": \"Translation for \\\"Read\\\"\",\n    \"importance\": \"low\",\n    \"default\": \"Read\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"name\": \"displayTOC\",\n    \"type\": \"text\",\n    \"label\": \"Translation for \\\"Display \'Table of contents\'\\\"\",\n    \"importance\": \"low\",\n    \"default\": \"Display \'Table of contents\'\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"name\": \"hideTOC\",\n    \"type\": \"text\",\n    \"label\": \"Translation for \\\"Hide \'Table of contents\'\\\"\",\n    \"importance\": \"low\",\n    \"default\": \"Hide \'Table of contents\'\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"name\": \"nextPage\",\n    \"type\": \"text\",\n    \"label\": \"Translation for \\\"Next page\\\"\",\n    \"importance\": \"low\",\n    \"default\": \"Next page\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"name\": \"previousPage\",\n    \"type\": \"text\",\n    \"label\": \"Translation for \\\"Previous page\\\"\",\n    \"importance\": \"low\",\n    \"default\": \"Previous page\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"name\": \"chapterCompleted\",\n    \"type\": \"text\",\n    \"label\": \"Translation for \\\"Page completed!\\\"\",\n    \"importance\": \"low\",\n    \"default\": \"Page completed!\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"name\": \"partCompleted\",\n    \"type\": \"text\",\n    \"label\": \"Translation for \\\"@pages of @total completed\\\" (@pages and @total will be replaced by actual values)\",\n    \"importance\": \"low\",\n    \"default\": \"@pages of @total completed\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"name\": \"incompleteChapter\",\n    \"type\": \"text\",\n    \"label\": \"Translation for \\\"Incomplete page\\\"\",\n    \"importance\": \"low\",\n    \"default\": \"Incomplete page\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"name\": \"navigateToTop\",\n    \"type\": \"text\",\n    \"label\": \"Translation for \\\"Navigate to the top\\\"\",\n    \"importance\": \"low\",\n    \"default\": \"Navigate to the top\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"name\": \"markAsFinished\",\n    \"type\": \"text\",\n    \"importance\": \"low\",\n    \"label\": \"Translation for \\\"I have finished this page\\\"\",\n    \"default\": \"I have finished this page\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"name\": \"fullscreen\",\n    \"type\": \"text\",\n    \"importance\": \"low\",\n    \"label\": \"Fullscreen button label\",\n    \"default\": \"Fullscreen\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"name\": \"exitFullscreen\",\n    \"type\": \"text\",\n    \"importance\": \"low\",\n    \"label\": \"Exit fullscreen button label\",\n    \"default\": \"Exit fullscreen\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"name\": \"bookProgressSubtext\",\n    \"type\": \"text\",\n    \"importance\": \"low\",\n    \"label\": \"Page progress in book\",\n    \"description\": \"\\\"@count\\\" will be replaced by page count, and \\\"@total\\\" with the total number of pages\",\n    \"default\": \"@count of @total pages\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"name\": \"interactionsProgressSubtext\",\n    \"type\": \"text\",\n    \"importance\": \"low\",\n    \"label\": \"Interaction progress\",\n    \"description\": \"\\\"@count\\\" will be replaced by interaction count, and \\\"@total\\\" with the total number of interactions\",\n    \"default\": \"@count of @total interactions\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"name\": \"submitReport\",\n    \"type\": \"text\",\n    \"importance\": \"low\",\n    \"label\": \"Translation for \\\"Submit report\\\"\",\n    \"default\": \"Submit Report\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"name\": \"restartLabel\",\n    \"type\": \"text\",\n    \"importance\": \"low\",\n    \"label\": \"Label for \\\"restart\\\" button\",\n    \"default\": \"Restart\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"name\": \"summaryHeader\",\n    \"type\": \"text\",\n    \"importance\": \"low\",\n    \"label\": \"Summary header\",\n    \"default\": \"Summary\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"name\": \"allInteractions\",\n    \"type\": \"text\",\n    \"importance\": \"low\",\n    \"label\": \"Translation for \\\"All interactions\\\"\",\n    \"default\": \"All interactions\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"name\": \"unansweredInteractions\",\n    \"type\": \"text\",\n    \"importance\": \"low\",\n    \"label\": \"Translation for \\\"Unanswered interactions\\\"\",\n    \"default\": \"Unanswered interactions\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"name\": \"scoreText\",\n    \"type\": \"text\",\n    \"importance\": \"low\",\n    \"label\": \"Score\",\n    \"description\": \"\\\"@score\\\" will be replaced with current score, and \\\"@maxscore\\\" will be replaced with max achievable score\",\n    \"default\": \"@score / @maxscore\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"name\": \"leftOutOfTotalCompleted\",\n    \"type\": \"text\",\n    \"importance\": \"low\",\n    \"label\": \"Per page interactions completion\",\n    \"description\": \"\\\"@left\\\" will be replaced with remaining interactions, and \\\"@max\\\" will be replaced with total number of interactions on the page\",\n    \"default\": \"@left of @max interactions completed\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"name\": \"noInteractions\",\n    \"type\": \"text\",\n    \"importance\": \"low\",\n    \"label\": \"Translation for \\\"No interactions\\\"\",\n    \"default\": \"No interactions\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"name\": \"score\",\n    \"type\": \"text\",\n    \"importance\": \"low\",\n    \"label\": \"Translation for \\\"Score\\\"\",\n    \"default\": \"Score\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"name\": \"summaryAndSubmit\",\n    \"type\": \"text\",\n    \"importance\": \"low\",\n    \"label\": \"Label for \\\"Summary &amp; submit\\\" button\",\n    \"default\": \"Summary &amp; submit\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"name\": \"noChapterInteractionBoldText\",\n    \"type\": \"text\",\n    \"importance\": \"low\",\n    \"label\": \"Translation for \\\"You have not interacted with any pages.\\\"\",\n    \"default\": \"You have not interacted with any pages.\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"name\": \"noChapterInteractionText\",\n    \"type\": \"text\",\n    \"importance\": \"low\",\n    \"label\": \"Translation for \\\"You have to interact with at least one page before you can see the summary.\\\"\",\n    \"default\": \"You have to interact with at least one page before you can see the summary.\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"name\": \"yourAnswersAreSubmittedForReview\",\n    \"type\": \"text\",\n    \"importance\": \"low\",\n    \"label\": \"Translation for \\\"Your answers are submitted for review!\\\"\",\n    \"default\": \"Your answers are submitted for review!\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"name\": \"bookProgress\",\n    \"type\": \"text\",\n    \"importance\": \"low\",\n    \"label\": \"Summary progress label\",\n    \"default\": \"Book progress\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"name\": \"interactionsProgress\",\n    \"type\": \"text\",\n    \"importance\": \"low\",\n    \"label\": \"Interactions progress label\",\n    \"default\": \"Interactions progress\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"name\": \"totalScoreLabel\",\n    \"type\": \"text\",\n    \"importance\": \"low\",\n    \"label\": \"Total score label\",\n    \"default\": \"Total score\",\n    \"common\": true,\n    \"optional\": true\n  },\n  {\n    \"name\": \"a11y\",\n    \"type\": \"group\",\n    \"label\": \"Accessibility texts\",\n    \"common\": true,\n    \"fields\": [\n      {\n        \"name\": \"progress\",\n        \"type\": \"text\",\n        \"label\": \"Page progress textual alternative\",\n        \"description\": \"An alternative text for the visual page progress. @page and @total variables available.\",\n        \"default\": \"Page @page of @total.\"\n      },\n      {\n        \"name\": \"menu\",\n        \"type\": \"text\",\n        \"label\": \"Label for expanding/collapsing navigation menu\",\n        \"default\": \"Toggle navigation menu\"\n      }\n    ]\n  }\n]\n', NULL, 1, 27, NULL, NULL, 'https://h5p.org/content-types/interactive-book', 1);
INSERT INTO `mdl_h5p_libraries` (`id`, `machinename`, `title`, `majorversion`, `minorversion`, `patchversion`, `runnable`, `fullscreen`, `embedtypes`, `preloadedjs`, `preloadedcss`, `droplibrarycss`, `semantics`, `addto`, `coremajor`, `coreminor`, `metadatasettings`, `tutorial`, `example`, `enabled`) VALUES
(124, 'H5P.KewArCode', 'KewAr Code', 1, 2, 2, 1, 0, 'iframe', 'dist/h5p-kewar-code.js', 'dist/h5p-kewar-code.css', '', '[\n  {\n    \"name\": \"introduction\",\n    \"type\": \"text\",\n    \"widget\": \"html\",\n    \"label\": \"Introductory text\",\n    \"importance\": \"medium\",\n    \"optional\": true,\n    \"description\": \"This text can optionally be presented along with your code.\",\n    \"enterMode\": \"div\",\n    \"tags\": [\n      \"sub\",\n      \"sup\",\n      \"strong\",\n      \"em\",\n      \"p\",\n      \"code\",\n      \"u\",\n      \"del\",\n      \"a\",\n      \"ul\",\n      \"ol\",\n      \"h1\",\n      \"h2\",\n      \"h3\",\n      \"h4\",\n      \"h5\",\n      \"h6\",\n      \"pre\",\n      \"hr\",\n      \"table\"\n    ],\n    \"font\": {\n      \"size\": true,\n      \"color\": true,\n      \"background\": true\n    }\n  },\n  {\n    \"name\": \"codeType\",\n    \"type\": \"select\",\n    \"label\": \"Code type\",\n    \"description\": \"Select what kind of code you want to generate\",\n    \"options\": [\n      {\n        \"value\": \"contact\",\n        \"label\": \"Contact\"\n      },\n      {\n        \"value\": \"event\",\n        \"label\": \"Event\"\n      },\n      {\n        \"value\": \"email\",\n        \"label\": \"Email address\"\n      },\n      {\n        \"value\": \"h5p\",\n        \"label\": \"H5P\"\n      },\n      {\n        \"value\": \"location\",\n        \"label\": \"Location\"\n      },\n      {\n        \"value\": \"phone\",\n        \"label\": \"Phone number\"\n      },\n      {\n        \"value\": \"sms\",\n        \"label\": \"SMS\"\n      },\n      {\n        \"value\": \"text\",\n        \"label\": \"Text\"\n      },\n      {\n        \"value\": \"url\",\n        \"label\": \"URL\"\n      }\n    ],\n    \"default\": \"url\",\n    \"widget\": \"editorKewArCode\"\n  },\n  {\n    \"name\": \"contact\",\n    \"type\": \"group\",\n    \"label\": \"Contact\",\n    \"importance\": \"high\",\n    \"expanded\": true,\n    \"fields\": [\n      {\n        \"name\": \"name\",\n        \"type\": \"text\",\n        \"label\": \"Name\",\n        \"placeholder\": \"John Smith\",\n        \"maxLength\": 150\n      },\n      {\n        \"name\": \"organization\",\n        \"type\": \"text\",\n        \"label\": \"Organization\",\n        \"placeholder\": \"H5P fan club\",\n        \"optional\": true,\n        \"maxLength\": 150\n      },\n      {\n        \"name\": \"title\",\n        \"type\": \"text\",\n        \"label\": \"Title\",\n        \"placeholder\": \"Master of None\",\n        \"optional\": true,\n        \"maxLength\": 100\n      },\n      {\n        \"name\": \"number\",\n        \"type\": \"text\",\n        \"label\": \"Phone number\",\n        \"description\": \"Phone number (please use the format +12 345 67890)\",\n        \"placeholder\": \"+12 345 67890\",\n        \"optional\": true,\n        \"regexp\": {\n          \"pattern\": \"^\\\\+[0-9]{1,3}[\\\\ ]?[0-9]{1,4}[\\\\ ]?[0-9]{1,8}$\",\n          \"modifiers\": \"\"\n        }\n      },\n      {\n        \"name\": \"email\",\n        \"type\": \"text\",\n        \"label\": \"Email address\",\n        \"description\": \"Email address to write message to\",\n        \"placeholder\": \"john@fictional-h5p-fan-club.org\",\n        \"optional\": true,\n        \"maxLength\": 150,\n        \"regexp\": {\n          \"pattern\": \"^[A-Z0-9\\\\._%+-]+@[A-Z0-9.-]+\\\\.[A-Z]{2,}$\",\n          \"modifiers\": \"i\"\n        }\n      },\n      {\n        \"name\": \"address\",\n        \"type\": \"group\",\n        \"label\": \"Address\",\n        \"importance\": \"medium\",\n        \"expanded\": true,\n        \"fields\": [\n          {\n            \"name\": \"extended\",\n            \"type\": \"text\",\n            \"label\": \"Extended address\",\n            \"description\": \"c/o information, etc.\",\n            \"placeholder\": \"c/o H5P Fan Club\",\n            \"optional\": true,\n            \"maxLength\": 150\n          },\n          {\n            \"name\": \"street\",\n            \"type\": \"text\",\n            \"label\": \"Street\",\n            \"description\": \"Street including number\",\n            \"placeholder\": \"1308 W. Dayton Street\",\n            \"optional\": true,\n            \"maxLength\": 150\n          },\n          {\n            \"name\": \"locality\",\n            \"type\": \"text\",\n            \"label\": \"Locality\",\n            \"description\": \"City name, etc.\",\n            \"placeholder\": \"Madison\",\n            \"optional\": true,\n            \"maxLength\": 100\n          },\n          {\n            \"name\": \"region\",\n            \"type\": \"text\",\n            \"label\": \"Region\",\n            \"description\": \"Federal state, county, etc.\",\n            \"placeholder\": \"WI\",\n            \"optional\": true,\n            \"maxLength\": 100\n          },\n          {\n            \"name\": \"zip\",\n            \"type\": \"text\",\n            \"label\": \"ZIP code\",\n            \"description\": \"ZIP code\",\n            \"placeholder\": \"53715\",\n            \"optional\": true,\n            \"maxLength\": 50\n          },\n          {\n            \"name\": \"country\",\n            \"type\": \"text\",\n            \"label\": \"Country\",\n            \"description\": \"Country\",\n            \"placeholder\": \"USA\",\n            \"optional\": true,\n            \"maxLength\": 100\n          }\n        ]\n      },\n      {\n        \"name\": \"url\",\n        \"type\": \"text\",\n        \"label\": \"Website\",\n        \"description\": \"Website to link to (must start with https:// or http://)\",\n        \"placeholder\": \"https://fictional-h5p-fan-club.org\",\n        \"regexp\": {\n          \"pattern\": \"https?://([0-9a-z.-]+).[a-z.]{2,}([0-9a-z.-_]*)*/?\",\n          \"modifiers\": \"i\"\n        },\n        \"optional\": true,\n        \"maxLength\": 300\n      },\n      {\n        \"name\": \"note\",\n        \"type\": \"text\",\n        \"label\": \"Note\",\n        \"description\": \"Note\",\n        \"placeholder\": \"John loves H5P.\",\n        \"optional\": true,\n        \"maxLength\": 500\n      }\n    ],\n    \"widget\": \"showWhen\",\n    \"showWhen\": {\n      \"rules\": [\n        {\n          \"field\": \"codeType\",\n          \"equals\": \"contact\"\n        }\n      ]\n    }\n  },\n  {\n    \"name\": \"event\",\n    \"type\": \"group\",\n    \"label\": \"Event\",\n    \"importance\": \"high\",\n    \"expanded\": true,\n    \"fields\": [\n      {\n        \"name\": \"title\",\n        \"type\": \"text\",\n        \"label\": \"Title\",\n        \"description\": \"Title for the calendar event\",\n        \"placeholder\": \"H5P Conference 2020\",\n        \"maxLength\": 200\n      },\n      {\n        \"name\": \"allDay\",\n        \"type\": \"boolean\",\n        \"label\": \"All day event\",\n        \"description\": \"Check if event will be valid all day long\"\n      },\n      {\n        \"name\": \"dateStart\",\n        \"type\": \"text\",\n        \"label\": \"Start date\",\n        \"description\": \"Start date of the event (please use the format yyyy/mm/dd)\",\n        \"placeholder\": \"2020/05/18\",\n        \"regexp\": {\n          \"pattern\": \"^[0-9]{4,}/0*([1-9]|1[0-2])/0*([1-9]|[12][0-9]|3[01])$\",\n          \"modifiers\": \"\"\n        }\n      },\n      {\n        \"name\": \"timeStart\",\n        \"type\": \"text\",\n        \"label\": \"Start time\",\n        \"description\": \"Start time of the event (please use the format hh:mm)\",\n        \"placeholder\": \"09:00\",\n        \"regexp\": {\n          \"pattern\": \"^0*([1-9]|1[0-9]|2[0-3]):0*([0-9]|[1-4][0-9]|5[0-9])$\",\n          \"modifiers\": \"\"\n        },\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"allDay\",\n              \"equals\": false\n            }\n          ]\n        }\n      },\n      {\n        \"name\": \"dateEnd\",\n        \"type\": \"text\",\n        \"label\": \"End date\",\n        \"description\": \"End date of the event (please use the format yyyy/mm/dd)\",\n        \"placeholder\": \"2020/05/20\",\n        \"regexp\": {\n          \"pattern\": \"^[0-9]{4,}/0*([1-9]|1[0-2])/0*([1-9]|[12][0-9]|3[01])$\",\n          \"modifiers\": \"\"\n        }\n      },\n      {\n        \"name\": \"timeEnd\",\n        \"type\": \"text\",\n        \"label\": \"End time\",\n        \"description\": \"End time of the event (please use the format hh:mm)\",\n        \"placeholder\": \"16:00\",\n        \"regexp\": {\n          \"pattern\": \"^0*([1-9]|1[0-9]|2[0-3]):0*([0-9]|[1-4][0-9]|5[0-9])$\",\n          \"modifiers\": \"\"\n        },\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"allDay\",\n              \"equals\": false\n            }\n          ]\n        }\n      },\n      {\n        \"name\": \"timezone\",\n        \"type\": \"select\",\n        \"label\": \"Timezone\",\n        \"description\": \"Select the time zone the event is supposed to take place in\",\n        \"options\": [\n          {\n            \"value\": \"-12:00\",\n            \"label\": \"UTC-12:00\"\n          },\n          {\n            \"value\": \"-11:00\",\n            \"label\": \"UTC-11:00\"\n          },\n          {\n            \"value\": \"-10:00\",\n            \"label\": \"UTC-10:00\"\n          },\n          {\n            \"value\": \"-9:30\",\n            \"label\": \"UTC-9:30\"\n          },\n          {\n            \"value\": \"-9:00\",\n            \"label\": \"UTC-9:00\"\n          },\n          {\n            \"value\": \"-8:00\",\n            \"label\": \"UTC-8:00\"\n          },\n          {\n            \"value\": \"-7:00\",\n            \"label\": \"UTC-7:00\"\n          },\n          {\n            \"value\": \"-6:00\",\n            \"label\": \"UTC-6:00\"\n          },\n          {\n            \"value\": \"-5:00\",\n            \"label\": \"UTC-5:00\"\n          },\n          {\n            \"value\": \"-4:00\",\n            \"label\": \"UTC-4:00\"\n          },\n          {\n            \"value\": \"-3:30\",\n            \"label\": \"UTC-3:30\"\n          },\n          {\n            \"value\": \"-3:00\",\n            \"label\": \"UTC-3:00\"\n          },\n          {\n            \"value\": \"-2:00\",\n            \"label\": \"UTC-2:00\"\n          },\n          {\n            \"value\": \"-1:00\",\n            \"label\": \"UTC-1:00\"\n          },\n          {\n            \"value\": \"0:00\",\n            \"label\": \"UTC\"\n          },\n          {\n            \"value\": \"1:00\",\n            \"label\": \"UTC+1:00\"\n          },\n          {\n            \"value\": \"2:00\",\n            \"label\": \"UTC+2:00\"\n          },\n          {\n            \"value\": \"3:00\",\n            \"label\": \"UTC+3:00\"\n          },\n          {\n            \"value\": \"3:30\",\n            \"label\": \"UTC+3:30\"\n          },\n          {\n            \"value\": \"4:00\",\n            \"label\": \"UTC+4:00\"\n          },\n          {\n            \"value\": \"4:00\",\n            \"label\": \"UTC+4:30\"\n          },\n          {\n            \"value\": \"5:00\",\n            \"label\": \"UTC+5:00\"\n          },\n          {\n            \"value\": \"5:30\",\n            \"label\": \"UTC+5:30\"\n          },\n          {\n            \"value\": \"5:45\",\n            \"label\": \"UTC+5:45\"\n          },\n          {\n            \"value\": \"6:00\",\n            \"label\": \"UTC+6:00\"\n          },\n          {\n            \"value\": \"6:30\",\n            \"label\": \"UTC+6:30\"\n          },\n          {\n            \"value\": \"7:00\",\n            \"label\": \"UTC+7:00\"\n          },\n          {\n            \"value\": \"8:00\",\n            \"label\": \"UTC+8:00\"\n          },\n          {\n            \"value\": \"9:00\",\n            \"label\": \"UTC+9:00\"\n          },\n          {\n            \"value\": \"9:30\",\n            \"label\": \"UTC+9:30\"\n          },\n          {\n            \"value\": \"10:00\",\n            \"label\": \"UTC+10:00\"\n          },\n          {\n            \"value\": \"10:30\",\n            \"label\": \"UTC+10:30\"\n          },\n          {\n            \"value\": \"11:00\",\n            \"label\": \"UTC+11:00\"\n          },\n          {\n            \"value\": \"12:00\",\n            \"label\": \"UTC+12:00\"\n          },\n          {\n            \"value\": \"12:45\",\n            \"label\": \"UTC+12:45\"\n          },\n          {\n            \"value\": \"13:00\",\n            \"label\": \"UTC+13:00\"\n          },\n          {\n            \"value\": \"14:00\",\n            \"label\": \"UTC+14:00\"\n          }\n        ],\n        \"default\": \"0:00\",\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"allDay\",\n              \"equals\": false\n            }\n          ]\n        }\n      },\n      {\n        \"name\": \"daylightSavings\",\n        \"type\": \"boolean\",\n        \"label\": \"Daylight savings\",\n        \"description\": \"Check if location that the event is taking place in uses daylight savings time\",\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"allDay\",\n              \"equals\": false\n            }\n          ]\n        }\n      },\n      {\n        \"name\": \"location\",\n        \"type\": \"text\",\n        \"label\": \"Location\",\n        \"description\": \"Name the location\",\n        \"placeholder\": \"Madison, USA\",\n        \"optional\": true,\n        \"maxLength\": 200\n      },\n      {\n        \"name\": \"description\",\n        \"type\": \"text\",\n        \"label\": \"Description\",\n        \"description\": \"Add a description for the event\",\n        \"placeholder\": \"3rd H5P conference\",\n        \"optional\": true,\n        \"maxLength\": 1500\n      }\n    ],\n    \"widget\": \"showWhen\",\n    \"showWhen\": {\n      \"rules\": [\n        {\n          \"field\": \"codeType\",\n          \"equals\": \"event\"\n        }\n      ]\n    }\n  },\n  {\n    \"name\": \"email\",\n    \"type\": \"group\",\n    \"label\": \"Email address\",\n    \"importance\": \"high\",\n    \"expanded\": true,\n    \"fields\": [\n      {\n        \"name\": \"email\",\n        \"type\": \"text\",\n        \"label\": \"Email address\",\n        \"description\": \"Email address to write message to\",\n        \"placeholder\": \"john@fictional-h5p-fan-club.org\",\n        \"maxLength\": 2000,\n        \"regexp\": {\n          \"pattern\": \"^[A-Z0-9\\\\._%+-]+@[A-Z0-9.-]+\\\\.[A-Z]{2,}$\",\n          \"modifiers\": \"i\"\n        }\n      }\n    ],\n    \"widget\": \"showWhen\",\n    \"showWhen\": {\n      \"rules\": [\n        {\n          \"field\": \"codeType\",\n          \"equals\": \"email\"\n        }\n      ]\n    }\n  },\n  {\n    \"name\": \"h5p\",\n    \"type\": \"group\",\n    \"label\": \"H5P content\",\n    \"importance\": \"high\",\n    \"expanded\": true,\n    \"fields\": [\n      {\n        \"name\": \"h5p\",\n        \"type\": \"library\",\n        \"label\": \"H5P content\",\n        \"description\": \"H5P content to display\",\n        \"options\": [\n          \"H5P.Accordion 1.0\",\n          \"H5P.AdventCalendar 0.3\",\n          \"H5P.Agamotto 1.5\",\n          \"H5P.Audio 1.5\",\n          \"H5P.AudioRecorder 1.0\",\n          \"H5P.ArithmeticQuiz 1.1\",\n          \"H5P.Blanks 1.14\",\n          \"H5P.Chart 1.2\",\n          \"H5P.Collage 0.3\",\n          \"H5P.Column 1.16\",\n          \"H5P.Crossword 0.4\",\n          \"H5P.CoursePresentation 1.25\",\n          \"H5P.Dialogcards 1.9\",\n          \"H5P.Dictation 1.3\",\n          \"H5P.DocumentationTool 1.8\",\n          \"H5P.DragQuestion 1.14\",\n          \"H5P.DragText 1.10\",\n          \"H5P.Essay 1.5\",\n          \"H5P.FindTheWords 1.4\",\n          \"H5P.Flashcards 1.6\",\n          \"H5P.GuessTheAnswer 1.5\",\n          \"H5P.Table 1.1\",\n          \"H5P.AdvancedText 1.1\",\n          \"H5P.IFrameEmbed 1.0\",\n          \"H5P.Image 1.1\",\n          \"H5P.MultiMediaChoice 0.3\",\n          \"H5P.ImageHotspots 1.10\",\n          \"H5P.ImageHotspotQuestion 1.8\",\n          \"H5P.ImageJuxtaposition 1.5\",\n          \"H5P.ImagePair 1.4\",\n          \"H5P.ImageSequencing 1.1\",\n          \"H5P.ImageSlider 1.1\",\n          \"H5P.InteractiveBook 1.7\",\n          \"H5P.InteractiveVideo 1.26\",\n          \"H5P.Link 1.3\",\n          \"H5P.MarkTheWords 1.11\",\n          \"H5P.MemoryGame 1.3\",\n          \"H5P.MultiChoice 1.16\",\n          \"H5P.Questionnaire 1.3\",\n          \"H5P.QuestionSet 1.20\",\n          \"H5P.SingleChoiceSet 1.11\",\n          \"H5P.SortParagraphs 0.11\",\n          \"H5P.Summary 1.10\",\n          \"H5P.Timeline 1.1\",\n          \"H5P.TrueFalse 1.8\",\n          \"H5P.Video 1.6\",\n          \"H5P.ThreeImage 0.5\"\n        ]\n      }\n    ],\n    \"widget\": \"showWhen\",\n    \"showWhen\": {\n      \"rules\": [\n        {\n          \"field\": \"codeType\",\n          \"equals\": \"h5p\"\n        }\n      ]\n    }\n  },\n  {\n    \"name\": \"location\",\n    \"type\": \"group\",\n    \"label\": \"Location\",\n    \"importance\": \"high\",\n    \"expanded\": true,\n    \"fields\": [\n      {\n        \"name\": \"latitude\",\n        \"type\": \"text\",\n        \"label\": \"Latitude\",\n        \"description\": \"Latitude (please use the format 53.864462)\",\n        \"placeholder\": \"69.646007\",\n        \"regexp\": {\n          \"pattern\": \"^((-?0*([0-9]|[1-7][0-9]|8[0-9])(\\\\.[0-9]{1,6})?)|(-?90))$\",\n          \"modifiers\": \"\"\n        }\n      },\n      {\n        \"name\": \"longitude\",\n        \"type\": \"text\",\n        \"label\": \"Longitude\",\n        \"description\": \"Longitude (please use the format 10.663792)\",\n        \"placeholder\": \"18.954036\",\n        \"regexp\": {\n          \"pattern\": \"^((-?0*([0-9]|[1-8][0-9]|9[0-9]|1[0-6][0-9]|17[0-9])(\\\\.[0-9]{1,6})?)|-?180)$\",\n          \"modifiers\": \"\"\n        }\n      }\n    ],\n    \"widget\": \"showWhen\",\n    \"showWhen\": {\n      \"rules\": [\n        {\n          \"field\": \"codeType\",\n          \"equals\": \"location\"\n        }\n      ]\n    }\n  },\n  {\n    \"name\": \"phone\",\n    \"type\": \"group\",\n    \"label\": \"Phone number\",\n    \"importance\": \"high\",\n    \"expanded\": true,\n    \"fields\": [\n      {\n        \"name\": \"number\",\n        \"type\": \"text\",\n        \"label\": \"Phone number\",\n        \"description\": \"Phone number to call (please use the format +12 345 67890)\",\n        \"placeholder\": \"+12 345 67890\",\n        \"regexp\": {\n          \"pattern\": \"^\\\\+[0-9]{1,3}[\\\\ ]?[0-9]{1,4}[\\\\ ]?[0-9]{1,8}$\",\n          \"modifiers\": \"\"\n        }\n      }\n    ],\n    \"widget\": \"showWhen\",\n    \"showWhen\": {\n      \"rules\": [\n        {\n          \"field\": \"codeType\",\n          \"equals\": \"phone\"\n        }\n      ]\n    }\n  },\n  {\n    \"name\": \"sms\",\n    \"type\": \"group\",\n    \"label\": \"SMS\",\n    \"importance\": \"high\",\n    \"expanded\": true,\n    \"fields\": [\n      {\n        \"name\": \"number\",\n        \"type\": \"text\",\n        \"label\": \"Phone number\",\n        \"description\": \"Phone number to send to (please use the format +12 345 67890)\",\n        \"placeholder\": \"+12 345 67890\",\n        \"regexp\": {\n          \"pattern\": \"^\\\\+[0-9]{1,3}[\\\\ ]?[0-9]{1,4}[\\\\ ]?[0-9]{1,8}$\",\n          \"modifiers\": \"\"\n        }\n      },\n      {\n        \"name\": \"message\",\n        \"type\": \"text\",\n        \"label\": \"Message\",\n        \"description\": \"Message to send\",\n        \"placeholder\": \"Pleas