\",\n        \"importance\": \"medium\",\n        \"optional\": true,\n        \"default\": \"#000000\",\n        \"widget\": \"colorSelector\",\n        \"spectrum\": {\n          \"showInput\": true\n        }\n      },\n      {\n        \"name\": \"backgroundColor\",\n        \"type\": \"text\",\n        \"label\": \"Background color\",\n        \"importance\": \"medium\",\n        \"optional\": true,\n        \"default\": \"#ffffff\",\n        \"widget\": \"colorSelector\",\n        \"spectrum\": {\n          \"showInput\": true,\n          \"showAlpha\": true,\n          \"preferredFormat\": \"rgb\"\n        }\n      },\n      {\n        \"name\": \"maxSize\",\n        \"type\": \"text\",\n        \"label\": \"Maximum size\",\n        \"description\": \"Maximum size for the code given in CSS notation (pixels by default if only a number is given)\",\n        \"importance\": \"medium\",\n        \"optional\": true,\n        \"regexp\": {\n          \"pattern\": \"^(([1-9]+.[0-9]+)|[0-9]+)(cm|mm|in|px|pt|pc|em|ex|ch|rem|vw|vh|vmin|vmax|%)?$\",\n          \"modifiers\": \"i\"\n        }\n      },\n      {\n        \"name\": \"alignment\",\n        \"type\": \"select\",\n        \"label\": \"Horizontal alignment\",\n        \"description\": \"Set horizontal alignment if you set a maximum size\",\n        \"options\": [\n          {\n            \"value\": \"left\",\n            \"label\": \"left\"\n          },\n          {\n            \"value\": \"center\",\n            \"label\": \"center\"\n          },\n          {\n            \"value\": \"right\",\n            \"label\": \"right\"\n          }\n        ],\n        \"default\": \"center\"\n      }\n    ]\n  },\n  {\n    \"name\": \"l10n\",\n    \"type\": \"group\",\n    \"common\": true,\n    \"label\": \"User interface\",\n    \"importance\": \"low\",\n    \"fields\": [\n      {\n        \"name\": \"address\",\n        \"type\": \"text\",\n        \"label\": \"Address\",\n        \"importance\": \"low\",\n   