\": \"Title\"\n      },\n      {\n        \"name\": \"url\",\n        \"type\": \"text\",\n        \"label\": \"URL\",\n        \"importance\": \"low\",\n        \"default\": \"URL\"\n      },\n      {\n        \"name\": \"zip\",\n        \"type\": \"text\",\n        \"label\": \"ZIP code\",\n        \"importance\": \"low\",\n        \"default\": \"ZIP code\"\n      }\n    ]\n  },\n  {\n    \"name\": \"a11y\",\n    \"type\": \"group\",\n    \"common\": true,\n    \"label\": \"Readspeaker\",\n    \"importance\": \"low\",\n    \"fields\": [\n      {\n        \"name\": \"openCodeInformation\",\n        \"type\": \"text\",\n        \"label\": \"QRCode. Display information (Text for Readspeakers)\",\n        \"importance\": \"low\",\n        \"default\": \"QRCode. Display information.\"\n      },\n      {\n        \"name\": \"closeCodeInformation\",\n        \"type\": \"text\",\n        \"label\": \"Hide information (Text for Readspeakers)\",\n        \"importance\": \"low\",\n        \"default\": \"Hide information.\"\n      },\n      {\n        \"name\": \"codeContents\",\n        \"type\": \"text\",\n        \"label\": \"Code contents (Text for Readspeakers)\",\n        \"importance\": \"low\",\n        \"default\": \". Code contents\"\n      }\n    ]\n  }\n]\n', NULL, NULL, NULL, NULL, NULL, 'https://h5p.org/content-types/kewar-code', 1),
