(126, 'H5P.AdventCalendar', 'Advent Calendar (beta)', 0, 3, 4, 1, 0, 'iframe', 'dist/h5p-advent-calendar.js', 'dist/h5p-advent-calendar.css', '', '[\n  {\n    \"name\": \"modeDoorImage\",\n    \"type\": \"select\",\n    \"label\": \"Mode for door images\",\n    \"description\": \"Select whether you want to set each custom door image yourself or let H5P do the work for you based on the calendar background image set in the behavioural settings.\",\n    \"options\": [\n      {\n        \"value\": \"manual\",\n        \"label\": \"I want to set each door image myself\"\n      },\n      {\n        \"value\": \"automatic\",\n        \"label\": \"H5P shall set the door images based on the background image\"\n      }\n    ],\n    \"default\": \"automatic\"\n  },\n  {\n    \"name\": \"doors\",\n    \"type\": \"list\",\n    \"label\": \"Doors\",\n    \"entity\": \"door\",\n    \"min\": 24,\n    \"max\": 24,\n    \"field\": {\n      \"name\": \"contentGroup\",\n      \"type\": \"group\",\n      \"fields\": [\n        {\n          \"name\": \"type\",\n          \"type\": \"select\",\n          \"label\": \"Content type\",\n          \"description\": \"Content type that shoud optionally pop up when the door is opened.\",\n          \"options\": [\n            {\n              \"value\": \"audio\",\n              \"label\": \"Audio\"\n            },\n            {\n              \"value\": \"image\",\n              \"label\": \"Image\"\n            },\n            {\n              \"value\": \"link\",\n              \"label\": \"Link\"\n            },\n            {\n              \"value\": \"text\",\n              \"label\": \"Text\"\n            },\n            {\n              \"value\": \"video\",\n              \"label\": \"Video\"\n            }\n          ]\n        },\n        {\n          \"name\": \"audio\",\n          \"type\": \"audio\",\n          \"label\": \"Audio\",\n          \"widget\": \"showWhen\",\n          \"showWhen\": {\n            \"rules\": [\n              {\n                \"field\": \"type\",\n                \"equals\": \"audio\"\n              }\n            ]\n          }\n        },\n        {\n          \"name\": \"image\",\n          \"type\": \"library\",\n          \"label\": \"Image\",\n          \"options\": [\n            \"H5P.Image 1.1\"\n          ],\n          \"widget\": \"showWhen\",\n          \"showWhen\": {\n            \"rules\": [\n              {\n                \"field\": \"type\",\n                \"equals\": \"image\"\n              }\n            ]\n          }\n        },\n        {\n          \"name\": \"link\",\n          \"type\": \"library\",\n          \"label\": \"Link\",\n          \"options\": [\n            \"H5P.Link 1.3\"\n          ],\n          \"widget\": \"showWhen\",\n          \"showWhen\": {\n            \"rules\": [\n              {\n                \"field\": \"type\",\n                \"equals\": \"link\"\n              }\n            ]\n          }\n        },\n        {\n          \"name\": \"text\",\n          \"type\": \"library\",\n          \"label\": \"Text\",\n          \"options\": [\n            \"H5P.AdvancedText 1.1\"\n          ],\n          \"widget\": \"showWhen\",\n          \"showWhen\": {\n            \"rules\": [\n              {\n                \"field\": \"type\",\n                \"equals\": \"text\"\n              }\n            ]\n          }\n        },\n        {\n          \"name\": \"video\",\n          \"type\": \"video\",\n          \"label\": \"Video\",\n          \"widget\": \"showWhen\",\n          \"showWhen\": {\n            \"rules\": [\n              {\n                \"field\": \"type\",\n                \"equals\": \"video\"\n              }\n            ]\n          }\n        },\n        {\n          \"name\": \"autoplay\",\n          \"type\": \"boolean\",\n          \"label\": \"Autoplay\",\n          \"default\": false,\n          \"widget\": \"showWhen\",\n          \"showWhen\": {\n            \"type\": \"or\",\n            \"rules\": [\n              {\n                \"field\": \"type\",\n                \"equals\": \"audio\"\n              },\n              {\n                \"field\": \"type\",\n                \"equals\": \"video\"\n              }\n            ]\n          }\n        },\n        {\n          \"name\": \"doorCover\",\n          \"type\": \"image\",\n          \"label\": \"Door image\",\n          \"description\": \"Image that will be used for the door. Needs to have a size ratio of 1:1 if you want the left half fit the right half.\",\n          \"optional\": true,\n          \"widget\": \"showWhen\",\n          \"showWhen\": {\n            \"rules\": [\n              {\n                \"field\": \"../../modeDoorImage\",\n                \"equals\": \"manual\"\n              }\n            ]\n          }\n        },\n        {\n          \"name\": \"previewImage\",\n          \"type\": \"image\",\n          \"label\": \"Background image\",\n          \"description\": \"Image that should appear inside the door. Will be the door\'s number by default.\",\n          \"optional\": true\n        }\n      ]\n    },\n    \"widgets\": [\n      {\n        \"name\": \"VerticalTabs\",\n        \"label\": \"Default\"\n      }\n    ]\n  },\n  {\n    \"name\": \"visuals\",\n    \"type\": \"group\",\n    \"label\": \"Visual settings\",\n    \"description\": \"These options will let you configure the visual appearance.\",\n    \"importance\": \"low\",\n    \"fields\": [\n      {\n        \"name\": \"backgroundImage\",\n        \"type\": \"image\",\n        \"label\": \"Calendar background image\",\n        \"optional\": true\n      },\n      {\n        \"name\": \"doorImageTemplate\",\n        \"type\": \"image\",\n        \"label\": \"Door image template\",\n        \"description\": \"If an image is set, it will be used for every door unless a specific door image is set for a single door.\",\n        \"optional\": true,\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"../modeDoorImage\",\n              \"equals\": \"manual\"\n            }\n          ]\n        }\n      },\n      {\n        \"name\": \"hideDoorBorder\",\n        \"type\": \"boolean\",\n        \"label\": \"Hide door border\",\n        \"default\": false,\n        \"optional\": true\n      },\n      {\n        \"name\": \"hideNumbers\",\n        \"type\": \"boolean\",\n        \"label\": \"Hide door numbers\",\n        \"default\": false,\n        \"optional\": true\n      },\n      {\n        \"name\": \"hideDoorKnobs\",\n        \"type\": \"boolean\",\n        \"label\": \"Hide door knobs\",\n        \"default\": false,\n        \"optional\": true\n      },\n      {\n        \"name\": \"hideDoorFrame\",\n        \"type\": \"boolean\",\n        \"label\": \"Hide door frame\",\n        \"default\": false,\n        \"optional\": true\n      },\n      {\n        \"name\": \"snow\",\n        \"type\": \"boolean\",\n        \"label\": \"Let it snow\",\n        \"description\": \"Will add some snow falling in front of the calendar. It never rains in Southern California, it never snows on IE11.\",\n        \"default\": false,\n        \"optional\": true\n      }\n    ]\n  },\n  {\n    \"name\": \"audio\",\n    \"type\": \"group\",\n    \"label\": \"Audio settings\",\n    \"description\": \"These options will let you configure the audio appearance.\",\n    \"importance\": \"low\",\n    \"fields\": [\n      {\n        \"name\": \"backgroundMusic\",\n        \"type\": \"audio\",\n        \"label\": \"Background music\",\n        \"optional\": true\n      },\n      {\n        \"name\": \"autoplay\",\n        \"type\": \"boolean\",\n        \"label\": \"Autoplay background music\",\n        \"description\": \"If set, the background music will play automatically once the content is opened. Please note: Some browsers\' media policy may prevent autoplay.\",\n        \"default\": false,\n        \"optional\": true\n      }\n    ]\n  },\n  {\n    \"name\": \"behaviour\",\n    \"type\": \"group\",\n    \"label\": \"Behavioural settings\",\n    \"description\": \"These options will let you override behaviour settings.\",\n    \"importance\": \"low\",\n    \"fields\": [\n      {\n        \"name\": \"modeDoorPlacement\",\n        \"type\": \"select\",\n        \"label\": \"Mode for door placement\",\n        \"description\": \"Select whether you want to set a fixed number of columns and rows for the doors or if H5P should decide dynamically depending on the available space. Note that the latter may interfere with the position of the background image and custom door cover images that should be at a particular position.\",\n        \"options\": [\n          {\n            \"value\": \"fixed\",\n            \"label\": \"Fixed\"\n          },\n          {\n            \"value\": \"dynamic\",\n            \"label\": \"Dynamic\"\n          }\n        ],\n        \"default\": \"dynamic\"\n      },\n      {\n        \"name\": \"doorPlacementRatio\",\n        \"type\": \"select\",\n        \"label\": \"Row-to-column ratio\",\n        \"description\": \"Select how many columns and rows the calender should use.\",\n        \"options\": [\n          {\n            \"value\": \"6x4\",\n            \"label\": \"6 Ă— 4\"\n          },\n          {\n            \"value\": \"4x6\",\n            \"label\": \"4 Ă— 6\"\n          }\n        ],\n        \"default\": \"6x4\",\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"modeDoorPlacement\",\n              \"equals\": \"fixed\"\n            }\n          ]\n        }\n      },\n      {\n        \"name\": \"randomize\",\n        \"type\": \"boolean\",\n        \"label\": \"Random order\",\n        \"description\": \"Shuffle the order of the doors. If the \\\"save content state\\\" option is set in the H5P settings, that order will stay the same when the user returns later.\",\n        \"default\": false,\n        \"optional\": true\n      },\n      {\n        \"name\": \"keepImageOrder\",\n        \"type\": \"boolean\",\n        \"label\": \"Keep order of images\",\n        \"description\": \"Shuffle doors, but keep the door cover images at their fixed positions starting with 1 in the upper left corner down to 24 in the lower right corner.\",\n        \"default\": false,\n        \"optional\": true,\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"randomize\",\n              \"equals\": true\n            }\n          ]\n        }\n      },\n      {\n        \"name\": \"designMode\",\n        \"type\": \"boolean\",\n        \"label\": \"Design mode\",\n        \"description\": \"When in design mode, all doors can be opened. Otherwise, the doors can only be opened in December on and after the respective day indicated by the door number.\",\n        \"default\": true,\n        \"optional\": true\n      }\n    ]\n  },\n  {\n    \"name\": \"l10n\",\n    \"type\": \"group\",\n    \"common\": true,\n    \"label\": \"Localization\",\n    \"importance\": \"low\",\n    \"fields\": [\n      {\n        \"name\": \"nothingToSee\",\n        \"type\": \"text\",\n        \"label\": \"Nothing to see\",\n        \"importance\": \"low\",\n        \"default\": \"There is nothing to see here!\\ud83c\\udf84\"\n      },\n      {\n        \"name\": \"dummy\",\n        \"type\": \"text\",\n        \"label\": \"Dummy\",\n        \"importance\": \"low\",\n        \"default\": \"Dummy\",\n        \"widget\": \"none\"\n      }\n    ]\n  },\n  {\n    \"name\": \"a11y\",\n    \"type\": \"group\",\n    \"common\": true,\n    \"label\": \"Accessibility\",\n    \"importance\": \"low\",\n    \"fields\": [\n      {\n        \"name\": \"door\",\n        \"type\": \"text\",\n        \"label\": \"Door\",\n        \"importance\": \"low\",\n        \"default\": \"Door\"\n      },\n      {\n        \"name\": \"locked\",\n        \"type\": \"text\",\n        \"label\": \"Locked\",\n        \"importance\": \"low\",\n        \"default\": \"Locked. It is not time to open this one yet.\"\n      },\n      {\n        \"name\": \"content\",\n        \"description\": \"Announce the content. @door is a variable and will be replaced with the related door description.\",\n        \"type\": \"text\",\n        \"label\": \"Content of\",\n        \"importance\": \"low\",\n        \"default\": \"Content of @door\"\n      },\n      {\n        \"name\": \"mute\",\n        \"type\": \"text\",\n        \"label\": \"Mute audio\",\n        \"importance\": \"low\",\n        \"default\": \"Mute audio\"\n      },\n      {\n        \"name\": \"unmute\",\n        \"type\": \"text\",\n        \"label\": \"Unmute audio\",\n        \"importance\": \"low\",\n        \"default\": \"Unmute audio\"\n      },\n      {\n        \"name\": \"closeWindow\",\n        \"type\": \"text\",\n        \"label\": \"Close window\",\n        \"importance\": \"low\",\n        \"default\": \"Close window\"\n      }\n    ]\n  }\n]\n', NULL, NULL, NULL, NULL, NULL, 'https://h5p.org/content-types/advent-calendar', 1);
INSERT INTO `mdl_h5p_libraries` (`id`, `machinename`, `title`, `majorversion`, `minorversion`, `patchversion`, `runnable`, `fullscreen`, `embedtypes`, `preloadedjs`, `preloadedcss`, `droplibrarycss`, `semantics`, `addto`, `coremajor`, `coreminor`, `metadatasettings`, `tutorial`, `example`, `enabled`) VALUES
(127, 'H5P.Crossword', 'Crossword', 0, 5, 13, 1, 0, 'iframe', 'dist/h5p-crossword.js', 'dist/h5p-crossword.css', '', '[\n  {\n    \"name\": \"taskDescription\",\n    \"label\": \"Task description\",\n    \"type\": \"text\",\n    \"widget\": \"html\",\n    \"importance\": \"high\",\n    \"description\": \"Describe your task here.\",\n    \"enterMode\": \"div\",\n    \"tags\": [\n      \"strong\",\n      \"em\",\n      \"u\",\n      \"a\",\n      \"ul\",\n      \"ol\",\n      \"h2\",\n      \"h3\",\n      \"hr\",\n      \"pre\",\n      \"code\"\n    ],\n    \"optional\": true\n  },\n  {\n    \"name\": \"words\",\n    \"label\": \"words\",\n    \"importance\": \"high\",\n    \"type\": \"list\",\n    \"widgets\": [\n      {\n        \"name\": \"VerticalTabs\",\n        \"label\": \"Default\"\n      }\n    ],\n    \"min\": 2,\n    \"entity\": \"Word\",\n    \"field\": {\n      \"name\": \"word\",\n      \"type\": \"group\",\n      \"label\": \"Word\",\n      \"fields\": [\n        {\n          \"name\": \"clue\",\n          \"type\": \"text\",\n          \"label\": \"Clue\",\n          \"description\": \"Clue that should point to the answer.\",\n          \"importance\": \"medium\"\n        },\n        {\n          \"name\": \"answer\",\n          \"type\": \"text\",\n          \"label\": \"Answer\",\n          \"description\": \"Answer to the clue.\",\n          \"importance\": \"medium\"\n        },\n        {\n          \"name\": \"extraClue\",\n          \"type\": \"library\",\n          \"label\": \"Extra clue\",\n          \"optional\": true,\n          \"options\": [\n            \"H5P.AdvancedText 1.1\",\n            \"H5P.Image 1.1\",\n            \"H5P.Audio 1.5\",\n            \"H5P.Video 1.6\"\n          ]\n        },\n        {\n          \"name\": \"fixWord\",\n          \"type\": \"boolean\",\n          \"label\": \"Fix word on grid\",\n          \"description\": \"Check if you want to fix the word to a particular position on the grid. Words with the same alignment may not be placed touching each other.\",\n          \"importance\": \"low\",\n          \"default\": false,\n          \"optional\": true\n        },\n        {\n          \"name\": \"row\",\n          \"type\": \"number\",\n          \"label\": \"Row\",\n          \"description\": \"Row index where the answer should start.\",\n          \"min\": 1,\n          \"max\": 100,\n          \"importance\": \"low\",\n          \"widget\": \"showWhen\",\n          \"showWhen\": {\n            \"rules\": [\n              {\n                \"field\": \"fixWord\",\n                \"equals\": true\n              }\n            ]\n          }\n        },\n        {\n          \"name\": \"column\",\n          \"type\": \"number\",\n          \"label\": \"Column\",\n          \"description\": \"Column index where the answer should start.\",\n          \"min\": 1,\n          \"max\": 100,\n          \"importance\": \"low\",\n          \"widget\": \"showWhen\",\n          \"showWhen\": {\n            \"rules\": [\n              {\n                \"field\": \"fixWord\",\n                \"equals\": true\n              }\n            ]\n          }\n        },\n        {\n          \"name\": \"orientation\",\n          \"type\": \"select\",\n          \"label\": \"Orientation\",\n          \"description\": \"Orientation for the answer.\",\n          \"options\": [\n            {\n              \"value\": \"across\",\n              \"label\": \"Across\"\n            },\n            {\n              \"value\": \"down\",\n              \"label\": \"Down\"\n            }\n          ],\n          \"default\": \"across\",\n          \"widget\": \"showWhen\",\n          \"showWhen\": {\n            \"rules\": [\n              {\n                \"field\": \"fixWord\",\n                \"equals\": true\n              }\n            ]\n          }\n        }\n      ]\n    }\n  },\n  {\n    \"name\": \"solutionWord\",\n    \"type\": \"text\",\n    \"label\": \"Overall solution word\",\n    \"description\": \"Optionally add a solution word that can be derived from particular characters on the grid. It will only be visible if all its characters can be found in the crossword. Please note: There\'s no accessibility support for this feature yet.\",\n    \"importance\": \"low\",\n    \"optional\": \"true\"\n  },\n  {\n    \"name\": \"overallFeedback\",\n    \"type\": \"group\",\n    \"label\": \"Overall Feedback\",\n    \"importance\": \"low\",\n    \"expanded\": true,\n    \"fields\": [\n      {\n        \"name\": \"overallFeedback\",\n        \"type\": \"list\",\n        \"widgets\": [\n          {\n            \"name\": \"RangeList\",\n            \"label\": \"Default\"\n          }\n        ],\n        \"importance\": \"high\",\n        \"label\": \"Define custom feedback for any score range\",\n        \"description\": \"Click the \\\"Add range\\\" button to add as many ranges as you need. Example: 0-20% Bad score, 21-91% Average Score, 91-100% Great Score!\",\n        \"entity\": \"range\",\n        \"min\": 1,\n        \"defaultNum\": 1,\n        \"optional\": true,\n        \"field\": {\n          \"name\": \"overallFeedback\",\n          \"type\": \"group\",\n          \"importance\": \"low\",\n          \"fields\": [\n            {\n              \"name\": \"from\",\n              \"type\": \"number\",\n              \"label\": \"Score Range\",\n              \"min\": 0,\n              \"max\": 100,\n              \"default\": 0,\n              \"unit\": \"%\"\n            },\n            {\n              \"name\": \"to\",\n              \"type\": \"number\",\n              \"min\": 0,\n              \"max\": 100,\n              \"default\": 100,\n              \"unit\": \"%\"\n            },\n            {\n              \"name\": \"feedback\",\n              \"type\": \"text\",\n              \"label\": \"Feedback for defined score range\",\n              \"importance\": \"low\",\n              \"placeholder\": \"Fill in the feedback\",\n              \"optional\": true\n            }\n          ]\n        }\n      }\n    ]\n  },\n  {\n    \"name\": \"theme\",\n    \"type\": \"group\",\n    \"label\": \"Theme\",\n    \"importance\": \"low\",\n    \"fields\": [\n      {\n        \"name\": \"backgroundImage\",\n        \"label\": \"Background image\",\n        \"type\": \"image\",\n        \"description\": \"Select an optional background image. It will be scaled to fit the background without stretching it.\",\n        \"importance\": \"low\",\n        \"optional\": true\n      },\n      {\n        \"name\": \"backgroundColor\",\n        \"type\": \"text\",\n        \"label\": \"Background color\",\n        \"description\": \"Choose a background color. It will either be used instead of a background image or as background for transparent areas.\",\n        \"importance\": \"low\",\n        \"optional\": true,\n        \"default\": \"#173354\",\n        \"widget\": \"colorSelector\",\n        \"spectrum\": {\n          \"showInput\": true,\n          \"showInitial\": true\n        }\n      },\n      {\n        \"name\": \"gridColor\",\n        \"type\": \"text\",\n        \"label\": \"Grid color\",\n        \"description\": \"Choose a color for the grid.\",\n        \"importance\": \"low\",\n        \"optional\": true,\n        \"default\": \"#000000\",\n        \"widget\": \"colorSelector\",\n        \"spectrum\": {\n          \"showInput\": true,\n          \"showInitial\": true\n        }\n      },\n      {\n        \"name\": \"cellBackgroundColor\",\n        \"type\": \"text\",\n        \"label\": \"Cell background color\",\n        \"description\": \"Choose the background color for a table cell.\",\n        \"importance\": \"low\",\n        \"optional\": true,\n        \"default\": \"#ffffff\",\n        \"widget\": \"colorSelector\",\n        \"spectrum\": {\n          \"showInput\": true,\n          \"showInitial\": true\n        }\n      },\n      {\n        \"name\": \"cellColor\",\n        \"type\": \"text\",\n        \"label\": \"Cell text color\",\n        \"description\": \"Choose the text color for a table cell.\",\n        \"importance\": \"low\",\n        \"optional\": true,\n        \"default\": \"#000000\",\n        \"widget\": \"colorSelector\",\n        \"spectrum\": {\n          \"showInput\": true,\n          \"showInitial\": true\n        }\n      },\n      {\n        \"name\": \"clueIdColor\",\n        \"type\": \"text\",\n        \"label\": \"Clue id color\",\n        \"description\": \"Choose the color of the clue id inside a table cell.\",\n        \"importance\": \"low\",\n        \"optional\": true,\n        \"default\": \"#606060\",\n        \"widget\": \"colorSelector\",\n        \"spectrum\": {\n          \"showInput\": true,\n          \"showInitial\": true\n        }\n      },\n      {\n        \"name\": \"cellBackgroundColorHighlight\",\n        \"type\": \"text\",\n        \"label\": \"Cell background color (highlighted)\",\n        \"description\": \"Choose the background color for a table cell that is highlighted.\",\n        \"importance\": \"low\",\n        \"optional\": true,\n        \"default\": \"#3e8de8\",\n        \"widget\": \"colorSelector\",\n        \"spectrum\": {\n          \"showInput\": true,\n          \"showInitial\": true\n        }\n      },\n      {\n        \"name\": \"cellColorHighlight\",\n        \"type\": \"text\",\n        \"label\": \"Cell text color (highlighted)\",\n        \"description\": \"Choose the text color for a table cell that is highlighted.\",\n        \"importance\": \"low\",\n        \"optional\": true,\n        \"default\": \"#ffffff\",\n        \"widget\": \"colorSelector\",\n        \"spectrum\": {\n          \"showInput\": true,\n          \"showInitial\": true\n        }\n      },\n      {\n        \"name\": \"clueIdColorHighlight\",\n        \"type\": \"text\",\n        \"label\": \"Cell id color (highlighted)\",\n        \"description\": \"Choose the color of the clue id inside a table cell that is highlighted.\",\n        \"importance\": \"low\",\n        \"optional\": true,\n        \"default\": \"#e0e0e0\",\n        \"widget\": \"colorSelector\",\n        \"spectrum\": {\n          \"showInput\": true,\n          \"showInitial\": true\n        }\n      }\n    ]\n  },\n  {\n    \"name\": \"behaviour\",\n    \"type\": \"group\",\n    \"label\": \"Behavioural settings\",\n    \"importance\": \"low\",\n    \"description\": \"These options will let you control how the task behaves.\",\n    \"fields\": [\n      {\n        \"name\": \"poolSize\",\n        \"type\": \"number\",\n        \"min\": 2,\n        \"label\": \"Number of words to be shown\",\n        \"importance\": \"low\",\n        \"description\": \"Create a randomized batch of words from the pool. The batch will always contain at least all the words that were fixed on the grid regardless of this setting. An empty value or 0 means to use all words.\",\n        \"optional\": true\n      },\n      {\n        \"name\": \"enableInstantFeedback\",\n        \"label\": \"Enable instant feedback\",\n        \"type\": \"boolean\",\n        \"importance\": \"low\",\n        \"default\": false\n      },\n      {\n        \"name\": \"scoreWords\",\n        \"label\": \"Score words\",\n        \"description\": \"If this option is enabled, words will be counted in order to determine the score. Otherwise, correct characters will be counted.\",\n        \"type\": \"boolean\",\n        \"importance\": \"low\",\n        \"default\": true\n      },\n      {\n        \"name\": \"applyPenalties\",\n        \"label\": \"Apply penalties\",\n        \"description\": \"If this option is enabled, each wrong answer will be given a penalty score of -1.\",\n        \"type\": \"boolean\",\n        \"importance\": \"low\",\n        \"default\": false,\n        \"optional\": true\n      },\n      {\n        \"name\": \"enableRetry\",\n        \"label\": \"Enable \\\"Retry\\\"\",\n        \"type\": \"boolean\",\n        \"importance\": \"low\",\n        \"default\": true,\n        \"optional\": true\n      },\n      {\n        \"name\": \"enableSolutionsButton\",\n        \"label\": \"Enable \\\"Solution\\\"\",\n        \"type\": \"boolean\",\n        \"importance\": \"low\",\n        \"default\": true,\n        \"optional\": true\n      },\n      {\n        \"name\": \"keepCorrectAnswers\",\n        \"type\": \"boolean\",\n        \"label\": \"Keep correct answers on retry\",\n        \"description\": \"If this option is enabled, correct answers will be kept when the user retries the task unless full score was achieved.\",\n        \"importance\": \"low\",\n        \"default\": false,\n        \"optional\": true,\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"enableRetry\",\n              \"equals\": true\n            }\n          ],\n          \"nullWhenHidden\": true\n        }\n      }\n    ]\n  },\n  {\n    \"name\": \"l10n\",\n    \"type\": \"group\",\n    \"common\": true,\n    \"label\": \"User interface\",\n    \"importance\": \"low\",\n    \"fields\": [\n      {\n        \"name\": \"across\",\n        \"type\": \"text\",\n        \"label\": \"Label for across\",\n        \"importance\": \"low\",\n        \"default\": \"Across\"\n      },\n      {\n        \"name\": \"down\",\n        \"type\": \"text\",\n        \"label\": \"Label for down\",\n        \"importance\": \"low\",\n        \"default\": \"Down\"\n      },\n      {\n        \"name\": \"checkAnswer\",\n        \"type\": \"text\",\n        \"label\": \"Text for \\\"Check\\\" button\",\n        \"importance\": \"low\",\n        \"default\": \"Check\"\n      },\n      {\n        \"name\": \"submitAnswer\",\n        \"type\": \"text\",\n        \"label\": \"Text for \\\"Submit\\\" button\",\n        \"importance\": \"low\",\n        \"default\": \"Submit\"\n      },\n      {\n        \"name\": \"tryAgain\",\n        \"label\": \"Text for \\\"Retry\\\" button\",\n        \"type\": \"text\",\n        \"importance\": \"low\",\n        \"default\": \"Retry\"\n      },\n      {\n        \"name\": \"showSolution\",\n        \"type\": \"text\",\n        \"label\": \"Text for \\\"Show solution\\\" button\",\n        \"importance\": \"low\",\n        \"default\": \"Show solution\"\n      },\n      {\n        \"name\": \"couldNotGenerateCrossword\",\n        \"type\": \"text\",\n        \"label\": \"Cannot create crossword\",\n        \"importance\": \"low\",\n        \"default\": \"Could not generate a crossword with the given words. Please try again with fewer words or words that have more characters in common.\"\n      },\n      {\n        \"name\": \"couldNotGenerateCrosswordTooFewWords\",\n        \"type\": \"text\",\n        \"label\": \"Cannot create crossword (too few words)\",\n        \"importance\": \"low\",\n        \"default\": \"Could not generate a crossword. You need at least two words.\"\n      },\n      {\n        \"name\": \"probematicWords\",\n        \"type\": \"text\",\n        \"label\": \"Probematic words\",\n        \"description\": \"List words that caused trouble while generating the crossword. @words is a placeholder that will be replaced by the actual problematic words.\",\n        \"importance\": \"low\",\n        \"default\": \"Some words could not be placed. If you are using fixed words, please make sure that their position doesn\'t prevent other words from being placed. Words with the same alignment may not be placed touching each other. Problematic word(s): @words\"\n      },\n      {\n        \"name\": \"extraClue\",\n        \"type\": \"text\",\n        \"label\": \"Extra clue\",\n        \"importance\": \"low\",\n        \"default\": \"Extra clue\"\n      },\n      {\n        \"name\": \"closeWindow\",\n        \"type\": \"text\",\n        \"label\": \"Close window\",\n        \"importance\": \"low\",\n        \"default\": \"Close window\"\n      }\n    ]\n  },\n  {\n    \"name\": \"a11y\",\n    \"type\": \"group\",\n    \"common\": true,\n    \"label\": \"Readspeaker\",\n    \"importance\": \"low\",\n    \"fields\": [\n      {\n        \"name\": \"crosswordGrid\",\n        \"type\": \"text\",\n        \"label\": \"Crossword grid description\",\n        \"importance\": \"low\",\n        \"default\": \"Crossword grid. Use arrow keys to navigate and the keyboard to enter characters. Alternatively, use Tab to navigate to type the answers in Fill in the Blanks style fields instead of the grid.\"\n      },\n      {\n        \"name\": \"column\",\n        \"type\": \"text\",\n        \"label\": \"Column\",\n        \"importance\": \"low\",\n        \"default\": \"Column\"\n      },\n      {\n        \"name\": \"row\",\n        \"type\": \"text\",\n        \"label\": \"Row\",\n        \"importance\": \"low\",\n        \"default\": \"Row\"\n      },\n      {\n        \"name\": \"across\",\n        \"type\": \"text\",\n        \"label\": \"Across\",\n        \"importance\": \"low\",\n        \"default\": \"Across\"\n      },\n      {\n        \"name\": \"down\",\n        \"type\": \"text\",\n        \"label\": \"Down\",\n        \"importance\": \"low\",\n        \"default\": \"Down\"\n      },\n      {\n        \"name\": \"empty\",\n        \"type\": \"text\",\n        \"label\": \"Empty\",\n        \"importance\": \"low\",\n        \"default\": \"Empty\"\n      },\n      {\n        \"name\": \"resultFor\",\n        \"description\": \"Result announcer. @clue is a variable and will be replaced by the respective clue.\",\n        \"type\": \"text\",\n        \"label\": \"Result for\",\n        \"importance\": \"low\",\n        \"default\": \"Result for: @clue\"\n      },\n      {\n        \"name\": \"correct\",\n        \"type\": \"text\",\n        \"label\": \"Correct\",\n        \"importance\": \"low\",\n        \"default\": \"Correct\"\n      },\n      {\n        \"name\": \"wrong\",\n        \"type\": \"text\",\n        \"label\": \"Wrong\",\n        \"importance\": \"low\",\n        \"default\": \"Wrong\"\n      },\n      {\n        \"name\": \"point\",\n        \"type\": \"text\",\n        \"label\": \"Point\",\n        \"importance\": \"low\",\n        \"default\": \"point\"\n      },\n      {\n        \"name\": \"solutionFor\",\n        \"description\": \"Solution announcer. @clue and @solution are variables and will be replaced by the respective values.\",\n        \"type\": \"text\",\n        \"label\": \"Solution for\",\n        \"importance\": \"low\",\n        \"default\": \"For @clue the solution is: @solution\"\n      },\n      {\n        \"name\": \"extraClueFor\",\n        \"description\": \"Extra clue announcer. @clue is a variable and will be replaced by the respective value.\",\n        \"type\": \"text\",\n        \"label\": \"Extra clue for\",\n        \"importance\": \"low\",\n        \"default\": \"Open extra clue for @clue\"\n      },\n      {\n        \"name\": \"letterSevenOfNine\",\n        \"description\": \"Announcing the current position. @position and @length are variables and will be replaced by their respective values.\",\n        \"type\": \"text\",\n        \"label\": \"Letter\",\n        \"importance\": \"low\",\n        \"default\": \"Letter @position of @length\"\n      },\n      {\n        \"name\": \"lettersWord\",\n        \"description\": \"Announcing the word length. @length is a variable and will be replaced by the respective value.\",\n        \"type\": \"text\",\n        \"label\": \"Length of word\",\n        \"importance\": \"low\",\n        \"default\": \"@length letter word\"\n      },\n      {\n        \"name\": \"check\",\n        \"type\": \"text\",\n        \"label\": \"Assistive technology description for \\\"Check\\\" button\",\n        \"importance\": \"low\",\n        \"default\": \"Check the characters. The responses will be marked as correct, incorrect, or unanswered.\"\n      },\n      {\n        \"name\": \"showSolution\",\n        \"type\": \"text\",\n        \"label\": \"Assistive technology description for \\\"Show Solution\\\" button\",\n        \"importance\": \"low\",\n        \"default\": \"Show the solution. The crossword will be filled with its correct solution.\"\n      },\n      {\n        \"name\": \"retry\",\n        \"type\": \"text\",\n        \"label\": \"Assistive technology description for \\\"Retry\\\" button\",\n        \"importance\": \"low\",\n        \"default\": \"Retry the task. Reset all responses and start the task over again.\"\n      },\n      {\n        \"name\": \"yourResult\",\n        \"type\": \"text\",\n        \"label\": \"Your result\",\n        \"description\": \"@score and @total are variables and will be replaced by their respective values.\",\n        \"importance\": \"low\",\n        \"default\": \"You got @score out of @total points\"\n      }\n    ]\n  }\n]\n', NULL, NULL, NULL, NULL, NULL, 'https://h5p.org/content-types/crossword', 1),
(128, 'H5P.SortParagraphs', 'Sort the Paragraphs', 0, 11, 9, 1, 0, 'iframe', 'dist/h5p-sort-paragraphs.js', 'dist/h5p-sort-paragraphs.css', '', '[\n  {\n    \"name\": \"media\",\n    \"type\": \"group\",\n    \"label\": \"Media\",\n    \"importance\": \"medium\",\n    \"fields\": [\n      {\n        \"name\": \"type\",\n        \"type\": \"library\",\n        \"label\": \"Type\",\n        \"importance\": \"medium\",\n        \"options\": [\n          \"H5P.Image 1.1\",\n          \"H5P.Video 1.6\",\n          \"H5P.Audio 1.5\"\n        ],\n        \"optional\": true,\n        \"description\": \"Optional media to display above the question.\"\n      },\n      {\n        \"name\": \"disableImageZooming\",\n        \"type\": \"boolean\",\n        \"label\": \"Disable image zooming\",\n        \"importance\": \"low\",\n        \"default\": false,\n        \"optional\": true,\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"type\",\n              \"equals\": \"H5P.Image 1.1\"\n            }\n          ]\n        }\n      }\n    ]\n  },\n  {\n    \"label\": \"Task description\",\n    \"importance\": \"high\",\n    \"name\": \"taskDescription\",\n    \"placeholder\": \"Describe what your students should do ...\",\n    \"description\": \"What your students should know.\",\n    \"type\": \"text\",\n    \"widget\": \"html\",\n    \"enterMode\": \"div\",\n    \"tags\": [\n      \"strong\",\n      \"em\",\n      \"u\",\n      \"a\",\n      \"ul\",\n      \"ol\",\n      \"h2\",\n      \"h3\",\n      \"hr\",\n      \"pre\",\n      \"code\"\n    ]\n  },\n  {\n    \"name\": \"paragraphs\",\n    \"label\": \"Paragraphs\",\n    \"type\": \"list\",\n    \"entity\": \"paragraph\",\n    \"min\": 3,\n    \"field\": {\n      \"name\": \"paragraph\",\n      \"label\": \"Paragraph\",\n      \"importance\": \"high\",\n      \"type\": \"text\",\n      \"widget\": \"html\",\n      \"enterMode\": \"div\",\n      \"tags\": [\n        \"strong\",\n        \"em\",\n        \"u\",\n        \"ul\",\n        \"ol\",\n        \"h2\",\n        \"h3\",\n        \"hr\",\n        \"pre\",\n        \"code\"\n      ]\n    }\n  },\n  {\n    \"name\": \"overallFeedback\",\n    \"type\": \"group\",\n    \"label\": \"Overall Feedback\",\n    \"importance\": \"low\",\n    \"expanded\": true,\n    \"fields\": [\n      {\n        \"name\": \"overallFeedback\",\n        \"type\": \"list\",\n        \"widgets\": [\n          {\n            \"name\": \"RangeList\",\n            \"label\": \"Default\"\n          }\n        ],\n        \"importance\": \"high\",\n        \"label\": \"Define custom feedback for any score range\",\n        \"description\": \"Click the \\\"Add range\\\" button to add as many ranges as you need. Example: 0-20% Bad score, 21-91% Average Score, 91-100% Great Score!\",\n        \"entity\": \"range\",\n        \"min\": 1,\n        \"defaultNum\": 1,\n        \"optional\": true,\n        \"field\": {\n          \"name\": \"overallFeedback\",\n          \"type\": \"group\",\n          \"importance\": \"low\",\n          \"fields\": [\n            {\n              \"name\": \"from\",\n              \"type\": \"number\",\n              \"label\": \"Score Range\",\n              \"min\": 0,\n              \"max\": 100,\n              \"default\": 0,\n              \"unit\": \"%\"\n            },\n            {\n              \"name\": \"to\",\n              \"type\": \"number\",\n              \"min\": 0,\n              \"max\": 100,\n              \"default\": 100,\n              \"unit\": \"%\"\n            },\n            {\n              \"name\": \"feedback\",\n              \"type\": \"text\",\n              \"label\": \"Feedback for defined score range\",\n              \"importance\": \"low\",\n              \"placeholder\": \"Fill in the feedback\",\n              \"optional\": true\n            }\n          ]\n        }\n      }\n    ]\n  },\n  {\n    \"name\": \"behaviour\",\n    \"type\": \"group\",\n    \"label\": \"Behavioural settings\",\n    \"importance\": \"low\",\n    \"description\": \"These options will let you control how the task behaves.\",\n    \"fields\": [\n      {\n        \"name\": \"scoringMode\",\n        \"label\": \"Scoring mode\",\n        \"description\": \"Decide whether to give points for each correctly placed paragraph or for each paragraph that is placed after the paragraph it is supposed to be placed after (\\\"correct sequence\\\")\",\n        \"type\": \"select\",\n        \"importance\": \"low\",\n        \"default\": \"positions\",\n        \"options\": [\n          {\n            \"value\": \"positions\",\n            \"label\": \"Correctly placed paragraph\"\n          },\n          {\n            \"value\": \"transitions\",\n            \"label\": \"Correct sequence\"\n          }\n        ]\n      },\n      {\n        \"name\": \"applyPenalties\",\n        \"label\": \"Apply penalties\",\n        \"description\": \"Decide whether to deduce a point for each paragraph that\'s not positioned correctly.\",\n        \"type\": \"boolean\",\n        \"importance\": \"low\",\n        \"default\": true,\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"scoringMode\",\n              \"equals\": \"positions\"\n            }\n          ]\n        }\n      },\n      {\n        \"name\": \"duplicatesInterchangeable\",\n        \"label\": \"Duplicate parapraphs interchangeable\",\n        \"description\": \"If set, when checking the answer, duplicate paragraphs will be treated as identical if their plain text is equal.\",\n        \"type\": \"boolean\",\n        \"importance\": \"low\",\n        \"default\": true,\n        \"optional\": true\n      },\n      {\n        \"name\": \"addButtonsForMovement\",\n        \"label\": \"Add buttons for movement\",\n        \"description\": \"On mobile devices, buttons for moving paragraphs can offer an extra accessibility benefit. If you prefer, you can deactivate them here.\",\n        \"type\": \"boolean\",\n        \"importance\": \"low\",\n        \"default\": true,\n        \"optional\": true\n      },\n      {\n        \"name\": \"enableRetry\",\n        \"label\": \"Enable \\\"Retry\\\" button\",\n        \"type\": \"boolean\",\n        \"importance\": \"low\",\n        \"default\": true,\n        \"optional\": true\n      },\n      {\n        \"name\": \"enableSolutionsButton\",\n        \"label\": \"Enable \\\"Show Solution\\\" button\",\n        \"type\": \"boolean\",\n        \"importance\": \"low\",\n        \"default\": true,\n        \"optional\": true\n      }\n    ]\n  },\n  {\n    \"name\": \"l10n\",\n    \"type\": \"group\",\n    \"common\": true,\n    \"label\": \"User interface\",\n    \"importance\": \"low\",\n    \"fields\": [\n      {\n        \"name\": \"checkAnswer\",\n        \"type\": \"text\",\n        \"label\": \"Text for \\\"Check\\\" button\",\n        \"importance\": \"low\",\n        \"default\": \"Check\"\n      },\n      {\n        \"name\": \"submitAnswer\",\n        \"type\": \"text\",\n        \"label\": \"Text for \\\"Submit\\\" button\",\n        \"importance\": \"low\",\n        \"default\": \"Submit\"\n      },\n      {\n        \"name\": \"tryAgain\",\n        \"label\": \"Text for \\\"Retry\\\" button\",\n        \"type\": \"text\",\n        \"importance\": \"low\",\n        \"default\": \"Retry\"\n      },\n      {\n        \"name\": \"showSolution\",\n        \"type\": \"text\",\n        \"label\": \"Text for \\\"Show solution\\\" button\",\n        \"importance\": \"low\",\n        \"default\": \"Show solution\"\n      },\n      {\n        \"name\": \"up\",\n        \"type\": \"text\",\n        \"label\": \"Title for \\\"Up\\\" button\",\n        \"importance\": \"low\",\n        \"default\": \"Up\"\n      },\n      {\n        \"name\": \"down\",\n        \"type\": \"text\",\n        \"label\": \"Title for \\\"Down\\\" button\",\n        \"importance\": \"low\",\n        \"default\": \"Down\"\n      },\n      {\n        \"name\": \"disabled\",\n        \"type\": \"text\",\n        \"label\": \"Title for button that is disabled\",\n        \"importance\": \"low\",\n        \"default\": \"Disabled\"\n      }\n    ]\n  },\n  {\n    \"name\": \"a11y\",\n    \"type\": \"group\",\n    \"common\": true,\n    \"label\": \"Readspeaker\",\n    \"importance\": \"low\",\n    \"fields\": [\n      {\n        \"name\": \"check\",\n        \"type\": \"text\",\n        \"label\": \"Assistive technology description for \\\"Check\\\" button\",\n        \"importance\": \"low\",\n        \"default\": \"Check the answers. The responses will be marked as correct or incorrect.\"\n      },\n      {\n        \"name\": \"showSolution\",\n        \"type\": \"text\",\n        \"label\": \"Assistive technology description for \\\"Show Solution\\\" button\",\n        \"importance\": \"low\",\n        \"default\": \"Show the solution. The correct solution will be displayed.\"\n      },\n      {\n        \"name\": \"retry\",\n        \"type\": \"text\",\n        \"label\": \"Assistive technology description for \\\"Retry\\\" button\",\n        \"importance\": \"low\",\n        \"default\": \"Retry the task. Reset all elements and start the task over again.\"\n      },\n      {\n        \"name\": \"yourResult\",\n        \"type\": \"text\",\n        \"label\": \"Your result\",\n        \"description\": \"@score will be replaced by the number of points. @total will be replaced by the maximum possible points.\",\n        \"importance\": \"low\",\n        \"default\": \"You got @score out of @total points\"\n      },\n      {\n        \"name\": \"listDescription\",\n        \"type\": \"text\",\n        \"label\": \"List description\",\n        \"importance\": \"low\",\n        \"default\": \"Sortable list of paragraphs.\"\n      },\n      {\n        \"name\": \"listDescriptionCheckAnswer\",\n        \"type\": \"text\",\n        \"label\": \"List description (check answer)\",\n        \"importance\": \"low\",\n        \"default\": \"List of paragraphs with results.\"\n      },\n      {\n        \"name\": \"listDescriptionShowSolution\",\n        \"type\": \"text\",\n        \"label\": \"List description (show solution)\",\n        \"importance\": \"low\",\n        \"default\": \"List of paragraphs with solutions.\"\n      },\n      {\n        \"name\": \"paragraph\",\n        \"type\": \"text\",\n        \"label\": \"Paragraph\",\n        \"importance\": \"low\",\n        \"default\": \"Paragraph\"\n      },\n      {\n        \"name\": \"correct\",\n        \"type\": \"text\",\n        \"label\": \"Correct\",\n        \"importance\": \"low\",\n        \"default\": \"correct\"\n      },\n      {\n        \"name\": \"wrong\",\n        \"type\": \"text\",\n        \"label\": \"Wrong\",\n        \"importance\": \"low\",\n        \"default\": \"wrong\"\n      },\n      {\n        \"name\": \"point\",\n        \"description\": \"@score will be replaced by 1 or -1.\",\n        \"type\": \"text\",\n        \"label\": \"Score explanation\",\n        \"importance\": \"low\",\n        \"default\": \"@score point\"\n      },\n      {\n        \"name\": \"sevenOfNine\",\n        \"description\": \"@current will be replaced by the current paragraph number. @total will be replaced by the number of paragraphs.\",\n        \"type\": \"text\",\n        \"label\": \"Paragraph numbering\",\n        \"importance\": \"low\",\n        \"default\": \"@current of @total\"\n      },\n      {\n        \"name\": \"currentPosition\",\n        \"description\": \"Will be followed by \\\"Paragraph numbering\\\".\",\n        \"type\": \"text\",\n        \"label\": \"Current position in list\",\n        \"importance\": \"low\",\n        \"default\": \"Current position in list\"\n      },\n      {\n        \"name\": \"instructionsSelected\",\n        \"type\": \"text\",\n        \"label\": \"Instruction when paragraph selected\",\n        \"importance\": \"low\",\n        \"default\": \"Press spacebar to reorder\"\n      },\n      {\n        \"name\": \"instructionsGrabbed\",\n        \"type\": \"text\",\n        \"label\": \"Instruction when paragraph grabbed\",\n        \"importance\": \"low\",\n        \"default\": \"Press up and down arrow keys to change position, spacebar to drop, escape to cancel\"\n      },\n      {\n        \"name\": \"grabbed\",\n        \"type\": \"text\",\n        \"label\": \"Grabbed\",\n        \"importance\": \"low\",\n        \"default\": \"Grabbed\"\n      },\n      {\n        \"name\": \"moved\",\n        \"type\": \"text\",\n        \"label\": \"Moved\",\n        \"importance\": \"low\",\n        \"default\": \"Moved\"\n      },\n      {\n        \"name\": \"dropped\",\n        \"type\": \"text\",\n        \"label\": \"Dropped\",\n        \"importance\": \"low\",\n        \"default\": \"Dropped\"\n      },\n      {\n        \"name\": \"reorderCancelled\",\n        \"type\": \"text\",\n        \"label\": \"Reorder cancelled\",\n        \"importance\": \"low\",\n        \"default\": \"Reorder cancelled\"\n      },\n      {\n        \"name\": \"finalPosition\",\n        \"description\": \"Will be followed by \\\"Paragraph numbering\\\".\",\n        \"type\": \"text\",\n        \"label\": \"Final position\",\n        \"importance\": \"low\",\n        \"default\": \"Final position\"\n      },\n      {\n        \"name\": \"nextParagraph\",\n        \"description\": \"Will be followed by \\\"correct\\\" or \\\"wrong\\\".\",\n        \"type\": \"text\",\n        \"label\": \"Next paragraph\",\n        \"importance\": \"low\",\n        \"default\": \"Next paragraph\"\n      },\n      {\n        \"name\": \"correctParagraph\",\n        \"description\": \"Will be followed by \\\"Paragraph numbering\\\".\",\n        \"type\": \"text\",\n        \"label\": \"Correct Paragraph\",\n        \"importance\": \"low\",\n        \"default\": \"Correct paragraph at position\"\n      }\n    ]\n  }\n]\n', NULL, NULL, NULL, NULL, NULL, 'https://h5p.org/content-types/sort-the-paragraphs', 1),
(129, 'H5P.Cornell', 'Cornell Notes', 0, 3, 2, 1, 0, 'iframe', 'dist/h5p-cornell.js', 'dist/h5p-cornell.css', '', '[\n  {\n    \"name\": \"headline\",\n    \"type\": \"text\",\n    \"label\": \"Headline\",\n    \"importance\": \"low\",\n    \"optional\": true,\n    \"description\": \"If set, will be used for the headline of the exercise instead of the content title.\"\n  },\n  {\n    \"label\": \"Instructions\",\n    \"importance\": \"medium\",\n    \"name\": \"instructions\",\n    \"type\": \"text\",\n    \"optional\": true,\n    \"description\": \"Students will see these instructions on top of the notes.\",\n    \"widget\": \"html\",\n    \"enterMode\": \"div\",\n    \"tags\": [\n      \"strong\",\n      \"em\",\n      \"u\",\n      \"a\",\n      \"ul\",\n      \"ol\",\n      \"h2\",\n      \"h3\",\n      \"hr\"\n    ]\n  },\n  {\n    \"label\": \"Exercise content\",\n    \"importance\": \"medium\",\n    \"name\": \"exerciseContent\",\n    \"type\": \"library\",\n    \"options\": [\n      \"H5P.Audio 1.5\",\n      \"H5P.AdvancedText 1.1\",\n      \"H5P.Video 1.6\"\n    ],\n    \"optional\": false\n  },\n  {\n    \"name\": \"notesFields\",\n    \"label\": \"Notes fields\",\n    \"description\": \"Settings for the notes fields.\",\n    \"importance\": \"low\",\n    \"type\": \"group\",\n    \"fields\": [\n      {\n        \"label\": \"Cue field title\",\n        \"importance\": \"low\",\n        \"name\": \"recallTitle\",\n        \"type\": \"text\",\n        \"default\": \"Cue\",\n        \"optional\": true,\n        \"description\": \"Title for the recall section.\"\n      },\n      {\n        \"label\": \"Cue field placeholder\",\n        \"importance\": \"low\",\n        \"name\": \"recallPlaceholder\",\n        \"type\": \"text\",\n        \"default\": \"Enter your comments, questions, the main idea, etc. that you derive from your notes!\",\n        \"optional\": true,\n        \"description\": \"Placeholder for the cue section as a reminder for your students.\"\n      },\n      {\n        \"label\": \"Notes field title\",\n        \"importance\": \"low\",\n        \"name\": \"notesTitle\",\n        \"type\": \"text\",\n        \"default\": \"Notes\",\n        \"optional\": true,\n        \"description\": \"Title for the notes section.\"\n      },\n      {\n        \"label\": \"Notes field placeholder\",\n        \"importance\": \"low\",\n        \"name\": \"notesPlaceholder\",\n        \"type\": \"text\",\n        \"default\": \"Enter dates, details, definitions, formulas, examples, etc. from the source material!\",\n        \"optional\": true,\n        \"description\": \"Placeholder for the notes section as a reminder for your students.\"\n      },\n      {\n        \"label\": \"Summary field title\",\n        \"importance\": \"low\",\n        \"name\": \"summaryTitle\",\n        \"type\": \"text\",\n        \"default\": \"Summary\",\n        \"optional\": true,\n        \"description\": \"Title for the summary section.\"\n      },\n      {\n        \"label\": \"Summary field placeholder\",\n        \"importance\": \"low\",\n        \"name\": \"summaryPlaceholder\",\n        \"type\": \"text\",\n        \"default\": \"Summarize what you have learned!\",\n        \"optional\": true,\n        \"description\": \"Placeholder for the summary section as a reminder for your students.\"\n      }\n    ]\n  },\n  {\n    \"name\": \"l10n\",\n    \"type\": \"group\",\n    \"common\": true,\n    \"label\": \"Localization\",\n    \"importance\": \"low\",\n    \"fields\": [\n      {\n        \"name\": \"notesSaved\",\n        \"type\": \"text\",\n        \"label\": \"Notes saved\",\n        \"importance\": \"low\",\n        \"default\": \"Notes saved\"\n      },\n      {\n        \"name\": \"save\",\n        \"type\": \"text\",\n        \"label\": \"Save\",\n        \"importance\": \"low\",\n        \"default\": \"Save\"\n      },\n      {\n        \"name\": \"noSaveContentState\",\n        \"type\": \"text\",\n        \"label\": \"Notes cannot be saved\",\n        \"importance\": \"low\",\n        \"default\": \"The platform either does not support the save content state feature or it is not activated in the platform\'s settings or you are not logged in. Your notes cannot be saved!\"\n      },\n      {\n        \"name\": \"copy\",\n        \"type\": \"text\",\n        \"label\": \"Text for \\\"Copy\\\" button\",\n        \"importance\": \"low\",\n        \"default\": \"Copy\"\n      },\n      {\n        \"name\": \"copyToClipboardSuccess\",\n        \"type\": \"text\",\n        \"label\": \"Notes copied to clipboard\",\n        \"importance\": \"low\",\n        \"default\": \"Notes copied to clipboard\"\n      },\n      {\n        \"name\": \"copyToClipboardError\",\n        \"type\": \"text\",\n        \"label\": \"Notes could not be copied to clipboard\",\n        \"importance\": \"low\",\n        \"default\": \"Notes could not be copied to clipboard\"\n      }\n    ]\n  },\n  {\n    \"name\": \"a11y\",\n    \"type\": \"group\",\n    \"common\": true,\n    \"label\": \"Readspeaker\",\n    \"importance\": \"low\",\n    \"fields\": [\n      {\n        \"name\": \"buttonFullscreenEnter\",\n        \"type\": \"text\",\n        \"label\": \"Fullscreen button title (enter)\",\n        \"importance\": \"low\",\n        \"default\": \"Enter fullscreen mode\"\n      },\n      {\n        \"name\": \"buttonFullscreenExit\",\n        \"type\": \"text\",\n        \"label\": \"Fullscreen button title (exit)\",\n        \"importance\": \"low\",\n        \"default\": \"Exit fullscreen mode\"\n      },\n      {\n        \"name\": \"buttonToggleOpenNotes\",\n        \"type\": \"text\",\n        \"label\": \"Toggle button title (when notes closed)\",\n        \"importance\": \"low\",\n        \"default\": \"Open notes\"\n      },\n      {\n        \"name\": \"buttonToggleCloseNotes\",\n        \"type\": \"text\",\n        \"label\": \"Toggle button title (when notes opened)\",\n        \"importance\": \"low\",\n        \"default\": \"Close notes\"\n      },\n      {\n        \"name\": \"notesOpened\",\n        \"type\": \"text\",\n        \"label\": \"Notes opened\",\n        \"importance\": \"low\",\n        \"default\": \"The view has switched to your notes.\"\n      },\n      {\n        \"name\": \"notesClosed\",\n        \"type\": \"text\",\n        \"label\": \"Notes closed\",\n        \"importance\": \"low\",\n        \"default\": \"The view has switched to the exercise.\"\n      },\n      {\n        \"name\": \"notesSaved\",\n        \"type\": \"text\",\n        \"label\": \"Notes saved\",\n        \"importance\": \"low\",\n        \"default\": \"The notes were saved to the platform.\"\n      },\n      {\n        \"name\": \"notesHide\",\n        \"type\": \"text\",\n        \"label\": \"Hide notes\",\n        \"importance\": \"low\",\n        \"default\": \"Hide @label notes\",\n        \"description\": \"@label is a placeholder and will be replaced with the respective label of the notes field.\"\n      },\n      {\n        \"name\": \"notesShow\",\n        \"type\": \"text\",\n        \"label\": \"Show notes\",\n        \"importance\": \"low\",\n        \"default\": \"Show @label notes\",\n        \"description\": \"@label is a placeholder and will be replaced with the respective label of the notes field.\"\n      }\n    ]\n  }\n]\n', NULL, NULL, NULL, NULL, NULL, 'https://h5p.org/node/1252534', 1),
