INSERT INTO `mdl_h5p_libraries` (`id`, `machinename`, `title`, `majorversion`, `minorversion`, `patchversion`, `runnable`, `fullscreen`, `embedtypes`, `preloadedjs`, `preloadedcss`, `droplibrarycss`, `semantics`, `addto`, `coremajor`, `coreminor`, `metadatasettings`, `tutorial`, `example`, `enabled`) VALUES
(133, 'H5P.ARScavenger', 'AR Scavenger (beta)', 1, 4, 1, 1, 0, 'iframe', 'dist/h5p-ar-scavenger.js', 'dist/h5p-ar-scavenger.css', '', '[\n  {\n    \"name\": \"showTitleScreen\",\n    \"label\": \"Show start screen\",\n    \"description\": \"If checked, the content will show the title screen when starting.\",\n    \"type\": \"boolean\",\n    \"default\": false,\n    \"optional\": true\n  },\n  {\n    \"name\": \"titleScreen\",\n    \"label\": \"Start screen\",\n    \"type\": \"group\",\n    \"importance\": \"low\",\n    \"fields\": [\n      {\n        \"name\": \"titleScreenIntroduction\",\n        \"label\": \"Introduction\",\n        \"type\": \"text\",\n        \"widget\": \"html\",\n        \"placeholder\": \"Welcome to ...\",\n        \"optional\": true,\n        \"enterMode\": \"div\",\n        \"tags\": [\n          \"strong\",\n          \"em\",\n          \"u\",\n          \"a\",\n          \"ul\",\n          \"ol\",\n          \"h2\",\n          \"h3\",\n          \"hr\",\n          \"pre\",\n          \"code\"\n        ]\n      },\n      {\n        \"name\": \"titleScreenImage\",\n        \"label\": \"Title screen image\",\n        \"type\": \"library\",\n        \"optional\": true,\n        \"options\": [\n          \"H5P.Image 1.1\"\n        ]\n      }\n    ],\n    \"widget\": \"showWhen\",\n    \"showWhen\": {\n      \"rules\": [\n        {\n          \"field\": \"showTitleScreen\",\n          \"equals\": true\n        }\n      ]\n    }\n  },\n  {\n    \"name\": \"markers\",\n    \"label\": \"Markers\",\n    \"type\": \"group\",\n    \"optional\": true,\n    \"expanded\": true,\n    \"importance\": \"high\",\n    \"fields\": [\n      {\n        \"name\": \"markers\",\n        \"label\": \"Markers\",\n        \"type\": \"list\",\n        \"importance\": \"medium\",\n        \"widgets\": [\n          {\n            \"name\": \"VerticalTabs\",\n            \"label\": \"Default\"\n          }\n        ],\n        \"min\": 1,\n        \"entity\": \"marker\",\n        \"field\": {\n          \"name\": \"markerGroup\",\n          \"type\": \"group\",\n          \"label\": \"Marker\",\n          \"fields\": [\n            {\n              \"name\": \"markerImage\",\n              \"label\": \"Marker image (original)\",\n              \"description\": \"Upload the image that you want to create a marker for. Should be a square image or it will be cropped. Keep in mind that you will need a unique marker image for every interaction.\",\n              \"type\": \"image\",\n              \"widget\": \"importantDescription\",\n              \"importantDescription\": {\n                \"description\": \"Please keep in mind some criteria for good marker images:<ul><li>High color contrast, ideally black and white</li><li>Asymmetry</li><li>The internal resolution of a marker is 16 x 16 pixels, using larger images can make marker detection worse</li><li>Single characters or short words yield good results</li></ul>\",\n                \"floatingButton\": true\n              },\n              \"optional\": true\n            },\n            {\n              \"name\": \"markerPattern\",\n              \"label\": \"Marker image (pattern)\",\n              \"description\": \"Download this image to use as a marker displayed on a screen or printed on paper.\",\n              \"type\": \"file\",\n              \"optional\": true,\n              \"widget\": \"arMarkerGenerator\",\n              \"arMarkerGenerator\": {\n                \"referencePath\": \"markerImage\"\n              }\n            },\n            {\n              \"name\": \"actionType\",\n              \"type\": \"select\",\n              \"label\": \"Action type\",\n              \"description\": \"Action that should be triggered when the marker is found.\",\n              \"options\": [\n                {\n                  \"value\": \"h5p\",\n                  \"label\": \"H5P interaction\"\n                },\n                {\n                  \"value\": \"model\",\n                  \"label\": \"3D model overlay\"\n                }\n              ],\n              \"default\": \"h5p\"\n            },\n            {\n              \"name\": \"interaction\",\n              \"label\": \"Interaction\",\n              \"type\": \"group\",\n              \"optional\": true,\n              \"expanded\": true,\n              \"widget\": \"showWhen\",\n              \"showWhen\": {\n                \"rules\": [\n                  {\n                    \"field\": \"actionType\",\n                    \"equals\": \"h5p\"\n                  }\n                ]\n              },\n              \"fields\": [\n                {\n                  \"name\": \"interaction\",\n                  \"label\": \"Interaction\",\n                  \"type\": \"library\",\n                  \"options\": [\n                    \"H5P.Accordion 1.0\",\n                    \"H5P.Agamotto 1.5\",\n                    \"H5P.Audio 1.5\",\n                    \"H5P.AudioRecorder 1.0\",\n                    \"H5P.Blanks 1.14\",\n                    \"H5P.Chart 1.2\",\n                    \"H5P.Collage 0.3\",\n                    \"H5P.CoursePresentation 1.25\",\n                    \"H5P.Dialogcards 1.9\",\n                    \"H5P.DocumentationTool 1.8\",\n                    \"H5P.DragQuestion 1.14\",\n                    \"H5P.DragText 1.10\",\n                    \"H5P.Essay 1.5\",\n                    \"H5P.GuessTheAnswer 1.5\",\n                    \"H5P.Table 1.1\",\n                    \"H5P.AdvancedText 1.1\",\n                    \"H5P.Image 1.1\",\n                    \"H5P.MultiMediaChoice 0.3\",\n                    \"H5P.ImageHotspots 1.10\",\n                    \"H5P.ImageHotspotQuestion 1.8\",\n                    \"H5P.ImageSlider 1.1\",\n                    \"H5P.InteractiveVideo 1.26\",\n                    \"H5P.Link 1.3\",\n                    \"H5P.MarkTheWords 1.11\",\n                    \"H5P.MemoryGame 1.3\",\n                    \"H5P.MultiChoice 1.16\",\n                    \"H5P.Questionnaire 1.3\",\n                    \"H5P.QuestionSet 1.20\",\n                    \"H5P.SingleChoiceSet 1.11\",\n                    \"H5P.Summary 1.10\",\n                    \"H5P.Timeline 1.1\",\n                    \"H5P.TrueFalse 1.8\",\n                    \"H5P.Video 1.6\"\n                  ]\n                },\n                {\n                  \"name\": \"dummy\",\n                  \"type\": \"text\",\n                  \"optional\": true,\n                  \"label\": \"Dummy\",\n                  \"widget\": \"none\"\n                }\n              ]\n            },\n            {\n              \"name\": \"model\",\n              \"label\": \"3D Model\",\n              \"type\": \"group\",\n              \"optional\": true,\n              \"expanded\": true,\n              \"widget\": \"showWhen\",\n              \"showWhen\": {\n                \"rules\": [\n                  {\n                    \"field\": \"actionType\",\n                    \"equals\": \"model\"\n                  }\n                ]\n              },\n              \"fields\": [\n                {\n                  \"name\": \"file\",\n                  \"label\": \"3D model file\",\n                  \"description\": \"Upload a glTF (.glb / .gltf) file here. The preferred format is \\\"glTF 2.0 binary\\\" in a single file.\",\n                  \"type\": \"file\",\n                  \"widget\": \"threeDModelLoader\",\n                  \"threeDModelLoader\": {\n                    \"fileTypeExtensions\": [\n                      \"gltf\",\n                      \"glb\"\n                    ],\n                    \"geometryPath\": \"geometry\",\n                    \"planePatternPath\": \"../markerPattern\"\n                  }\n                },\n                {\n                  \"name\": \"geometry\",\n                  \"label\": \"Geometry\",\n                  \"type\": \"group\",\n                  \"optional\": true,\n                  \"fields\": [\n                    {\n                      \"name\": \"scale\",\n                      \"label\": \"Scale\",\n                      \"description\": \"Scale the model up or down to match your marker size.\",\n                      \"type\": \"group\",\n                      \"optional\": true,\n                      \"widget\": \"inputrow\",\n                      \"inputrow\": {\n                        \"HTML5NumberField\": true,\n                        \"changedOnEnter\": true\n                      },\n                      \"fields\": [\n                        {\n                          \"name\": \"scale\",\n                          \"label\": \"Percentage\",\n                          \"type\": \"number\",\n                          \"optional\": true,\n                          \"default\": 100,\n                          \"min\": 1\n                        },\n                        {\n                          \"name\": \"dummy\",\n                          \"label\": \"Dummy\",\n                          \"type\": \"text\",\n                          \"optional\": true,\n                          \"widget\": \"none\"\n                        }\n                      ]\n                    },\n                    {\n                      \"name\": \"position\",\n                      \"label\": \"Position\",\n                      \"description\": \"Set the model\'s offset position relative to the marker.\",\n                      \"type\": \"group\",\n                      \"optional\": true,\n                      \"widget\": \"inputrow\",\n                      \"inputrow\": {\n                        \"HTML5NumberField\": false,\n                        \"changedOnEnter\": true\n                      },\n                      \"fields\": [\n                        {\n                          \"name\": \"x\",\n                          \"label\": \"X-offset\",\n                          \"type\": \"number\",\n                          \"optional\": true,\n                          \"default\": 0,\n                          \"decimals\": 2\n                        },\n                        {\n                          \"name\": \"y\",\n                          \"label\": \"Y-offset\",\n                          \"type\": \"number\",\n                          \"optional\": true,\n                          \"default\": 0,\n                          \"decimals\": 2\n                        },\n                        {\n                          \"name\": \"z\",\n                          \"label\": \"Z-offset\",\n                          \"type\": \"number\",\n                          \"optional\": true,\n                          \"default\": 0,\n                          \"decimals\": 2\n                        }\n                      ]\n                    },\n                    {\n                      \"name\": \"rotation\",\n                      \"label\": \"Rotation\",\n                      \"description\": \"Set the rotation in degrees.\",\n                      \"type\": \"group\",\n                      \"optional\": true,\n                      \"widget\": \"inputrow\",\n                      \"inputrow\": {\n                        \"HTML5NumberField\": true,\n                        \"changedOnEnter\": true\n                      },\n                      \"fields\": [\n                        {\n                          \"name\": \"x\",\n                          \"label\": \"X-axis\",\n                          \"type\": \"number\",\n                          \"optional\": true,\n                          \"default\": 0,\n                          \"min\": -359,\n                          \"max\": 359\n                        },\n                        {\n                          \"name\": \"y\",\n                          \"label\": \"Y-axis\",\n                          \"type\": \"number\",\n                          \"optional\": true,\n                          \"default\": 0,\n                          \"min\": -359,\n                          \"max\": 359\n                        },\n                        {\n                          \"name\": \"z\",\n                          \"label\": \"Z-axis\",\n                          \"type\": \"number\",\n                          \"optional\": true,\n                          \"default\": 0,\n                          \"min\": -359,\n                          \"max\": 359\n                        }\n                      ]\n                    }\n                  ]\n                }\n              ]\n            }\n          ]\n        }\n      }\n    ]\n  },\n  {\n    \"name\": \"showEndScreen\",\n    \"label\": \"Show end screen\",\n    \"description\": \"If checked, show an end screen when all interactions have been completed. The end screen will not be available if you only use 3D models though.\",\n    \"type\": \"boolean\",\n    \"default\": false,\n    \"optional\": true\n  },\n  {\n    \"name\": \"endScreen\",\n    \"label\": \"End screen\",\n    \"type\": \"group\",\n    \"importance\": \"low\",\n    \"fields\": [\n      {\n        \"name\": \"endScreenImage\",\n        \"label\": \"end screen image\",\n        \"type\": \"library\",\n        \"optional\": true,\n        \"options\": [\n          \"H5P.Image 1.1\"\n        ]\n      },\n      {\n        \"name\": \"endScreenOutro\",\n        \"label\": \"End screen text\",\n        \"type\": \"text\",\n        \"widget\": \"html\",\n        \"placeholder\": \"You did it!\",\n        \"optional\": true,\n        \"enterMode\": \"div\",\n        \"tags\": [\n          \"strong\",\n          \"em\",\n          \"u\",\n          \"a\",\n          \"ul\",\n          \"ol\",\n          \"h2\",\n          \"h3\",\n          \"hr\",\n          \"pre\",\n          \"code\"\n        ]\n      },\n      {\n        \"name\": \"overallFeedback\",\n        \"type\": \"group\",\n        \"label\": \"Overall Feedback\",\n        \"importance\": \"low\",\n        \"expanded\": true,\n        \"fields\": [\n          {\n            \"name\": \"overallFeedback\",\n            \"type\": \"list\",\n            \"widgets\": [\n              {\n                \"name\": \"RangeList\",\n                \"label\": \"Default\"\n              }\n            ],\n            \"importance\": \"high\",\n            \"label\": \"Define custom feedback for any score range\",\n            \"description\": \"Click the \\\"Add range\\\" button to add as many ranges as you need. Example: 0-20% Bad score, 21-91% Average Score, 91-100% Great Score!\",\n            \"entity\": \"range\",\n            \"min\": 1,\n            \"defaultNum\": 1,\n            \"optional\": true,\n            \"field\": {\n              \"name\": \"overallFeedback\",\n              \"type\": \"group\",\n              \"importance\": \"low\",\n              \"fields\": [\n                {\n                  \"name\": \"from\",\n                  \"type\": \"number\",\n                  \"label\": \"Score Range\",\n                  \"min\": 0,\n                  \"max\": 100,\n                  \"default\": 0,\n                  \"unit\": \"%\"\n                },\n                {\n                  \"name\": \"to\",\n                  \"type\": \"number\",\n                  \"min\": 0,\n                  \"max\": 100,\n                  \"default\": 100,\n                  \"unit\": \"%\"\n                },\n                {\n                  \"name\": \"feedback\",\n                  \"type\": \"text\",\n                  \"label\": \"Feedback for defined score range\",\n                  \"importance\": \"low\",\n                  \"placeholder\": \"Fill in the feedback\",\n                  \"optional\": true\n                }\n              ]\n            }\n          }\n        ]\n      }\n    ],\n    \"widget\": \"showWhen\",\n    \"showWhen\": {\n      \"rules\": [\n        {\n          \"field\": \"showEndScreen\",\n          \"equals\": true\n        }\n      ]\n    }\n  },\n  {\n    \"name\": \"behaviour\",\n    \"type\": \"group\",\n    \"importance\": \"low\",\n    \"label\": \"Behavioural settings\",\n    \"fields\": [\n      {\n        \"name\": \"enableRetry\",\n        \"label\": \"Enable \\\"Retry\\\" button\",\n        \"type\": \"boolean\",\n        \"importance\": \"low\",\n        \"description\": \"If checked, learners can retry the task.\",\n        \"default\": true,\n        \"optional\": true\n      },\n      {\n        \"name\": \"enableSolutionsButton\",\n        \"label\": \"Enable \\\"Solutions\\\" button\",\n        \"type\": \"boolean\",\n        \"importance\": \"low\",\n        \"description\": \"If checked, learners can view the solutions of all interactions.\",\n        \"default\": false,\n        \"optional\": true,\n        \"widget\": \"none\"\n      },\n      {\n        \"name\": \"overrideShowSolutionButton\",\n        \"type\": \"select\",\n        \"label\": \"Override \\\"Show Solution\\\" button\",\n        \"importance\": \"low\",\n        \"description\": \"This option allows to enable or disable the \\\"Show Solution\\\" button for all contents or to use their respective behavioural settings.\",\n        \"options\": [\n          {\n            \"value\": \"useBehavioural\",\n            \"label\": \"Use behavioural setting\"\n          },\n          {\n            \"value\": \"always\",\n            \"label\": \"Always show button\"\n          },\n          {\n            \"value\": \"never\",\n            \"label\": \"Never show button\"\n          }\n        ],\n        \"default\": \"useBehavioural\"\n      },\n      {\n        \"name\": \"overrideRetryButton\",\n        \"type\": \"select\",\n        \"label\": \"Override \\\"Retry\\\" button\",\n        \"importance\": \"low\",\n        \"description\": \"This option allows to enable or disable the \\\"Retry\\\" button for all contents or to use their respective behavioural settings.\",\n        \"options\": [\n          {\n            \"value\": \"useBehavioural\",\n            \"label\": \"Use behavioural setting\"\n          },\n          {\n            \"value\": \"always\",\n            \"label\": \"Always show button\"\n          },\n          {\n            \"value\": \"never\",\n            \"label\": \"Never show button\"\n          }\n        ],\n        \"default\": \"useBehavioural\"\n      },\n      {\n        \"name\": \"fallbackHeight\",\n        \"type\": \"number\",\n        \"importance\": \"low\",\n        \"label\": \"Fallback height\",\n        \"description\": \"Set a fallback heigth in px for cases when there are cross orgin resource sharing (CORS) issues.\",\n        \"default\": 400,\n        \"min\": 100,\n        \"optional\": true\n      }\n    ]\n  },\n  {\n    \"name\": \"l10n\",\n    \"type\": \"group\",\n    \"common\": true,\n    \"label\": \"Localization\",\n    \"importance\": \"low\",\n    \"fields\": [\n      {\n        \"name\": \"start\",\n        \"type\": \"text\",\n        \"label\": \"Start button\",\n        \"importance\": \"low\",\n        \"default\": \"Start\"\n      },\n      {\n        \"name\": \"retry\",\n        \"type\": \"text\",\n        \"label\": \"Retry button\",\n        \"importance\": \"low\",\n        \"default\": \"Retry\"\n      },\n      {\n        \"name\": \"nothingToSee\",\n        \"type\": \"text\",\n        \"label\": \"Find a marker to see an interaction.\",\n        \"importance\": \"low\",\n        \"default\": \"Find a marker to see an interaction.\"\n      },\n      {\n        \"name\": \"errorBrowserNotSupported\",\n        \"type\": \"text\",\n        \"label\": \"Error: browser not supported\",\n        \"importance\": \"low\",\n        \"default\": \"It seems that your browser cannot run this content type, unfortunately.\"\n      },\n      {\n        \"name\": \"errorNoCameraAccess\",\n        \"type\": \"text\",\n        \"label\": \"Error: No camera access\",\n        \"importance\": \"low\",\n        \"default\": \"Could not access camera.\"\n      },\n      {\n        \"name\": \"errorNoCameraSupport\",\n        \"type\": \"text\",\n        \"label\": \"Error: No camera support\",\n        \"importance\": \"low\",\n        \"default\": \"Your browser does not seem to support a camera.\"\n      },\n      {\n        \"name\": \"errorNoMarkers\",\n        \"type\": \"text\",\n        \"label\": \"Error: No markers\",\n        \"importance\": \"low\",\n        \"default\": \"Did someone forget to add markers?\"\n      },\n      {\n        \"name\": \"warningBrave\",\n        \"type\": \"text\",\n        \"label\": \"Warning: Brave browser\",\n        \"importance\": \"low\",\n        \"default\": \"You seem to be using the Brave browser. Nice! But its strict privacy settings may prevent the camera from working.\"\n      },\n      {\n        \"name\": \"initializingContent\",\n        \"type\": \"text\",\n        \"label\": \"Initializing content\",\n        \"importance\": \"low\",\n        \"default\": \"Initializing content. Please don\'t forget to allow camera access.\"\n      }\n    ]\n  },\n  {\n    \"name\": \"a11y\",\n    \"type\": \"group\",\n    \"common\": true,\n    \"label\": \"Readspeaker\",\n    \"importance\": \"low\",\n    \"fields\": [\n      {\n        \"name\": \"buttonFullScreenEnter\",\n        \"type\": \"text\",\n        \"label\": \"FullScreen button title: enter\",\n        \"importance\": \"low\",\n        \"default\": \"Enter fullscreen mode\"\n      },\n      {\n        \"name\": \"buttonFullScreenExit\",\n        \"type\": \"text\",\n        \"label\": \"FullScreen button title: exit\",\n        \"importance\": \"low\",\n        \"default\": \"Exit fullscreen mode\"\n      },\n      {\n        \"name\": \"buttonSwitchViewAction\",\n        \"type\": \"text\",\n        \"label\": \"\'Switch view\' button title (when action closed)\",\n        \"importance\": \"low\",\n        \"default\": \"Switch to exercise\"\n      },\n      {\n        \"name\": \"buttonSwitchViewCamera\",\n        \"type\": \"text\",\n        \"label\": \"\'Switch view\' button title (when action opened)\",\n        \"importance\": \"low\",\n        \"default\": \"Switch to camera\"\n      },\n      {\n        \"name\": \"buttonSwitchViewDisabled\",\n        \"type\": \"text\",\n        \"label\": \"\'Button disabled\' message for \'switch view button\'\",\n        \"importance\": \"low\",\n        \"default\": \"You cannot switch the view right now\"\n      },\n      {\n        \"name\": \"buttonQuit\",\n        \"type\": \"text\",\n        \"label\": \"\'Quit\' button title\",\n        \"importance\": \"low\",\n        \"default\": \"Quit and show evaluation\"\n      },\n      {\n        \"name\": \"buttonQuitDisabled\",\n        \"type\": \"text\",\n        \"label\": \"\'Button disabled\' message for \'quit button\'\",\n        \"importance\": \"low\",\n        \"default\": \"You have not yet completed all exercises\"\n      },\n      {\n        \"name\": \"actionOpened\",\n        \"type\": \"text\",\n        \"label\": \"Action opened\",\n        \"importance\": \"low\",\n        \"default\": \"The view has switched to an exercise.\"\n      },\n      {\n        \"name\": \"actionClosed\",\n        \"type\": \"text\",\n        \"label\": \"Action closed\",\n        \"importance\": \"low\",\n        \"default\": \"The view has switched to the camera.\"\n      }\n    ]\n  }\n]\n', NULL, NULL, NULL, NULL, NULL, 'https://h5p.org/content-types/ar-scavenger', 1),
