(135, 'H5PEditor.ImportantDescription', 'H5PEditor.ImportantDescription', 0, 1, 4, 0, 0, '', 'dist/h5p-editor-important-description.js', 'dist/h5p-editor-important-description.css', '', '', NULL, 1, 12, NULL, NULL, NULL, 1),
(136, 'H5PEditor.InputRow', 'H5PEditor.InputRow', 1, 0, 1, 0, 0, '', 'dist/h5p-editor-input-row.js', 'dist/h5p-editor-input-row.css', '', '', NULL, 1, 12, NULL, NULL, NULL, 1),
(137, 'H5PEditor.ThreeDModelLoader', 'H5PEditor.ThreeDModelLoader', 1, 0, 4, 0, 0, '', 'dist/h5p-editor-3d-model-loader.js', 'dist/h5p-editor-3d-model-loader.css', '', '', NULL, 1, 12, NULL, NULL, NULL, 1),
(138, 'H5P.StructureStrip', 'Structure Strip', 1, 0, 6, 1, 0, 'iframe', 'dist/h5p-structure-strip.js', 'dist/h5p-structure-strip.css', '', '[\n  {\n    \"name\": \"media\",\n    \"type\": \"group\",\n    \"label\": \"Media\",\n    \"importance\": \"medium\",\n    \"fields\": [\n      {\n        \"name\": \"type\",\n        \"type\": \"library\",\n        \"label\": \"Type\",\n        \"importance\": \"medium\",\n        \"options\": [\n          \"H5P.Image 1.1\",\n          \"H5P.Video 1.6\",\n          \"H5P.Audio 1.5\"\n        ],\n        \"optional\": true,\n        \"description\": \"Optional media to display above the question.\"\n      },\n      {\n        \"name\": \"disableImageZooming\",\n        \"type\": \"boolean\",\n        \"label\": \"Disable image zooming\",\n        \"importance\": \"low\",\n        \"default\": false,\n        \"optional\": true,\n        \"widget\": \"showWhen\",\n        \"showWhen\": {\n          \"rules\": [\n            {\n              \"field\": \"type\",\n              \"equals\": \"H5P.Image 1.1\"\n            }\n          ]\n        }\n      }\n    ]\n  },\n  {\n    \"name\": \"taskDescription\",\n    \"type\": \"text\",\n    \"label\": \"Task description\",\n    \"description\": \"Explain to your students what\'s expected of them.\",\n    \"widget\": \"html\",\n    \"optional\": true,\n    \"enterMode\": \"div\",\n    \"tags\": [\n      \"strong\",\n      \"em\",\n      \"u\",\n      \"a\",\n      \"ul\",\n      \"ol\",\n      \"h2\",\n      \"h3\",\n      \"hr\"\n    ]\n  },\n  {\n    \"name\": \"sections\",\n    \"type\": \"list\",\n    \"label\": \"Sections\",\n    \"entity\": \"section\",\n    \"min\": 1,\n    \"widgets\": [\n      {\n        \"name\": \"VerticalTabs\",\n        \"label\": \"Default\"\n      }\n    ],\n    \"field\": {\n      \"name\": \"sectionParams\",\n      \"type\": \"group\",\n      \"label\": \"Section parameters\",\n      \"fields\": [\n        {\n          \"name\": \"title\",\n          \"type\": \"text\",\n          \"label\": \"Title\"\n        },\n        {\n          \"name\": \"description\",\n          \"type\": \"text\",\n          \"label\": \"Hints\",\n          \"description\": \"Optionally add hints or particular instructions for this section.\",\n          \"optional\": true,\n          \"widget\": \"html\",\n          \"enterMode\": \"div\",\n          \"tags\": [\n            \"strong\",\n            \"em\",\n            \"u\",\n            \"a\",\n            \"ul\",\n            \"ol\",\n            \"h2\",\n            \"h3\",\n            \"hr\"\n          ]\n        },\n        {\n          \"name\": \"weight\",\n          \"type\": \"number\",\n          \"label\": \"Weight\",\n          \"description\": \"Determine how long each section is expected to be in relation to the other sections. Example: Section 1 = 1; Section 2 = 3 (triple the length of 1); Section 3 = 1 (same length as section 1).\",\n          \"min\": 1,\n          \"default\": 1\n        },\n        {\n          \"name\": \"colorBackground\",\n          \"type\": \"text\",\n          \"label\": \"Background color\",\n          \"importance\": \"medium\",\n          \"optional\": true,\n          \"default\": \"#96ceb4\",\n          \"widget\": \"colorSelector\",\n          \"spectrum\": {\n            \"showInput\": true,\n            \"showInitial\": true,\n            \"showPalette\": true,\n            \"palette\": [\n              [\n                \"#96ceb4\",\n                \"#ffeead\",\n                \"#ff6f69\",\n                \"ffcc5c\",\n                \"#88d8b0\"\n              ],\n              [\n                \"#845ec2\",\n                \"#d65db1\",\n                \"#ff6f91\",\n                \"#ff9671\",\n                \"#ffc75f\"\n              ],\n              [\n                \"#a8e6cf\",\n                \"#dcedc1\",\n                \"#ffd3b6\",\n                \"#ffaaa5\",\n                \"#ff8b94\"\n              ],\n              [\n                \"#009688\",\n                \"#35a79c\",\n                \"#54b2a9\",\n                \"#65c3ba\",\n                \"#83d0c9\"\n              ]\n            ]\n          }\n        },\n        {\n          \"name\": \"colorText\",\n          \"type\": \"text\",\n          \"label\": \"Text color\",\n          \"importance\": \"medium\",\n          \"optional\": true,\n          \"default\": \"#1c1c1c\",\n          \"widget\": \"colorSelector\",\n          \"spectrum\": {\n            \"showInput\": true,\n            \"showPalette\": true,\n            \"palette\": [\n              [\n                \"#154c37\",\n                \"#74682e\",\n                \"#680000\",\n                \"#6f4c00\",\n                \"#005434\"\n              ],\n              [\n                \"#ffe4ff\",\n                \"#4a0034\",\n                \"#6a001d\",\n                \"#6c1400\",\n                \"#6e4700\"\n              ],\n              [\n                \"#25604e\",\n                \"#586741\",\n                \"#745139\",\n                \"#712b2c\",\n                \"#6d001f\"\n              ],\n              [\n                \"#002115\",\n                \"#002a25\",\n                \"#00332f\",\n                \"#00423d\",\n                \"#004d49\"\n              ],\n              [\n                \"#000000\",\n                \"#1c1c1c\",\n                \"#393939\",\n                \"#555555\",\n                \"#717171\"\n              ],\n              [\n                \"#8e8e8e\",\n                \"#aaaaaa\",\n                \"#c6c6c6\",\n                \"#e3e3e3\",\n                \"#ffffff\"\n              ]\n            ]\n          }\n        }\n      ]\n    }\n  },\n  {\n    \"name\": \"behaviour\",\n    \"type\": \"group\",\n    \"label\": \"Behavioural settings\",\n    \"importance\": \"low\",\n    \"description\": \"These options will let you control how the task behaves.\",\n    \"fields\": [\n      {\n        \"name\": \"enableRetry\",\n        \"label\": \"Enable \\\"Retry\\\"\",\n        \"type\": \"boolean\",\n        \"importance\": \"low\",\n        \"default\": true,\n        \"optional\": true\n      },\n      {\n        \"name\": \"enableSolutionsButton\",\n        \"label\": \"Enable \\\"Solution\\\"\",\n        \"type\": \"boolean\",\n        \"importance\": \"low\",\n        \"default\": true,\n        \"optional\": true,\n        \"widget\": \"none\"\n      },\n      {\n        \"name\": \"slack\",\n        \"label\": \"Slack\",\n        \"description\": \"Slack is built-in flexibility of a section\'s length, calculated in percentage.\",\n        \"type\": \"number\",\n        \"importance\": \"low\",\n        \"default\": 10,\n        \"min\": 0,\n        \"max\": 50\n      },\n      {\n        \"name\": \"textLengthMin\",\n        \"label\": \"Minimum text length\",\n        \"description\": \"Define an absolute minimum total text length. Please note that a section\'s weight compared to other sections is the main driver for the feedback message, not this minimum value.\",\n        \"type\": \"number\",\n        \"importance\": \"low\",\n        \"min\": 0,\n        \"optional\": true\n      },\n      {\n        \"name\": \"textLengthMax\",\n        \"label\": \"Maximum text length\",\n        \"description\": \"Define an absolute maximum total text length. Please note that a section\'s weight compared to other sections is the main driver for the feedback message, not this maximum value.\",\n        \"type\": \"number\",\n        \"importance\": \"low\",\n        \"min\": 0,\n        \"optional\": true\n      },\n      {\n        \"name\": \"feedbackMode\",\n        \"label\": \"Feedback mode\",\n        \"description\": \"Decide whether you want to display feedback while typing or only when the student requests it.\",\n        \"type\": \"select\",\n        \"importance\": \"low\",\n        \"options\": [\n          {\n            \"label\": \"On request\",\n            \"value\": \"onRequest\"\n          },\n          {\n            \"label\": \"While typing\",\n            \"value\": \"whileTyping\"\n          }\n        ],\n        \"default\": \"onRequest\"\n      }\n    ]\n  },\n  {\n    \"name\": \"l10n\",\n    \"type\": \"group\",\n    \"common\": true,\n    \"label\": \"User interface\",\n    \"importance\": \"low\",\n    \"fields\": [\n      {\n        \"name\": \"copy\",\n        \"type\": \"text\",\n        \"label\": \"Text for \\\"Copy\\\" button\",\n        \"importance\": \"low\",\n        \"default\": \"Copy\"\n      },\n      {\n        \"name\": \"checkAnswer\",\n        \"type\": \"text\",\n        \"label\": \"Text for \\\"Check\\\" button\",\n        \"importance\": \"low\",\n        \"default\": \"Check\"\n      },\n      {\n        \"name\": \"tryAgain\",\n        \"label\": \"Text for \\\"Retry\\\" button\",\n        \"type\": \"text\",\n        \"importance\": \"low\",\n        \"default\": \"Retry\"\n      },\n      {\n        \"name\": \"showSolution\",\n        \"type\": \"text\",\n        \"label\": \"Text for \\\"Show solution\\\" button\",\n        \"importance\": \"low\",\n        \"default\": \"Show solution\",\n        \"widget\": \"none\"\n      },\n      {\n        \"name\": \"allSectionsGood\",\n        \"type\": \"text\",\n        \"label\": \"All sections good\",\n        \"description\": \"Feedback text shown when all sections are of tolerable length.\",\n        \"importance\": \"low\",\n        \"default\": \"Your sections\' lengths are all fine.\"\n      },\n      {\n        \"name\": \"sectionTooShort\",\n        \"type\": \"text\",\n        \"label\": \"Section too short\",\n        \"description\": \"Feedback text shown for sections that are too short (@title will be replaced by the section title, @chars will be replaced by the number of characters missing).\",\n        \"importance\": \"low\",\n        \"default\": \"Your section \\\"@title\\\" is too short. You need at least @chars more characters.\"\n      },\n      {\n        \"name\": \"sectionTooLong\",\n        \"type\": \"text\",\n        \"label\": \"Section too long\",\n        \"description\": \"Feedback text shown for sections that are too long (@title will be replaced by the section title, @chars will be replaced by the number of characters needing removal).\",\n        \"importance\": \"low\",\n        \"default\": \"Your section \\\"@title\\\" is too long. Remove at least @chars characters.\"\n      },\n      {\n        \"name\": \"tooShort\",\n        \"type\": \"text\",\n        \"label\": \"Section too short (when typing)\",\n        \"description\": \"Status shown when typing for sections that are too short (@chars will be replaced by the number of characters missing).\",\n        \"importance\": \"low\",\n        \"default\": \"@chars characters too short\"\n      },\n      {\n        \"name\": \"tooLong\",\n        \"type\": \"text\",\n        \"label\": \"Section too long (when typing)\",\n        \"description\": \"Status shown when typing for sections that are too long (@chars will be replaced by the number of characters needing removal).\",\n        \"importance\": \"low\",\n        \"default\": \"@chars characters too long\"\n      },\n      {\n        \"name\": \"copyToClipboardSuccess\",\n        \"type\": \"text\",\n        \"label\": \"Text copied to clipboard\",\n        \"importance\": \"low\",\n        \"default\": \"Your text was copied to the clipboard\"\n      },\n      {\n        \"name\": \"copyToClipboardError\",\n        \"type\": \"text\",\n        \"label\": \"Cannot copy to clipboard\",\n        \"importance\": \"low\",\n        \"default\": \"Your text could not be copied to the clipboard\"\n      },\n      {\n        \"name\": \"section\",\n        \"type\": \"text\",\n        \"label\": \"Section\",\n        \"importance\": \"low\",\n        \"default\": \"Section\"\n      },\n      {\n        \"name\": \"messageNoSection\",\n        \"label\": \"Text for \\\"No section\\\" message\",\n        \"type\": \"text\",\n        \"importance\": \"low\",\n        \"default\": \"There was no section given for this structure strip.\"\n      }\n    ]\n  },\n  {\n    \"name\": \"a11y\",\n    \"type\": \"group\",\n    \"common\": true,\n    \"label\": \"Readspeaker\",\n    \"importance\": \"low\",\n    \"fields\": [\n      {\n        \"name\": \"feedback\",\n        \"type\": \"text\",\n        \"label\": \"Feedback (text for readspeakers)\",\n        \"importance\": \"low\",\n        \"default\": \"Feedback\"\n      },\n      {\n        \"name\": \"copyToClipboard\",\n        \"type\": \"text\",\n        \"label\": \"Copy your text to the clipboard (text for readspeakers)\",\n        \"importance\": \"low\",\n        \"default\": \"Copy text to clipboard\"\n      },\n      {\n        \"name\": \"closeWindow\",\n        \"type\": \"text\",\n        \"label\": \"Close window (text for readspeakers)\",\n        \"importance\": \"low\",\n        \"default\": \"Close window\"\n      },\n      {\n        \"name\": \"showHints\",\n        \"type\": \"text\",\n        \"label\": \"Show hints (text for readspeakers)\",\n        \"importance\": \"low\",\n        \"default\": \"Show hints\"\n      }\n    ]\n  }\n]\n', NULL, 1, 27, NULL, NULL, 'https://h5p.org/content-types/structure-strip', 1),
(139, 'H5P.InfoWall', 'Information Wall', 0, 4, 9, 1, 0, 'iframe', 'dist/h5p-info-wall.js', 'dist/h5p-info-wall.css', '', '[\n  {\n    \"name\": \"infoWall\",\n    \"type\": \"group\",\n    \"importance\": \"high\",\n    \"expanded\": true,\n    \"widget\": \"infoWall\",\n    \"fields\": [\n      {\n        \"name\": \"header\",\n        \"type\": \"text\",\n        \"label\": \"Header\",\n        \"description\": \"Optional header for the information wall.\",\n        \"importance\": \"high\",\n        \"optional\": true\n      },\n      {\n        \"name\": \"propertiesGroup\",\n        \"type\": \"group\",\n        \"label\": \"Properties\",\n        \"importance\": \"high\",\n        \"expanded\": false,\n        \"fields\": [\n          {\n            \"name\": \"properties\",\n            \"type\": \"list\",\n            \"label\": \"Properties\",\n            \"description\": \"Properties for the entries\",\n            \"importance\": \"high\",\n            \"entity\": \"property\",\n            \"min\": 1,\n            \"widgets\": [\n              {\n                \"name\": \"VerticalTabs\",\n                \"label\": \"Default\"\n              }\n            ],\n            \"field\": {\n              \"name\": \"propertyItems\",\n              \"type\": \"group\",\n              \"label\": \"Property items\",\n              \"fields\": [\n                {\n                  \"name\": \"label\",\n                  \"type\": \"text\",\n                  \"label\": \"Label\",\n                  \"default\": \"Unnamed\"\n                },\n                {\n                  \"name\": \"showLabel\",\n                  \"type\": \"boolean\",\n                  \"label\": \"Show property label\",\n                  \"default\": false,\n                  \"optional\": true\n                },\n                {\n                  \"name\": \"searchInProperty\",\n                  \"type\": \"boolean\",\n                  \"label\": \"Enable searching in the property\",\n                  \"default\": true,\n                  \"optional\": true\n                },\n                {\n                  \"name\": \"styling\",\n                  \"type\": \"group\",\n                  \"label\": \"Styling override\",\n                  \"fields\": [\n                    {\n                      \"name\": \"bold\",\n                      \"type\": \"boolean\",\n                      \"label\": \"Bold\",\n                      \"optional\": true\n                    },\n                    {\n                      \"name\": \"italic\",\n                      \"type\": \"boolean\",\n                      \"label\": \"Italic\",\n                      \"optional\": true\n                    }\n                  ]\n                }\n              ]\n            }\n          },\n          {\n            \"name\": \"dummy\",\n            \"type\": \"text\",\n            \"widget\": \"none\"\n          }\n        ]\n      },\n      {\n        \"name\": \"panels\",\n        \"type\": \"list\",\n        \"label\": \"Panels\",\n        \"description\": \"Panels for the wall\",\n        \"importance\": \"high\",\n        \"entity\": \"panel\",\n        \"min\": 1,\n        \"widgets\": [\n          {\n            \"name\": \"VerticalTabs\",\n            \"label\": \"Default\"\n          }\n        ],\n        \"field\": {\n          \"name\": \"entriesGroup\",\n          \"type\": \"group\",\n          \"label\": \"Entry items\",\n          \"fields\": [\n            {\n              \"name\": \"panelTitle\",\n              \"type\": \"text\",\n              \"label\": \"Title for panel\"\n            },\n            {\n              \"name\": \"image\",\n              \"type\": \"library\",\n              \"label\": \"Image\",\n              \"optional\": true,\n              \"options\": [\n                \"H5P.Image 1.1\"\n              ]\n            },\n            {\n              \"name\": \"entries\",\n              \"type\": \"list\",\n              \"label\": \"Entries\",\n              \"description\": \"Entries for the properties\",\n              \"entity\": \"value\",\n              \"widgets\": [\n                {\n                  \"name\": \"InfoWallPassiveList\",\n                  \"label\": \"Default\"\n                }\n              ],\n              \"min\": 1,\n              \"field\": {\n                \"name\": \"value\",\n                \"type\": \"text\",\n                \"widget\": \"html\",\n                \"label\": \"Label to be changed automatically\",\n                \"optional\": true,\n                \"enterMode\": \"div\",\n                \"tags\": [\n                  \"strong\",\n                  \"em\",\n                  \"u\",\n                  \"del\",\n                  \"sub\",\n                  \"sup\",\n                  \"a\",\n                  \"ul\",\n                  \"ol\",\n                  \"h1\",\n                  \"h2\",\n                  \"h3\",\n                  \"h4\",\n                  \"h5\",\n                  \"h6\",\n                  \"hr\",\n                  \"pre\",\n                  \"code\",\n                  \"table\"\n                ],\n                \"font\": {\n                  \"size\": true,\n                  \"color\": true,\n                  \"background\": true\n                }\n              }\n            },\n            {\n              \"name\": \"keywords\",\n              \"type\": \"text\",\n              \"label\": \"Additional keywords\",\n              \"description\": \"Add additional keywords separated by a blank space that will be used for filtering but not be visible to the user.\",\n              \"optional\": true\n            }\n          ]\n        }\n      },\n      {\n        \"name\": \"behaviour\",\n        \"type\": \"group\",\n        \"importance\": \"low\",\n        \"label\": \"Behavioural settings\",\n        \"description\": \"These options will let you control how the task behaves.\",\n        \"fields\": [\n          {\n            \"name\": \"useFallbackImage\",\n            \"type\": \"boolean\",\n            \"label\": \"Use fallback for missing images\",\n            \"default\": false,\n            \"optional\": true\n          },\n          {\n            \"name\": \"fallbackImage\",\n            \"type\": \"library\",\n            \"label\": \"Image\",\n            \"optional\": true,\n            \"options\": [\n              \"H5P.Image 1.1\"\n            ],\n            \"widget\": \"showWhen\",\n            \"showWhen\": {\n              \"rules\": [\n                {\n                  \"field\": \"useFallbackImage\",\n                  \"equals\": true\n                }\n              ]\n            }\n          },\n          {\n            \"name\": \"imageWidth\",\n            \"label\": \"Image width\",\n            \"type\": \"number\",\n            \"importance\": \"low\",\n            \"description\": \"Image width in px.\",\n            \"default\": 150\n          },\n          {\n            \"name\": \"imageHeight\",\n            \"label\": \"Image height\",\n            \"type\": \"number\",\n            \"importance\": \"low\",\n            \"description\": \"Image height in px.\",\n            \"default\": 150\n          },\n          {\n            \"name\": \"alternateBackground\",\n            \"label\": \"Alternate panel background\",\n            \"type\": \"boolean\",\n            \"importance\": \"low\",\n            \"description\": \"If checked, each 2nd panel will have slightly darker background than the others.\",\n            \"default\": true,\n            \"optional\": true\n          },\n          {\n            \"name\": \"offerFilterField\",\n            \"label\": \"Offer filter field\",\n            \"type\": \"boolean\",\n            \"importance\": \"low\",\n            \"description\": \"If checked, users will be able to filter the info wall.\",\n            \"default\": true,\n            \"optional\": true\n          },\n          {\n            \"name\": \"modeFilterField\",\n            \"label\": \"Mode for filter field\",\n            \"type\": \"select\",\n            \"importance\": \"low\",\n            \"description\": \"Choose whether the filter should narrow down or broaden the search with every new keyword.\",\n            \"options\": [\n              {\n                \"value\": \"and\",\n                \"label\": \"Narrow down\"\n              },\n              {\n                \"value\": \"or\",\n                \"label\": \"Broaden\"\n              }\n            ],\n            \"default\": \"or\",\n            \"optional\": false,\n            \"widget\": \"showWhen\",\n            \"showWhen\": {\n              \"rules\": [\n                {\n                  \"field\": \"offerFilterField\",\n                  \"equals\": true\n                }\n              ]\n            }\n          }\n        ]\n      },\n      {\n        \"name\": \"l10n\",\n        \"type\": \"group\",\n        \"common\": true,\n        \"label\": \"User interface\",\n        \"importance\": \"low\",\n        \"fields\": [\n          {\n            \"name\": \"noEntriesError\",\n            \"type\": \"text\",\n            \"label\": \"No content entered\",\n            \"importance\": \"low\",\n            \"default\": \"The author did not enter anything.\"\n          },\n          {\n            \"name\": \"noMatchesForFilter\",\n            \"type\": \"text\",\n            \"label\": \"No matches found\",\n            \"description\": \"@query is a placeholder and will be replaced by the respective query that was entered.\",\n            \"importance\": \"low\",\n            \"default\": \"There are not matches for @query.\"\n          },\n          {\n            \"name\": \"enterToFilter\",\n            \"type\": \"text\",\n            \"label\": \"Enter to filter\",\n            \"description\": \"Message for screen readers.\",\n            \"importance\": \"low\",\n            \"default\": \"Enter a query to filter the content for relevant entries.\"\n          },\n          {\n            \"name\": \"listChanged\",\n            \"type\": \"text\",\n            \"label\": \"List changed.\",\n            \"description\": \"Message for screen readers. @visible and @total are placeholders and will be preplaced with the respective values.\",\n            \"importance\": \"low\",\n            \"default\": \"List changed. Showing @visible of @total items.\"\n          }\n        ]\n      }\n    ]\n  }\n]', NULL, NULL, NULL, NULL, NULL, 'https://h5p.org/content-types/information-wall', 1),
(140, 'H5PEditor.InfoWall', 'H5PEditor.InfoWall', 0, 2, 6, 0, 0, '', 'dist/h5peditor-info-wall.js', 'dist/h5peditor-info-wall.css', '', '', NULL, 1, 12, NULL, NULL, NULL, 1),
(141, 'H5PEditor.InfoWallPassiveList', 'H5PEditor.InfoWallPassiveList', 0, 1, 5, 0, 0, '', 'dist/h5peditor-info-wall-passive-list.js', '', '', '', NULL, 1, 12, NULL, NULL, NULL, 1);
INSERT INTO `mdl_h5p_libraries` (`id`, `machinename`, `title`, `majorversion`, `minorversion`, `patchversion`, `runnable`, `fullscreen`, `embedtypes`, `preloadedjs`, `preloadedcss`, `droplibrarycss`, `semantics`, `addto`, `coremajor`, `coreminor`, `metadatasettings`, `tutorial`, `example`, `enabled`) VALUES
(142, 'H5P.GameMap', 'Game Map', 1, 5, 4, 1, 0, 'iframe', 'dist/h5p-game-map.js', 'dist/h5p-game-map.css', '', '[{\"name\":\"showTitleScreen\",\"label\":\"Show title screen\",\"description\":\"If checked, a title screen will show up when starting.\",\"type\":\"boolean\",\"default\":false,\"optional\":true},{\"name\":\"titleScreen\",\"label\":\"Title screen\",\"type\":\"group\",\"importance\":\"low\",\"fields\":[{\"name\":\"titleScreenIntroduction\",\"label\":\"Introduction\",\"type\":\"text\",\"widget\":\"html\",\"placeholder\":\"Welcome to ...\",\"optional\":true,\"enterMode\":\"div\",\"tags\":[\"sub\",\"sup\",\"strong\",\"em\",\"p\",\"code\",\"u\",\"del\",\"a\",\"ul\",\"ol\",\"hr\",\"pre\",\"code\"],\"font\":{\"size\":true,\"color\":true,\"background\":true},\"default\":\"<p style=\\\"text-align: center;\\\"></p>\"},{\"name\":\"titleScreenMedium\",\"label\":\"Title screen media\",\"type\":\"library\",\"optional\":true,\"options\":[\"H5P.Image 1.1\",\"H5P.Video 1.6\"]}],\"widget\":\"gamemapshowwhen\",\"gamemapshowwhen\":{\"rules\":[{\"field\":\"showTitleScreen\",\"equals\":true}]}},{\"name\":\"headline\",\"label\":\"Headline\",\"type\":\"text\",\"description\":\"Optional headline for the titlebar.\",\"optional\":true},{\"name\":\"gamemapSteps\",\"type\":\"group\",\"label\":\"Game map editor\",\"importance\":\"high\",\"widget\":\"wizard\",\"fields\":[{\"name\":\"backgroundImageSettings\",\"label\":\"Background\",\"type\":\"group\",\"importance\":\"high\",\"fields\":[{\"name\":\"backgroundImage\",\"type\":\"image\",\"label\":\"Background image\",\"importance\":\"high\",\"description\":\"Select an image to use as the background of the game map.\",\"optional\":true},{\"name\":\"backgroundColor\",\"type\":\"text\",\"label\":\"Background color\",\"description\":\"Choose a color to use as the background of the game map.\",\"default\":\"rgb(255, 255, 255)\",\"widget\":\"colorSelector\",\"spectrum\":{\"showInput\":true,\"showInitial\":true,\"preferredFormat\":\"rgb\"}}]},{\"name\":\"gamemap\",\"label\":\"Game map\",\"type\":\"group\",\"importance\":\"high\",\"widget\":\"gamemap\",\"fields\":[{\"name\":\"dummy\",\"type\":\"boolean\",\"widget\":\"none\",\"optional\":true},{\"name\":\"elements\",\"type\":\"list\",\"label\":\"Elements\",\"importance\":\"high\",\"entity\":\"Element\",\"field\":{\"name\":\"elements\",\"type\":\"group\",\"label\":\"Elements\",\"importance\":\"high\",\"fields\":[{\"name\":\"id\",\"type\":\"text\",\"label\":\"Id\",\"widget\":\"none\"},{\"name\":\"type\",\"type\":\"text\",\"label\":\"Type\",\"widget\":\"none\"},{\"name\":\"label\",\"type\":\"text\",\"label\":\"Stage label\",\"description\":\"This label will be displayed on top of your exercise and will help you to connect different stages with one another.\",\"importance\":\"medium\"},{\"name\":\"canBeStartStage\",\"type\":\"boolean\",\"label\":\"User can start here\",\"description\":\"If checked, this stage will be a stage that the user start at. If no stage or more than one stage can be the start stage, the starting stage will be chosen randomly.\",\"importance\":\"medium\",\"default\":false},{\"name\":\"time\",\"type\":\"group\",\"label\":\"Time limit\",\"description\":\"Define timer related settings.\",\"fields\":[{\"name\":\"timeLimit\",\"type\":\"number\",\"label\":\"Time limit\",\"description\":\"Optional time limit in seconds. If a user exceeds this time, the exercise will close, be reset, and the user will loose a life if lives are limited.\",\"min\":1,\"optional\":true},{\"name\":\"timeoutWarning\",\"type\":\"number\",\"label\":\"Timeout warning time\",\"description\":\"Optionally set when a timeout warning audio should be played (number of remaining seconds). An audio needs to be set in the audio settings.\",\"min\":1,\"optional\":true}]},{\"name\":\"accessRestrictions\",\"type\":\"group\",\"label\":\"Access restrictions\",\"description\":\"Define restrictions for unlocking.\",\"fields\":[{\"name\":\"allOrAnyRestrictionSet\",\"type\":\"select\",\"label\":\"All or any restriction set\",\"description\":\"Choose if all or any of the following restrictions need to be met.\",\"optional\":true,\"options\":[{\"value\":\"all\",\"label\":\"All\"},{\"value\":\"any\",\"label\":\"Any\"}],\"default\":\"all\"},{\"name\":\"restrictionSetList\",\"type\":\"list\",\"optional\":true,\"label\":\"Restriction sets\",\"entity\":\"restriction set\",\"widgets\":[{\"name\":\"VerticalTabs\",\"label\":\"Default\"}],\"field\":{\"name\":\"restrictionSetGroup\",\"type\":\"group\",\"label\":\"Restriction set\",\"fields\":[{\"name\":\"allOrAnyRestriction\",\"type\":\"select\",\"label\":\"All or any restriction\",\"description\":\"Choose if all or any of the following restrictions need to be met.\",\"options\":[{\"value\":\"all\",\"label\":\"All\"},{\"value\":\"any\",\"label\":\"Any\"}],\"default\":\"any\"},{\"name\":\"restrictionList\",\"type\":\"list\",\"label\":\"Restrictions\",\"entity\":\"restriction\",\"optional\":true,\"field\":{\"name\":\"restrictionGroup\",\"type\":\"group\",\"label\":\"Restriction\",\"fields\":[{\"name\":\"restrictionType\",\"label\":\"Restriction type\",\"type\":\"select\",\"optional\":true,\"options\":[{\"value\":\"totalScore\",\"label\":\"Total score\"},{\"value\":\"stageScore\",\"label\":\"Stage score\"},{\"value\":\"stageProgress\",\"label\":\"Stage progress\"},{\"value\":\"time\",\"label\":\"Time\"}],\"default\":\"totalScore\"},{\"name\":\"totalScoreGroup\",\"type\":\"group\",\"label\":\"Total score\",\"expanded\":true,\"fields\":[{\"name\":\"totalScoreOperator\",\"label\":\"Operator for total score\",\"type\":\"select\",\"optional\":true,\"options\":[{\"value\":\"lessThan\",\"label\":\"less than\"},{\"value\":\"equalTo\",\"label\":\"equal to\"},{\"value\":\"notEqualTo\",\"label\":\"not equal to\"},{\"value\":\"greaterThan\",\"label\":\"greater than\"}],\"default\":\"greaterThan\"},{\"name\":\"totalScoreValue\",\"label\":\"Value of total score to compare to\",\"type\":\"number\",\"optional\":true}],\"widget\":\"