\",\"label\":\"Style\",\"importance\":\"low\",\"expanded\":true,\"fields\":[{\"name\":\"colorPath\",\"type\":\"text\",\"label\":\"Color path\",\"optional\":true,\"default\":\"rgba(0, 0, 0, 0.7)\",\"widget\":\"colorSelector\",\"spectrum\":{\"showInput\":true,\"showInitial\":true,\"showAlpha\":true,\"preferredFormat\":\"rgb\"}},{\"name\":\"colorPathCleared\",\"type\":\"text\",\"label\":\"Color path cleared\",\"optional\":true,\"default\":\"rgba(0, 130, 0, 0.7)\",\"widget\":\"colorSelector\",\"spectrum\":{\"showInput\":true,\"showInitial\":true,\"showAlpha\":true,\"preferredFormat\":\"rgb\"}},{\"name\":\"pathWidth\",\"type\":\"select\",\"label\":\"Path width\",\"default\":\"0.2\",\"optional\":false,\"options\":[{\"value\":\"0.1\",\"label\":\"thin\"},{\"value\":\"0.2\",\"label\":\"medium\"},{\"value\":\"0.3\",\"label\":\"thick\"}]},{\"name\":\"pathStyle\",\"type\":\"select\",\"label\":\"Path style\",\"default\":\"dotted\",\"optional\":false,\"options\":[{\"value\":\"solid\",\"label\":\"Solid\"},{\"value\":\"dotted\",\"label\":\"Dotted\"},{\"value\":\"dashed\",\"label\":\"Dashed\"},{\"value\":\"double\",\"label\":\"Double\"}]}]}]},{\"name\":\"misc\",\"type\":\"group\",\"label\":\"Miscellaneous\",\"collapsed\":true,\"importance\":\"low\",\"fields\":[{\"name\":\"useAnimation\",\"type\":\"boolean\",\"label\":\"Animate map\",\"description\":\"Decide if the map should be animated. Even if you set this option, the content type will honor the users\' browser setting if they prefer reduced motion.\",\"default\":true},{\"name\":\"dummy\",\"type\":\"boolean\",\"label\":\"Dummy\",\"widget\":\"none\"}]}]},{\"name\":\"audio\",\"type\":\"group\",\"importance\":\"low\",\"label\":\"Audio settings\",\"fields\":[{\"name\":\"backgroundMusic\",\"type\":\"group\",\"importance\":\"low\",\"label\":\"Background music\",\"fields\":[{\"name\":\"music\",\"type\":\"audio\",\"label\":\"Background music\",\"optional\":true},{\"name\":\"muteDuringExercise\",\"type\":\"boolean\",\"label\":\"Mute when taking exercises\",\"default\":true,\"optional\":true}]},{\"name\":\"ambient\",\"type\":\"group\",\"importance\":\"low\",\"label\":\"Events\",\"fields\":[{\"name\":\"clickStageLocked\",\"type\":\"audio\",\"label\":\"Click on locked stage\",\"description\":\"Will be played on the map when clicking on a locked stage.\",\"optional\":true},{\"name\":\"checkExerciseNotFullScore\",\"type\":\"audio\",\"label\":\"Check exercise (not full score)\",\"description\":\"Will be played when an answer is checked and the user did not get full score.\",\"optional\":true},{\"name\":\"checkExerciseFullScore\",\"type\":\"audio\",\"label\":\"Check exercise (full score)\",\"description\":\"Will be played when an answer is checked and the user did get full score.\",\"optional\":true},{\"name\":\"unlockStage\",\"type\":\"audio\",\"label\":\"Unlocking a stage\",\"description\":\"Will be played on the map when a stage gets unlocked.\",\"optional\":true},{\"name\":\"openExercise\",\"type\":\"audio\",\"label\":\"Open exercise\",\"description\":\"Will be played when an exercise is opened.\",\"optional\":true},{\"name\":\"closeExercise\",\"type\":\"audio\",\"label\":\"Close exercise\",\"description\":\"Will be played when an exercise is closed.\",\"optional\":true},{\"name\":\"showDialog\",\"type\":\"audio\",\"label\":\"Show dialog\",\"description\":\"Will be played when a confirmation dialog is shown.\",\"optional\":true},{\"name\":\"fullScore\",\"type\":\"audio\",\"label\":\"Full score\",\"description\":\"Will be played when the user reaches full score for the map.\",\"optional\":true},{\"name\":\"lostLife\",\"type\":\"audio\",\"label\":\"Lost a life\",\"description\":\"Will be played when the user loses a life.\",\"optional\":true},{\"name\":\"gainedLife\",\"type\":\"audio\",\"label\":\"Gained life\",\"description\":\"Will be played when the user gains a life.\",\"optional\":true},{\"name\":\"gameOver\",\"type\":\"audio\",\"label\":\"Game over\",\"description\":\"Will be played when the user is game over.\",\"optional\":true},{\"name\":\"extraTime\",\"type\":\"audio\",\"label\":\"Gained extra time\",\"description\":\"Will be played when the user gains extra time.\",\"optional\":true},{\"name\":\"timeoutWarning\",\"type\":\"audio\",\"label\":\"Timeout warning\",\"description\":\"Will be played when the user is running out of time for an exercise or if the global time runs out.\",\"optional\":true},{\"name\":\"endscreenNoSuccess\",\"type\":\"audio\",\"label\":\"End screen (not full score)\",\"description\":\"Will be played on the end screen if the user did not get full score.\",\"optional\":true},{\"name\":\"endscreenSuccess\",\"type\":\"audio\",\"label\":\"End screen (full score)\",\"description\":\"Will be played on the end screen if the user got full score.\",\"optional\":true}]}]},{\"name\":\"behaviour\",\"type\":\"group\",\"importance\":\"low\",\"label\":\"Behavioural settings\",\"fields\":[{\"name\":\"lives\",\"label\":\"Lives\",\"description\":\"Set the number of lives for a user or leave empty for unlimited lives. Users will lose a life when they do not get full score and they cannot continue once all lives are lost.\",\"type\":\"number\",\"min\":1,\"optional\":true},{\"name\":\"timeLimitGlobal\",\"type\":\"number\",\"label\":\"Global time limit\",\"description\":\"Optional time limit in seconds for the whole game. If a user exceeds this time, the game will be over immediately.\",\"min\":1,\"optional\":true},{\"name\":\"timeoutWarningGlobal\",\"type\":\"number\",\"label\":\"Timeout warning time\",\"description\":\"Optionally set when a timeout warning audio should be played (number of remaining seconds). An audio needs to be set in the audio settings.\",\"min\":1,\"optional\":true},{\"name\":\"finishScore\",\"type\":\"number\",\"label\":\"Finish score\",\"description\":\"Optional score that can be lower than the summed maximum score of all exercises, so users can receive full score without completing all exercises.\",\"min\":0,\"optional\":true},{\"name\":\"enableRetry\",\"label\":\"Enable \\\"Retry\\\" button\",\"type\":\"boolean\",\"default\":true,\"optional\":true},{\"name\":\"enableSolutionsButton\",\"label\":\"Enable \\\"Show solutions\\\" button\",\"type\":\"boolean\",\"default\":true,\"optional\":true},{\"name\":\"map\",\"type\":\"group\",\"label\":\"Map\",\"fields\":[{\"name\":\"showLabels\",\"type\":\"boolean\",\"label\":\"Show stage labels\",\"description\":\"Choose whether a stage\'s label will be shown on hovering a stage with the mouse. The label will not show on touch devices.\",\"default\":true},{\"name\":\"roaming\",\"type\":\"select\",\"label\":\"Roaming\",\"description\":\"Choose whether users can roam all stages freely, need to finish a stage to get access to that stage\'s neighbors, or need to pass a stage to get access to that stage\'s neigbors.\",\"options\":[{\"value\":\"free\",\"label\":\"Roam freely\"},{\"value\":\"complete\",\"label\":\"Complete to clear stage\"},{\"value\":\"success\",\"label\":\"Succeed to clear stage\"}],\"default\":\"free\"},{\"name\":\"fog\",\"type\":\"select\",\"label\":\"Visibility range\",\"description\":\"Select how far the user can see ahead\",\"optional\":true,\"options\":[{\"value\":\"all\",\"label\":\"See all stages\"},{\"value\":\"1\",\"label\":\"See all unlocked stages and their adjacent neighbors\"},{\"value\":\"0\",\"label\":\"See only unlocked stages\"}],\"default\":\"all\",\"widget\":\"gamemapshowwhen\",\"gamemapshowwhen\":{\"nullWhenHidden\":true,\"rules\":[{\"field\":\"roaming\",\"equals\":[\"complete\",\"success\"]}]}}]}]},{\"name\":\"l10n\",\"type\":\"group\",\"label\":\"User interface\",\"common\":true,\"fields\":[{\"name\":\"start\",\"type\":\"text\",\"label\":\"Start\",\"default\":\"Start\"},{\"name\":\"continue\",\"type\":\"text\",\"label\":\"Continue\",\"default\":\"Continue\"},{\"name\":\"restart\",\"type\":\"text\",\"label\":\"Restart\",\"default\":\"Restart\"},{\"name\":\"showSolutions\",\"type\":\"text\",\"label\":\"Show solutions\",\"default\":\"Show solutions\"},{\"name\":\"completedMap\",\"type\":\"text\",\"label\":\"Completed the map\",\"default\":\"You have completed the map!\"},{\"name\":\"fullScoreButnoLivesLeft\",\"type\":\"text\",\"label\":\"Full score, but no lives left\",\"default\":\"You have achieved full score, but lost all your lifes!\"},{\"name\":\"fullScoreButTimeout\",\"type\":\"text\",\"label\":\"Full score, but timed out\",\"default\":\"You have achieved full score, but ran out of time!\"},{\"name\":\"confirmFinishHeader\",\"type\":\"text\",\"label\":\"Dialog header finish map\",\"default\":\"Finish map?\"},{\"name\":\"confirmFinishDialog\",\"type\":\"text\",\"label\":\"Dialog text finish map: General\",\"default\":\"If you finish now, you will not be able to explore the map any longer.\"},{\"name\":\"confirmFinishDialogSubmission\",\"type\":\"text\",\"label\":\"Dialog text finish map: Submission\",\"default\":\"Your score will be submitted.\"},{\"name\":\"confirmFinishDialogQuestion\",\"type\":\"text\",\"label\":\"Dialog text finish map: Question\",\"default\":\"Do you really want to finish the map?\"},{\"name\":\"confirmAccessDeniedHeader\",\"type\":\"text\",\"label\":\"Dialog header access denied\",\"default\":\"Stage locked\"},{\"name\":\"confirmAccessDeniedDialog\",\"type\":\"text\",\"label\":\"Dialog text access denied: General\",\"default\":\"This stage requires you to meet some goals before it can be opened.\"},{\"name\":\"yes\",\"type\":\"text\",\"label\":\"Yes\",\"default\":\"Yes\"},{\"name\":\"no\",\"type\":\"text\",\"label\":\"No\",\"default\":\"No\"},{\"name\":\"confirmGameOverHeader\",\"type\":\"text\",\"label\":\"Dialog header game over\",\"default\":\"Game over!\"},{\"name\":\"confirmGameOverDialog\",\"type\":\"text\",\"label\":\"Dialog text game over\",\"default\":\"You have lost all your lives. Please try again!\"},{\"name\":\"confirmGameOverDialogTimeout\",\"type\":\"text\",\"label\":\"Dialog text game over by timeout\",\"default\":\"You have run out of time. Please try again!\"},{\"name\":\"confirmTimeoutHeader\",\"type\":\"text\",\"label\":\"Dialog header time out\",\"default\":\"Time out!\"},{\"name\":\"confirmTimeoutDialog\",\"type\":\"text\",\"label\":\"Dialog text time out\",\"default\":\"You ran out of time.\"},{\"name\":\"confirmTimeoutDialogLostLife\",\"type\":\"text\",\"label\":\"Dialog text time out (lost a life)\",\"default\":\"You ran out of time and lost a life.\"},{\"name\":\"confirmScoreIncompleteHeader\",\"type\":\"text\",\"label\":\"Dialog header score incomplete\",\"default\":\"Not full score!\"},{\"name\":\"confirmIncompleteScoreDialogLostLife\",\"type\":\"text\",\"label\":\"Dialog text score incomplete (lost a life)\",\"default\":\"You did not achieve full score and lost a life.\"},{\"name\":\"confirmFullScoreHeader\",\"type\":\"text\",\"label\":\"Dialog header full score\",\"default\":\"You achieved full score!\"},{\"name\":\"confirmFullScoreDialog\",\"type\":\"text\",\"label\":\"Dialog text full score\",\"default\":\"You have collected enough points to finish this map with a full score, but you are free to explore the rest if you wish to. Your score will be submitted once you finish the map.\"},{\"name\":\"confirmFullScoreDialogLoseLivesAmendmend\",\"type\":\"text\",\"label\":\"Dialog text full score (amendment, if lives are set)\",\"default\":\"But beware! You may still lose lives!\"},{\"name\":\"ok\",\"type\":\"text\",\"label\":\"OK\",\"default\":\"OK\"},{\"name\":\"noStages\",\"type\":\"text\",\"label\":\"No stages were set\",\"default\":\"No valid stages were set for the map.\"},{\"name\":\"settings\",\"type\":\"text\",\"label\":\"Settings\",\"default\":\"Settings\"},{\"name\":\"volumeMusic\",\"type\":\"text\",\"label\":\"Volume of music\",\"default\":\"Volume of music\"},{\"name\":\"volumeSFX\",\"type\":\"text\",\"label\":\"Volume of sound effects\",\"default\":\"Volume of sound effects\"},{\"name\":\"restrictionsAllOfLong\",\"type\":\"text\",\"label\":\"The stage will not be available unless\",\"default\":\"The stage will not be available unless:\"},{\"name\":\"restrictionsAnyOfLong\",\"type\":\"text\",\"label\":\"The stage will not be available unless any of\",\"default\":\"The stage will not be available unless any of:\"},{\"name\":\"restrictionsAllOf\",\"type\":\"text\",\"label\":\"All of:\",\"default\":\"All of:\"},{\"name\":\"restrictionsAnyOf\",\"type\":\"text\",\"label\":\"Any of:\",\"default\":\"Any of:\"},{\"name\":\"restrictionTotalScoreLessThan\",\"type\":\"text\",\"label\":\"Total score less than\",\"default\":\"You have a total score less than @value.\"},{\"name\":\"restrictionTotalScoreEqualTo\",\"type\":\"text\",\"label\":\"Total score equal to\",\"default\":\"You have a total score equal to @value.\"},{\"name\":\"restrictionTotalScoreNotEqualTo\",\"type\":\"text\",\"label\":\"Total score not equal to\",\"default\":\"You have a total score not equal to @value.\"},{\"name\":\"restrictionTotalScoreGreaterThan\",\"type\":\"text\",\"label\":\"Total score greater than\",\"default\":\"You have a total score greater than @value.\"},{\"name\":\"restrictionStageScoreLessThan\",\"type\":\"text\",\"label\":\"Stage score less than\",\"default\":\"You have a score less than @value in stage @label.\"},{\"name\":\"restrictionStageScoreEqualTo\",\"type\":\"text\",\"label\":\"Stage score equal to\",\"default\":\"You have a score equal to @value in stage @label.\"},{\"name\":\"restrictionStageScoreNotEqualTo\",\"type\":\"text\",\"label\":\"Stage score not equal to\",\"default\":\"You have a score not equal to @value in stage @label.\"},{\"name\":\"restrictionStageScoreGreaterThan\",\"type\":\"text\",\"label\":\"Stage score greater than\",\"default\":\"You have a score greater than @value in stage @label.\"},{\"name\":\"restrictionStageProgressIs\",\"type\":\"text\",\"label\":\"Stage progress is\",\"default\":\"The progress of stage @label is @value.\"},{\"name\":\"restrictionStageProgressIsNot\",\"type\":\"text\",\"label\":\"Stage progress is not\",\"default\":\"Ths progress of stage @label is not @value.\"},{\"name\":\"restrictionTimeBefore\",\"type\":\"text\",\"label\":\"Time before\",\"default\":\"The current time is before @value.\"},{\"name\":\"restrictionTimeOn\",\"type\":\"text\",\"label\":\"Time is\",\"default\":\"The current time is @value.\"},{\"name\":\"restrictionTimeNotOn\",\"type\":\"text\",\"label\":\"Time is not\",\"default\":\"The current time is not @value.\"},{\"name\":\"restrictionTimeAfter\",\"type\":\"text\",\"label\":\"Time after\",\"default\":\"The current time is after @value.\"},{\"name\":\"unstarted\",\"type\":\"text\",\"label\":\"Not started\",\"default\":\"not started\"},{\"name\":\"opened\",\"type\":\"text\",\"label\":\"Started\",\"default\":\"started\"},{\"name\":\"completed\",\"type\":\"text\",\"label\":\"Completed\",\"default\":\"completed\"},{\"name\":\"cleared\",\"type\":\"text\",\"label\":\"Completed successfully\",\"default\":\"completed successfully\"},{\"name\":\"missingContent\",\"type\":\"text\",\"label\":\"Missing content\",\"default\":\"No content was set for this stage!\"}]},{\"name\":\"a11y\",\"type\":\"group\",\"label\":\"Accessibility texts\",\"common\":true,\"fields\":[{\"name\":\"buttonFinish\",\"type\":\"text\",\"label\":\"Finish\",\"default\":\"Finish the map\"},{\"name\":\"buttonAudioActive\",\"type\":\"text\",\"label\":\"Audio button (unmuted)\",\"default\":\"Mute audio. Currently unmuted.\"},{\"name\":\"buttonAudioInactive\",\"type\":\"text\",\"label\":\"Audio button (muted)\",\"default\":\"Unmute audio. Currently muted.\"},{\"name\":\"close\",\"type\":\"text\",\"label\":\"Close\",\"default\":\"Close\"},{\"name\":\"yourResult\",\"type\":\"text\",\"label\":\"Your result\",\"description\":\"@score will be replaced by the number of points. @total will be replaced by the maximum possible points.\",\"default\":\"You got @score out of @total points\"},{\"name\":\"mapWasOpened\",\"type\":\"text\",\"label\":\"Map was opened\",\"default\":\"The map was opened.\"},{\"name\":\"mapSolutionsWasOpened\",\"type\":\"text\",\"label\":\"Map was opened (solutions mode)\",\"default\":\"The map was opened in solutions mode.\"},{\"name\":\"startScreenWasOpened\",\"type\":\"text\",\"label\":\"Title screen was opened\",\"default\":\"The title screen was opened.\"},{\"name\":\"endScreenWasOpened\",\"type\":\"text\",\"label\":\"End screen was opened\",\"default\":\"The end screen was opened.\"},{\"name\":\"exerciseLabel\",\"type\":\"text\",\"label\":\"Exercise label\",\"description\":\"@stagelabel is a placeholder and will be replaced with the respective stage label.\",\"default\":\". Exercise for @stagelabel\"},{\"name\":\"stageButtonLabel\",\"type\":\"text\",\"label\":\"Stage button label\",\"description\":\"@stagelabel is a placeholder and will be replaced with the respective stage label.\",\"default\":\"Stage: @stagelabel\"},{\"name\":\"adjacentStageLabel\",\"type\":\"text\",\"label\":\"adjacent stage label\",\"description\":\"@stagelabelOrigin and @stagelabelNeighbor are placeholders and will be replaced with the respective stage labels.\",\"default\":\"Adjacent stage of @stagelabelOrigin: @stagelabelNeighbor\"},{\"name\":\"locked\",\"type\":\"text\",\"label\":\"Locked\",\"default\":\"Locked\"},{\"name\":\"cleared\",\"type\":\"text\",\"label\":\"Cleared\",\"default\":\"Cleared\"},{\"name\":\"applicationInstructions\",\"type\":\"text\",\"label\":\"Description of map navigation\",\"default\":\"Use space or enter key to activate current stage. Use arrow keys to select adjacent stage. Use space or enter key on adjacent stage to navigate there.\"},{\"name\":\"applicationDescription\",\"type\":\"text\",\"label\":\"Description of map\",\"default\":\"Map\"},{\"name\":\"movedToStage\",\"type\":\"text\",\"label\":\"Moved to stage\",\"description\":\"@stagelabel is a placeholder and will be replaced with the respective stage label.\",\"default\":\"Moved to @stagelabel\"},{\"name\":\"stageUnlocked\",\"type\":\"text\",\"label\":\"Unlocked stage\",\"description\":\"@stagelabel is a placeholder and will be replaced with the respective stage label.\",\"default\":\"Stage @stagelabel was unlocked.\"},{\"name\":\"toolbarFallbackLabel\",\"type\":\"text\",\"label\":\"Toolbar fallback label\",\"default\":\"Game Map\"},{\"name\":\"enterFullscreen\",\"type\":\"text\",\"label\":\"Enter fullscreen\",\"default\":\"Enter fullscreen mode\"},{\"name\":\"exitFullscreen\",\"type\":\"text\",\"label\":\"Exit fullscreen\",\"default\":\"Exit fullscreen mode\"}]}]\n', NULL, 1, 27, NULL, NULL, 'https://h5p.org/content-types/game-map', 1),
