(8, 6, 2, 'Welcome to Basis Data', 'Hi Admin, you are enrolled in the course Basis Data.', 4, 'Hi Admin, you are enrolled in the course Basis Data.', NULL, 'moodle', 'enrolcoursewelcomemessage', 'http://moodle.test/user/view.php?id=2&amp;course=3', 'Basis Data', NULL, 1777970596, NULL),
(9, 2, 2, 'Moodle updates are available (http://moodle.test)', 'Update notifications\r\n\r\nThere is a newer Moodle version available!\r\nMoodle 5.2+ (Build: 20260501) Version 2026042000.02 (Stable version)\r\nMoodle 5.1.4+ (Build: 20260501) Version 2025100604.02 (Stable version)\r\n\r\nSee http://moodle.test/admin/index.php for more details\r\n\r\nIt is strongly recommended that you update your site to the latest version to obtain all recent security and bug fixes.\r\n\r\nYour Moodle site http://moodle.test is configured to automatically check for available updates. You are receiving this message as the administrator of the site. You can disable automatic checks for available updates in Site administration / Server / Update notifications or customise the delivery of this message via your preferences page.\r\n', 2, '<h1>Update notifications</h1>\r\n<h2>There is a newer Moodle version available!</h2>\r\n<ul>\r\n<li><strong>Moodle 5.2+ (Build: 20260501)</strong> Version 2026042000.02 (Stable version)</li>\r\n<li><strong>Moodle 5.1.4+ (Build: 20260501)</strong> Version 2025100604.02 (Stable version)</li>\r\n</ul>\r\n<p>See <a href=\"http://moodle.test/admin/index.php\">http://moodle.test/admin/index.php</a> for more details</p>\r\n<p>It is strongly recommended that you update your site to the latest version to obtain all recent security and bug fixes.</p>\r\n<footer><p style=\"font-size:smaller; color:#333;\">Your Moodle site <a href=\"http://moodle.test\">http://moodle.test</a> is configured to automatically check for available updates. You are receiving this message as the administrator of the site. You can disable automatic checks for available updates in Site administration / Server / Update notifications or customise the delivery of this message via your preferences page.</p></footer>', 'Update notifications', 'moodle', 'availableupdate', NULL, NULL, NULL, 1777974364, NULL),
(10, 6, 2, 'Welcome to Basis Data', 'Hi Admin, you are enrolled in the course Basis Data.', 4, 'Hi Admin, you are enrolled in the course Basis Data.', NULL, 'moodle', 'enrolcoursewelcomemessage', 'http://moodle.test/user/view.php?id=2&amp;course=3', 'Basis Data', NULL, 1778565188, NULL),
(11, 6, 2, 'Welcome to Administrasi Sistem Jaringan', 'Hi Admin, you are enrolled in the course Administrasi Sistem Jaringan.', 4, 'Hi Admin, you are enrolled in the course Administrasi Sistem Jaringan.', NULL, 'moodle', 'enrolcoursewelcomemessage', 'http://moodle.test/user/view.php?id=2&amp;course=2', 'Administrasi Sistem Jaringan', NULL, 1778566674, NULL),
(12, 6, 7, 'Welcome to Basis Data', 'Hi vania, you are enrolled in the course Basis Data.', 4, 'Hi vania, you are enrolled in the course Basis Data.', NULL, 'moodle', 'enrolcoursewelcomemessage', 'http://moodle.test/user/view.php?id=7&amp;course=3', 'Basis Data', NULL, 1778577332, NULL);
