INSERT INTO `mdl_tiny_autosave` (`id`, `elementid`, `contextid`, `pagehash`, `userid`, `drafttext`, `draftid`, `pageinstance`, `timemodified`) VALUES
(5, 'id_description_editor', 3, '8abe747c0716b71a9a18194ac43ef16771903aed', 2, '', 593475715, '7d5faa85beab1e913483ed3002adb4b0', 1773559985),
(11, 'id_summary_editor', 14, 'c91c91ab6054777613ebde470610f3cb691d412a', 2, '<p>Mata pelajaranÂ <strong>Administrasi Sistem Jaringan</strong> bertujuan untuk memberikan pemahaman kepada peserta didik mengenai konsep, prinsip, serta praktik dalam pengelolaan dan administrasi sistem jaringan komputer. Pembelajaran ini mencakup materi tentang instalasi sistem operasi jaringan, konfigurasi layanan jaringan, manajemen pengguna, pengaturan hak akses, serta pemeliharaan dan pengamanan sistem jaringan.</p>\n<p>Melalui kegiatan pembelajaran yang mengintegrasikan teori dan praktik, peserta didik diharapkan mampu mengelola layanan jaringan secara efektif dan efisien sesuai dengan kebutuhan organisasi atau lingkungan kerja. Selain itu, mata pelajaran ini juga bertujuan untuk mengembangkan kemampuan berpikir logis, ketelitian, serta keterampilan teknis yang relevan dengan bidang teknologi jaringan komputer.</p>', 523899033, 'c1a859a8dd45764fe1aefc48281d60ed', 1773594121),
